-- Poems batch 327
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e77f148f-7db7-4f74-8e2f-d37e53dd45b4','寄王晉卿都尉','釋道潜','宋','宋诗','song-poetry','','[]','主第耽耽冠北城，位居侯伯固尊榮。',64,'全唐诗/poet.song.52000.json','["主第耽耽冠北城，位居侯伯固尊榮。", "肯將踏月趨朝脚，來伴穿雲渡水行。", "池上紅蕖應漸老，山中紫笋尚抽萌。", "嵩陽迤邐川原勝，聞說它時卜釣耕。"]'),
('b9eb8be1-9502-491d-8e90-a5a86398d3f8','與田承君宗丞話舊','釋道潜','宋','宋诗','song-poetry','','[]','赤日下西谷，松門斂餘暉。',216,'全唐诗/poet.song.52000.json','["赤日下西谷，松門斂餘暉。", "蕭蕭征馬鳴，客子來者誰。", "故人田子方，六月并州歸。", "崎嶇千里道，問子來何爲。", "君命不竢駕，詎敢辭炎曦。", "禪庭梵唄歇，軟語同逶迤。", "梧桐挂凉月，清潤含裳衣。", "人生實萍梗，同附一渺瀰。", "驚風或暫先，波定還相依。", "昔我在南兖，識君英妙時。", "軒軒勇氣節，凜凜如熊羆。", "聲名固已早，時命殊淹遲。", "今茲向魏闕，驥足將騰夷。", "聖君隆至治，諫諍求瑕玼。", "嘗聞至人語，子可補拾遺。", "一言開堯聰，四海風俗移。", "無爲外重失，蹇諤當自持。", "贈言古者事，吾豈忘前規。"]'),
('19bbbd9f-225f-4964-951c-09343065d0de','登嶽頂呈試可邦直','釋道潜','宋','宋诗','song-poetry','','[]','偉哉中國擅五岳，巍巍崧高據其尊。',240,'全唐诗/poet.song.52000.json','["偉哉中國擅五岳，巍巍崧高據其尊。", "四時百辟盡朝會，雲幢烟蓋來追奔。", "自餘衆阜何足數，擾擾羅列真兒孫。", "秋霖乍開原野凈，隆曦破海浮朝暾。", "淵明曠達不事事，勝日結客遊山樊。", "山腰下馬躡風磴，杖屨詰曲躋巑岏。", "窗經玉女猨鳥寂，石漱飛瀏鳴潺湲。", "長松吟風和哀響，肌膚凜栗凄神魂。", "行窮絕頂已晡側，雲烟爲我開餘昏。", "昂頭去天驚尺五，星斗歷歷俯可捫。", "超然擬與人世絕，彷彿有路通崑崙。", "洛陽奇峰三十六，領略併入一眼吞。", "平生方寸喜壯觀，茲游氣豁殊軒軒。", "二豪詞筆有餘地，請賦傑句留山巔。", "風流便可付千載，歐梅尹謝相與傳。"]'),
('0b3714c0-dedf-4abd-bd65-284b6e81da6e','送王彥齡承務還河內','釋道潜','宋','宋诗','song-poetry','','[]','武陵王郎高韵度，鞍馬四方無定住。',128,'全唐诗/poet.song.52000.json','["武陵王郎高韵度，鞍馬四方無定住。", "眼逢泉石便吟哦，咳唾珠璣不論數。", "我亦悠悠事不羈，浪萍風梗隨安之。", "少室山前古蘭若，邂逅便與同襟期。", "興來岸幘一長嘯，清聲激越穿雲嶠。", "竹林故事獨未泯，人物如君亦高調。", "秋風獵獵促鳴蟬，歸路千山入馬鞭。", "白袍烏袖宜圖畫，不羨襄陽孟浩然。"]'),
('85d65efb-e23c-4fe4-b7ea-47a2085a31bd','寄宗室周臣觀察','釋道潜','宋','宋诗','song-poetry','','[]','帝胄天孫多茂良，似公人物更難方。',64,'全唐诗/poet.song.52000.json','["帝胄天孫多茂良，似公人物更難方。", "詩書自負青雲器，風月能收古錦囊。", "科斗雷文陳几席，鱗衣蟻食耀杯觴。", "都城邂逅傾遲素，崧少歸來一夢長。"]'),
('8e901120-6e33-4f4d-8833-70271414dc8b','題宗室公震防禦畫後','釋道潜','宋','宋诗','song-poetry','','[]','錯莫江雲結暝陰，歸飛宿翼半浮沉。',64,'全唐诗/poet.song.52000.json','["錯莫江雲結暝陰，歸飛宿翼半浮沉。", "毫端領略無遺種，想見雍容物外心。", "蒹葭照雪含餘潤，古木欃天氣老成。", "山谷不來居士死，何人爲子一題評。"]'),
('bf85d145-df0b-43af-962d-057e6323d963','同趙伯充防禦觀東坡所畫枯木  其一','釋道潜','宋','宋诗','song-poetry','','[]','經綸志業終不試，晚歲收功翰墨林。',32,'全唐诗/poet.song.52000.json','["經綸志業終不試，晚歲收功翰墨林。", "偶向僧坊委陳迹，每經風雨聽龍吟。"]'),
('c38c15be-1938-428f-88c7-8f059cbc3cae','同趙伯充防禦觀東坡所畫枯木  其二','釋道潜','宋','宋诗','song-poetry','','[]','蕭然素壁倚枯枝，行路驚嗟况所思。',32,'全唐诗/poet.song.52000.json','["蕭然素壁倚枯枝，行路驚嗟况所思。", "惆悵騎鯨天上去，却來人世恐無期。"]'),
('654ec2f6-b620-4a66-8236-a375b6a0b840','大年觀察許作從駕出南薰門雪霽圖因以詩督之','釋道潜','宋','宋诗','song-poetry','','[]','南薰門外照初陽，寶馬琱鞍從玉皇。',64,'全唐诗/poet.song.52000.json','["南薰門外照初陽，寶馬琱鞍從玉皇。", "千丈雪雲開遠野，萬枝瓊樹鬭新粧。", "筆端妙處君先得，老去閑情我未忘。", "乞與山林資翫好，高懸素壁爛生光。"]'),
('5e829be5-09bd-4be7-93ee-edb7970dde8d','與廖明略學士賦餘干縣白雲亭一首呈吳明府','釋道潜','宋','宋诗','song-poetry','','[]','白雲翔太虛，時來傍孤城。',96,'全唐诗/poet.song.52000.json','["白雲翔太虛，時來傍孤城。", "超然此榮觀，常恐鸞鶴迎。", "能賦自疇昔，騷人遺典刑。", "嗣音竟有屬，異代逢淵明。", "揮毫無停綴，臨流有餘清。", "光風轉洲渚，爽氣生軒楹。", "况復廖常州，吐辭皆正聲。", "跂予浪續貂，坐想徒摇旌。"]'),
('975834fe-266a-425d-9cd0-bb425e1a0c1c','賦王立之承奉園亭 大裘軒','釋道潜','宋','宋诗','song-poetry','','[]','經綸志四海，齟齬不得申。',24,'全唐诗/poet.song.52000.json','["經綸志四海，齟齬不得申。", "大裘縱千丈，姑覆洛陽春。"]'),
('57963e95-13c7-4dd5-a18f-a56338f7f6d7','賦王立之承奉園亭 載酒堂','釋道潜','宋','宋诗','song-poetry','','[]','子雲草玄時，載酒客常滿。',24,'全唐诗/poet.song.52000.json','["子雲草玄時，載酒客常滿。", "君今慕若人，竹戶誰來款。"]'),
('e180a382-dd4b-454c-a9f9-e9352ce730c1','賦王立之承奉園亭 漱醉亭','釋道潜','宋','宋诗','song-poetry','','[]','潭潭百尺井，汲引鳴飛瀾。',24,'全唐诗/poet.song.52000.json','["潭潭百尺井，汲引鳴飛瀾。", "驚回午醉客，一漱齒頰寒。"]'),
('3e7ede35-93b0-4fe0-aed2-53dd5331eb74','賦王立之承奉園亭 介庵','釋道潜','宋','宋诗','song-poetry','','[]','一庵容宇宙，介意安在哉。',24,'全唐诗/poet.song.52000.json','["一庵容宇宙，介意安在哉。", "珍重庵中人，空洞無纖埃。"]'),
('a5a36324-e5e7-4a37-a5a0-1b1f26e02e14','賦王立之承奉園亭 頓有亭','釋道潜','宋','宋诗','song-poetry','','[]','君家十亭觀，棋置宛相望。',24,'全唐诗/poet.song.52000.json','["君家十亭觀，棋置宛相望。", "是中富墨妙，偉哉蘇與黄。"]'),
('2dfc5b9d-66f2-41ff-817a-054907f51ce9','賦王立之承奉園亭 亦愛亭','釋道潜','宋','宋诗','song-poetry','','[]','扶疏蔭佳木，五月風來徐。',24,'全唐诗/poet.song.52000.json','["扶疏蔭佳木，五月風來徐。", "淵明方偃臥，亦自愛吾廬。"]'),
('7ceeab6d-e132-4864-a1d9-6000fa5075b5','賦王立之承奉園亭 永日亭','釋道潜','宋','宋诗','song-poetry','','[]','長安貴富人，歲月馬上遷。',24,'全唐诗/poet.song.52000.json','["長安貴富人，歲月馬上遷。", "岸巾怡永日，心事獨翛然。"]'),
('1b35dae5-82c8-4782-b826-c17f15ad60e6','賦王立之承奉園亭 求定齋','釋道潜','宋','宋诗','song-poetry','','[]','南華鑑止水，炯然見須眉。',24,'全唐诗/poet.song.52000.json','["南華鑑止水，炯然見須眉。", "夫子果能定，物豈逃妍媸。"]'),
('06874468-47fb-428a-a379-57cc3c60914d','賦王立之承奉園亭 泠然齋','釋道潜','宋','宋诗','song-poetry','','[]','虛室晝生白，清風襲衣屨。',24,'全唐诗/poet.song.52000.json','["虛室晝生白，清風襲衣屨。", "圓蒲燕坐人，泠然欲仙去。"]'),
('fcdc8b2e-0ba5-4423-9853-805780e722e2','賦王立之承奉園亭 賦歸堂','釋道潜','宋','宋诗','song-poetry','','[]','王郎英妙年，功名固堪勉。',24,'全唐诗/poet.song.52000.json','["王郎英妙年，功名固堪勉。", "浩然賦歸歟，持操真可羨。"]'),
('09c7ccbb-e431-4361-aa45-fcb999f39284','送慈義偁師遊嵩少','釋道潜','宋','宋诗','song-poetry','','[]','道人家住錦溪頭，衣裓常含爽氣浮。',64,'全唐诗/poet.song.52000.json','["道人家住錦溪頭，衣裓常含爽氣浮。", "偶踏塵埃經北闕，却尋雲水過西州。", "冰銷陰壑蘭芽動，柳岸長條春意柔。", "少室峰前無異路，莫將陳迹苦追求。"]'),
('7fa862aa-1daa-4d2c-b5fc-e83defc0d730','東坡先生挽詞  其一','釋道潜','宋','宋诗','song-poetry','','[]','造物周千載，真材得豫章。',48,'全唐诗/poet.song.52000.json','["造物周千載，真材得豫章。", "經綸等伊呂，辭學過班楊。", "德厚傾蠻貊，名高震虜羌。", "數奇終不偶，難與問蒼蒼。"]'),
('81de5beb-d29d-43d2-9740-9eb11f1bbde0','東坡先生挽詞  其二','釋道潜','宋','宋诗','song-poetry','','[]','博學無前古，雄文冠兩京。',48,'全唐诗/poet.song.52000.json','["博學無前古，雄文冠兩京。", "筆頭千字落，詞力九河傾。", "雅量同安石，高才類孔明。", "平生勳業志，鬰鬰閟佳城。"]'),
('f498fdc7-05c1-4cea-92d7-e2a0422b92e6','東坡先生挽詞  其三','釋道潜','宋','宋诗','song-poetry','','[]','少年持國論，不羨洛陽人。',48,'全唐诗/poet.song.52000.json','["少年持國論，不羨洛陽人。", "抗疏忘機骫，危言駭搢紳。", "丹衷那有謂，康濟在斯民。", "竟謫江湖去，端居寂寞濱。"]'),
('dd5e9511-1338-4296-a996-8c1d6514a34f','東坡先生挽詞  其四','釋道潜','宋','宋诗','song-poetry','','[]','初復中原日，人爭拜馬蹄。',48,'全唐诗/poet.song.52000.json','["初復中原日，人爭拜馬蹄。", "梅花辭庾嶺，甘溜酌曹溪。", "梁木傾何速，椿年竟不齊。", "靈輀向崧洛，行路亦悽悽。"]'),
('5112aefe-f71d-42dd-ad02-0ada3dc1139f','東坡先生挽詞  其五','釋道潜','宋','宋诗','song-poetry','','[]','一時英俊附門墉，兄弟從來號兩龍。',64,'全唐诗/poet.song.53000.json','["一時英俊附門墉，兄弟從來號兩龍。", "雄辯未饒端木賜，題評肯下郭林宗。", "精神烱烱風前鶴，操節稜稜雪後松。", "無復勝游參杖屨，追雲弄月更雍容。"]'),
('7d4ed29d-c41e-46db-a247-a54448ef1a78','東坡先生挽詞  其六','釋道潜','宋','宋诗','song-poetry','','[]','群驚投老竄炎荒，瘴雨蠻烟豈易當。',64,'全唐诗/poet.song.53000.json','["群驚投老竄炎荒，瘴雨蠻烟豈易當。", "燾氣內全真自葆，鐵心無動亦何妨。", "海山出處憑誰共，蜑叟追隨樂未央。", "準易著書人不見，微言分付有諸郎。"]'),
('10f78b4c-c090-42ee-a57e-b601dc619026','東坡先生挽詞  其七','釋道潜','宋','宋诗','song-poetry','','[]','羽扇綸巾擁帥權，高才大纛拂雲烟。',64,'全唐诗/poet.song.53000.json','["羽扇綸巾擁帥權，高才大纛拂雲烟。", "初聞父老誦嘉語，綽有風流似昔賢。", "謫籍數年居瘴海，功名無分勒燕然。", "空餘雪浪齋中石，留與邦人萬古傳。"]'),
('fd8db16d-d74c-4cb5-bbd0-004236c82da2','東坡先生挽詞  其八','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','當年吳會友名緇，盡是人天大導師。',64,'全唐诗/poet.song.53000.json','["當年吳會友名緇，盡是人天大導師。", "拔俗高標元自悟，妙明真覺本何疑。", "籃輿行處依然在，蓮社風流固已衰。", "它日西湖吊陳迹，斷橋隄柳不勝悲。"]'),
('9b680239-2bef-4a2e-98f7-e06a8aa9d029','東坡先生挽詞  其九','釋道潜','宋','宋诗','song-poetry','','[]','德政從來主意寬，奮髯時怒豈容奸。',32,'全唐诗/poet.song.53000.json','["德政從來主意寬，奮髯時怒豈容奸。", "儻逢大事能談笑，未必風流劣謝安。"]'),
('a5f0e9ca-114c-4b57-b6e3-a39552e41b8c','東坡先生挽詞  其一○','釋道潜','宋','宋诗','song-poetry','','[]','峨冠正笏立談叢，凜凜群驚國士風。',32,'全唐诗/poet.song.53000.json','["峨冠正笏立談叢，凜凜群驚國士風。", "却戴葛巾從杖屨，直將和氣接兒童。"]'),
('fe4968c3-d0ec-4b33-9280-8c8d3137e493','東坡先生挽詞  其一一','釋道潜','宋','宋诗','song-poetry','','[]','大河當日决澶淵，橫被東徐正渺漫。',32,'全唐诗/poet.song.53000.json','["大河當日决澶淵，橫被東徐正渺漫。", "城上結廬親指顧，敢將忠義折狂瀾。"]'),
('39c07c48-1c53-4658-8a41-a788bea1fc68','東坡先生挽詞  其一二','釋道潜','宋','宋诗','song-poetry','','[]','文登五日召公歸，海市奇觀與願違。',32,'全唐诗/poet.song.53000.json','["文登五日召公歸，海市奇觀與願違。", "已蟄魚龍能再起，人間異事古來稀。"]'),
('7a5b38db-dc0e-4c43-a5c4-390174b03c32','東坡先生挽詞  其一三','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖卷葑拓漪漣，十里橫吞碧玉天。',32,'全唐诗/poet.song.53000.json','["西湖卷葑拓漪漣，十里橫吞碧玉天。", "自謂前身真白傅，至今陳迹尚依然。"]'),
('94e2157c-72f0-453f-a11f-cb57c3115311','東坡先生挽詞  其一四','釋道潜','宋','宋诗','song-poetry','','[]','臨淮大士本無私，應物長於險處施。',32,'全唐诗/poet.song.53000.json','["臨淮大士本無私，應物長於險處施。", "親護舟航渡南海，知公盛德未全衰。"]'),
('17071ba4-01f2-4663-af8c-f70b6a4d1422','東坡先生挽詞  其一五','釋道潜','宋','宋诗','song-poetry','','[]','畫圖雖不上凌烟，道德芬芳滿世間。',32,'全唐诗/poet.song.53000.json','["畫圖雖不上凌烟，道德芬芳滿世間。", "遼鶴已歸東海去，列仙風骨若爲攀。"]'),
('bb20d613-1aba-42f0-8272-762a9d82f18c','孔子韶方平與其姪處度相訪於香山作此詩以贈之','釋道潜','宋','宋诗','song-poetry','','[]','洙泗芬芳遠，高材尚可求。',48,'全唐诗/poet.song.53000.json','["洙泗芬芳遠，高材尚可求。", "二難俱韵勝，小阮更風流。", "語款時容接，詩豪未易酬。", "平生喜人物，邂逅此相投。"]'),
('349dc836-570c-4d7a-91a0-d0b8e79b198e','孔平子書閤所藏石菖蒲','釋道潜','宋','宋诗','song-poetry','','[]','寒溪之濱，沙石之竇。',60,'全唐诗/poet.song.53000.json','["寒溪之濱，沙石之竇。", "産此靈苗，蔚然而秀。", "有美君子，採持而歸。", "文石相并，滀涵清漪。", "根盤九節，霜雪不槁。", "置之幽齋，永以爲好。"]'),
('6e1212b0-baf0-44eb-a18f-b3f88eb00a1c','送處度赴試','釋道潜','宋','宋诗','song-poetry','','[]','異哉曲阜幾世孫，白玉受性良且溫。',128,'全唐诗/poet.song.53000.json','["異哉曲阜幾世孫，白玉受性良且溫。", "詩書禮義祖家學，擾擾自餘何足論。", "良辰往往專吟諷，遠壓曹劉攀屈宋。", "肯與齊梁作後塵，秋月春花恣嘲弄。", "我方杖策過西州，指點雲山結勝游。", "已有詔書催去興，豈宜泉石更淹留。", "征車曉送登長陌，月沒參橫河漢白。", "期君安穩上龍門，不怕臨流遭點額。"]'),
('4b844702-6cfa-48d6-a4ce-267623d68f17','次韵李端叔題孔方平書齋壁  其一','釋道潜','宋','宋诗','song-poetry','','[]','萬事年來即罷休，心縈雲水尚追求。',32,'全唐诗/poet.song.53000.json','["萬事年來即罷休，心縈雲水尚追求。", "草堂早晚投君宿，紙帳蒲團不用收。"]'),
('30782ee7-58c3-496a-bcc9-cfd2342d1bd6','次韵李端叔題孔方平書齋壁  其二','釋道潜','宋','宋诗','song-poetry','','[]','菊叢稍稍敷金蕊，蕎麥芃芃放雪花。',32,'全唐诗/poet.song.53000.json','["菊叢稍稍敷金蕊，蕎麥芃芃放雪花。", "榆柳繚牆蒼靄密，誰知中有隠人家。"]'),
('fe39313f-7908-4cf7-a7f7-7d0e2a24448b','次韵李端叔題孔方平書齋壁  其三','釋道潜','宋','宋诗','song-poetry','','[]','白頭幕府尚崎嶇，南畝歸休盍早圖。',32,'全唐诗/poet.song.53000.json','["白頭幕府尚崎嶇，南畝歸休盍早圖。", "滍上山川要佳句，安排風月待相如。"]'),
('4b52d25e-9829-4407-bc31-a5868796cd13','次韵李端叔題孔方平書齋壁  其四','釋道潜','宋','宋诗','song-poetry','','[]','舍南舍北盡雲山，此處躬耕有底難。',32,'全唐诗/poet.song.53000.json','["舍南舍北盡雲山，此處躬耕有底難。", "社飲雞豚好鄰里，一盃相屬百憂寬。"]'),
('5accd567-6661-42d2-a517-0c966093d1d2','次韵李端叔題孔方平書齋壁  其五','釋道潜','宋','宋诗','song-poetry','','[]','馬蹄逐逐走埃塵，官府寧容自在身。',32,'全唐诗/poet.song.53000.json','["馬蹄逐逐走埃塵，官府寧容自在身。", "夜宿南溪孔居士，青燈相對話悲辛。"]'),
('b2b22a04-2293-44a7-80d0-768624ac63fb','次韵李端叔題孔方平書齋壁  其六','釋道潜','宋','宋诗','song-poetry','','[]','愛君簷外蕭蕭竹，翠幹扶疏一樣齊。',32,'全唐诗/poet.song.53000.json','["愛君簷外蕭蕭竹，翠幹扶疏一樣齊。", "莫道此君無俯仰，驚風墜雪亦須低。"]'),
('146e121b-9229-4c6d-b1fa-6b47fa4ddb2c','次韵李端叔題孔方平書齋壁  其七','釋道潜','宋','宋诗','song-poetry','','[]','端居終日少逢迎，佳客時來一座傾。',32,'全唐诗/poet.song.53000.json','["端居終日少逢迎，佳客時來一座傾。", "不見諸郎事弦管，幽窗唯有讀書聲。"]'),
('36f90e55-0f56-496f-8e85-6646d0953ed5','次韵李端叔題孔方平書齋壁  其八','釋道潜','宋','宋诗','song-poetry','','[]','肝膽未應分楚越，高曾元共水雲鄉。',32,'全唐诗/poet.song.53000.json','["肝膽未應分楚越，高曾元共水雲鄉。", "愛君善作離騷語，清警殊非俗肺腸。"]'),
('d0accc07-8bcc-494b-811b-a30f06f36b6c','次韵李端叔題孔方平書齋壁  其九','釋道潜','宋','宋诗','song-poetry','','[]','仲尼道德高千古，老子微言冠百家。',32,'全唐诗/poet.song.53000.json','["仲尼道德高千古，老子微言冠百家。", "餘澤風流俱擅美，那云玉樹倚兼葭。"]'),
('9587a6fe-3e18-4f5e-b3c1-0a033109b963','次韵李端叔題孔方平書齋壁  其一○','釋道潜','宋','宋诗','song-poetry','','[]','吾黨從來跡易親，只緣同是箇中人。',32,'全唐诗/poet.song.53000.json','["吾黨從來跡易親，只緣同是箇中人。", "滍川魚鳥渾相識，來往沙頭肯厭頻。"]'),
('f304e159-1a33-4b40-87e0-997fb847cf83','行歌亭  其一','釋道潜','宋','宋诗','song-poetry','','[]','自古山林浪得名，欲要人爵謾逃形。',32,'全唐诗/poet.song.53000.json','["自古山林浪得名，欲要人爵謾逃形。", "唯餘滍上行歌者，獨免移文勒戶庭。"]'),
('0423330b-ac64-42a7-9598-707cf2571f1f','行歌亭  其二','釋道潜','宋','宋诗','song-poetry','','[]','先生本自負經綸，志在丘園世莫親。',32,'全唐诗/poet.song.53000.json','["先生本自負經綸，志在丘園世莫親。", "不信請看門下客，盡爲金馬玉堂人。"]'),
('99e3abc4-2125-4fa3-b77f-0dc421b9d2b3','行歌亭  其三','釋道潜','宋','宋诗','song-poetry','','[]','嘗聞箕潁臥巢由，振蕩高風冠九州。',32,'全唐诗/poet.song.53000.json','["嘗聞箕潁臥巢由，振蕩高風冠九州。", "欲識當年孔寧極，依稀堪與若人儔。"]'),
('f703c04b-0e14-4960-b8b7-5a5f8b80ede4','行歌亭  其四','釋道潜','宋','宋诗','song-poetry','','[]','滍川勝氣藹葱葱，遠訪先生舊隠風。',32,'全唐诗/poet.song.53000.json','["滍川勝氣藹葱葱，遠訪先生舊隠風。", "閱禮敦詩見猶子，故知餘澤未終窮。"]'),
('cd515849-d94f-40c1-b6a3-b570137509c9','次韵孔處度李榮期同游汝陽城西等慈寺溪堂','釋道潜','宋','宋诗','song-poetry','','[]','汝陽介崧洛，郡邑古且幽。',120,'全唐诗/poet.song.53000.json','["汝陽介崧洛，郡邑古且幽。", "出郭纔數里，招提據清流。", "千章鬰古木，中有百尺樓。", "循梯到朱欄，眼接萬象游。", "二豪俱才華，筆力勝九牛。", "佳辰同覽眺，高懷肯悲秋。", "軒渠發笑語，遼亂驚鳬鷗。", "平生讀書要，取用不假鈎。", "想當援毫初，應手如見投。", "挹子明月光，泠然洗吾眸。"]'),
('8dc579e2-d83e-42a1-84b2-12b7d16fbd81','次韵方平見寄','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄花弄色近重陽，山果紅梨迥得霜。',64,'全唐诗/poet.song.53000.json','["黄花弄色近重陽，山果紅梨迥得霜。", "節物撩人興不淺，交情如子味何長。", "終期霧豹栖巖穴，且作賓鴻寄野塘。", "它日西湖能過我，胡麻供飯煮芹香。"]'),
('2d802b19-2b59-4a2e-a944-bbeecc6d2cb0','寄題南陽劉氏松堂','釋道潜','宋','宋诗','song-poetry','','[]','南陽自古誇雄都，山川淑氣無時無。',192,'全唐诗/poet.song.53000.json','["南陽自古誇雄都，山川淑氣無時無。", "中間豪傑相間出，臥龍光武興王圖。", "有唐昌黎百世士，布衣奮起爲師儒。", "風流異代骨雖朽，餘澤尚可濡焦枯。", "劉郎先子挺奇質，志業文史稱鄉閭。", "詞場較蓺一不售，掉頭便卜溪山居。", "朋雲友月終歲事，挾冊教子猶區區。", "青松寸根手自植，氣概今已凌凡株。", "虬髯龍甲拂天籟，颯若風雨來江湖。", "悲哉孝思論罔極，新構永與甘棠俱。", "西州騷人競與賦，盛事相詫無賢愚。", "續貂自昔人所誚，詩成出袖增躊躇。"]'),
('ec4d4c19-2662-44d0-85da-5d35f8804e4d','同韓子蒼游黄山觀約高壽朋張公碩不至','釋道潜','宋','宋诗','song-poetry','','[]','駝裘躍馬去翩翩，一舍逡巡箭脫弦。',64,'全唐诗/poet.song.53000.json','["駝裘躍馬去翩翩，一舍逡巡箭脫弦。", "仙事未須窮傳記，勝游聊爲好山川。", "穿林絡石驚寒瀏，繚白縈青對篆烟。", "惆悵能文二三子，操觚安得共周旋。"]'),
('6b2991ca-09ab-4c1f-a457-e1c2869926f8','子蒼見和二篇再用前韵酬之','釋道潜','宋','宋诗','song-poetry','','[]','涉世伊余實强顔，傷弓困翼尚驚弦。',64,'全唐诗/poet.song.53000.json','["涉世伊余實强顔，傷弓困翼尚驚弦。", "論文已失李太白，採藥行尋葛稚川。", "請置黄公新石研，歸磨潘子古松烟。", "幽窗寫就經綸志，它日風雲去斡旋。"]'),
('6cc05ed2-6fe1-4187-9772-24009e3a2f4c','次韵王潜翁題王孝孫所藏摩詰聽松圖','釋道潜','宋','宋诗','song-poetry','','[]','輞川奇處固難評，眼裏瞳人要自明。',64,'全唐诗/poet.song.53000.json','["輞川奇處固難評，眼裏瞳人要自明。", "落落信爲霜後操，蕭蕭那慮世間聲。", "忘言我已輸三士，妙曲渠寧羨九成。", "此去黄塵沙漠底，時時開匣睹余清。"]'),
('e7157b40-9c1d-425b-b11d-23c38c2ff912','游葉城韓氏東園','釋道潜','宋','宋诗','song-poetry','','[]','曾臺累榭蔚相望，古木連雲出繚牆。',64,'全唐诗/poet.song.53000.json','["曾臺累榭蔚相望，古木連雲出繚牆。", "可但陶朱能計略，須知猗頓亦材良。", "松風菊露滋清夜，楚舞吳歌奉宴觴。", "好在諸郎俱挾冊，起家儒術未應忘。"]'),
('38e63a7b-e867-4811-a69e-5e82f49b49e0','過張公碩廷直息軒','釋道潜','宋','宋诗','song-poetry','','[]','涪翁六蓺學，力可當萬人。',204,'全唐诗/poet.song.53000.json','["涪翁六蓺學，力可當萬人。", "施州亦英特，文武備一身。", "風味真頡頏，宛然喜相親。", "詩壇嘗屢戰，妙譽傾縉紳。", "涪翁往播遷，風義頗凋淪。", "施州奮不顧，伏臘賙且勤。", "霜雪槁群木，凜然見松筠。", "施州歸夜臺，遺編照青春。", "嗟我獨不識，覽卷徒悲辛。", "有子紹門戶，飄飄氣方振。", "能文得父風，作語殊不陳。", "流源日疏鑿，豈易量涯津。", "結廬依通衢，隔牆鬧蹄輪。", "頹然小軒上，息偃全天真。", "男兒功名志，蠖屈終一申。", "誰能效急急，俛仰車馬塵。", "涪翁爲子名，高意庶可循。"]'),
('c4edeb77-043f-48a9-b2d2-5d4f9e22cbb3','靜舍與蔡秀如承事會話','釋道潜','宋','宋诗','song-poetry','','[]','浮雲無根蒂，合散不可拘。',228,'全唐诗/poet.song.53000.json','["浮雲無根蒂，合散不可拘。", "忽然隨高風，千里各須臾。", "吾生共天壤，出處良亦如。", "憶昔淮水濱，與君傾蓋初。", "翹翹兩弟昆，文彩照冰壺。", "門闌本世胄，折節勝寒儒。", "扁舟倚高岸，爲我飯伊蒲。", "清談落犀麈，鄙吝驚掃除。", "一別今四載，相忘寄江湖。", "朅來過汝潁，吊舊投生芻。", "夤緣訪山水，歲晚倦回車。", "蕭蕭古寺底，彷彿日已晡。", "聞君戶外音，倒屣迎前趨。", "胡爲乎來哉，吏牒頗馳驅。", "高材困所役，何似林間樗。", "清寒凜敗屋，猛燄焚枯株。", "胡床坐相對，氣貌溫以舒。", "明朝各異縣，那得同蘧廬。", "無煩歎離索，且盡一笑娛。"]'),
('24e1b9b5-6034-4c9b-a939-2307fe493d37','贈耿純叔祕校二令姪','釋道潜','宋','宋诗','song-poetry','','[]','高門知積慶，堂上有諸郎。',48,'全唐诗/poet.song.53000.json','["高門知積慶，堂上有諸郎。", "禮樂非童子，詩書見義方。", "經營羞弱羽，騰踏羨飛黄。", "富貴由勤苦，五車安可忘。"]'),
('824bf7e2-3017-4683-9284-3bc6af994a55','讀子蒼詩卷  其一','釋道潜','宋','宋诗','song-poetry','','[]','蜀國奇男子，能文到古人。',48,'全唐诗/poet.song.53000.json','["蜀國奇男子，能文到古人。", "淳源稽大雅，妙曲和陽春。", "節物驚摇落，僧坊斷四鄰。", "看君新著述，時與短檠親。"]'),
('67da9100-6bd4-4670-8b7f-4f6ec9ef5dac','讀子蒼詩卷  其二','釋道潜','宋','宋诗','song-poetry','','[]','大冊雄文未許窺，百篇先讀海陵詩。',32,'全唐诗/poet.song.53000.json','["大冊雄文未許窺，百篇先讀海陵詩。", "疲駑伏櫪空驤首，飛兔流星作麽追。"]'),
('26aee9b9-cfea-4ef6-9762-80a609a1e0c9','贈賢上人','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','恒山道人棄妻孥，壞衣祝髮從浮圖。',144,'全唐诗/poet.song.53000.json','["恒山道人棄妻孥，壞衣祝髮從浮圖。", "愛纏欲網豈易脫，慧劍劃斷真須臾。", "飄然雲水出鄉國，力學生死來東都。", "心猨意馬就羈束，肯逐萬境爭馳驅。", "回看舊事真一夢，清渭濁涇良自殊。", "楚山歲晚俄邂逅，雪屋對語依圓蒲。", "勸子南游下吳越，小航短棹尋西湖。", "我家住處湖岸北，如椽翠竹森千株。", "竹間扣扉試訪我，定有猨鶴聲相呼。"]'),
('712f983a-4c89-45a9-9acc-e5a1d9e417e5','次韵高壽朋殿直喜雪  其一','釋道潜','宋','宋诗','song-poetry','','[]','俄頃風雲變物華，撒鹽飛絮鬭輕花。',32,'全唐诗/poet.song.53000.json','["俄頃風雲變物華，撒鹽飛絮鬭輕花。", "只應陋巷無貧者，玉戶瑶階共一家。"]'),
('627204a6-9fb2-4300-887e-96f369ebba4b','次韵高壽朋殿直喜雪  其二','釋道潜','宋','宋诗','song-poetry','','[]','挾風穿箔打窗紗，窗裏人看窗外花。',32,'全唐诗/poet.song.53000.json','["挾風穿箔打窗紗，窗裏人看窗外花。", "噴玉流珠君豈羨，從來自是五侯家。"]'),
('70788fd3-a28a-4c21-ba34-2fe026fd6bf1','書申正己秀才所藏雀竹圖後  其一','釋道潜','宋','宋诗','song-poetry','','[]','荒園古塹雪溟濛，細竹枯條共一叢。',32,'全唐诗/poet.song.53000.json','["荒園古塹雪溟濛，細竹枯條共一叢。", "寒雀喧饑正無頼，輸他孔翠食樊籠。"]'),
('854462e7-efb9-40e4-958a-a0a0cd01c9ba','書申正己秀才所藏雀竹圖後  其二','釋道潜','宋','宋诗','song-poetry','','[]','樊籠得食暫時優，身世經年類楚囚。',32,'全唐诗/poet.song.53000.json','["樊籠得食暫時優，身世經年類楚囚。", "何似東阡與南陌，暖風晴日恣遨遊。"]'),
('6ace4c63-f097-4e92-8f7f-e83182d1f2a9','過韓氏莊登小閣  其一','釋道潜','宋','宋诗','song-poetry','','[]','繚牆千堵氣雄深，小構亭亭出數尋。',32,'全唐诗/poet.song.53000.json','["繚牆千堵氣雄深，小構亭亭出數尋。", "刈穫一空雲水白，闌干注目見遙岑。"]'),
('0524c3b6-76a9-4f4e-b824-543170988c8a','過韓氏莊登小閣  其二','釋道潜','宋','宋诗','song-poetry','','[]','玉秀蘭芬好弟昆，時來挾冊視田園。',32,'全唐诗/poet.song.53000.json','["玉秀蘭芬好弟昆，時來挾冊視田園。", "囷場古木千章合，彷彿秦人避世村。"]'),
('5e7a4390-c769-4276-a252-2a4a5cef6f3b','鄭元規秀才內樂庵','釋道潜','宋','宋诗','song-poetry','','[]','內樂名庵誰所擇，澗上文人題榜額。',64,'全唐诗/poet.song.53000.json','["內樂名庵誰所擇，澗上文人題榜額。", "想見風流庵內人，定匪紛華域中客。", "紆朱懷金何足誇，簞食瓢飲真生涯。", "了無憂患到心境，得失雞蟲良可嗟。"]'),
('23ac9901-3787-4e4a-b150-3a0ec14b0111','李榮期秀才杞菊軒','釋道潜','宋','宋诗','song-poetry','','[]','草木助盤餐，紛紛固多品。',168,'全唐诗/poet.song.53000.json','["草木助盤餐，紛紛固多品。", "精英唯竹萌，香軟獨楮菌。", "杞菊於其間，甘清有餘韵。", "達人忘口體，道德自滋潤。", "天隨與東坡，風味實相近。", "窮通均一致，了不見喜慍。", "春苗共採擷，秋英配蘭紉。", "後先屬文詞，金聲而玉振。", "李子妙窮經，屢遭有司擯。", "奔軍未云怯，再舉當决陣。", "開軒植杞菊，澹泊守定分。", "回頭語世俗，未用誚饑困。", "二豪勉躋攀，孔聖故許進。", "長卿亦何人，區區能慕藺。"]'),
('452074ac-3949-49e0-b559-5fb7763f6506','寄潘仲升秀才','釋道潜','宋','宋诗','song-poetry','','[]','漢唐誇汝南，豪傑不勝數。',96,'全唐诗/poet.song.53000.json','["漢唐誇汝南，豪傑不勝數。", "山川有靈蓄，鬰鬰久不吐。", "邇來見潘子，秀色實眉宇。", "是家賢伯仲，學術本鄒魯。", "他時俱特立，肯與噲等伍。", "浪爲葉城游，邂逅得晤語。", "異鄉逢歲晏，越鳥思南舉。", "江湖結後期，細與論今古。"]'),
('61c246b3-417d-488d-873d-3975c2cc2e60','次韵方平送李南仲赴試春闈','釋道潜','宋','宋诗','song-poetry','','[]','四溟鳬雁集天池，十目先看俊翮飛。',64,'全唐诗/poet.song.53000.json','["四溟鳬雁集天池，十目先看俊翮飛。", "養氣有餘吞大敵，窮經無繆識玄微。", "塵埃舊服辭阿緆，雨露新袍授楚衣。", "拜命還家春尚好，桃花流水漲漁磯。"]'),
('ea6f3da2-577f-434e-baad-931343692d40','劉福老長官佚老堂','釋道潜','宋','宋诗','song-poetry','','[]','淵明未掛冠，志已蹈方外。',108,'全唐诗/poet.song.53000.json','["淵明未掛冠，志已蹈方外。", "何時辭五斗，散髮從傲睨。", "閑中氣味好，至樂無與對。", "黄香識君心，機事勸早計。", "古來軒冕事，端受外物制。", "有如纏蔓瓜，詎肯脫根蒂。", "一朝秋風至，零落驚潰潰。", "佚老得天和，晚景期百歲。", "超然閭里間，高風邈難繼。"]'),
('b7fef5d4-b41a-4fdd-8b02-5de4893ded17','贈權上人兼簡其兄高致虛秀才','釋道潜','宋','宋诗','song-poetry','','[]','豫章山川足靈氣，天與四時滋萬彙。',160,'全唐诗/poet.song.53000.json','["豫章山川足靈氣，天與四時滋萬彙。", "翹然雙幹秀一門，儒釋殊科道無異。", "一操經術游廣文，一事瓶盂尋祖意。", "功名生死兩俱徹，論報君親各無愧。", "上人餘力擅風騷，三昧何妨間遊戲。", "窮愁肯學郊與島，高瞻已能追晉魏。", "文章妙處均製饌，不放鹹酸傷至味。", "少陵彭澤造其真，運斤成風有餘地。", "眉陽老人文所宗，此語得之吾敢祕。", "斯君向上踏玄關，奔逸絕塵那可跂。"]'),
('c36b1edd-c232-4ff7-8265-2c816c6414a8','孫傳師密學挽辭  其一','釋道潜','宋','宋诗','song-poetry','','[]','淮海衣冠盛，門闌占一時。',48,'全唐诗/poet.song.53000.json','["淮海衣冠盛，門闌占一時。", "朝廷矜棣萼，人物得熊羆。", "暫倚軒裳貴，還隨舟壑移。", "新阡埋玉樹，黄霧慘餘悲。"]'),
('9870ccf0-fc01-4b87-a45c-b3d8bcb0b9cf','孫傳師密學挽辭  其二','釋道潜','宋','宋诗','song-poetry','','[]','王畿初作邑，終日坐鳴弦。',48,'全唐诗/poet.song.53000.json','["王畿初作邑，終日坐鳴弦。", "雅量能知變，平戎在未然。", "裕陵俄識拔，鵬路遽騰騫。", "二十年間事，凄凉付逝川。"]'),
('d4edc582-4ec7-4691-b499-b06fe7760b1d','孫傳師密學挽辭  其三','釋道潜','宋','宋诗','song-poetry','','[]','逸氣凌崧華，高標藹搢紳。',48,'全唐诗/poet.song.53000.json','["逸氣凌崧華，高標藹搢紳。", "經綸真漢將，談笑却胡塵。", "白首遭微譴，青雲阻要津。", "功名關造物，一語未能陳。"]'),
('6eab8c61-7f65-4f60-bc41-9aaa2903f205','孫傳師密學挽辭  其四','釋道潜','宋','宋诗','song-poetry','','[]','伯仲持哀日，余方傾蓋初。',48,'全唐诗/poet.song.53000.json','["伯仲持哀日，余方傾蓋初。", "炷香翻貝葉，酌茗飯園蔬。", "一作邗溝別，空傳桂嶺書。", "升堂揖遺像，回首意何如。"]'),
('dcc9c806-a85f-4a9f-96a1-56cad1d1c079','孫志甫主簿挽詞  其一','釋道潜','宋','宋诗','song-poetry','','[]','彼美荆岑玉，斯人實可儔。',48,'全唐诗/poet.song.53000.json','["彼美荆岑玉，斯人實可儔。", "眉間見和氣，皮裏識陽秋。", "夫子常稱德，蓬山素並游。", "一官雖不壽，撫己亦何羞。"]'),
('e5d082d8-bc2c-4c42-ae05-33fba9370d25','孫志甫主簿挽詞  其二','釋道潜','宋','宋诗','song-poetry','','[]','篤學誰如子，窮經志亦勤。',48,'全唐诗/poet.song.53000.json','["篤學誰如子，窮經志亦勤。", "干將曾未試，寶氣已沈淪。", "天遠終難問，眉酸謾自顰。", "佇瞻蘭玉秀，褒及墓中身。"]'),
('1ef0437f-0ca2-46ce-b2c0-fb44e39cfe3e','次韵張敏叔工部題郭殿直遠趣軒','釋道潜','宋','宋诗','song-poetry','','[]','高棟曾軒何用爲，此軒雖小景無遺。',64,'全唐诗/poet.song.53000.json','["高棟曾軒何用爲，此軒雖小景無遺。", "惜當麥壠堆青日，不見波濤卷雪時。", "眼底衣冠多邂逅，胸中貴賤少參差。", "問君卜築隋隄上，幾見春光上柳絲。"]'),
('8822df4b-7338-4836-b234-523836c9defa','蒙泉堂','釋道潜','宋','宋诗','song-poetry','','[]','百尺蒼崖底，蒙泉自我名。',48,'全唐诗/poet.song.53000.json','["百尺蒼崖底，蒙泉自我名。", "滀涵滋造化，汲引絕虧盈。", "碧甃深仍固，朱欄小易成。", "慇懃中夜月，長與照澄明。"]'),
('beb0b8c3-95f7-4f4d-be65-4c533a9efb21','八月十七夜夢中作','釋道潜','宋','宋诗','song-poetry','','[]','夜半秋江不見人，翠荷擎出露華新。',32,'全唐诗/poet.song.53000.json','["夜半秋江不見人，翠荷擎出露華新。", "江神水仙來共飲，一掬遺我生精神。"]'),
('d05ee393-804d-441c-a926-780aff1a5475','哭休上人','釋道潜','宋','宋诗','song-poetry','','[]','從來疑造物，無處識其真。',48,'全唐诗/poet.song.53000.json','["從來疑造物，無處識其真。", "好月難終夕，名花不盡春。", "青燈空照室，白㲲謾遺巾。", "泣血憐慈母，悲酸動四鄰。"]'),
('29a93337-5b22-4bee-9ca4-b2980e5b0cd4','邃隠堂','釋道潜','宋','宋诗','song-poetry','','[]','雅構何幽眇，真宜邃隠名。',48,'全唐诗/poet.song.53000.json','["雅構何幽眇，真宜邃隠名。", "朝雲半峰秀，夜月一簾明。", "終歲塵痕少，無時爽氣清。", "炷香翻貝葉，安穩老餘生。"]'),
('60293714-87dc-4948-b822-50aaaebd02b4','寧川西寺水閣呈周格非承議','釋道潜','宋','宋诗','song-poetry','','[]','岧嶢畫棟與雲平，一派寒流玉鏡清。',64,'全唐诗/poet.song.53000.json','["岧嶢畫棟與雲平，一派寒流玉鏡清。", "三島勝形方足擬，千鈞筆力始能名。", "鷗翻翠靄光中去，山倚朱欄靜處橫。", "令尹政閑勤把酒，風流未減謝宣城。"]'),
('120a8e04-c557-4e2b-bddc-1130bee0ac9b','僧首然師院北軒觀牡丹','釋道潜','宋','宋诗','song-poetry','','[]','鳥聲鳴春春漸融，千花萬草爭春工。',160,'全唐诗/poet.song.53000.json','["鳥聲鳴春春漸融，千花萬草爭春工。", "紛紛桃李自繚亂，牡丹得體能從容。", "琱欄玉砌昇曉日，輕烟薄霧初冥蒙。", "深紅淺紫忽爛熳，如以蜀錦羅庭中。", "姚黄貴極未易睹，綠葉遮護藏深叢。", "露華膏沐披正色，肯事夭冶分纖穠。", "從來品目壓天下，百卉羞澀莫敢同。", "清浄老禪根道妙，即此幻色談真空。", "上人封植匪玩好，庶敬先烈存遺風。", "遨芳公子應未耳，且樂樽俎怡歌鍾。"]'),
('c1927c5c-6e40-4ee5-b163-547fc8401f5c','用法穎韵寄信上人','釋道潜','宋','宋诗','song-poetry','','[]','懷素高閑世罕追，君今端與若人期。',64,'全唐诗/poet.song.53000.json','["懷素高閑世罕追，君今端與若人期。", "龍蛇落紙驚飛電，心手相忘豈所思。", "驥子神駒天與俊，朝燕暮越足難羈。", "超然遽作雙溪別，肯學紛紛兒女悲。"]'),
('b9028ecf-d5df-4445-8d23-b6f60551347c','昌化雙溪堂呈府簽判趙德茂宣德','釋道潜','宋','宋诗','song-poetry','','[]','吳會溪山總可憐，此堂雄覽獨能全。',64,'全唐诗/poet.song.53000.json','["吳會溪山總可憐，此堂雄覽獨能全。", "銀河兩派來天上，黛色千峰落檻前。", "樵斧聲沉蒼靄裏，釣竿人立白鷗邊。", "多才李賀知無敵，妙句行看陋衆妍。"]'),
('ead14b45-d520-4996-b0c8-c9ed381ad49e','用法穎韵寄詵上人','釋道潜','宋','宋诗','song-poetry','','[]','吾生出處異周顒，猨鶴休驚蕙帳空。',64,'全唐诗/poet.song.53000.json','["吾生出處異周顒，猨鶴休驚蕙帳空。", "木筍薦盤非世味，胡麻供飯古人風。", "時翻貝葉千行偈，戰勝詩魔五字功。", "杖屨儻來償素約，與君同盡此生中。"]'),
('3d93939b-b43d-4c74-a057-9a7d1eb02f08','山中書事','釋道潜','宋','宋诗','song-poetry','','[]','身世從來薄所營，晚歸丘壑更忘情。',64,'全唐诗/poet.song.53000.json','["身世從來薄所營，晚歸丘壑更忘情。", "隨眠煩惱何曾有，無樹菩提本不生。", "布襪青鞋供我老，月溪沙路恣經行。", "細炊雲子齋厨飯，要配香芹碧澗羹。"]'),
('e78289e9-1645-43d2-8f34-fcccfd9c8bcd','次韵孔天瑞秀才見寄','釋道潜','宋','宋诗','song-poetry','','[]','雙溪秋色最關情，想見登臨爽氣生。',64,'全唐诗/poet.song.53000.json','["雙溪秋色最關情，想見登臨爽氣生。", "木落草枯山自瘦，潦收沙白水偏明。", "眼中舊事烟雲散，篋裏新詩早晚成。", "來歲如今好時節，看君高步躡鵬程。"]'),
('397a6ea7-1f75-402a-a4ed-1090e8845b31','聽天竺慧照師琴','釋道潜','宋','宋诗','song-poetry','','[]','太古淳音久已虧，多君妙指善醫治。',64,'全唐诗/poet.song.53000.json','["太古淳音久已虧，多君妙指善醫治。", "高山流水意雖在，白雪陽春和者誰。", "不放驚飈侵澗戶，只容明月侍簾帷。", "滿堂賓客俱傾耳，共失芙蓉漏轉時。"]'),
('b1f59b7b-5bff-455f-8f17-1f6c2b761b57','寄伯言明發','釋道潜','宋','宋诗','song-poetry','','[]','御城東畔聽鳴珂，公子當年爲我過。',64,'全唐诗/poet.song.53000.json','["御城東畔聽鳴珂，公子當年爲我過。", "論議凜然無兩可，文章妙絕具三多。", "情親意合方傾倒，雲散風流欲奈何。", "儻附南鴻寄消息，吾今蹤跡閟巖阿。"]'),
('27032352-8155-4a78-88c7-8e7d97c201eb','過玉師室觀霅川范生梅花','釋道潜','宋','宋诗','song-poetry','','[]','桃李韵粗俗，江梅清獨妍。',156,'全唐诗/poet.song.53000.json','["桃李韵粗俗，江梅清獨妍。", "幽姿有時睹，如揖姑射仙。", "從來丹青手，默數三四賢。", "徐熙擅江左，趙子名西川。", "中間復誰何，絕特推老邊。", "風流迨茲泯，范子俄超然。", "迺知苕霅勝，秀氣常回旋。", "斯人非畫師，勢利不可鎸。", "興來即揮毫，游戲三昧前。", "一枝豈易得，答子能拳拳。", "橫斜有餘態，肌粉含霏烟。", "我來玩几席，歎賞徒留連。", "恨無處士詩，二妙相並傳。"]'),
('be868ff1-e004-4e35-96db-22b944287118','處順齋','釋道潜','宋','宋诗','song-poetry','','[]','生前不用驚毀譽，身後何須千載名。',32,'全唐诗/poet.song.53000.json','["生前不用驚毀譽，身後何須千載名。", "處順安時真曠達，本無哀樂動幽情。"]'),
('4d6419d5-7dba-4447-9b29-0c90a8abb228','贈聖可證師','釋道潜','宋','宋诗','song-poetry','','[]','吾道日凋喪，末流殊可嗟。',120,'全唐诗/poet.song.53000.json','["吾道日凋喪，末流殊可嗟。", "師門互開闢，學者如泥沙。", "欲求超然姿，駑廄搜渥洼。", "子初爲兒童，岐嶷衆所誇。", "長能游學海，宛轉窮津涯。", "誰知蓬蒿底，忽睹挺生麻。", "向來挈瓶盂，同我棲烟霞。", "朝昏事禪悅，神觀靜不譁。", "子今未三十，涵養滋根芽。", "行看覺苑中，綽現優曇花。"]'),
('bbdcf407-34fa-4d88-a898-a7b216dd10c5','次韵通守楊叔豐大夫游狼山  其一','釋道潜','宋','宋诗','song-poetry','','[]','朱輪千騎擁郊坰，政暇尋山固有名。',64,'全唐诗/poet.song.53000.json','["朱輪千騎擁郊坰，政暇尋山固有名。", "眼接青蒼心已喜，身經曠野路尤平。", "潮吞浦溆渾如海，蜃吐烟雲謾作城。", "欲訪真仙迷紫府，空端依約步虛聲。"]'),
('7c42d7a0-ba8e-4394-a40a-e9df0d709fcc','次韵通守楊叔豐大夫游狼山  其二','釋道潜','宋','宋诗','song-poetry','','[]','吳楚封疆一望間，時平無事可相關。',64,'全唐诗/poet.song.53000.json','["吳楚封疆一望間，時平無事可相關。", "樂天標致元非俗，靈運襟懷本愛山。", "蠟屐斜穿橫嶺上，角巾相對野僧閑。", "扁舟却恨南來晚，勝事風流不預攀。"]'),
('a01ec463-3f81-4ec6-9f9e-2a444d27f193','過都監趙思正崇班容膝庵','釋道潜','宋','宋诗','song-poetry','','[]','公子居閑厭華屋，一官江海辭羈束。',144,'全唐诗/poet.song.53000.json','["公子居閑厭華屋，一官江海辭羈束。", "端能有志學淵明，數板垣牆營小築。", "榜名容膝雅所宜，寄傲南窗聊自足。", "祖宗承平逾百年，胄緒蕃衍如雲烟。", "敦詩閱禮不勝數，人物似君尤卓然。", "論文講蓺未易料，虛己下士常折旋。", "憶昔初逢大梁下，風味向人如倒蔗。", "苦遭猨鶴促還山，回首相望驚百舍。", "誰言江路渺雲濤，一舸春風重命駕。"]'),
('f6d673ea-259a-40dc-b8f3-de67f27d498b','酬王衮臣朝奉見贈','釋道潜','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','吾聞終南山，鬰茀參斗牛。',168,'全唐诗/poet.song.53000.json','["吾聞終南山，鬰茀參斗牛。", "其下多賢豪，學術貫九流。", "公生實異稟，氣奪河漢秋。", "妙齡升廣文，岐嶷壓上游。", "登科三十年，仕宦真悠悠。", "功名信有命，富貴豈力求。", "邇來居海上，未解鍾儀囚。", "高懷素聞道，對客忘咿嚘。", "相懽固傾倒，不可即掉頭。", "今我來自東，邂逅欣綢繆。", "新詩激謬懦，詞力勁且遒。", "怳如開武庫，左右森戈矛。", "便當偃旗鼓，罷戰爲良謀。", "與公從逍遙，放浪追子休。"]'),
('3ffc22fa-27d6-48ed-ad3c-f682d106ac04','觀宗室伯山司戶詩卷','釋道潜','宋','宋诗','song-poetry','','[]','參軍暫輟簿書忙，爲我聊開古錦囊。',64,'全唐诗/poet.song.53000.json','["參軍暫輟簿書忙，爲我聊開古錦囊。", "玉骨已能含秀氣，珠璣那解不輝光。", "王孫挾策真難事，妙質如君豈易量。", "它日讎書天祿閣，聲名端可繼劉郎。"]'),
('8c1cb9e5-30a3-4c07-9b8c-86500ac4ae32','次韵思正雨中偶興','釋道潜','宋','宋诗','song-poetry','','[]','招提岑寂古城隈，海雨江風日日來。',64,'全唐诗/poet.song.53000.json','["招提岑寂古城隈，海雨江風日日來。", "但覺園林芳意盡，不知紅紫爲誰開。", "花飛南陌渾空柳，綠染中庭半是苔。", "有客衝泥能過我，筍輿駝褐夜深回。"]'),
('fe6e2eb6-ed2c-4b9f-abb7-efe25b7f7140','酬趙存道都曹見贈','釋道潜','宋','宋诗','song-poetry','','[]','騷人久無聞，風雅日浸衰。',144,'全唐诗/poet.song.53000.json','["騷人久無聞，風雅日浸衰。", "汀洲空蘭芷，憔悴無芳姿。", "參軍妙述作，鮑謝相並馳。", "明珠不自耀，光彩閟陸離。", "聊因五斗粟，暫寄東海湄。", "官身雖簿領，游刃能一麾。", "寥寥古寺空，轉砌春日遲。", "閉關時却掃，寂寂下書帷。", "唐虞悉觀覽，百氏了不遺。", "論文慎許可，紀律嚴自持。", "昨朝發新詠，落語皆瑰奇。", "世無楊德祖，詎識黄絹詞。"]'),
('743ebeae-7494-4536-9db0-92dd5b5ea82c','次韵思正游南寺賞牡丹','釋道潜','宋','宋诗','song-poetry','','[]','叢芳依小院，妙色發纖穠。',48,'全唐诗/poet.song.53000.json','["叢芳依小院，妙色發纖穠。", "綽約宜朝露，溫柔怯午風。", "興隨懽宴盡，事逐斷雲空。", "應待酴醾放，招携更與同。"]'),
('8d405447-8087-41aa-98bb-aa631de51aeb','贈思正令子','釋道潜','宋','宋诗','song-poetry','','[]','堪愛君家小鳳雛，炯然眉目照冰壺。',32,'全唐诗/poet.song.53000.json','["堪愛君家小鳳雛，炯然眉目照冰壺。", "他年足逸詩書圃，翰墨場中千里駒。"]'),
('7fecc5f8-f88c-4184-a5ec-aaf07c9f71d1','思正挈家游張氏園有詩俾余次韵','釋道潜','宋','宋诗','song-poetry','','[]','邦人莫訝氣如虹，生長皇家富貴叢。',64,'全唐诗/poet.song.53000.json','["邦人莫訝氣如虹，生長皇家富貴叢。", "陶寫年華樽俎外，吟哦風物笑談中。", "伶倫奏曲千般巧，錦綵纏頭一樣紅。", "琴瑟獻酬還可樂，牽衣兒女復相同。"]'),
('04fa640c-404a-4e43-be71-433305f39f3c','維楊秋日西郊  其一','釋道潜','宋','宋诗','song-poetry','','[]','雨洗高梧爽氣浮，鳴蟬相喚作新秋。',32,'全唐诗/poet.song.53000.json','["雨洗高梧爽氣浮，鳴蟬相喚作新秋。", "翻空白鳥一行去，目送岡巒欲盡頭。"]'),
('a98fadb9-79b5-4218-ab87-fbb363cfed51','維楊秋日西郊  其二','釋道潜','宋','宋诗','song-poetry','','[]','瓜花零落豆花繁，秋入隋家舊苑看。',32,'全唐诗/poet.song.53000.json','["瓜花零落豆花繁，秋入隋家舊苑看。", "水調遺音今寂寞，空餘壞道瀉哀湍。"]'),
('e5f2e0af-c9ec-4e25-8f19-374c3edeb006','維楊秋日西郊  其三','釋道潜','宋','宋诗','song-poetry','','[]','潦水初收古澗清，小橋斜倚數魚行。',32,'全唐诗/poet.song.53000.json','["潦水初收古澗清，小橋斜倚數魚行。", "神林社日傳簫鼓，秋稼如雲歲有成。"]'),
('6106add7-c509-4f26-b905-5872dfe08318','維楊秋日西郊  其四','釋道潜','宋','宋诗','song-poetry','','[]','枯榆偃蹇若蒼龍，影占荒郊半畝宮。',32,'全唐诗/poet.song.53000.json','["枯榆偃蹇若蒼龍，影占荒郊半畝宮。", "下有牧羊雙稚子，臥吹蘆管對西風。"]'),
('d979fb75-2615-497d-9f53-03f0ce989a74','題東坡墨竹贈官妓','釋道潜','宋','宋诗','song-poetry','','[]','小鳳團牋已自奇，謫仙重掃歲寒枝。',32,'全唐诗/poet.song.53000.json','["小鳳團牋已自奇，謫仙重掃歲寒枝。", "梢頭餘墨猶含潤，恰似梳風洗雨時。"]'),
('56810696-1093-4e54-9dcc-1fc619463ed0','秋','釋道潜','宋','宋诗','song-poetry','','[]','牆角風欺竹影斜，數聲啼盡欲栖鴉。',32,'全唐诗/poet.song.53000.json','["牆角風欺竹影斜，數聲啼盡欲栖鴉。", "重門已閉斷還往，獨捲疏簾看月華。"]'),
('f6947f46-2e3f-4aa6-a157-d5e6470c2ab9','醉眠亭','釋道潜','宋','宋诗','song-poetry','','[]','嘗聞李謫仙，飲酒興無盡。',88,'全唐诗/poet.song.53000.json','["嘗聞李謫仙，飲酒興無盡。", "醉來臥空山，天地即衾枕。", "當時放迹奇，流俗不可近。", "君今外形骸，與世不拘窘。", "寸心合虛曠，萬事一以泯。", "開亭向幽圃，朝夕事醉寢。", "茅檐落日欲醒時，起對嬋娟拂瑶軫。"]'),
('a9517fff-5676-4c57-a0a0-1b9f280e70e1','歸溪上','釋道潜','宋','宋诗','song-poetry','','[]','市朝塵土污人衣，遠憶雲山便賦歸。',32,'全唐诗/poet.song.53000.json','["市朝塵土污人衣，遠憶雲山便賦歸。", "溪水繞門秋欲晚，苕花漠漠鷺鷥飛。"]'),
('5a88acd9-81b0-4ff3-bead-7aefa47c5537','梅花','釋道潜','宋','宋诗','song-poetry','','[]','咸平處士風流遠，招得梅花枝上魂。',32,'全唐诗/poet.song.53000.json','["咸平處士風流遠，招得梅花枝上魂。", "疏影暗香如昨日，不知人世幾黄昏。"]'),
('00e20210-5a9f-4172-bc07-6cd4732b7a18','句  其一','釋道潜','宋','宋诗','song-poetry','','[]','風約亂雲歸隴首，角催明月出波心。',16,'全唐诗/poet.song.53000.json','["風約亂雲歸隴首，角催明月出波心。"]'),
('05859c2b-71aa-43bf-b1d4-b6e12820cb86','句  其二','釋道潜','宋','宋诗','song-poetry','','[]','浩瀚霜風刮天地，溫泉火井無生意。',16,'全唐诗/poet.song.53000.json','["浩瀚霜風刮天地，溫泉火井無生意。"]'),
('da7c0d95-7b1d-43a5-a533-43222dc92cff','句  其三','釋道潜','宋','宋诗','song-poetry','','[]','但看黄鶴山頂雲，化作白龍潭上雨。',16,'全唐诗/poet.song.53000.json','["但看黄鶴山頂雲，化作白龍潭上雨。"]'),
('d3ac654b-e737-4e86-9c17-26bca8c38f36','句  其四','釋道潜','宋','宋诗','song-poetry','','[]','墮杳靄更上，迎暉亭徙倚。',12,'全唐诗/poet.song.53000.json','["墮杳靄更上，迎暉亭徙倚。"]'),
('98ba1e62-b2fd-4c47-9061-83b4da562610','馬上詠落葉','孔平仲','宋','宋诗','song-poetry','','[]','蔌蔌林中葉，落勢殊未休。',108,'全唐诗/poet.song.53000.json','["蔌蔌林中葉，落勢殊未休。", "念汝春夏間，芃芃一何稠。", "朝烟坐蒼翠，暮雨借膏油。", "及今乃委地，只以藉馬牛。", "焚之揚其灰，或用糞田疇。", "當記排空出，結陰彌道周。", "物生固有數，時去安可留。", "况汝易擺觸，性質本纖柔。", "惟有松竹秀，獨當天地秋。"]'),
('7eec27a7-5d4e-4492-b93a-b56316fa4839','使紙甚費','孔平仲','宋','宋诗','song-poetry','','[]','家貧何所費，使紙如使水。',216,'全唐诗/poet.song.53000.json','["家貧何所費，使紙如使水。", "親交或見遺，自買不知幾。", "置之几案間，數軸俄空矣。", "作字本不工，學書非不喜。", "不知何故盡，疑若有神鬼。", "若云隨置郵，性復懶牋啟。", "間或强爲之，皆出不得已。", "橫斜若幡脚，齟齬如雁齒。", "數易僅能成，紛紛多廢委。", "敘致失輕重，畏慎防觸抵。", "往往已緘封，時時又刪洗。", "遂令巾衍竭，大半或緣此。", "昔無楮先生，云自蔡倫始。", "假令行竹簡，禿野未供使。", "人生有知慧，不若愚且鄙。", "古來取卿相，未必皆經史。", "誰教識點畫，空耗五斗米。", "咄嗟爲此詩，又是一張紙。"]'),
('e766453b-9a3e-45c2-b1c1-4e780136450d','謝王通叟回文詩','孔平仲','宋','宋诗','song-poetry','','[]','北風吹波客桅折，潯陽維舟不敢發。',144,'全唐诗/poet.song.53000.json','["北風吹波客桅折，潯陽維舟不敢發。", "觀君和我回文詩，滿眼春光破冰雪。", "山間玉少白石多，造化積英費融結。", "如君藻思豈易得，姓名盧駱推前列。", "他人平步取卿相，乃獨區區困羈紲。", "江湖漂泊隨斷梗，歲月崢嶸逼華髮。", "頹然放肆孰可測，一馬固能齊萬物。", "胡琴雖已隔黄壤，寶燈吐燄高于月。", "人生樂事君得多，誰羨腰金擁幢節。"]'),
('daa9a2e9-ba1b-4ffd-a935-f8ee169b92ee','送王通叟','孔平仲','宋','宋诗','song-poetry','','[]','潯陽江頭夜吹簫，旁若無人聲正調。',64,'全唐诗/poet.song.53000.json','["潯陽江頭夜吹簫，旁若無人聲正調。", "問之誰何天鬻子，謫官東南數千里。", "當時司馬泣琵琶，君獨怡然奏宮徵。", "但能如此游世間，于諸榮辱何憂喜。"]'),
('dc3b8c2d-f30f-43f7-ad7a-a56a9e2902b6','送朱君貺德安宰罷任還','孔平仲','宋','宋诗','song-poetry','','[]','潯陽五邑誰善政，歷陵令尹朱爲姓。',176,'全唐诗/poet.song.53000.json','["潯陽五邑誰善政，歷陵令尹朱爲姓。", "孜孜常以民存心，四境安娛吏無橫。", "吾愛其人頗真率，笑語詼諧喜譏評。", "山有猛虎藜藿長，人得朋友衣冠正。", "當時文學推第一，闊步青雲乃蹊徑。", "大賢百里固非地，赤子三年且無病。", "如君才智可自達，今歸朝廷惟所應。", "君臣昔以譬壎箎，吉甫文武陛下聖。", "當陳半策綰萬金，翩翩六翮凌風勁。", "江邊鍾官老鑄錢，坐髀已消窮且暝。", "倘君富貴不通書，當驗行藏素非佞。"]'),
('ea79ea3d-19e1-4fa4-b151-7f01e4ea0264','用常甫元韵寄彭澤曾移忠','孔平仲','宋','宋诗','song-poetry','','[]','清秋古邑氣象開，健令曳組從南來。',320,'全唐诗/poet.song.53000.json','["清秋古邑氣象開，健令曳組從南來。", "淵明已往狄公死，繼有賢者荒山隈。", "九江安流息駭浪，百里和氣迎新雷。", "積年逋事一朝决，落筆翩翩何快哉。", "幽潜曲折皆照見，正以寶鑑懸高臺。", "古稱豈弟民父母，君視百姓猶嬰孩。", "近來俗吏狃文法，往往習尚以利回。", "惟君用心知自性，造次所發皆矜哀。", "政成訟簡當暇日，間或吟詩持酒盃。", "言辭泠泠韵不俗，識子眉宇無纖埃。", "長篇示我已踰月，詩債甚久煩君催。", "我如荒田廢耕墾，嘉穀不植歲且災。", "爲君遊頑揠枯槁，滿把所收惟草萊。", "金山萬丈絕梯級，手聚沙礫空成堆。", "龍鱗難攀徒自苦，狗尾强續良可咍。", "想君風采方引領，忽見泝浪停高桅。", "迎門倒履喜如沃，相與一笑傾新醅。", "曹亭孤峙眺回遠，杖策共尋幽磴苔。", "諸峰積雪倚天白，此處酬唱須清才。", "老雞爪嘴未易犯，斂翅避子甘低徊。"]'),
('39844899-83b7-4122-9373-c29015f3fab1','送周元翁赴省試','孔平仲','宋','宋诗','song-poetry','','[]','靜如秋潭月，秀比玉山岑。',108,'全唐诗/poet.song.53000.json','["靜如秋潭月，秀比玉山岑。", "濂溪素積善，遺澤乃在今。", "一鳴先衆人，再鳴慰我心。", "茁芽舊固好，浚養日愈深。", "歲暮冰雪氣，關山車馬音。", "去者轍相結，豈止旅思侵。", "期君賈餘勇，梟俊將成禽。", "策功居第一，受賞綰千金。", "高堂遲捷布，華髮正盈簪。"]'),
('7426d6ac-acac-4143-9ace-e5029db84f35','因讀黄魯直所與周法曹詩詩與字俱好以此寄之','孔平仲','宋','宋诗','song-poetry','','[]','魯直之文如電坼霜開，魯直之書如雨行冰散。',164,'全唐诗/poet.song.53000.json','["魯直之文如電坼霜開，魯直之書如雨行冰散。", "駸駸步驟日加遠，與子三年不相見。", "庭柯未長一尺圍，起視孤標插星漢。", "昨朝誦子所作詩，使我自失長嗟嘆。", "我衰力薄空辛勤，直欲爲子焚筆研。", "此才不使重臺閣，四十青衫尚爲縣。", "南山積雪玉倚空，高亭壓城天北風。", "安得與子跨飛鴻，與我共哦清景中。", "鏘金紆紫世不空，豪傑卓犖豈易逢。", "願言與子長相從，四方上下爲雲龍。"]'),
('bfd70a15-fb86-430f-8c80-f543cfe59200','寄子由','孔平仲','宋','宋诗','song-poetry','','[]','晨興悲風鳴，霜霰集我屋。',216,'全唐诗/poet.song.53000.json','["晨興悲風鳴，霜霰集我屋。", "忽驚歲云晚，日月疾轉轂。", "穴蟲知天時，閉戶各潜伏。", "而我亦勞止，擾擾尚馳逐。", "宵征戴星明，暮飯多見燭。", "灰塵彫鬚眉，銅臭蝕肌肉。", "念當投劾去，牽繫五斗粟。", "豈無數畝田，亦有千箇竹。", "平生羨爲農，水旱憂不足。", "空效鳥雀饑，唧啾如聚哭。", "內顧復遲回，行藏類羝觸。", "長卿著犢鼻，揚子投天祿。", "岷峨能生賢，獨不主爲福。", "如君乃栖栖，似我宜碌碌。", "連山積雪壯，霽色明群玉。", "對此想清標，凜然疑在目。", "安得兩翅長，高舉逐黄鵠。", "飛去墮君前，綢繆論心曲。"]'),
('fc419b28-e023-4c13-9dde-ff5020840f28','元豐四年十二月大雪郡侯送酒','孔平仲','宋','宋诗','song-poetry','','[]','平明大雪風怒嘷，屋上卷來亭下高。',208,'全唐诗/poet.song.53000.json','["平明大雪風怒嘷，屋上卷來亭下高。", "更深更密皆能到，所在紛紛如雨毛。", "堆床壓案掃復聚，取筆欲書冰折毫。", "鬚眉沾白催我老，自頸以下類擁袍。", "此時只好閉門坐，右手把酒左持螯。", "奈何巑岏據聽事，千兵踏藉泥如糟。", "强登曹亭要望遠，紙傘掣手不可操。", "黑陰遮眼鋪水墨，寒氣刮耳投兵刀。", "饑腸及午尚未飯，更搜詩句無乃勞。", "幸有使君憐寂寞，亟使兵厨分凍醪。", "余雖不飲爲一釂，兩頰生春紅勝桃。", "醉眼瞢騰視天地，蜾蠃螟蛉輕二豪。", "勿令小暖氣便壯，自笑世間皆我曹。"]'),
('97c2708d-b287-41e9-b251-dd6d1c0ea2cb','寄常甫','孔平仲','宋','宋诗','song-poetry','','[]','北風三日雪，南湖一尺冰。',24,'全唐诗/poet.song.53000.json','["北風三日雪，南湖一尺冰。", "晚雲遮望眼，不見玉山城。"]'),
('ad975dc7-e03d-4553-b377-7e269e33a2b1','宵興','孔平仲','宋','宋诗','song-poetry','','[]','我眠何由安，擊鼓中夜起。',144,'全唐诗/poet.song.53000.json','["我眠何由安，擊鼓中夜起。", "出門若秉燭，月色照千里。", "屋瓦微有光，紛紛雪正委。", "清寒薄駝裘，六合氣如水。", "既歸整燈火，危坐閱書史。", "羸僮拭眼睫，侍我色不喜。", "問之强應對，固以噤口齒。", "金壺澀冰澌，城上更屢死。", "戍兵飽且昏，汗漫睡方美。", "援桴雖賤事，其實關衆耳。", "奈何司晨夕，倒錯一至此。", "惟有赤幘雞，嘐嘐鳴不已。"]'),
('841e2966-5f7f-4191-b517-9eda0d2b142a','十二月二十五日大雪','孔平仲','宋','宋诗','song-poetry','','[]','前時大雪風擾之，有無厚薄皆不齊。',128,'全唐诗/poet.song.53000.json','["前時大雪風擾之，有無厚薄皆不齊。", "今朝大雪無風色，下隰高原總盈尺。", "由來此物本陰氣，偏近黄昏落尤劇。", "斜縈碎委百千態，不是天上誰做得。", "錚錚鳴霰已三日，厭坐北窗聞滴瀝。", "自非猛下意不醒，半夜一天星斗白。", "漫漫玉琢人世界，蹂踐成泥真可惜。", "呼童梯屋器貯之，猶得煎茶待嘉客。"]'),
('df42a9da-ee27-4f07-a58c-03666318732c','城東作','孔平仲','宋','宋诗','song-poetry','','[]','九江雖僑寓，城東乃松楸。',108,'全唐诗/poet.song.53000.json','["九江雖僑寓，城東乃松楸。", "泉府固勞冗，十日得一休。", "朝出暮可還，駕言循故丘。", "雨洗川原浄，鳥啼岩谷幽。", "白楊吟悲風，澗水咽長流。", "江西走濁浪，中有蛟鼉游。", "可望不可涉，裴徊倚山陬。", "眈眈林間鴝，歲老爪如鈎。", "飛下啄餘祭，肉食惟自謀。"]'),
('5e8a42dc-daf4-4860-924a-3785275e0643','詠道上松','孔平仲','宋','宋诗','song-poetry','','[]','長松高落落，積雪白皚皚。',108,'全唐诗/poet.song.53000.json','["長松高落落，積雪白皚皚。", "鱗鬣凍且僵，鬰結久不開。", "觀其纏壓意，直使同枯荄。", "雁带寒光去，鳥傳春信來。", "微陽入直幹，生意忽已回。", "豁若醉初醒，整頓出塵埃。", "秀色媚山腹，孤標摩斗魁。", "時至自當復，安得長摧頹。", "若非根本壯，何能異草萊。"]'),
('aa689fc3-227b-48b7-a849-ad3bf9992f80','狂犬','孔平仲','宋','宋诗','song-poetry','','[]','吾家有狂犬，其走如脫兔。',132,'全唐诗/poet.song.53000.json','["吾家有狂犬，其走如脫兔。", "撐突盤盂翻，搜爬堂廡汙。", "逢人吠不止，鷄噪貓且怒。", "固難在家庭，只可守村墅。", "不見已半年，意謂少懲懼。", "昨日至城東，摇尾喜若赴。", "銜衣復抱膝，屢叱不肯去。", "一躍數尺高，其强乃如故。", "豈惟性則然，汝分亦天賦。", "未聞有驊騮，蹄嚙棄中路。", "安敢携汝歸，重令兒女怖。"]'),
('eaf36505-a22f-402e-bc41-8825cf019f17','子明棋戰兩敗輸張遇墨并蒙見許夏間出篋中所藏以相示詩索所負且堅元約','孔平仲','宋','宋诗','song-poetry','','[]','平生性好墨，以此爲晝夜。',288,'全唐诗/poet.song.53000.json','["平生性好墨，以此爲晝夜。", "陳玄爾何爲，能使我心化。", "四方購殊品，十倍酬善價。", "江南號第一，易水乃其亞。", "古錦綴爲囊，香羅裁作帕。", "精粗校白黑，情僞考真詐。", "欣然趣自得，其樂勝書畫。", "英英清河公，風格繼王謝。", "語舊則鄉邦，論親乃姻婭。", "前時偶休澣，亟之城南舍。", "所嗜與我同，奇蓄乃自詫。", "奕秋約籌局，張遇賭龍麝。", "貪多而務得，廉遜或不暇。", "鉛刀試一割，駑足效十駕。", "决勝有如兵，必爭還似射。", "黑雲半離披，玉馬恣蹂藉。", "初鳴已驚人，再鼓遂定霸。", "物情矜俊捷，天幸蒙假借。", "功成不自高，垂首甘褻駡。", "但當償所負，然諾重嵩華。", "彎弓既有獲，豈不願鴞炙。", "滌硯俟見臨，倒屣出相迓。", "陵尊且犯貴，此罪在不赦。", "更許觀篋中，前期指朱夏。"]'),
('4a5e3d7b-32f1-4e75-a0c7-cfe1d075f63f','再寄子由','孔平仲','宋','宋诗','song-poetry','','[]','湓城趨高安，相望若鄰屋。',216,'全唐诗/poet.song.53000.json','["湓城趨高安，相望若鄰屋。", "思君腸九迴，終夕轉車轂。", "一從江上別，再見臘與伏。", "岧嶢阻躋攀，疲曳愧躡逐。", "此心敢忘德，烱烱如寸燭。", "念昔見教勤，綢繆均骨肉。", "及今無所成，長大惟食粟。", "讀君黄樓賦，溢耳感絲竹。", "蹈海始知深，秋水暫自足。", "斯文道中喪，吊古堪慟哭。", "勃興得公家，萬物困陵觸。", "聲名載不朽，豈羨卿相祿。", "琢琱窮乃工，未剝不爲復。", "嗟予空有心，資性本碌碌。", "佳篇屢寄酬，珍賜比金玉。", "隋珠照十乘，只報一魚目。", "反顧拙丹青，何由希畫鵠。", "黄華强再奏，取笑陽春曲。"]'),
('402ad1cf-0449-4e9a-a5e9-27eb36c30079','久雨','孔平仲','宋','宋诗','song-poetry','','[]','涉春寒未衰，苦雨天欲破。',120,'全唐诗/poet.song.53000.json','["涉春寒未衰，苦雨天欲破。", "所向泥沒膝，閉戶祇悲臥。", "雲如傍檻飛，風若吹瓦墮。", "群陰無際涯，翕翕相唱和。", "草木出隨陽，生意固已挫。", "蛟龍舞波豪，鳥雀噪枝惰。", "陂池尚未完，時節不可過。", "殘租待晴輸，新種須暖播。", "霪霖何時已，天意亦誰奈。", "窮巷爾何爲，悲吟追楚些。"]'),
('5b0f5456-7810-4e0c-9571-c52bfe1bd464','寒食郊外','孔平仲','宋','宋诗','song-poetry','','[]','涔涔雨沉城，浩浩泥沒轍。',156,'全唐诗/poet.song.53000.json','["涔涔雨沉城，浩浩泥沒轍。", "四山氣如蒸，萬里天欲雪。", "我時出郊坰，山徑屢曲折。", "雖懷顛沛憂，亦有觀覽悅。", "幽花媚林薄，粲粲生意發。", "紅紫相後先，各自有時節。", "長松困冰雪，憔悴終不屈。", "及今翠夭嬌，騰拔見筋骨。", "陰陽有代謝，物性安可奪。", "請視大塊中，紛紛盡毫末。", "興衰若鱗次，今古猶市閱。", "只此晦與晴，變態亦俄忽。", "歸路日已煬，披襟滌初熱。"]'),
('7850fe74-7c0f-4796-806a-cc44117b3f63','余比見管勾太平觀劉朝奉見嫌太盛教以一食之法自用有效因以告子由且進先耆後欲之說蒙示長篇竊服高致謹再用元韵和寄','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山九江南，勝隠類王屋。',216,'全唐诗/poet.song.53000.json','["廬山九江南，勝隠類王屋。", "中有劉先生，逃榮棄朱轂。", "我嘗問持養，次第蒙攝伏。", "操心要常存，尤戒忌追逐。", "教人啖火棗，喻世指風燭。", "一從屏晚膳，已覺失頤肉。", "諒能早如此，盎自有餘粟。", "寢甘無復夢，行健不須竹。", "華池涌清波，漱飲每充足。", "當使百靈朝，如聞九蟲哭。", "欲塵亦遂掃，由味方有觸。", "甘肥自煎熬，其毒甚回祿。", "願公亦澹薄，同享秀眉福。", "丈夫貴决烈，安得猶碌碌。", "淘沙始見金，椎石方逢玉。", "所以老氏言，爲腹不爲目。", "未能便仙去，輕舉隨白鵠。", "且保臨老年，眼明腰不曲。"]'),
('c5721d28-caac-4e8f-9e01-93d3e1599dc3','送徐德古','孔平仲','宋','宋诗','song-poetry','','[]','魚蝦爭後先，波浪拂西北。',24,'全唐诗/poet.song.53000.json','["魚蝦爭後先，波浪拂西北。", "今朝臥龍起，且與收風色。"]'),
('86fcec55-1aa3-4e1f-9d1a-dcddf7bd7e67','常甫招客望海亭','孔平仲','宋','宋诗','song-poetry','','[]','蓬萊釀酒酒已成，賀家池上新採菱。',336,'全唐诗/poet.song.53000.json','["蓬萊釀酒酒已成，賀家池上新採菱。", "紫衣侍立烏帽走，吾兄招客望海亭。", "歸來爲我道客語，出沒帆牆俱可數。", "醉中遙指北山下，云此白處乃海浦。", "入山迤邐數百山，客居乃在一山顛。", "雖非陽侯所窟宅，風濤澒洞已拍天。", "餘山亦有人雜居，山無桑麻只捕魚。", "海中百怪所會聚，海馬海人并海馿。", "或如七十之老翁，或如三尺之侏儒。", "手足口眼莫不見，鞭磔盡作人號呼。", "千艘競造石首脯，雨聲颯颯魚來初。", "截波一網千萬尾，棹歌喜噪翻蓬壺。", "垂釣忽挂綠鸚鵡，探石仍得真珊瑚。", "晚晴蜃結彩霞閣，夜黑龍呈明月珠。", "紅漣紫液碧瀲灧，頃刻變態世所無。", "我聞此景若在眼，便欲駕舶尋天吳。", "昔時管寧亦避地，吾祖嘆息思乘桴。", "我今何爲不可往，誰能俛首甘區區。", "平時此亭景最美，自謂清曠更無比。", "一聞客語心坐馳，却上望海汙潢耳。", "嗟哉好惡隨所遷，世間萬事多如此。"]'),
('1efc87e8-744c-4787-a120-6efdc666c302','官松','孔平仲','宋','宋诗','song-poetry','','[]','我行九江南，曠野圍空山。',288,'全唐诗/poet.song.53000.json','["我行九江南，曠野圍空山。", "道旁何所有，高松立巑岏。", "藏標隠雲霧，秀氣凌岡巒。", "橫騫却與走，怪狀千萬端。", "中有清風發，能令朱夏寒。", "流金五六月，方苦行路難。", "騎者欲顛沛，負者面如丹。", "氣息幾斷絕，至此方少寬。", "消渴飲甘露，涸轍投長瀾。", "迺知古人意，爲惠無窮年。", "亦有被剪伐，行列頗不完。", "豈非風雷變，或者盜賊繁。", "土人對我嘆，云有縣長官。", "爲政猛于虎，下令如走丸。", "取此爲宮室，將以資宴歡。", "良工操斧斤，睥睨長林間。", "擇其最高大，餘者棄不觀。", "千夫擁一柱，九牛力回旋。", "至今空根悲，泣淚尚未乾。", "彼令誠何心，緩急迷後先。", "毫末至合抱，忍以頃刻殘。", "萬衆所庇頼，易爲一身安。", "居上恬莫問，在下畏不言。", "世事類若斯，嗚呼一摧肝。"]'),
('bc71997a-3779-482a-854b-d29deeb5a870','越州飛來山','孔平仲','宋','宋诗','song-poetry','','[]','物之體性重，惟有石最堅。',288,'全唐诗/poet.song.53000.json','["物之體性重，惟有石最堅。", "迴風捲黄沙，直下萬丈淵。", "如何崔嵬山，乃解飛青天。", "瑯琊趨會稽，道里固甚懸。", "想當初來時，詭異可得言。", "豈非巨靈擘，或謂秦帝鞭。", "雷公挾電母，欻霍相後先。", "夸蛾負崖脚，天丁撮其顛。", "北斗借神兵，虎豹下九關。", "海王驅魚送，百里聞腥羶。", "悲號與憊喘，洒汗成流川。", "呼雲以自蔽，日月不得宣。", "棲鳥失其巢，哀哀啼白猿。", "草木困擺撼，枝葉半不全。", "置之秦望陰，百怪散作烟。", "有龍走不轍，化作錦色鰻。", "攢身入竅穴，噴出清泠泉。", "都人駭相報，平地見巍然。", "既來亦能去，惟恐復騰騫。", "浮屠鎮其上，副以屋蟬聯。", "朝吟諸佛經，暮講西方禪。", "以此相縶縛，羈孤幾千年。", "我聞已有日，今朝始攀緣。", "高堂置美酒，遠目凌孤鳶。"]'),
('4e7cfb4a-63b8-483a-94af-67ffe7e61ba8','和常父寄經父','孔平仲','宋','宋诗','song-poetry','','[]','候得早潮來，江邊風又起。',132,'全唐诗/poet.song.53000.json','["候得早潮來，江邊風又起。", "錢塘與海接，浩渺無涯涘。", "長鯨呼鱷魚，蛟龍正掉尾。", "豈惟波浪聲，號泣半溺鬼。", "臨流不敢渡，尋尺如千里。", "儌幸亦可往，無力觸萬死。", "蕭然古山根，客棹于此艤。", "吳亭明可數，游觀信爲美。", "安敢慕紛華，而不重行止。", "回首臥龍居，想在青雲裏。", "相思寂莫晚，誰伴西樓倚。"]'),
('07c0caac-6649-4727-ac68-83ba45aee06b','見潮','孔平仲','宋','宋诗','song-poetry','','[]','朝亦見潮來，暮亦見潮來。',24,'全唐诗/poet.song.53000.json','["朝亦見潮來，暮亦見潮來。", "維舟不敢渡，西望興悠哉。"]'),
('06f72e32-09ff-4f2d-9eb5-c88b834ca250','秋夜舟中','孔平仲','宋','宋诗','song-poetry','','[]','昨夜强風萬弩過，舟中側聽披衣坐。',96,'全唐诗/poet.song.53000.json','["昨夜强風萬弩過，舟中側聽披衣坐。", "秋來已覺陰氣繁，晨興更見波濤大。", "衰梧弱柳不足數，修篁摧折幾百箇。", "飛廉鬰然方用事，一威能令萬物挫。", "人言風怒未渠央，我觀暴忽勢不長。", "會見平川凈如鏡，刀魚鳴櫓過錢塘。"]'),
('2f321d5c-d586-4385-81ec-ece3168a1d9d','和常父望湖亭','孔平仲','宋','宋诗','song-poetry','','[]','深灣謂無風，試向江頭望。',192,'全唐诗/poet.song.53000.json','["深灣謂無風，試向江頭望。", "混混過新潮，峨峨起層浪。", "前驤復後踴，極力不相讓。", "踣落皆有聲，擺觸頗用壯。", "游龍出鬐鬛，怒馬軒頸項。", "紛綸白雪外，疊去不知向。", "勢將銀漢接，高與海門抗。", "吳城挂水墨，越估增怊悵。", "我欲絕橫流，忠信固可仗。", "丈夫七尺軀，魚腹豈易葬。", "緬懷馮河戒，艤棹未敢忘。", "夜夢大樽浮，東行視溟漲。", "入宮謁陽侯，舉袂揖伍相。", "問其孰呼吸，乃使此倔强。", "謝云天所爲，茲語吾恐妄。", "却欲詰蒼蒼，無梯不能上。"]'),
('abc741c7-3dbc-4091-9f45-53d2015dd128','和常父初五日渡江','孔平仲','宋','宋诗','song-poetry','','[]','半旬滯西陵，霖雨注船屋。',192,'全唐诗/poet.song.53000.json','["半旬滯西陵，霖雨注船屋。", "昨日風更豪，江邊拔長木。", "初宵尚哮吼，海水皆倒蹙。", "向晚稍蕭條，飛廉想遭戮。", "重雲掃陰晦，皎皎見星宿。", "大哉天地內，變化反手速。", "我行不憚早，畏此潮信足。", "刀魚頗輕捷，舟子短結束。", "十夫共一艣，喜噪比趨陸。", "船頭列火炬，幕下燒絳燭。", "蛟龍睡方醒，水陸駭竄伏。", "吟哦未及終，已在吳堤曲。", "青山繞逶迤，樓閣媚初旭。", "錢塘雖舊游，夢想嘗在目。", "便當跨月輪，俯耳聽清瀑。", "重陽復不遠，共采岩前菊。"]'),
('118ff681-851b-4bd2-91c6-d0612b472357','游六和寺','孔平仲','宋','宋诗','song-poetry','','[]','同尋六和寺，去旁蒼崖行。',264,'全唐诗/poet.song.53000.json','["同尋六和寺，去旁蒼崖行。", "崢嶸石林氣，㶁㶁流水鳴。", "見此俗慮減，入門心更清。", "盤空到窈窕，小憩山前亭。", "天晴修竹外，颯有風雨聲。", "僧云金魚池，近日秋雨足。", "餘波落清壁，散作雪色瀑。", "徐興視其流，登高穿屈曲。", "忽逢白練飛，碎點濺珠玉。", "清泠振毛髮，瀟洒蕩心腹。", "金魚在何處，演漾戲平陸。", "鱗鬣老愈黄，點漆作雙目。", "憶爲兒童時，嘗劇此池旁。", "聞人說金魚，已謂百歲强。", "今踰二十年，僧死草木荒。", "此魚尚無恙，纖質不改常。", "謂魚非靈物，安得擅久長。", "四海波浪高，三江網羅密。", "長鯨喪明珠，幽暗無白日。", "我疑龍變化，就此溪中逸。", "紛綸乾坤爭，浩蕩風霆出。", "何如守一泓，無得亦無失。"]'),
('f28eecfd-a7fe-4ce2-9a8b-a62673d5288b','和常父湖州界中','孔平仲','宋','宋诗','song-poetry','','[]','常民踏車將納水，今民踏車將出水。',192,'全唐诗/poet.song.53000.json','["常民踏車將納水，今民踏車將出水。", "大田不復見溝塍，洪潦汗漫來千里。", "昨在會稽固已聞，湖州春雨夏不止。", "吹堤卷石冒城郭，餘波之潴此乃是。", "至今蒲蠃在民屋，冢樹伐盡生葭葦。", "茅簷破漏不暇完，父子煢煢瘦相倚。", "西風摇落天地秋，下汙上萊無所收。", "新田今已不可種，問民出水將安求。", "水乾魚蝦或易得，且以咀嚼充饑喉。", "貧者往往鬻兒女，征徭紛紛復不休。", "我從農夫遺斗米，自顧飽食誠堪羞。", "四方近日苦窮乏，嗟我有意奚能周。"]'),
('be68ff83-cc06-4aa7-9eeb-da7baa111ea2','戲張子厚','孔平仲','宋','宋诗','song-poetry','','[]','子厚誇善棋，益我以五黑。',96,'全唐诗/poet.song.53000.json','["子厚誇善棋，益我以五黑。", "其初示之羸，良久出半策。", "波衝與席卷，揉攘見敗北。", "我師如玄雲，汗漫滿八極。", "子厚若殘雪，點點無幾白。", "是時秋風高，萬里鷹隼擊。", "鷦鷯伏深枝，顧視頗喪魄。", "勒銘亭碑陰，所以詫棋客。"]'),
('f907fe73-e87e-49d1-832f-fbe753a395f8','泛漣水','孔平仲','宋','宋诗','song-poetry','','[]','漣漪二十里，清淡得我性。',48,'全唐诗/poet.song.53000.json','["漣漪二十里，清淡得我性。", "微風不復摇，天水相與凈。", "秋容入崖柳，晚色依漁艇。", "彷彿會稽游，南湖似明鏡。"]'),
('b426999b-cf81-4662-b3d0-1ec1162ddd3c','楊道中同行而追隨不可及聞先在海州','孔平仲','宋','宋诗','song-poetry','','[]','紫芝眉宇不可見，一葉小舟如掣電。',64,'全唐诗/poet.song.53000.json','["紫芝眉宇不可見，一葉小舟如掣電。", "青山雲外半出沒，白鳥溪邊空絢練。", "朝行蒼莽带殘月，暮宿蕭條聞落霰。", "豈無斗酒爲君傾，起望蒼波隔長堰。"]'),
('c07a1ec1-a22d-4066-b271-473ad0f1ab64','日出','孔平仲','宋','宋诗','song-poetry','','[]','仲冬十一月，我行赴高密。',96,'全唐诗/poet.song.53000.json','["仲冬十一月，我行赴高密。", "路出東海上，晨起駭初日。", "騰騰若車輪，只向平地出。", "較于昔所見，得此十之七。", "蟾蜍尚弄影，皎皎橫參畢。", "輝光一迸散，夜氣掃若失。", "扶桑想可到，俗慮苦難訖。", "壯觀曾未厭，側嘆流景疾。"]'),
('32dd7d83-c95e-4822-98c6-d90a8db58cb2','早行','孔平仲','宋','宋诗','song-poetry','','[]','客興謂已旦，出視見落月。',120,'全唐诗/poet.song.53000.json','["客興謂已旦，出視見落月。", "瘦馬入荒陂，霜花重如雪。", "海風吹萬里，兩耳凍幾脫。", "歲晏已苦寒，近北尤凜洌。", "况當清曉行，遡此原野闊。", "笠飛带繞頸，指强不能結。", "農家烟火微，炙手粗可熱。", "豈能迂我留，而就苟且活。", "仰頭視四宇，夜氣亦漸豁。", "苦心待正晝，白日想不闕。"]'),
('d102beaf-c9ee-401e-be09-ccffc4a9060f','夢錫惠墨答以蜀茶','孔平仲','宋','宋诗','song-poetry','','[]','墨者色自黑，黑者墨之宜。',264,'全唐诗/poet.song.53000.json','["墨者色自黑，黑者墨之宜。", "所以陳玄號，聞之于退之。", "近世工頗拙，所巧惟見欺。", "摹成古鼎篆，團作革靴皮。", "揮毫自慘淡，色比突中煤。", "誰最畜佳品，鄭君真好奇。", "贈我以所貴，有不讓金犀。", "堅如雷公石，端若大禹圭。", "研磨出深黝，落紙光陸離。", "較之囊中舊，相去乃雲泥。", "辱君此賜固已厚，何以報之乏瓊玖。", "不如投君以嗜好，君性嗜茶人罕有。", "建溪龍鳳想厭多，越上槍旗不禁久。", "我收蜀茗亦可飲，得我峨眉高太守。", "人情或以少爲珍，心若喜之當適口。", "更憐此物來處遠，三峽驚波如電卷。", "江湖重覆千萬里，淮海浩蕩漣漪淺。", "舍舟登陸尚相隨，今以答君非不腆。", "開緘碾潑試一嘗，尤稱君家銅葉盞。"]'),
('19080840-31a2-4465-ba87-ef865f964393','夜聚楊節之秘校廨宇','孔平仲','宋','宋诗','song-poetry','','[]','雲亂海天低，風吹馬耳破。',48,'全唐诗/poet.song.53000.json','["雲亂海天低，風吹馬耳破。", "黄昏訪主人，同向幽齋坐。", "談資綠酒長，歡敵紅裙座。", "倒載夜深歸，雪花如掌大。"]'),
('d490888b-6a72-49a5-85dd-0f8611238926','止謁先聖廟者','孔平仲','宋','宋诗','song-poetry','','[]','高密古名城，其地近闕里。',168,'全唐诗/poet.song.53000.json','["高密古名城，其地近闕里。", "弦歌聲相聞，往往重夫子。", "學官雖荒凉，廟貌頗嚴偉。", "上元施燈燭，下俗奠醪醴。", "高焚百和香，競爇黄金紙。", "所求乃福祥，此事最鄙俚。", "朝廷謹庠序，五路茲焉始。", "建宮以主之，不肖實當此。", "澆敝皆掃除，安可循舊軌。", "丁寧戒閽人，來者悉禁止。", "嘗聞之魯論，丘之禱久矣。", "生也既無求，歿豈享淫祀。", "夜亭甚清虛，古柏自風起。", "悅之以其道，吾祖當亦喜。"]'),
('46b73197-8e7a-4a3c-b5da-7f38aa1087dc','還楊秘校賦','孔平仲','宋','宋诗','song-poetry','','[]','楊君示我賦一編，讀之百復不能已。',128,'全唐诗/poet.song.53000.json','["楊君示我賦一編，讀之百復不能已。", "新詞琢就若瑶琨，故實織成侔錦綺。", "可憐苦心自少年，近日改科無用此。", "雖然此才頗富贍，貫穿縱橫惟所使。", "有如安車馳大道，左驂驊騮右騄駬。", "東西南北皆可往，但顧欲適何如耳。", "勉旃力習以待舉，尺一佇聞招特起。", "他時名望壓盧駱，闊步青雲此焉始。"]'),
('a464fbba-3a57-44fc-aacd-62ecf5261b55','常父寄蕈','孔平仲','宋','宋诗','song-poetry','','[]','此物固已美，採之從歷山。',48,'全唐诗/poet.song.53000.json','["此物固已美，採之從歷山。", "蒙兄遠相寄，深意在加餐。", "冷落虀鹽地，蕭條蓬艾間。", "書云次越品，寧復昔時歡。"]'),
('2510ffc5-8159-49c2-92cf-406689047ab3','讀莊子','孔平仲','宋','宋诗','song-poetry','','[]','損此以錙銖，益我以千金。',96,'全唐诗/poet.song.53000.json','["損此以錙銖，益我以千金。", "豈足爲輕重，徒能勞爾心。", "覆彼以狐貉，蒙此以絺綌。", "豈足爲厚薄，徒能損卿德。", "南山有鷙鳥，睥睨天地秋。", "有意橫八極，固非守一丘。", "老鴟嚇腐鼠，安可施于此。", "鵷雛尚不屑，况非鵷雛比。"]'),
('00be71ac-6745-4702-8a13-1034099b1629','郡官送楊文思獨以事不赴','孔平仲','宋','宋诗','song-poetry','','[]','匆匆行人行，車馬已在坂。',72,'全唐诗/poet.song.53000.json','["匆匆行人行，車馬已在坂。", "主人留客止，客畏白日晚。", "陽關發哀唱，春物况滿眼。", "城中流水長，離恨不可浣。", "我雖居學宮，不往若疏懶。", "斯心獨摇摇，送客千里遠。"]'),
('15758066-3915-4df9-99cf-a6f43b47caea','夢錫楊節之孫昌齡見過小飲','孔平仲','宋','宋诗','song-poetry','','[]','夢錫更時事，恢然君子儒。',252,'全唐诗/poet.song.53000.json','["夢錫更時事，恢然君子儒。", "節之瓊樹枝，秀氣發扶疏。", "昌齡出相家，謙謹乃繩樞。", "三人于交游，得一固有餘。", "日暮俱訪我，止駕共躊躇。", "四天忽陰沉，風聲若江湖。", "寒色尚可畏，促膝同附爐。", "高密酒雖貴，爲君開一壺。", "拳栗自東越，殷榴從上都。", "羹烹歷山蕈，膾斫注溝魚。", "鮮蛤寔海錯，肥羊非市屠。", "後食淮南蓴，此皆北所無。", "主人不敢愛，且以爲賓娛。", "夢錫飲中豪，節之亦其徒。", "昌齡稍姦黠，我勸勢頗麤。", "左手扼其肩，右手進觥盂。", "勉强爲我盡，淋漓滿衣裾。", "醉坐各忘去，蓬燭已見跗。", "幽談入鬼怪，巧謔相揶揄。", "勿言輕此樂，此樂勝笙竽。", "明朝酒醒後，相對禮如初。"]'),
('877f620d-a1f1-4e0f-8ebf-790f4df9de63','夢錫遺蔗','孔平仲','宋','宋诗','song-poetry','','[]','憶昔游五嶺，甘蔗彌野闊。',96,'全唐诗/poet.song.53000.json','["憶昔游五嶺，甘蔗彌野闊。", "一來瑯琊城，此味久所闕。", "商人自東南，駕海連天筏。", "所致雖不多，愛養尚如活。", "傍求未得之，分遺意特達。", "中凝甘露漿，外削紫玉屑。", "漸欣入佳境，仍喜對高節。", "應知方著書，持此解消渴。"]'),
('9dbb2473-197f-4e5c-8fa9-c0219c13848d','呈宋思叔縣丞','孔平仲','宋','宋诗','song-poetry','','[]','宋君吾未識，名譽素講聞。',72,'全唐诗/poet.song.53000.json','["宋君吾未識，名譽素講聞。", "海上一邂逅，歡然如故人。", "相交但數語，所見已終身。", "固非輕許與，亦有白頭新。", "之官頗迫促，折柳長亭春。", "馳情自今始，悵望西南雲。"]'),
('4f56ed84-bbeb-4166-bbd8-1571b18d945a','寄舍弟','孔平仲','宋','宋诗','song-poetry','','[]','西園草碧色，南湖水綠波。',24,'全唐诗/poet.song.53000.json','["西園草碧色，南湖水綠波。", "五雲亭上意，爭奈艷陽何。"]'),
('a49ca077-2ecc-4b9b-aa90-35cddc970d8d','二月一日','孔平仲','宋','宋诗','song-poetry','','[]','春時雖已半，春色猶尚淺。',56,'全唐诗/poet.song.53000.json','["春時雖已半，春色猶尚淺。", "海上冰霰多，城中花木晚。", "今朝天氣始微晴，萬里東風照眼明。", "南河截水共游賞，好約扁舟載酒行。"]'),
('856d43b6-a9c8-45dc-8034-81f486e0c23f','收家書','孔平仲','宋','宋诗','song-poetry','','[]','早承會稽信，晚接清江使。',96,'全唐诗/poet.song.53000.json','["早承會稽信，晚接清江使。", "兩地千里餘，尺書同日至。", "既知骨肉安，復得鄰里事。", "丁寧問兒女，委瑣及奴婢。", "開包視封題，親故各有寄。", "牛狸與黄雀，路遠不易致。", "東人罕曾識，專享無所遺。", "豈徒抵萬金，鼓腹快異味。"]'),
('9fa4f56e-cc54-4f58-8912-c2b782f4936f','春天','孔平仲','宋','宋诗','song-poetry','','[]','春天酣酣睡最美，日轉花陰猶未起。',112,'全唐诗/poet.song.53000.json','["春天酣酣睡最美，日轉花陰猶未起。", "須臾夢覺聞風聲，波濤翻空千萬里。", "出門四望氣慘淡，寒色射人如潑水。", "旋見大雪落交加，向晚綏綏尚不止。", "游絲柳絮復何有，百鳥捲舌愁欲死。", "陰陽變化固有漸，乃何暴忽有如此。", "清江野客心傷悲，寂寞無言對桃李。"]'),
('aa1ff2f5-27b1-46df-969a-e928c9be8edf','觀舞','孔平仲','宋','宋诗','song-poetry','','[]','宴館簇金絲，繡茵呈舞旋。',48,'全唐诗/poet.song.53000.json','["宴館簇金絲，繡茵呈舞旋。", "雲鬟應節低，蓮步隨歌轉。", "勢多體不犯，妙絕乃習貫。", "含笑有餘情，小揖更微盼。"]'),
('1bd83e58-2641-4796-b485-36054e9b6b00','寧采','孔平仲','宋','宋诗','song-poetry','','[]','寧采糞上英，莫折園中柳。',72,'全唐诗/poet.song.53000.json','["寧采糞上英，莫折園中柳。", "人情愈薄惡，變態在回首。", "紛紛苦相攻，把臂曾締友。", "陰機多鬼禍，似此奚可久。", "巧言奮南箕，定籍挂北斗。", "豺虎雖不食，且使烏啄口。"]'),
('eafb7c10-2dbb-4d48-ae97-bec58c17553d','城南','孔平仲','宋','宋诗','song-poetry','','[]','密州三月猶有寒，地平更在大海上。',64,'全唐诗/poet.song.53000.json','["密州三月猶有寒，地平更在大海上。", "昨朝雨止氣已晴，今日繁陰北風壯。", "城南蹙水傍城流，幾處垂楊繫小舟。", "傳聞寂寂無車馬，紅杏夭桃各自稠。"]'),
('579cd559-f181-4ff4-b60e-c66cb2ca3fe7','諸君送黄仲勉戶曹予以事不預遣人送綠楊一枝贈別','孔平仲','宋','宋诗','song-poetry','','[]','不能送行客，贈以綠楊枝。',24,'全唐诗/poet.song.53000.json','["不能送行客，贈以綠楊枝。", "試看青青眼，此心當自知。"]'),
('2a5e5960-99f5-4690-afa7-3a410e533d33','春風','孔平仲','宋','宋诗','song-poetry','','[]','春風掃浮雲，萬里青天出。',48,'全唐诗/poet.song.53000.json','["春風掃浮雲，萬里青天出。", "三星次第呈，明月入我室。", "昨宵苦陰雨，並坐不見膝。", "相去能幾時，皎皎如白日。"]'),
('af59d85c-f724-4be5-a2eb-52a5dc362412','送夢錫往齊州','孔平仲','宋','宋诗','song-poetry','','[]','望君之行車，既遠目亦收。',84,'全唐诗/poet.song.53000.json','["望君之行車，既遠目亦收。", "惟有隨君心，千里不能休。", "我兄在歷城，相別歲已周。", "音問月三四，東西交置郵。", "豈如一相見，君今涉其州。", "爲我道亡恙，深言致綢繆。", "先馳魂夢往，迎子鵲山頭。"]'),
('e71c831f-206c-4011-b350-7468f4210866','晚出','孔平仲','宋','宋诗','song-poetry','','[]','空城鳥欲棲，漸夕收炎暑。',48,'全唐诗/poet.song.53000.json','["空城鳥欲棲，漸夕收炎暑。", "槐葉綠生風，椿花落如雨。", "出門何所適，有口不敢語。", "披豁向青天，望銷雲一縷。"]'),
('441e8e45-1fcf-42f1-a683-514233ef9d3d','常父寄半夏','孔平仲','宋','宋诗','song-poetry','','[]','齊州多半夏，採自鵲山陽。',228,'全唐诗/poet.song.53000.json','["齊州多半夏，採自鵲山陽。", "纍纍圓且白，千里遠寄將。", "新婦初解包，諸子喜若狂。", "皆云已法製，無滑可以嘗。", "大兒强占據，端坐斥四旁。", "次女出其腋，一攫已半亡。", "須臾被辛螫，棄餘不復藏。", "競以手捫舌，啼噪滿中堂。", "父至笑且驚，亟使啖以薑。", "中宵方稍定，久此燈燭光。", "大鈞播萬物，不擇窳與良。", "虎掌出深谷，鳶頭蔽高岡。", "春草善殺魚，野葛挽人腸。", "各以類自播，敢問孰主張。", "水玉名雖佳，神農錄之方。", "其外則皎潔，其中慕堅剛。", "奈何藴毒性，入口有所傷。", "老兄好服食，似此亦可防。", "急難我輩事，感惕成此章。"]'),
('3a1b9ccf-6088-4c9d-95dd-a64a376c2b91','送董監部赴舉','孔平仲','宋','宋诗','song-poetry','','[]','西風槐半黄，行客車馬動。',96,'全唐诗/poet.song.53000.json','["西風槐半黄，行客車馬動。", "揚鞭望都城，壯氣不可控。", "朝廷新改科，詩賦斥無用。", "君能通古書，義理善折衷。", "先鋒陳典謨，後騎出歌貢。", "以茲趨大敵，坐可圖百中。", "青春聞喜處，醉弁宮花重。", "去矣當自强，勿作思歸夢。"]'),
('3987ac07-a3c4-4573-a61b-fe065bb33690','惜別爲從道作','孔平仲','宋','宋诗','song-poetry','','[]','嘗聞直諒冠三友，自古才難非特今。',96,'全唐诗/poet.song.53000.json','["嘗聞直諒冠三友，自古才難非特今。", "今也脅肩事諂笑，君獨苦口工規箴。", "我常從之求過失，箕踞慢駡猶甘心。", "其言未必俱中理，披沙往往逢黄金。", "今將去矣誰復嗣，已覺別恨凌秋陰。", "胸中抖擻宜一盡，留作更允相思深。"]'),
('dbc70a44-10d4-4225-bd7d-b67070b8f3dc','送從道','孔平仲','宋','宋诗','song-poetry','','[]','去年風雲攪天暗，君馬區區之海涯。',128,'全唐诗/poet.song.53000.json','["去年風雲攪天暗，君馬區區之海涯。", "今年苦寒又訪別，正是去年行役時。", "信陽雖遠重來得，小桃常探春消息。", "如今官滿去不返，又見花開誰記憶。", "乾坤浩蕩歸無鄉，歲月崢嶸老相逼。", "一官奔走隨所使，後期會合知南北。", "篇詩惜別人少和，須知此別真可惜。", "黄髯半醉舌若蜚，它日樽前無此客。"]'),
('b1448e6b-54d4-4ea7-a6ab-949f8d3c3a01','出城','孔平仲','宋','宋诗','song-poetry','','[]','駐馬河之西，送車皆已返。',36,'全唐诗/poet.song.53000.json','["駐馬河之西，送車皆已返。", "郊原人漸少，風物秋將晚。", "身如獨鳥輕，意與青山遠。"]'),
('b37bb1bd-f99a-4edc-be1a-2bef62eda46e','迷途','孔平仲','宋','宋诗','song-poetry','','[]','吹燈治行裝，戴月即前路。',96,'全唐诗/poet.song.53000.json','["吹燈治行裝，戴月即前路。", "深村苦多歧，乃使行者悞。", "東西皆可往，曲折何所遇。", "泥中虎鬭跡，草木新封墓。", "陰雲忽以興，四顧增恐懼。", "及今亦誰咎，初失在跬步。", "林木杳崢嶸，邱原莽回互。", "雖聞叱牛聲，欲問不知處。"]'),
('ce6fbaf6-3c16-411f-993b-f246c05fa640','費縣','孔平仲','宋','宋诗','song-poetry','','[]','途經古費邑，遺堞草萊平。',48,'全唐诗/poet.song.53000.json','["途經古費邑，遺堞草萊平。", "東瞻龜蒙山，西望顓臾城。", "弗擾以畔召，仲尼猶欲行。", "許由亦有塚，孑孑何獨清。"]'),
('abb4659f-55ad-4a23-98e0-961027cf7f41','遇雨','孔平仲','宋','宋诗','song-poetry','','[]','客行日暮饑且渴，况值漫山雨未絕。',64,'全唐诗/poet.song.53000.json','["客行日暮饑且渴，况值漫山雨未絕。", "蜀黍林中氣慘淡，黄牛岡頭路曲折。", "狂風亂掣紙傘飛，瘦馬屢拜油裳裂。", "記得默齋端坐時，惟愛霶𩃱洗煩熱。"]'),
('c86a86b7-3320-4137-9d04-c6f9f77d1d23','宵興','孔平仲','宋','宋诗','song-poetry','','[]','宵興視星斗，側身坐長嘆。',120,'全唐诗/poet.song.53000.json','["宵興視星斗，側身坐長嘆。", "秋風忽已至，萬木鳴珊珊。", "垂髫初執卷，結髮乃彈冠。", "功名當及時，一失何由還。", "丈夫惜少壯，日月如走丸。", "念躬累尚寡，筋力無所難。", "白首佩黄金，意氣亦已闌。", "所以飛騰心，顧盼生羽翰。", "詩人詠嵩高，不爾歌考槃。", "胡爲兩未决，碌碌守一官。"]'),
('ea696bd6-53fd-4a95-9248-9e0e4bfe27ea','呈夢錫  其一','孔平仲','宋','宋诗','song-poetry','','[]','妻孥能相期，每出必遽還。',24,'全唐诗/poet.song.53000.json','["妻孥能相期，每出必遽還。", "如其歸稍晚，必謁鄭推官。"]'),
('6b8d6f13-5480-440b-b1f4-e4d69b61eaac','呈夢錫  其二','孔平仲','宋','宋诗','song-poetry','','[]','與君來往半歲餘，三日不見已爲疏。',96,'全唐诗/poet.song.53000.json','["與君來往半歲餘，三日不見已爲疏。", "入門褫带不相揖，下馬且復休僕夫。", "形骸禮數不足問，但論肝鬲之何如。", "昨朝萬事俱撥置，與子齋中同負爐。", "去時苦寒冒風雪，歸路清輝踏霜月。", "但取樽前笑語歡，豈知門外陰晴別。"]'),
('be8bb1df-b7dd-4b14-9f1d-2d529a955d65','韓大夫城','孔平仲','宋','宋诗','song-poetry','','[]','大夫今安在，唯有廢城存。',96,'全唐诗/poet.song.53000.json','["大夫今安在，唯有廢城存。", "流水抱沙曲，依依楊柳村。", "居者五六家，荆榛深閉門。", "青青麥隴直，藹藹桑枝繁。", "牛羊任所適，僮稚更不喧。", "啼鳥靜逾遠，落花風自翻。", "昔稱老農賤，吾意野人尊。", "謀身莽無定，太息視乾坤。"]'),
('6bf9e4bf-be52-487d-b28b-b8e58cf29bef','青州作','孔平仲','宋','宋诗','song-poetry','','[]','京東地平夷，自古四戰國。',180,'全唐诗/poet.song.53000.json','["京東地平夷，自古四戰國。", "九州此居三，山海在封域。", "北趨京洛近，南卷江淮直。", "富饒足魚鹽，飽暖遍牟麥。", "英雄欲飛騰，假此爲羽翼。", "隆準蹙秦亡，金蟆伺唐隙。", "方今不憂此，所重只西北。", "兵防最寡少，主帥失銓擇。", "蒿萊蔽城隍，繡澀滿戈戟。", "慢爲盜之資，忽者禍所植。", "吾視士大夫，赳赳半雄特。", "歌謠尚慷慨，闊達本多匿。", "腹心宜先安，豫備乃長策。", "衆方誦太平，我乃虞盜賊。", "雖言亦誰聽，痛哭損肝膈。"]'),
('3b2b1b89-83b1-4cf7-98e1-7be17cc5ee18','立秋日呈夢錫','孔平仲','宋','宋诗','song-poetry','','[]','今日纔立秋，凉風已蕭瑟。',96,'全唐诗/poet.song.53000.json','["今日纔立秋，凉風已蕭瑟。", "我不感時節，念子行有日。", "憶初同赴官，相後惟一月。", "子先脫然去，我獨不得發。", "江邊舍未還，汴上生計足。", "古之仕爲榮，今則富者福。", "子隨鴻鵠高，我戀升斗食。", "豈徒別離悲，更有長太息。"]'),
('410b9074-c506-4648-8435-f65f218f3306','曾子固令詠齊州景物作二十一詩以獻 閱武堂','孔平仲','宋','宋诗','song-poetry','','[]','開拓乾坤遠，歡娛歲序深。',24,'全唐诗/poet.song.53000.json','["開拓乾坤遠，歡娛歲序深。", "堂前猶閱武，自是太平心。"]'),
('a114c836-a5da-4b51-989c-87fea20b0e39','曾子固令詠齊州景物作二十一詩以獻 閱武堂下新渠','孔平仲','宋','宋诗','song-poetry','','[]','東來細溜長，西去餘波漲。',24,'全唐诗/poet.song.53000.json','["東來細溜長，西去餘波漲。", "能收四海心，樂此一渠上。"]'),
('7bab230f-fcea-4e3d-bad0-550a92cf7d90','曾子固令詠齊州景物作二十一詩以獻 凝香齋','孔平仲','宋','宋诗','song-poetry','','[]','東郡經年久，西齋一事無。',24,'全唐诗/poet.song.53000.json','["東郡經年久，西齋一事無。", "蕭然靜相對，惟有博山爐。"]'),
('dc7c5326-f923-4bb7-8bdd-1ff5486356bc','曾子固令詠齊州景物作二十一詩以獻 芍藥廳','孔平仲','宋','宋诗','song-poetry','','[]','芍藥花初發，牽公詩思濃。',24,'全唐诗/poet.song.53000.json','["芍藥花初發，牽公詩思濃。", "露紅烟紫句，全勝綠盤龍。"]'),
('1f095197-3bf1-4945-b647-6797020fdb8f','曾子固令詠齊州景物作二十一詩以獻 仁風廳','孔平仲','宋','宋诗','song-poetry','','[]','太守政何如，茲焉名可見。',24,'全唐诗/poet.song.53000.json','["太守政何如，茲焉名可見。", "齊州一萬家，揮以袁宏扇。"]'),
('3cf589e1-eb47-4934-a9c8-d036ae716e58','曾子固令詠齊州景物作二十一詩以獻 竹齋','孔平仲','宋','宋诗','song-poetry','','[]','淅淅風敲韵，亭亭日轉陰。',24,'全唐诗/poet.song.53000.json','["淅淅風敲韵，亭亭日轉陰。", "公應喜來此，相得歲寒心。"]'),
('f9a3063b-8591-4238-a144-a9f4edece802','曾子固令詠齊州景物作二十一詩以獻 水香亭','孔平仲','宋','宋诗','song-poetry','','[]','龍頭落潺湲，雁齒駕清淺。',24,'全唐诗/poet.song.53000.json','["龍頭落潺湲，雁齒駕清淺。", "夜闌氣益佳，雨霽香尤遠。"]'),
('335f2da4-2b01-40fa-8b61-19b3644fd6cc','曾子固令詠齊州景物作二十一詩以獻 采香亭','孔平仲','宋','宋诗','song-poetry','','[]','芙蓉近可攀，香草供幽賦。',24,'全唐诗/poet.song.53000.json','["芙蓉近可攀，香草供幽賦。", "公才如命騷，此是冥搜處。"]'),
('81634e18-8ea8-4656-91b3-9ee8f97c54f7','曾子固令詠齊州景物作二十一詩以獻 靜化堂','孔平仲','宋','宋诗','song-poetry','','[]','四境靜山川，一枕閒風月。',24,'全唐诗/poet.song.53000.json','["四境靜山川，一枕閒風月。", "野水抱城幽，青天垂木末。"]'),
('e58910f1-18b4-4bbd-97a0-613ffc4b2b7a','曾子固令詠齊州景物作二十一詩以獻 鵲山亭','孔平仲','宋','宋诗','song-poetry','','[]','老杜詩猶在，重華事已無。',24,'全唐诗/poet.song.53000.json','["老杜詩猶在，重華事已無。", "千秋陵谷變，塵起鵲山湖。"]'),
('cc4336b9-f19c-43ed-afdc-3c1ca2798fd7','曾子固令詠齊州景物作二十一詩以獻 芙蓉橋','孔平仲','宋','宋诗','song-poetry','','[]','出城跨岧嶢，驚目見花艷。',24,'全唐诗/poet.song.53000.json','["出城跨岧嶢，驚目見花艷。", "飛蓋每來游，佳境此其漸。"]'),
('98711440-6680-4cf0-b000-4dc84a5177b0','曾子固令詠齊州景物作二十一詩以獻 芙蓉臺','孔平仲','宋','宋诗','song-poetry','','[]','漾舟入芙蓉，花亂舟欹側。',24,'全唐诗/poet.song.53000.json','["漾舟入芙蓉，花亂舟欹側。", "安穩此凭欄，清香生履舄。"]'),
('aa46b3ec-0834-4ae2-8165-91d758a8ce88','曾子固令詠齊州景物作二十一詩以獻 環波亭','孔平仲','宋','宋诗','song-poetry','','[]','瀟洒塵埃外，崔嵬清淺中。',24,'全唐诗/poet.song.53000.json','["瀟洒塵埃外，崔嵬清淺中。", "四軒春水闊，兩岸畫橋通。"]'),
('14813a4a-fd11-4aaa-909a-f84ec1f03333','曾子固令詠齊州景物作二十一詩以獻 水西橋','孔平仲','宋','宋诗','song-poetry','','[]','景物此清淡，幽亭獨細論。',24,'全唐诗/poet.song.53000.json','["景物此清淡，幽亭獨細論。", "恐人容易過，常鎖水西門。"]'),
('2c8686c6-8f18-430f-a620-d4ccd534036d','曾子固令詠齊州景物作二十一詩以獻 水西亭','孔平仲','宋','宋诗','song-poetry','','[]','河流春已深，野色晚更靜。',24,'全唐诗/poet.song.53000.json','["河流春已深，野色晚更靜。", "生計慕園畦，歸心付漁艇。"]'),
('35fb7b3c-5e25-4a81-bfab-69dd0056fc64','曾子固令詠齊州景物作二十一詩以獻 西湖','孔平仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','芙渠十頃闊，藻荇一篙深。',24,'全唐诗/poet.song.53000.json','["芙渠十頃闊，藻荇一篙深。", "晚日江鄉景，秋風澤國心。"]'),
('c3a46885-dffb-4fdf-9edf-094a765184ff','曾子固令詠齊州景物作二十一詩以獻 百花橋','孔平仲','宋','宋诗','song-poetry','','[]','花滿紅橋外，尋芳未渡橋。',24,'全唐诗/poet.song.53000.json','["花滿紅橋外，尋芳未渡橋。", "春風相調引，已有異香飄。"]'),
('28ebf5c3-9abc-4460-8ba7-cabc38f08ac1','曾子固令詠齊州景物作二十一詩以獻 北湖','孔平仲','宋','宋诗','song-poetry','','[]','塵汙遠已留，淥凈此不雜。',24,'全唐诗/poet.song.53000.json','["塵汙遠已留，淥凈此不雜。", "僻招水鳥棲，清數游魚鬣。"]'),
('e40309e1-3c42-4f28-ac39-57ac50e8ceea','曾子固令詠齊州景物作二十一詩以獻 百花臺','孔平仲','宋','宋诗','song-poetry','','[]','南瞻復北顧，春水綠漫漫。',24,'全唐诗/poet.song.53000.json','["南瞻復北顧，春水綠漫漫。", "此地尋花柳，全勝別處看。"]'),
('ec2dbdc1-8c3d-4ab4-86ca-7e0bb7aadf30','曾子固令詠齊州景物作二十一詩以獻 百花堤','孔平仲','宋','宋诗','song-poetry','','[]','花發紅雲合，公來醉玉頹。',24,'全唐诗/poet.song.53000.json','["花發紅雲合，公來醉玉頹。", "傍城行怯遠，却泛小舟迴。"]'),
('4f1c1ad3-55e2-4f3a-a803-fca9f2726b51','曾子固令詠齊州景物作二十一詩以獻 北渚亭','孔平仲','宋','宋诗','song-poetry','','[]','高深極前臨，蒼莽接迴眺。',24,'全唐诗/poet.song.53000.json','["高深極前臨，蒼莽接迴眺。", "齊州景物多，于此領其要。"]'),
('8fd12dc5-b3ce-4add-909e-747d69b95cdb','又寄夢錫','孔平仲','宋','宋诗','song-poetry','','[]','自君臥漳濱，我意恍若疾。',144,'全唐诗/poet.song.53000.json','["自君臥漳濱，我意恍若疾。", "無人與笑言，兀兀守一室。", "當寢或不寢，當食或不食。", "有思氣填胸，可駭幾戰慄。", "想君端在家，比我乃安逸。", "妻孥以嬉娛，簿領久閣筆。", "南城趨北城，道路無所隔。", "我豈無僕馬，子不見賓客。", "哦亭足清風，林木助蕭瑟。", "葵花無數開，蓮葉亦已出。", "起來定何時，幸會能幾日。", "已令蒭白醪，待子歡促膝。"]'),
('31e75ffc-48ad-4365-904a-be88fcb6731c','寄王達夫高密令','孔平仲','宋','宋诗','song-poetry','','[]','高城已吹角，月暗星河落。',56,'全唐诗/poet.song.53000.json','["高城已吹角，月暗星河落。", "與子語不休，青燈同寂寞。", "平明車馬去匆匆，一飯相邀不得同。", "交情世契兩皆厚，東望白雲千萬重。"]'),
('f960caf4-4f4a-4f1d-b75d-b6c3385baa18','謁夢錫見几上粉箋援筆書此','孔平仲','宋','宋诗','song-poetry','','[]','飄飄雲容高，慘慘日色薄。',48,'全唐诗/poet.song.53000.json','["飄飄雲容高，慘慘日色薄。", "此時駕君車，去意不可縛。", "鳴蟬送凄切，白露催摇落。", "山城更海上，觸目添蕭索。"]'),
('389507ff-de6e-40f3-95a7-2338eceeaafd','晚集城樓','孔平仲','宋','宋诗','song-poetry','','[]','高樓百尺修木尾，對面南山翠相倚。',64,'全唐诗/poet.song.53000.json','["高樓百尺修木尾，對面南山翠相倚。", "凭欄談笑青雲裏，秋標摩空日色死。", "海風蕭蕭東萬里，吹襟洗鬢清如水。", "下視黄埃濁波起，車馬紛紜只螻蟻。"]'),
('cad026e7-0c85-4a88-8cdd-e344337a0dfd','陰山七騎','孔平仲','宋','宋诗','song-poetry','','[]','青氈作帽黑藥靴，進退颯颯生風沙。',112,'全唐诗/poet.song.53000.json','["青氈作帽黑藥靴，進退颯颯生風沙。", "胡歌胡舞胡兩跪，問胡何爲乃至此。", "象胡之人假爲之，朱顔的皪秀兩眉。", "手操弓矢仰視天，如見飛雁馳平川。", "主稱此樂直萬錢，坐客競飲黄金船。", "世人見識無百年，追歡收快貴目前。", "當時披髮祭于野，自非辛有誰知者。"]'),
('c99caa8e-2782-4529-852a-482ca934e90f','君住','孔平仲','宋','宋诗','song-poetry','','[]','君住水西我水東，東岸波生西岸風。',64,'全唐诗/poet.song.53000.json','["君住水西我水東，東岸波生西岸風。", "哀哉中截錦繡段，上襦下裳各一半。", "小星隆隆怒且鳴，前驅貪狼後欃槍。", "何如盡遣收芒角，惟放當天皓月行。"]'),
('3608f673-2e51-4b97-912f-9b9316403efe','雞冠','孔平仲','宋','宋诗','song-poetry','','[]','我初種雞冠，其小乃毫芒。',132,'全唐诗/poet.song.53000.json','["我初種雞冠，其小乃毫芒。", "曾未得幾時，忽已過我長。", "根株既猥大，枝葉亦開張。", "吐花凌朝曦，生意殊未央。", "陰風自西來，慘淡驅清霜。", "一夜忽變故，葉萎花已黄。", "當此繁盛時，爲爾賞壺觴。", "及今乃腐草，好玩安可常。", "呼童盡剪拔，昔恐踐踏傷。", "庭除稍曠闊，耳目加清凉。", "竹枝久蒙蔽，迥立獨蒼蒼。"]'),
('fd841a8f-bca2-49e0-8000-d6ace10e23d2','月三章  其一','孔平仲','宋','宋诗','song-poetry','','[]','夜如何其月在隅，問行何爲乃躊躇，海波壓輪不得驅。',40,'全唐诗/poet.song.53000.json','["夜如何其月在隅，問行何爲乃躊躇，海波壓輪不得驅。", "中庭有客心不樂，欲挽玉兔鞭蟾蜍。"]'),
('f6219e55-715d-4f06-b0dc-8d5796448b5c','月三章  其二','孔平仲','宋','宋诗','song-poetry','','[]','夜如何其月正美，起視萬物如明水，山魈避人鬼火死。',40,'全唐诗/poet.song.53000.json','["夜如何其月正美，起視萬物如明水，山魈避人鬼火死。", "中庭有客立不移，何暇眼力看箕尾。"]'),
('1ce8f7b7-8126-4f7b-a559-f0a890603cd8','月三章  其三','孔平仲','宋','宋诗','song-poetry','','[]','夜如何其月落愁，光輝奄奄星益稠，白雲擁漢波不流。',40,'全唐诗/poet.song.53000.json','["夜如何其月落愁，光輝奄奄星益稠，白雲擁漢波不流。", "中庭有客心不樂，放志萬里誰能收。"]'),
('e55a4347-9b08-42c6-9d71-8e7960a8ca13','代小子廣孫寄翁翁','孔平仲','宋','宋诗','song-poetry','','[]','爹爹來密州，再歲得兩子。',168,'全唐诗/poet.song.53000.json','["爹爹來密州，再歲得兩子。", "牙兒秀且厚，鄭鄭已生齒。", "翁翁尚未見，既見想懽喜。", "廣孫讀書多，寫字輒兩紙。", "三三足精神，大安能步履。", "翁翁雖舊識，伎倆非昔比。", "何時得團聚，盡使羅拜跪。", "婆婆到輦下，翁翁在省裏。", "大婆八十五，寢膳近何似。", "爹爹與妳妳，無日不思爾。", "每到時節佳，或對飲食美。", "一一俱上心，歸期當屈指。", "昨日又開爐，連天北風起。", "飲闌却蕭條，舉目數千里。"]'),
('946914c3-6581-460c-836f-f6da4861a1df','詠無核紅柿','孔平仲','宋','宋诗','song-poetry','','[]','林中有丹果，壓枝一何稠。',144,'全唐诗/poet.song.53000.json','["林中有丹果，壓枝一何稠。", "爲柿已軟美，嗟爾骨亦柔。", "風霜變顔色，雨露加膏油。", "大哉造化心，于爾何綢繆。", "荆筐載趨市，價賤良易求。", "剖心無所有，入口頗相投。", "爲栗外屈强，老者所不收。", "爲棗中亦剛，飼兒戟其喉。", "衆言咀嚼快，惟爾無所憂。", "排羅置前列，圓熟當高秋。", "且以悅一時，長久豈暇謀。", "咄哉潰爛速，棄擲將誰尤。"]'),
('39d3e4a0-86bd-4984-9eb7-4fcea6d4922b','寄從道','孔平仲','宋','宋诗','song-poetry','','[]','憶初撫掌笑，嘗謂子猿猱。',120,'全唐诗/poet.song.53000.json','["憶初撫掌笑，嘗謂子猿猱。", "斑然武而文，譏駡舌若刀。", "髭黄喉骨結，內敏見秋毫。", "論官則甚微，意氣一何高。", "今思乃麟鳳，百十未易遭。", "子行白日靜，回首常蕭騷。", "聞子在定州，深山坐披毛。", "何如東海上，萬疊觀波濤。", "不見歲再晚，北風方怒嘷。", "圍爐捧美酒，思子持蟹螯。"]'),
('9c465def-fb10-40e3-85ef-5eca3e3b6ad2','食桃','孔平仲','宋','宋诗','song-poetry','','[]','剪彼十圍木，架此百尺梁。',96,'全唐诗/poet.song.53000.json','["剪彼十圍木，架此百尺梁。", "十圍不加大，百尺不加長。", "胡爲被錦綉，空爾飾文章。", "根斷膚已剝，至朽不復昌。", "食桃棄其核，下與糞壞藏。", "雨露之所濡，發生乃微芒。", "回首枝幹大，冉冉出我牆。", "開花又結子，意態何煌煌。"]'),
('ec8452d8-3a3a-4363-a3d8-50b3a8b15c8a','出郭','孔平仲','宋','宋诗','song-poetry','','[]','出郭十里餘，蒼莽迎遠目。',96,'全唐诗/poet.song.53000.json','["出郭十里餘，蒼莽迎遠目。", "桑枝强崢嶸，榆柳已先禿。", "誰言禾黍熟，饑鳥不滿腹。", "平時想郊居，至此思邑屋。", "北風吹層陰，冉冉白日速。", "及歸已云暮，景色異初矚。", "去年十二月，踏雪茲往復。", "嗟今再見冬，回首如信宿。"]'),
('adc85191-27c4-4c51-afe8-2728ab018597','太守視新堂','孔平仲','宋','宋诗','song-poetry','','[]','遙遙元崇胄，藹藹東州守。',156,'全唐诗/poet.song.53000.json','["遙遙元崇胄，藹藹東州守。", "留心學校事，遇我在僚友。", "蔽空起新堂，鼛鼓百夫走。", "枉駕親視之，丁寧到榱枓。", "北風沙瞇眼，佇立相與久。", "宴我登哦亭，推我居席首。", "初嘗百花釀，肴蔌無不有。", "是日十月中，新霜脫人肘。", "醺酣一消鑠，和氣回物朽。", "昔人歌魯侯，在泮嘗飲酒。", "我今作此詩，亦以綴厥後。", "美哉姚侯政，豈弟民父母。", "此詩所不歌，先已載民口。"]'),
('aa8255ed-8c8e-4235-8bf6-2e7a3f33749a','日月','孔平仲','宋','宋诗','song-poetry','','[]','月行一何速，暫上青山還復落。',62,'全唐诗/poet.song.53000.json','["月行一何速，暫上青山還復落。", "衆星厥弛不肯休，參橫畢直爭頭角。", "日行比月更疾馳，一日一夜繞天圍。", "光輝所燭萬里同，牆邊炙背快老翁。"]'),
('db19523d-e399-488b-b24c-d086ce670f37','孤雁','孔平仲','宋','宋诗','song-poetry','','[]','空城夜已寂，一雁度雲端。',72,'全唐诗/poet.song.53000.json','["空城夜已寂，一雁度雲端。", "汀洲亦可止，何不怯霜寒。", "豈非防暗禍，驚矯失自安。", "孤音訴明月，天高路漫漫。", "以鶉置懷袖，比汝乏羽翰。", "蒙恩傍溫暖，豈念宵征難。"]'),
('abb0d7d3-71d3-46bb-88dc-f30aeebb0289','祈雨','孔平仲','宋','宋诗','song-poetry','','[]','皇天久不雨，旱風滿東國。',144,'全唐诗/poet.song.53000.json','["皇天久不雨，旱風滿東國。", "春田廢鉏犁，秋事闕牟麥。", "縣官緊租賦，守令抱憂責。", "交馳謁並望，不敢愛牲帛。", "而我處學宮，于邦乃賓客。", "霜寒怯早起，臥聽車馬適。", "方茲祈求急，不預奔走役。", "精誠倘蒙報，豈不沾潤澤。", "古有支離形，亦有支離德。", "而我頗施施，支離在官職。", "雖然憫元元，覽鏡見顔色。", "高詠雲漢篇，千秋意悽惻。"]'),
('45e68154-3ffb-47c0-98a3-1f37972c32cf','牆東新圃','孔平仲','宋','宋诗','song-poetry','','[]','平時乃糞壤，此日遣杷鋤。',72,'全唐诗/poet.song.53000.json','["平時乃糞壤，此日遣杷鋤。", "豈徒植花卉，兼列果與蔬。", "去家無百步，幽境若村墟。", "君公茲避世，聊慰憶荒廬。", "春風尋細草，夜月倚高梧。", "穿垣置小戶，直接東城隅。"]'),
('ff3cb881-acd6-48be-af2c-0ce40011e483','食鰒','孔平仲','宋','宋诗','song-poetry','','[]','風流東武鰒，三月已看花。',108,'全唐诗/poet.song.53000.json','["風流東武鰒，三月已看花。", "及冬稍稍盛，來自滄海涯。", "味腴半附石，體潔不藏沙。", "被之以火光，何幸掛齒牙。", "一舉連十頭，不復錄魚蝦。", "海物類多毒，惟汝性則佳。", "清水洗病眸，七九爲等差。", "况今咀其肉，課效想更加。", "劉邕最可怪，辛苦剝瘡痂。"]'),
('e5512396-5cfe-4a55-892c-7bd6a8949ac6','食梨','孔平仲','宋','宋诗','song-poetry','','[]','東方早寒雪霜摯，新梨十月已滿市。',149,'全唐诗/poet.song.53000.json','["東方早寒雪霜摯，新梨十月已滿市。", "削成黄蠟圓且長，味甘骨冷體有香。", "芳尊命友先衆果，百十磊砢升君堂。", "贈君玉壺層冰之皎潔，副以金莖皓露之清凉。", "奈何撥火取煨栗，梨雖至美或不嘗。", "顰眉三嚥手摩腹，謂此發病爲第一，奪之兒口餳止哭。", "君不記南方無此物，五更酒渴喚水時，思此千里莫致之。", "及今乃以多見賤，南方橘柚東方梨。"]'),
('89c1d36c-1554-4f3f-9400-0751805f91b1','十月二十一日夜','孔平仲','宋','宋诗','song-poetry','','[]','紞紞有如打兩鼓，星河漫漫參在戶。',176,'全唐诗/poet.song.53000.json','["紞紞有如打兩鼓，星河漫漫參在戶。", "百鳥已棲人不行，西南洶洶有異聲。", "有若鬼神移山嶽，又如戰敗百萬兵。", "出門望見乃火起，椽落瓦裂咫尺鳴。", "問之相去一里間，紅光爍爍侵天明。", "長烟涌波月魄死，其間有物如撒星。", "是時久旱水泉竭，高屋一燎如毛翎。", "小兒但知聚看笑，不知擾擾人縱橫。", "皇皇奔走最可念，耿耿不寢心飛驚。", "明朝出視火起處，焦木頹垣不知數。", "白頭老姥啼向天，嘆息之聲滿行路。"]'),
('889a2ee5-4e46-4c6d-9fe8-d16e1f86c23f','觀馬騎','孔平仲','宋','宋诗','song-poetry','','[]','馬軍上馬挾角弓，東西排列次第同。',64,'全唐诗/poet.song.53000.json','["馬軍上馬挾角弓，東西排列次第同。", "鳴金一敲馳且射，七十二疋如旋風。", "黄塵紛紛有殺氣，得雋呼聲動天地。", "想見陰山血戰時，出沒飛騰千萬騎。"]'),
('8d483ce6-08d2-4c3e-abc2-5d0194bf7f21','會食','孔平仲','宋','宋诗','song-poetry','','[]','學官不置酒，相聚惟一飯。',84,'全唐诗/poet.song.53000.json','["學官不置酒，相聚惟一飯。", "公家事何多，客至日已晚。", "乘饑騁大嚼，美惡寧復揀。", "僕夫無所餘，顧我色不滿。", "潑茶旋煎湯，就火自哄盞。", "從容共談謔，熟視笑而睆。", "昌齡豈其慍，策馬獨先返。"]'),
('126d79fc-1739-4f5d-9fb9-a9cadb1a93bf','集于昌齡之舍','孔平仲','宋','宋诗','song-poetry','','[]','初筵悄無語，良久歡且發。',96,'全唐诗/poet.song.53000.json','["初筵悄無語，良久歡且發。", "就爐自溫杯，覺此飲量闊。", "既觀舞袖垂，又聽歌聲闋。", "醉心漸紛紜，醉眼成恍惚。", "勿輕栢直狗，所負尚可悅。", "當年入績事，今日逼華髮。", "愈令坐客心，感嘆惜時節。", "夜長更恐曉，起挽青天月。"]'),
('b05d0a62-c356-4b53-8a36-71cd25ddc872','常山四詩 迎神','孔平仲','宋','宋诗','song-poetry','','[]','木摵摵兮若有聞，風回回兮吹塵。',47,'全唐诗/poet.song.53000.json','["木摵摵兮若有聞，風回回兮吹塵。", "神之來兮何暮，斗斜月落兮夜將向晨。", "跪捧香兮謹以俟，久注目兮山雲。"]'),
('89fb2fdf-9c10-4f28-9b7b-428dc1642d88','常山四詩 酌神','孔平仲','宋','宋诗','song-poetry','','[]','不敢告勞兮山之盤盤，祀事孔脩兮誠心亦殫。',52,'全唐诗/poet.song.53000.json','["不敢告勞兮山之盤盤，祀事孔脩兮誠心亦殫。", "陳肴羞兮堂下，奠旨酒兮石之間。", "神庶幾兮享此，既醉且飽兮留聽余言。"]'),
('420976bb-686f-4c7d-b602-6ca3ea10b4ad','常山四詩 禱神','孔平仲','宋','宋诗','song-poetry','','[]','歲且大旱兮田事甚荒，疫癘將作兮火菑流行。',60,'全唐诗/poet.song.53000.json','["歲且大旱兮田事甚荒，疫癘將作兮火菑流行。", "循神之名兮其德有常，靈鑒不遠兮照此忱誠。", "出雲洩洩兮靈雨其雱，庶幾此民兮不乏粢盛。"]'),
('6ec3c7cc-3d5b-4a4b-8166-d06b82abe0ba','常山四詩 送神','孔平仲','宋','宋诗','song-poetry','','[]','巫傴僂兮告神將歸，屏息再拜兮儼若初來。',54,'全唐诗/poet.song.53000.json','["巫傴僂兮告神將歸，屏息再拜兮儼若初來。", "神之樂兮游衍，風爲車兮雲爲旂。", "槁者待蘇兮瘠者需肥，自今已往兮余日望之。"]'),
('4e61cf1b-6ef9-4b3e-967d-37df0e0c1d64','大風吟','孔平仲','宋','宋诗','song-poetry','','[]','昨宵月暈大如輪，邪氣來逼金波渾。',64,'全唐诗/poet.song.53000.json','["昨宵月暈大如輪，邪氣來逼金波渾。", "嫦娥怨泣帝所聞，飛符北方起風神。", "聲如驅濤洗陰雲，欲以快意乃自昏。", "紛紛欲盡江南土，散作彌天萬里塵。"]'),
('a0b2b2c3-d6dd-40ae-91d4-09990e7436de','兄長舟次會稽以十月九日發書清江親故以此日遣使仍以十一月十二日同到去歲會稽書清江人亦同日到嘗有詩記其事','孔平仲','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','清江在何處，限以龍王大孤彭浪之險阻，鄱陽彭蠡淮海之波濤。',164,'全唐诗/poet.song.53000.json','["清江在何處，限以龍王大孤彭浪之險阻，鄱陽彭蠡淮海之波濤。", "會稽在何處，錢塘江邊風浪惡，金山寺下黿鼉驕。", "大冬雪霜道路塞，饑年往往多盜賊。", "如何兩處發書日月同，至此亦不差頃刻。", "開緘讀訖更反復，兩處久不通消息。", "丁寧勞問若相見，滿堂歡喜動顔色。", "枝間鵲噪今幾日，總報平安豈非吉。", "年年歲晏享異味，牛狸黄雀并金橘。", "從容進僕問鄉閭，歸心倏起成蕭瑟。"]'),
('48b93fb5-21a7-4e78-b196-47b9be20648f','十一月二十日德音','孔平仲','宋','宋诗','song-poetry','','[]','敕書夜半至，主者不能發。',156,'全唐诗/poet.song.53000.json','["敕書夜半至，主者不能發。", "星辰稍低回，萬里收落月。", "平明宣帝詞，軫慮極慘怛。", "所憂在愆陽，雨澤嗟久竭。", "周王望雲漢，湯后訟女謁。", "又聞泰一馭，已駐黄金闕。", "所至爲福祥，行當掃災孽。", "因茲肆大眚，洗滌如海闊。", "上刑脫窀穸，輕繫弛縲紲。", "生還今可期，向者或長訣。", "讙呼滿行道，感泣有白髮。", "苟非皇恩深，安得汝輩活。", "千城聚和氣，散作連天雪。"]'),
('3693b73a-c120-4c49-b2bb-5fc0612a2bd9','宿澇澤','孔平仲','宋','宋诗','song-poetry','','[]','出城雲物好，更聽歌聲發。',36,'全唐诗/poet.song.53000.json','["出城雲物好，更聽歌聲發。", "行路已微陰，暮村逢霰雪。", "衾寒不成寐，奄奄殘燈滅。"]'),
('b6530260-27cf-4187-9174-860f511f9730','召伯水落','孔平仲','宋','宋诗','song-poetry','','[]','朝落一寸水，暮落一寸水。',48,'全唐诗/poet.song.53000.json','["朝落一寸水，暮落一寸水。", "卷水去入湖，更值南風起。", "舟行意雖急，滯礙乃如此。", "矗矗在吾前，千艘正銜尾。"]'),
('b5f1c1f6-66a9-4ba9-b043-be78d0141a84','舟行却回','孔平仲','宋','宋诗','song-poetry','','[]','清晨移舟出沙嘴，宿氛卷盡天如洗。',212,'全唐诗/poet.song.53000.json','["清晨移舟出沙嘴，宿氛卷盡天如洗。", "日高五丈行十里，白雲之中黑雲起。", "回舟急趨舊泊處，四山沉沉日色死。", "逆風颯颯初尚微，浪頭已高白參差。", "又聞西北崩崖陷谷有異聲，大風橫擊波如鱗。", "操舟之子雖習貫，掣柁才開又投岸。", "有如磁石引針去，時時颭撲愁中斷。", "長篙勁艣不易勝，僅得入口如再生。", "迴望後舟尚出沒，使人淚落肝膽驚。", "昨日廟中奠旨酒，巫語甚吉許我行。", "奈何中路輒反覆，欺誕何者爲神明。", "豈非風者天號令，必欲逆知非汝能。", "浪傳消息得醉飽，萬一猶足爲威靈。"]'),
('5675e9ca-5104-48b6-9b36-1a4e1d19335f','長蘆詠蝗','孔平仲','宋','宋诗','song-poetry','','[]','飛蝗乎，飛蝗乎，誰使汝爲飛蝗，而如此之孽也。',246,'全唐诗/poet.song.53000.json','["飛蝗乎，飛蝗乎，誰使汝爲飛蝗，而如此之孽也。", "一氣所生乃自然，百蟲之中何爲者。", "若歲大旱汝則多，人雖畏之可奈何。", "來時漫不見首尾，往往蔽日連數里。", "河南却集河北岸，東村西村鬧如螘。", "捕逐百千才十一，入地如錐又生子。", "山林所過爲一空，萬口颯颯如雨風。", "稻粱黍稷復何有，田疇已盡腹未充。", "農夫去歲望得雪，千耦輩作乘春發。", "耕耘喜及苗已長，與汝何冤乃遭齧。", "忍見深冬瘦如腊，徵賦繁興蓄積缺。", "我有薄田在江州，五歲之中三不收。", "流災得無及彼土，搏手安敢期高秋。", "陰陽調和非我事，凍餒逼迫同民憂。", "有生所往隨有累，不及飲啄波中鷗。"]'),
('efd93dc4-6b65-429f-9be6-6cd3d604d36c','金陵觀雨','孔平仲','宋','宋诗','song-poetry','','[]','丞相初下車，憂勤到南畝。',108,'全唐诗/poet.song.53000.json','["丞相初下車，憂勤到南畝。", "旱乾爲祈禱，甘雨輒盈缶。", "氣從鍾山發，浪入秦淮吼。", "奔騰與擺蹙，執熱復何有。", "我時在舟中，清爽浮戶牖。", "垢衣得浣濯，快意一搔首。", "深宵對明月，滅燭坐更久。", "昨日見投龍，于今慰枯朽。", "至誠必有答，况乃調元手。"]'),
('89c5f739-6ffc-429d-8b51-359f61459d09','觀暴','孔平仲','宋','宋诗','song-poetry','','[]','怒雷殷殷西南天，黑氣一抹如長烟。',128,'全唐诗/poet.song.53000.json','["怒雷殷殷西南天，黑氣一抹如長烟。", "鯨噓鼇噫蛟吐涎，龍呼其儔相後先。", "散爲飛雲蓋蜿蜒，以尾卷海洒百川。", "河伯乃在坎底眠，震驚掉動憂不全。", "白浪湧起高于船，岡馳隰舞山回旋。", "崩衝擺落蔚高騫，聲勢烈烈孰使然。", "須臾寂靜又改前，餘氛倚漢猶青玄。", "小蝦奮頭如自賢，神龍歸宮魚出泉。"]'),
('9841f654-fb8d-457d-a523-0623764ae927','太平','孔平仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江卷波作沙色，中有數頃如潑墨。',128,'全唐诗/poet.song.53000.json','["長江卷波作沙色，中有數頃如潑墨。", "是爲望夫之高山，沉沉影落江心黑。", "操篙下探不見底，側行牽挽難爲力。", "疾風爲我西北來，打鼓張帆何快哉。", "百夫呼噪絕水府，心膽壯敵山崔嵬。", "須臾已入大信口，回聽怒浪聲如雷。", "姑孰堂前溪水清，扁舟夜泊已三更。", "微微雨過有秋意，漠漠雲開對月明。"]'),
('8a5e4758-7974-4ffb-acba-7b94d9c43f33','觀牛渡江','孔平仲','宋','宋诗','song-poetry','','[]','荷蓑而騎彼牧童，驅牛亂流江水中。',115,'全唐诗/poet.song.53000.json','["荷蓑而騎彼牧童，驅牛亂流江水中。", "徐行不復用鞭箠，母當其前犢後從。", "濁波沄沄出頭角，見者往往疑蛟龍。", "牛身千鈞水不測，步步乃與丘陵同。", "天機自然有所解，物理如此誰能窮。", "君不見軋犖山腹垂至膝，一馬不能載其躬。", "帝前每作胡旋舞，翩翩勁捷如旋風。"]'),
('371c4285-237f-42ad-995c-5f9432c16444','太平','孔平仲','宋','宋诗','song-poetry','','[]','溪行曲入四五里，乃見江城大如斗。',64,'全唐诗/poet.song.53000.json','["溪行曲入四五里，乃見江城大如斗。", "人烟疏少白日靜，風物澄明新雨後。", "古來豪俊多在此，悵望千秋一回首。", "謝家青山空自高，李白扁舟復何有。"]'),
('80489750-c5dd-4f51-ac3f-9db870e26d59','泊舟姑孰堂','孔平仲','宋','宋诗','song-poetry','','[]','崎嶇遵狹港，託庇倚葭蘆。',120,'全唐诗/poet.song.53000.json','["崎嶇遵狹港，託庇倚葭蘆。", "泊舟姑孰堂，乃在溪上居。", "此溪來處遠，東引丹陽湖。", "微風起天外，爽氣得秋初。", "而我尚厭暑，卷簾心不舒。", "蓬頭赤兩脚，躑躅遶四隅。", "坐砌未爲愜，偃身臥碑趺。", "中宵倦摇箑，流汗落衣裾。", "因觀今則然，自問昔何如。", "人情有未足，不見有有餘。"]'),
('6e9280d2-5563-4acf-b6e9-ceecd0923cfe','于將軍','孔平仲','宋','宋诗','song-poetry','','[]','長安遣兵百勝强，意氣何有漢中王。',304,'全唐诗/poet.song.53000.json','["長安遣兵百勝强，意氣何有漢中王。", "七軍之心俱猛鷙，虎兕插羽將翱翔。", "睥睨荆益可席卷，白帝城高如堵牆。", "秣馬蓐食朝欲戰，雷聲殷殷山之陽。", "沉陰苦雨十餘日，漢水溢出高騰驤。", "蒼黄不暇治步伍，攀緣蹙踏半死傷。", "計窮豈不欲奔走，四望如海皆茫茫。", "鼉鳴魚躍尚恐懼，萬一敵至誰敢當。", "遙觀大船載旗鼓，聞說乃是關雲長。", "蒙衝直繞長堤下，勁弩强弓無敵者。", "雖有鐵騎何所施，排空白浪如奔馬。", "將軍拱手就縶縛，咋舌無聲面深赭。", "捷書一日到錦城，隻輪不返皆西行。", "將軍疇昔負朋友，若此昌豨猶得生。", "循環報復雖天意，壯士所惜惟功名。", "曹瞞相知三十年，臨危不及龐明賢。", "歸來頭白已顦顇，泣涕頓首尤可憐。", "高陵畫像何詭譎，乃令慚痛入九泉。", "淯水之師勇冠世，英雄成敗皆偶然。"]'),
('133a0a88-de8f-47cb-963f-ee40f3b2c00c','紫髯將軍','孔平仲','宋','宋诗','song-poetry','','[]','華容女子哭幽囚，吉利如虎入荆州。',209,'全唐诗/poet.song.53000.json','["華容女子哭幽囚，吉利如虎入荆州。", "縛其孤雛斂貔貅，長驅水步八十萬。", "欲獵于吳吳主憂，羣臣勸迎同一說。", "拔刀斫案心膽裂，揆彼之量豈我容。", "開門納狼計何拙，魯家狂兒策最長。", "倡而和者有周郎，區區黄蓋乃乞降。", "龍幡遮火燒赤壁，東南風急天絳色。", "江中戰舸岸上營，烟焰飛騰半焚溺。", "雷鼓大進聲滿川，輕銳迫逐皆崩奔。", "紫髯將軍更歡喜，曹公坐翅不得鶱。", "子布元表何齪齪，成敗之决在一言。", "君不見甘露寶鼎間，典午受禪吳猶存。", "青蓋入洛雖可惜，猶勝俛首臣老賊。"]'),
('82119835-3440-4d23-aa17-b2f08d2ca98b','武宗','孔平仲','宋','宋诗','song-poetry','','[]','武宗惟雄俊，有臣委用專。',228,'全唐诗/poet.song.53000.json','["武宗惟雄俊，有臣委用專。", "德裕才略大，感恩罄所宣。", "是時岩廊上，六合氣可吞。", "論兵决勝負，萬里在目前。", "一平回鶻凶，再洗上黨昏。", "楊弁不知時，迺敢盜太原。", "豈信明光甲，遣人斬其元。", "廷謀昧知幾，唯有君相然。", "成立三大功，慷慨在一言。", "風霆運不測，日月朗高懸。", "李唐勢已去，至此岌復纏。", "外內已息兵，崇卑定乾坤。", "遂令河北師，弭耳如孤豚。", "事書史冊上，讀之快心魂。", "千載若信宿，凜凜風烈存。", "世人多說劍，不見斫伐痕。", "玩弄反自傷，何用飾璵璠。", "迂哉賈生餌，果爾房琯奔。", "施爲貴寔效，詎主衒空文。"]'),
('e8645cae-c013-4796-bb8c-5afe21e62c79','奉天行','孔平仲','宋','宋诗','song-poetry','','[]','蒼蒼行露出苑門，孤城逼仄不可存。',144,'全唐诗/poet.song.53000.json','["蒼蒼行露出苑門，孤城逼仄不可存。", "賊兵之來若風雨，頃刻城下皆雲屯。", "紛紛矢石蔽空黑，天子垂泣對將軍。", "將軍提筆書滿背，城中白丁久奪氣。", "草車之焚雖已矣，雲橋百尺虹蜺起。", "下瞰城中笑飲酒，乾陵赭袍擁朱紫。", "朔方大將來赴急，彷徨中路不敢入。", "豺狼合從堪慟哭，翠華崎嶇又巡蜀。", "聖神文武何至此，堂上有人面如鬼。"]'),
('9a3d70fc-6e80-4fa7-8522-2ea80d672a32','天門山','孔平仲','宋','宋诗','song-poetry','','["\u5929\u95e8\u5c71"]','惟天莽蒼蒼，乃立此門闕。',120,'全唐诗/poet.song.53000.json','["惟天莽蒼蒼，乃立此門闕。", "山本如城高，剖鑿中斷裂。", "兩峰競秀倚，千古勢相戛。", "大江方南來，逼束不得洩。", "潴爲無底深，散作萬頃闊。", "想當割據時，閉固孰敢發。", "夕陽坐荒亭，詩思摹峭拔。", "清晨放舟出，回首見呀豁。", "西梁尚局促，壯觀心頗闊。", "安得呼化工，努力更一揠。"]'),
('25780fb3-689d-4353-b798-2cfc4a2d0fd2','靈壁東','孔平仲','宋','宋诗','song-poetry','','[]','明珠大貝玉玲瓏，美人營營出深宮。',96,'全唐诗/poet.song.53000.json','["明珠大貝玉玲瓏，美人營營出深宮。", "清矑一盼失英雄，羽觴行酒樂未終。", "胡陵殺氣迴飛鴻，投杯擲筯自挽弓。", "麾兵大戰靈壁東，血流爭波入海紅。", "何爲羈孤鐵馬中，搗沙折木天北風。", "突圍而出追失蹤，四五年間蛇作龍。"]'),
('6222d0b4-d818-47aa-8695-a6423ed8ed84','題贛州嘉濟廟祈雨感應','孔平仲','宋','宋诗','song-poetry','','[]','江東禱雨真靈跡，香火未收簷溜滴。',64,'全唐诗/poet.song.53000.json','["江東禱雨真靈跡，香火未收簷溜滴。", "城中到此夜五更，渡口歸時水三尺。", "高田流滿入低田，萬耦齊耕破曉烟。", "但願吾民得飽飯，年年歲歲是豐年。"]'),
('d3134e63-fc5e-4b0b-92d1-b6b7029341b5','答陳君佐戲吟','孔平仲','宋','宋诗','song-poetry','','[]','與君居兩邦，如隔萬里道。',96,'全唐诗/poet.song.53000.json','["與君居兩邦，如隔萬里道。", "相從得旬日，所恨太不早。", "清談已解憂，大笑時絕倒。", "贈我以古風，應手拾瓌寶。", "間亦藏戲言，顧我欲高蹈。", "答之以不答，羨子富文藻。", "滄溟在人外，中有群仙島。", "相約逍遙游，餐霞食瑶草。"]'),
('5ad49c58-eca4-48e4-a44f-43c52d0549b8','游子吟','孔平仲','宋','宋诗','song-poetry','','[]','遠游如飛蓬，漂泊天之涯。',56,'全唐诗/poet.song.53000.json','["遠游如飛蓬，漂泊天之涯。", "不及百尺樓，繫在垂楊堤。", "琉璃爲鍾玉爲斝，繁弦促管花陰下。", "青春此樂輸幾人，客身皇皇一羸馬。"]'),
('8a48e095-afb2-405e-a389-0b4f2b634e1f','汴堤行','孔平仲','宋','宋诗','song-poetry','','[]','長堤杳杳如絲直，隠以金椎密無迹。',64,'全唐诗/poet.song.53000.json','["長堤杳杳如絲直，隠以金椎密無迹。", "當年何人種綠榆，千里分陰送行客。", "波間交語船上下，馬頭揖別人南北。", "日輪西入鳥不飛，從古舟車無斷時。"]'),
('95f27f5d-2ef7-4530-8a9d-83619bc45d01','酒帘','孔平仲','宋','宋诗','song-poetry','','[]','百尺風外帘，常時懸高閣。',48,'全唐诗/poet.song.53000.json','["百尺風外帘，常時懸高閣。", "若誇酒味美，聊勸行人酌。", "但澆愁腸寬，奚畏守犬惡。", "客心方摇旌，逢此慰寂寞。"]'),
('e9acf4e6-e154-4503-b63a-1bd35878e30b','書驛舍壁','孔平仲','宋','宋诗','song-poetry','','[]','巍巍使館開華堂，行人舊題詩滿堂。',115,'全唐诗/poet.song.53000.json','["巍巍使館開華堂，行人舊題詩滿堂。", "去年讀之多好語，今歲重尋在何處。", "驛吏却云官長來，堊以赤白墁青灰。", "銀鈎錯落應手沒，當時嘲謔誰爲才。", "嗚呼萬事祇如此，古人豪强安在哉。", "寄語征途往還客，不如揮毫落金石。", "金石雖堅有時滅，君不聞海波成田淮水絕。"]'),
('75d24ede-63c1-4616-b406-ed3baf008b57','發虹縣','孔平仲','宋','宋诗','song-poetry','','[]','驅馬汴河西，從此游帝鄉。',132,'全唐诗/poet.song.53000.json','["驅馬汴河西，從此游帝鄉。", "瞻言驛堠短，喜及春日長。", "碧瓦映茅茨，人烟密相望。", "蒭茭足供馬，亦有酒可嘗。", "旁觀波瀾起，萬柁攢舟航。", "一跌性命已，豈惟肌骨傷。", "不如榆柳堤，中路穩騰驤。", "去家漸及旬，猶走淮楚疆。", "却視故山隠，忽在天一方。", "東軒復難到，蘭芷媚幽香。", "馳光不可留，游女已採桑。"]'),
('ea187c77-736c-448e-a1af-4f686ce7eebc','水頭','孔平仲','宋','宋诗','song-poetry','','[]','荒灣斗轉河如束，千古癡龍臥空谷。',112,'全唐诗/poet.song.53000.json','["荒灣斗轉河如束，千古癡龍臥空谷。", "公然收水入毫芒，萬里崑崙傾不足。", "春妍睡醒鱗甲開，頃刻已放波頭來。", "衝梢掠操何迅速，噴雲濺雪爭崔嵬。", "舟人傳呼隘兩岸，駭若百蟄逢驚雷。", "連樁繫纜猶恐脫，不爾船碇俱傾頹。", "須臾水面如平掌，客子棹歌船下上。"]'),
('16635739-cbdb-4c77-957e-a8e06890879f','峴山行','孔平仲','宋','宋诗','song-poetry','','[]','驅馬峴山南，磴滑不能上。',24,'全唐诗/poet.song.53000.json','["驅馬峴山南，磴滑不能上。", "惆悵石城人，秋風摇兩槳。"]'),
('ecb53a16-de96-4cab-9426-4fc1f406cd3d','寄王彥昭教授','孔平仲','宋','宋诗','song-poetry','','[]','別君已經年，相見如一日。',168,'全唐诗/poet.song.53000.json','["別君已經年，相見如一日。", "分教淮南生，中路忽相失。", "我志如柳惠，何嘗厭三黜。", "君才如叔夜，猶苦不堪七。", "趣向大抵同，離合何不一。", "輕裝入隋堤，正值柳陰密。", "倉庚交交飛，布穀命其匹。", "壯歲甘遠游，豈暇念家室。", "永城去亳近，馬足翩翩逸。", "我往何時還，君處不能出。", "新詩近應多，爛漫排古律。", "黄花不可見，誰爲子鳴瑟。", "交游固難得，會面那易必。", "作詩寄秋風，以寫胸中鬰。"]'),
('01a682ac-1e31-49a2-897d-d78e5e9390a9','書所見','孔平仲','宋','宋诗','song-poetry','','[]','昂昂林邊鶴，何事不天飛。',72,'全唐诗/poet.song.53000.json','["昂昂林邊鶴，何事不天飛。", "徘徊方塘面，獨啄青苔衣。", "得非戀其傍，修竹垂芳菲。", "高竿擢春秀，清影弄朝暉。", "曾于畫圖見，恍若迷是非。", "興與佳景會，悠然久忘機。"]'),
('93eeab2a-c79a-4e1d-9516-137bac643725','村鼓','孔平仲','宋','宋诗','song-poetry','','[]','潭潭村鼓鳴，羨爾田家樂。',48,'全唐诗/poet.song.53000.json','["潭潭村鼓鳴，羨爾田家樂。", "閃閃綠榆叢，風清如葦籥。", "我懷物外趣，世味久零落。", "焉得太古民，相携去耕鑿。"]'),
('37bf1d9a-d35b-46f6-aa9b-fa8a07624337','酇陽觀棋','孔平仲','宋','宋诗','song-poetry','','[]','繫馬酇陽岸，湍波怒奔霆。',180,'全唐诗/poet.song.53000.json','["繫馬酇陽岸，湍波怒奔霆。", "却坐南軒上，曠若耳目清。", "兩翁方圍棋，玉石相分爭。", "初味若恬淡，鋒交漸縱橫。", "攻南意窺北，翻復乃人情。", "計慮臨危出，或從死中生。", "勇者喜見色，怯者噤無聲。", "誰云一枰小，鬭智亦已精。", "昔有爛柯者，棄俗游崢嶸。", "彼實方外人，歲月固可輕。", "我今則異此，久爲世網嬰。", "一官猶坎軻，三徑尚未耕。", "妻子寄異縣，飄飄望東京。", "寸晷尤可惜，客子當念程。", "飲水上馬去，兩翁任輸贏。"]'),
('984d823e-dd76-4d4a-91b9-34d2a2e57aef','蝴蝶行','孔平仲','宋','宋诗','song-poetry','','[]','蝴蝶飛，渡河來。',48,'全唐诗/poet.song.53000.json','["蝴蝶飛，渡河來。", "河北花已落，河南花正開。", "盈盈採花女，撲打還家去。", "推身飛入粉奩中，芳草綿綿舊時路。"]'),
('da437025-e817-4726-a369-ce3e10342fa0','枯柳','孔平仲','宋','宋诗','song-poetry','','[]','窾枯路傍柳，種插從何年。',124,'全唐诗/poet.song.53000.json','["窾枯路傍柳，種插從何年。", "枯條不可見，人立何巋然。", "輕脆豈耐久，心腹俱空穿。", "上無一鳥巢，下繫萬里船。", "想見方濃時，飛花舞青天。", "行人多攀折，慘淡駐征鞭。", "今也傲突兀，東西過誰憐。", "陋質非焦桐，難試朱絲弦。", "英華餘歲許，白蟻爭回旋。", "雷公飛火試一照，深處恐有乖龍眠。"]'),
('07e932ec-fe95-410b-8ce6-1ecb60cde953','戲寄邵瞻遠','孔平仲','宋','宋诗','song-poetry','','[]','道人養金丹，笑我餐芝朮。',48,'全唐诗/poet.song.53000.json','["道人養金丹，笑我餐芝朮。", "青瞳何皎然，照映冰雪質。", "壺中玉樓好，天外鸞驂逸。", "境清莫回顧，世味甜如蜜。"]'),
('c5f13691-9651-42ff-8b50-80cb7189e0dc','車班班','孔平仲','宋','宋诗','song-poetry','','[]','車班班，入函關。',48,'全唐诗/poet.song.53000.json','["車班班，入函關。", "馬蕭蕭，渡渭橋。", "關下游人不相識，橋邊美酒留行客。", "海闊天高雲滿空，風吹日暮還南北。"]'),
('f0168692-286a-4eec-8bca-79e5e3b98944','發穀熟縣寄揚州同寮','孔平仲','宋','宋诗','song-poetry','','[]','清晨出古縣，獨遇賣花翁。',152,'全唐诗/poet.song.53000.json','["清晨出古縣，獨遇賣花翁。", "芍藥三數朵，瓊苞出漸紅。", "皎如情人未梳洗，朱簾半掩嬌春風。", "去年維揚陪勝賞，此花開謝旬月中。", "名園勝剎處處有，深畦淺壟無西東。", "品流已多搜絕異，若數英俊遺凡庸。", "邇年新花更奇巧，造化彫琢何時窮。", "離家今日已千里，雲雨浩蕩迷淮東。", "而今又及賞花月，因循不賞花更空。", "寄語維揚好相識，花時勉泛黄金鍾。"]'),
('01c7ed5b-99d2-4f07-940d-d2b99021a073','別二友','孔平仲','宋','宋诗','song-poetry','','[]','鶴棲萬年松，孤音夜號霜。',72,'全唐诗/poet.song.53000.json','["鶴棲萬年松，孤音夜號霜。", "雙鳳想其悲，一來助翱翔。", "會合歡未已，離別慘可傷。", "驚風動地起，彼此隨飄揚。", "鶴飛望南山，鳳亦歸故鄉。", "回頭失舊侶，雲路徒蒼蒼。"]'),
('d9e37d72-bf9f-4ce8-ae7b-ff309f5c93f3','東樓置酒賞桃李花','孔平仲','宋','宋诗','song-poetry','','[]','朱樓直瞰清池灣，池上彩翠多奇山。',80,'全唐诗/poet.song.53000.json','["朱樓直瞰清池灣，池上彩翠多奇山。", "春光爛漫桃李發，倒影照映澄波間。", "遠看已好重攀折，堆積金盤霞間雪。", "促拍更歌金縷衣，不辭醉倒花時節。", "歸來酒醒夢闌時，袖上餘香猶未滅。"]'),
('7cd89a51-4304-4a8a-82be-45858de8074a','寄勉甫','孔平仲','宋','宋诗','song-poetry','','[]','猛虎不伏櫪，摶鵬笑韝鷹。',168,'全唐诗/poet.song.53000.json','["猛虎不伏櫪，摶鵬笑韝鷹。", "丈夫志四海，羞愧守門庭。", "君實豪傑士，貧賤鄉人輕。", "憤發策蹇馿，西走游玉京。", "負書入太學，大带參諸生。", "文章逸莫控，學問驟以升。", "曾未年歲餘，譁譁得聲名。", "定知有所立，俯拾紫與青。", "顧我孤陋者，聾瞽其聰明。", "譬如山下泉，礙險尚未行。", "無人爲激進，安得歸滄溟。", "所願同君游，揚波浩東傾。", "此志何日遂，長呼涕淋纓。", "北望風誼美，心焉如旆旌。"]'),
('c083fe20-9bc9-4bed-ad43-9ca23e71616e','落花','孔平仲','宋','宋诗','song-poetry','','[]','嶺南冬深花照灼，比至春初花已落。',64,'全唐诗/poet.song.53000.json','["嶺南冬深花照灼，比至春初花已落。", "乘閒携酒到西園，鳥散蜂歸春寂寞。", "江南此際春如何，紅杏海棠開正多。", "歸期不及春風日，猶見池塘著綠荷。"]'),
('72694ba8-0d05-4015-a371-68ad0d1a6248','送客到江亭','孔平仲','宋','宋诗','song-poetry','','[]','春江碧波渺天去，兩岸紅桃落如雨。',64,'全唐诗/poet.song.53000.json','["春江碧波渺天去，兩岸紅桃落如雨。", "主人到此送行人，落日留連會歌舞。", "渡頭楊柳正依依，拂水摇風千萬絲。", "看看亦整東歸棹，誰折長條贈我歸。"]'),
('c3caf489-9e4d-4d0c-8870-351ac90e6830','剪玫瑰寄晦之仍書此爲戲','孔平仲','宋','宋诗','song-poetry','','[]','去年君嘗寄薔薇，今年我亦寄玫瑰。',112,'全唐诗/poet.song.53000.json','["去年君嘗寄薔薇，今年我亦寄玫瑰。", "薔薇赭赤未足愛，玫瑰瑩白花草魁。", "南園春深桃杏落，但見芳草連莓苔。", "唯茲皎潔滿欄檻，玉冠瑶佩天邊來。", "主人愛惜屢顧眄，賞心未暇携樽罍。", "寄君憑君巧吟咏，仍須對景傾金杯。", "莫令薔薇竊見此，恐遂羞媿不復開。"]'),
('746590aa-aae2-4fbd-b283-0b662bd0a1ef','寄鄒蹇叔','孔平仲','宋','宋诗','song-poetry','','[]','西園春深百草長，殘花紛紛綠葉光。',112,'全唐诗/poet.song.53000.json','["西園春深百草長，殘花紛紛綠葉光。", "蜂歸蝶散情已薄，獨我遶樹行如狂。", "亟令沽酒藉地飲，臥嗅落蕊傾金觴。", "醉來意氣頗脫略，睥睨天地如毫芒。", "狂歌大笑誰對值，山猿谷鳥啼斜陽。", "却思高陽舊徒侶，安得飛至坐我傍。", "登城引望不可見，雲峰古木徒蒼蒼。"]'),
('d8ceb559-af3a-4120-970b-094efbdfb1c9','南卒','孔平仲','宋','宋诗','song-poetry','','[]','坐食者南卒，驕與子弟俱。',120,'全唐诗/poet.song.53000.json','["坐食者南卒，驕與子弟俱。", "負甲則俯僂，荷戈不能趨。", "嘈然金鼓鳴，氣駭失所圖。", "固無一技良，徒有七尺軀。", "吾聞孫子教，弱女成武夫。", "吾欲練汝輩，使之虓虎如。", "奈何天子詔，苦禁蓄兵書。", "軍旅非素習，壯士心踟躕。", "羣蠻屢騷動，主將復左除。", "有急何以報，思之可驚吁。"]'),
('33fe1096-5877-453c-9e7d-a64980b3f50a','夜聞蒼鶴唳','孔平仲','宋','宋诗','song-poetry','','[]','爲鶴不能白，安用蒼其形。',72,'全唐诗/poet.song.53000.json','["爲鶴不能白，安用蒼其形。", "厥頂又不朱，無乃盜虛名。", "雌雄守枯木，絕意沖太清。", "夜號如嬰兒，聒我夢寐驚。", "日欲火其巢，念汝雛方生。", "亟宜罷吻噪，報我存養情。"]'),
('d168f9df-d540-4698-96b2-4d9fd7127764','愍囚','孔平仲','宋','宋诗','song-poetry','','[]','囚豈不樂有父母，囚豈不樂有室家。',64,'全唐诗/poet.song.53000.json','["囚豈不樂有父母，囚豈不樂有室家。", "公行劫掠自取死，迫于窮餓情非它。", "腥膻所得能幾許，哭入東市肩相摩。", "嗚呼法令難力救，囚乎囚乎奈若何。"]'),
('e96b77b3-be5d-4317-9422-6abc38084905','移石','孔平仲','宋','宋诗','song-poetry','','[]','誰言磐石堅，勢不可動摇。',48,'全唐诗/poet.song.53000.json','["誰言磐石堅，勢不可動摇。", "健犢引大車，載行速如飄。", "良因植根淺，未免遷徙勞。", "觸類當自省，我今慎所操。"]'),
('1dbb28b2-ff58-4810-a048-43b10fd06764','春夕寄兄長','孔平仲','宋','宋诗','song-poetry','','[]','南北萬里道，兄弟隔年別。',48,'全唐诗/poet.song.53000.json','["南北萬里道，兄弟隔年別。", "嬉鸞雙翱翔，病馬隻羈紲。", "友關危坐久，顧影愁腸絕。", "清夜不可晨，吟殘半窗月。"]'),
('01ad7488-c21e-4e88-8b3d-48a5ec7ce369','養虎','孔平仲','宋','宋诗','song-poetry','','[]','西鄰養虎已被齧，東鄰養虎計何拙。',64,'全唐诗/poet.song.53000.json','["西鄰養虎已被齧，東鄰養虎計何拙。", "哺之既久爪牙强，定看一日難羈紲。", "寄語東鄰宜早圖，野心變態在須臾。", "壯士匣中有神劍，欲斬虎頭君許無。"]'),
('9baeacda-59a0-482b-bd64-04e4b1a01cdc','折楊柳','孔平仲','宋','宋诗','song-poetry','','[]','江頭楊柳春依依，主人此時傷別離。',64,'全唐诗/poet.song.53000.json','["江頭楊柳春依依，主人此時傷別離。", "留連祖席日欲晚，風弄綠影摇金巵。", "手攀長條贈君歸，紛紛閒愁如絮飛。", "人生聚散似魚雁，此柳春深有幾枝。"]'),
('ae0d5752-7ec2-4ee3-bcaa-1813efdf08bd','王昭君','孔平仲','宋','宋诗','song-poetry','','[]','昭君十五入漢宮，自倚花艷如芙蓉。',160,'全唐诗/poet.song.53000.json','["昭君十五入漢宮，自倚花艷如芙蓉。", "黄金不買畫者筆，西子變作嫫女容。", "羊車忽略久不幸，夜夜月照羅帷空。", "嬌癡怨恨掩袂泣，常恐蘭蕙摧霜風。", "不堪坐守寂寞苦，遂願將身嫁胡虜。", "神仙縹緲下朝陽，再拜玉墀辭漢主。", "天顔驚顧初相識，自起欲留留不得。", "吁嗟拂袖歸禁中，却看飛燕無顔色。", "嬋娟去去陰山道，幾日風沙貌枯槁。", "千秋萬古恨無窮，墳上春風無寸草。"]'),
('f5d9177d-632f-4fd9-8291-4ba0c11d1445','春日行','孔平仲','宋','宋诗','song-poetry','','[]','鶑啼花笑清明天，黄金買酒斗十千。',64,'全唐诗/poet.song.53000.json','["鶑啼花笑清明天，黄金買酒斗十千。", "良時恣意一酩酊，醉倒扶起南堂眠。", "須臾更深殘酒醒，明月當窗風氣冷。", "閒愁萬緒從中來，幾欲長號淚如綆。"]'),
('11b5e8ad-d457-4be3-940f-57cf45af6481','子夜四時歌 春','孔平仲','宋','宋诗','song-poetry','','[]','二月春色來，三月春色老。',24,'全唐诗/poet.song.53000.json','["二月春色來，三月春色老。", "東風收花去，滿地留芳草。"]'),
('a73bce8f-70a4-4e28-8b4a-f35fcd1454bb','子夜四時歌 夏','孔平仲','宋','宋诗','song-poetry','','[]','火雲堆長空，赤日沸岩瀑。',24,'全唐诗/poet.song.53000.json','["火雲堆長空，赤日沸岩瀑。", "芙蓉已焦死，不減篔簹綠。"]'),
('92e613b0-f918-41e3-8765-de6711293ada','子夜四時歌 秋','孔平仲','宋','宋诗','song-poetry','','[]','慘淡秋雲高，蕭瑟西風起。',24,'全唐诗/poet.song.53000.json','["慘淡秋雲高，蕭瑟西風起。", "坐感歲華遷，悲歌淚如水。"]'),
('a1a2ef45-4689-416a-a32a-4443f920fd59','子夜四時歌 冬','孔平仲','宋','宋诗','song-poetry','','[]','風凄薄愁雲，雨冷成飛雪。',24,'全唐诗/poet.song.53000.json','["風凄薄愁雲，雨冷成飛雪。", "莫作苦寒吟，行行桃李月。"]'),
('c26fdf1c-bef8-46cb-ad3d-bf144c8962fa','和經父秋夕','孔平仲','宋','宋诗','song-poetry','','[]','爽籟愛蟲吟，凄音悲漏永。',48,'全唐诗/poet.song.53000.json','["爽籟愛蟲吟，凄音悲漏永。", "青燈無定焰，照此心情冷。", "風生蕙帳寒，月滿松窗靜。", "萬慮歸寂寥，都忘榮辱境。"]'),
('a343b2e5-8d01-4d10-afd3-cb7a6c3b17a0','次韵常父二十九日閘上作','孔平仲','宋','宋诗','song-poetry','','[]','泊舟不厭城南淺，談笑淹留驚晷短。',80,'全唐诗/poet.song.53000.json','["泊舟不厭城南淺，談笑淹留驚晷短。", "爲傳潮信艤江干，暫移已覺如天遠。", "足音來此慰寂寞，酒面自紅爐自暖。", "預愁會合有暌離，人事猶如月虧滿。", "何如便賦歸去來，百尺高帆席同卷。"]'),
('3c2bd127-196c-4cdf-a064-89908de58414','招常父承君舟中觀雪','孔平仲','宋','宋诗','song-poetry','','[]','泊舟亭下水，隔岸有脩竹。',36,'全唐诗/poet.song.53000.json','["泊舟亭下水，隔岸有脩竹。", "晨起雪紛紛，開簾見群玉。", "請來同此景，一醉杯中綠。"]'),
('2e40c266-f842-490a-b026-60ec3425b69a','發儀真寄常父兄','孔平仲','宋','宋诗','song-poetry','','[]','丱角同出處，中路稍差池。',180,'全唐诗/poet.song.53000.json','["丱角同出處，中路稍差池。", "往事如一夢，新年生白髭。", "小官仍齟齬，異國更羈棲。", "長時恨隔闊，既見少開眉。", "朝共壚邊飲，暮同窗下棋。", "一日復一日，眷眷不忍離。", "今茲解舟去，豈爲赴同期。", "久住恐相溷，蕭然生事微。", "欲將眼中淚，一灑別時衣。", "諸緒正牢落，勿令心重悲。", "融怡和笑語，惝怳迷東西。", "甘言戒婢子，循髮祝阿宜。", "憒憒情懷惡，正同中酒時。", "晚泊蘆荻岸，江天雲四垂。", "高城已不見，春雨更如絲。"]'),
('4a306617-3e5c-454f-b77a-d3924b259bf9','二十二日大風發長蘆','孔平仲','宋','宋诗','song-poetry','','[]','張帆風尚小，出口勢愈急。',276,'全唐诗/poet.song.53000.json','["張帆風尚小，出口勢愈急。", "扁舟已中流，前後無所及。", "側看岸旋轉，白浪若山岌。", "磔砉時有聲，百罅水爭入。", "危檣聽欲折，柁柄脫操執。", "我有常病妻，素羸多不粒。", "及茲益憒亂，臥喘氣吸吸。", "婢姥半北人，茲險未嘗習。", "蒼皇面深墨，嘔噦皆膽汁。", "可憐兒女輩，往往相聚泣。", "出門强指揮，飛沫濺衣濕。", "江豚踴吾前，猵獺作人立。", "意如驁吾嚱，出沒相百十。", "呼神擲楮泉，祈佛啟經襲。", "是時正月尾，於節甫驚蟄。", "雲氣作冥晦，氣候變寒澀。", "日中僅得止，性命危若拾。", "紛然方寸亂，魂幹久不集。", "官期幸未迫，安用苦汲汲。", "官兵勇貪程，一震當少戢。", "何如彼居民，生不出井邑。", "吾田雖曠瘠，飦粥粗可給。", "勞生嘿自慨，茅舍行且葺。"]'),
('8f0a3423-bd1c-4644-9260-02a7c00e01e5','讀江淹集','孔平仲','宋','宋诗','song-poetry','','[]','煌煌一疋錦，爛爛五色筆。',120,'全唐诗/poet.song.53000.json','["煌煌一疋錦，爛爛五色筆。", "始從何處得，悵此夢中失。", "淹也雖善文，葳蕤少筋骨。", "譬人氣不深，往往多奄忽。", "晚年既富貴，外學仍老佛。", "豈非有所怠，寖使天才屈。", "奈何不自尤，秘怪疑鬼物。", "我有十文舟，夙期駕溟渤。", "褰霞謁東皇，擘浪窺月窟。", "唯憂倦或止，視此頗自栗。"]'),
('583ec2f5-5e6f-4f67-8d40-f7138122ef2a','馬當夾阻風','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蒿田荻野無人烟，我來日暮雙繫船。',226,'全唐诗/poet.song.53000.json','["蒿田荻野無人烟，我來日暮雙繫船。", "半夜星斗垂欄干，銀河倒影摇清川。", "人言神物當會合，鐵纜纏繞安如山。", "五更洶洶有聲至，車騎蹴踏乾坤翻。", "怒雷殷殷雨隨下，黑風三日不見天。", "此中道路多險惡，正在馬當小孤之兩間。", "三江五湖所鍾聚，直下無底旁無邊。", "掀騰擺觸作意氣，更無拘束隨所便。", "巨磯突若虎頭出，黄沙莽作車輪旋。", "端居不動尚股栗，誰敢身試蛟龍淵。", "自吾汎洛涉淮泗，間關淫滯今半年。", "廬山蒼翠已在目，毋用急進干憂患。", "不如宿留會澄霽，淹速有數非偶然。", "篘中酒熟聊一醉，春夢酣酣牽晝眠。"]'),
('c64d28f0-a054-4ce5-9c70-14db129d99c8','初夏','孔平仲','宋','宋诗','song-poetry','','[]','初夏新雨餘，蕭然風轉北。',72,'全唐诗/poet.song.53000.json','["初夏新雨餘，蕭然風轉北。", "芭蕉索索鳴，庭戶有秋色。", "清寒思挾纊，向暑袗絺綌。", "陰陽孰主張，變態只頃刻。", "幽軒暮支頤，佳趣生靜默。", "雲氣薄南山，坐令蒼翠隔。"]'),
('6f705c56-03f3-4516-ba2f-55756f4c7df0','喜雨','孔平仲','宋','宋诗','song-poetry','','[]','低田有水高田乾，南風日日吹塵土。',96,'全唐诗/poet.song.53000.json','["低田有水高田乾，南風日日吹塵土。", "新秧已生未種得，此時却得彌天雨。", "連山蔽空望不極，溢徑盈庭勢漂鹵。", "從今歲事當有成，飽喫香秔胡可數。", "老來涉世心益懶，只欲棲遲守環堵。", "若令積穀支歲年，便可終焉事農圃。"]'),
('1f8721b9-d26f-474a-9b1e-cdfd3dddf633','鑄錢行','孔平仲','宋','宋诗','song-poetry','','[]','三更趨役抵昏休，寒呻暑吟神鬼愁。',64,'全唐诗/poet.song.53000.json','["三更趨役抵昏休，寒呻暑吟神鬼愁。", "從來鼓鑄知多少，銅沙疊就城南道。", "錢成水運入京師，朝輸暮給苦不支。", "海內如今半爲盜，農持斗粟却空歸。"]'),
('53b9915f-65aa-44b4-a809-8bc8b405cd6f','呈范清老','孔平仲','宋','宋诗','song-poetry','','[]','范子愛高臥，家政付兒孫。',120,'全唐诗/poet.song.53000.json','["范子愛高臥，家政付兒孫。", "將身比瞑目，達理吾所尊。", "前日過所居，蔓草深閉門。", "范子欠伸起，性寡笑與言。", "相與尋幽寺，復將坐前軒。", "斜陽滿庭下，不厭鳥雀喧。", "擘雲青山秀，經雨野水渾。", "念此景清曠，非君誰與論。", "少年一傾蓋，白首義彌敦。", "頹然各忘返，明月照黄昏。"]'),
('f60c2e0e-c73d-418e-b5fb-484523f81827','曹亭三絕句  其一','孔平仲','宋','宋诗','song-poetry','','[]','外看江水長，裏見荷花發。',24,'全唐诗/poet.song.53000.json','["外看江水長，裏見荷花發。", "廬阜收白雲，南浦浸明月。"]'),
('e58b8918-847b-44e0-8f75-19f31b30134d','曹亭三絕句  其二','孔平仲','宋','宋诗','song-poetry','','[]','漾舟荷花裏，艤棹綠楊陰。',24,'全唐诗/poet.song.53000.json','["漾舟荷花裏，艤棹綠楊陰。", "却上曹亭望，山高江水深。"]'),
('e7795653-6958-46ea-8e9c-d4bcb133fd2f','曹亭三絕句  其三','孔平仲','宋','宋诗','song-poetry','','[]','登臨常患遠，游覽不能繼。',24,'全唐诗/poet.song.53000.json','["登臨常患遠，游覽不能繼。", "此景對門牆，箯輿日三四。"]'),
('28cd3b3c-1675-4ae0-97b5-b8d4f18dc6cc','夜入監中','孔平仲','宋','宋诗','song-poetry','','[]','欹枕汗如洗，出門更已深。',72,'全唐诗/poet.song.53000.json','["欹枕汗如洗，出門更已深。", "長風萬里至，河漢清人心。", "芙蕖有佳氣，楊柳摇疏陰。", "秋聲繁促織，月色動棲禽。", "落魄衣忘带，逍遙髮懶簪。", "聽從凉冷入，一快直千金。"]'),
('d0c95523-9017-4128-a8db-1fe0013c1f9d','七月六日作','孔平仲','宋','宋诗','song-poetry','','[]','隔江見雨來，尤苦風大疾。',144,'全唐诗/poet.song.53000.json','["隔江見雨來，尤苦風大疾。", "蓬蓬宇宙中，掀攪若無物。", "百川水倒流，瓦石亦飛越。", "濃雲最輕浮，暫聚非永結。", "隨吹東西揚，散漫頗倉猝。", "竟無點滴惠，初勢不可遏。", "正昏露青天，方曀見白日。", "但增塵土高，益使水泉竭。", "農夫憂歲事，悵望眼流血。", "蛟龍不能神，卷尾藏窟穴。", "空餘鳥雀噪，庭戶晚更熱。", "深夜氣稍蘇，林端挂明月。"]'),
('a521c33e-c489-4157-87d3-9ef649ad127c','暇日至家園','孔平仲','宋','宋诗','song-poetry','','[]','仕宦吾已知，退休不如早。',120,'全唐诗/poet.song.53000.json','["仕宦吾已知，退休不如早。", "九江園地勝，萬个竹色好。", "每到必徘徊，翛然寄懷抱。", "于此築亭臺，於彼植花草。", "傍嶺更栽松，引池將溉稻。", "經營各有處，何日室遂考。", "薄田方待歲，一雨洗枯槁。", "指穀以易泉，橐囊助傾倒。", "茅茨若粗完，世路迹可埽。", "南山多白雲，臨望娛我老。"]'),
('19e4199d-b971-402f-8ec1-5412ef266054','城東作','孔平仲','宋','宋诗','song-poetry','','[]','九江非吾土，久寓忘羈棲。',168,'全唐诗/poet.song.53000.json','["九江非吾土，久寓忘羈棲。", "丘墳之所宅，舍此亦安歸。", "錢官最閒暇，因得治其私。", "松楸鬰在望，時復至郊圻。", "駕言上東原，藹藹晨露晞。", "草木新過雨，秀色可療饑。", "念此道旁民，散居在山蹊。", "新秋百物熟，入城各有携。", "芋迸紫卵壯，薑抽紅笋肥。", "欓香憶烹鯉，稻白想流匙。", "養生無不有，美味仍及時。", "此土遂可老，行當結茅茨。", "雲水有深約，塵埃無盡期。", "人生適意耳，富貴亦何爲。"]'),
('8fba7647-ed2e-435c-bc09-bb574f5d4f4e','月夜','孔平仲','宋','宋诗','song-poetry','','[]','平生最好月，况此秋夜闌。',132,'全唐诗/poet.song.53000.json','["平生最好月，况此秋夜闌。", "長風送蕩漾，浩露洗團團。", "仰頭視虛空，光采如可餐。", "星辰斂芒角，河漢收波瀾。", "更無微雲翳，挂此白玉盤。", "六合靜皎皎，萬木凉珊珊。", "爲爾廢昏臥，徘徊更漏殘。", "更登高處望，歷歷見湖山。", "爽氣集冰雪，清心生羽翰。", "便欲御泠然，因之游廣寒。", "一臨天池水，沐浴隨飛仙。"]'),
('ff9f2751-5eb9-46e1-a1c9-7ecab2a26fdb','送鄭君玉','孔平仲','宋','宋诗','song-poetry','','[]','西風黄葉下，送子以秋色。',48,'全唐诗/poet.song.53000.json','["西風黄葉下，送子以秋色。", "彭蠡一歸舟，關山遠行客。", "民思似秤平，郡戴如弦直。", "交游亦難值，出語皆肝膈。"]'),
('532e2b55-0779-4db0-9fdd-4dfb32e0ee23','出城一首','孔平仲','宋','宋诗','song-poetry','','[]','驅馬出北門，秋色滿平皋。',96,'全唐诗/poet.song.53000.json','["驅馬出北門，秋色滿平皋。", "泄雲弄微陰，寒日照我袍。", "遵途升復降，控縱亦已勞。", "落松被徑軟，青蒿倚崖高。", "南顧臨大江，厲風蔚波濤。", "蛟龍正崛强，舟楫未易操。", "亦有泝洄人，揚帆氣方豪。", "覆舟諒由險，豈曰命所遭。"]'),
('956006a2-a262-4000-b81c-f82e0ddcb50a','九日獨登曹亭','孔平仲','宋','宋诗','song-poetry','','[]','重陽不見菊，節物愈凋零。',168,'全唐诗/poet.song.53000.json','["重陽不見菊，節物愈凋零。", "性復不嗜飲，對酒只如酲。", "秋堂靜便臥，既起思殊清。", "登高未免俗，亦不造林坰。", "屋西連郡郛，木末乃曹亭。", "杖藜只獨往，坐對南山青。", "蕭瑟西風高，泱漭滯雨晴。", "斷雲見天色，殘潦知地形。", "遙峰落照斂，別浦暝烟生。", "歸鳥向村急，孤舟當渡橫。", "此時有佳興，乃惡聞人聲。", "况令預尊俎，而使聽竽笙。", "嗟吾趣尚僻，取笑世上英。", "豈宜濫簪紱，但可老柴荆。"]'),
('4e2a84bd-4e88-4bc8-85ae-d870b19bfc1d','寄常父','孔平仲','宋','宋诗','song-poetry','','[]','愁霏久不霽，翳此白日光。',228,'全唐诗/poet.song.53000.json','["愁霏久不霽，翳此白日光。", "陰風薄庭柯，落葉墮我旁。", "蕭條秋氣高，百感攪中腸。", "側觀南飛雁，肅肅尚有行。", "念昔來此土，弟晜各康彊。", "二季皆鸑鷟，梧桐殞朝陽。", "踟躕故所游，墟墓草已荒。", "會合須臾期，去日一何長。", "吾兄近仳別，咫尺非異方。", "官守畏簡書，羈絆不得驤。", "如星限河漢，東西但相望。", "江魚肥可薦，庭菊粲以芳。", "崢嶸時節晚，誰與共一觴。", "伯氏副邊城，苦寒天早霜。", "石火雖云煖，不如還故鄉。", "群飛隘霄極，弱羽因飄揚。", "祿薄未足飽，胡爲久皇皇。", "古人有三高，彼豈悅膏粱。", "願言同斯志，畢景事耕桑。"]'),
('bdc4cfa6-b422-462c-be61-f27ecfd62f29','九月二十九夜作','孔平仲','宋','宋诗','song-poetry','','[]','江城月黑風雨寒，四無人聲夜向闌。',64,'全唐诗/poet.song.53000.json','["江城月黑風雨寒，四無人聲夜向闌。", "有鳥九頭天外過，嚶嚶軋軋鳴悲酸。", "吹燈滅燭小兒怖，犬呼其鄰嘷且怒。", "天明日出百怪消，長空蹤跡無尋處。"]'),
('8ae40cf7-5187-4cb6-ba38-dd2e1e505e9b','堂前皂筴樹','孔平仲','宋','宋诗','song-poetry','','[]','堂前皂筴樹，落葉已如積。',96,'全唐诗/poet.song.53000.json','["堂前皂筴樹，落葉已如積。", "籬上牽牛花，青青照秋色。", "四序都幾何，推遷半陳迹。", "晝短夜益長，晴薄陰易得。", "浮雲忽以興，慘慘風自北。", "便有挾纊心，人誰顧絺綌。", "饑蚊爾胡爲，乃欲長肉食。", "翼翅不能舉，自此且衰息。"]'),
('106d1e10-bedb-486e-84c7-a7e8b2c024bc','朱君以建昌霜橘見寄報以蛤蜊','孔平仲','宋','宋诗','song-poetry','','[]','贈我以海昏清霜之橘，報君以淮南紫脣之蛤。',84,'全唐诗/poet.song.53000.json','["贈我以海昏清霜之橘，報君以淮南紫脣之蛤。", "橘膚軟美中更甜，蛤體堅頑口長合。", "開花結子幸採摘，沒水藏泥豈蘄得。", "二物同時有不同，賦形與性由天公。", "請君下筯聊一飽，莫索珠璣向此中。"]'),
('fb0510f6-4198-43e8-9b6f-25608cdb139f','冬日久雨有懷保德','孔平仲','宋','宋诗','song-poetry','','[]','陽洩已氤氳，陰疏不凝結。',48,'全唐诗/poet.song.53000.json','["陽洩已氤氳，陰疏不凝結。", "可憐終日雨，總是連天雪。", "雖貧布衣煖，尚欲應時節。", "坐想大河東，苦寒山石裂。"]'),
('7828efba-cf6b-4843-94fd-c3bc29678b27','小庵詩','孔平仲','宋','宋诗','song-poetry','','[]','甃石爲道，旁植冬青不死之靈草。',154,'全唐诗/poet.song.53000.json','["甃石爲道，旁植冬青不死之靈草。", "跨水爲橋，上有百年老木之清陰。", "小庵又在北牆北，花竹重重深更深。", "公餘竟日無一事，卜此佳趣聊棲心。", "明月爲我遲遲不肯去，清風爲我淅淅生好音。", "闃然宴坐如澗谷，樂以真樂非絲金。", "君看此庵亦何有，架竹編茅容側肘。", "人生自足乃有餘，不羨簷牙切星斗。", "朝携一筇杖，暮炷一爐香。", "悠然每獨笑，物我兩皆忘。"]'),
('72c2d22c-3601-4f6b-a20c-74f0f19104ab','元豐三年十一月施君發之縣丞艤舟潯陽出所收書相示好之篤蓄之多裝裱之妙可尚也詩以記其事','孔平仲','宋','宋诗','song-poetry','','[]','發之之舟繫湓水，示我名書百餘紙。',96,'全唐诗/poet.song.53000.json','["發之之舟繫湓水，示我名書百餘紙。", "自言此乃十之一，訪尋藏蓄尚未已。", "裝褫卷襲皆精緻，從前所見無此比。", "城荒俗陋誰與游，如君好事固可喜。", "天寒手冷不厭觀，似我賞音知有幾。", "自今有得當助君，不憚緘封寄千里。"]'),
('5b8b7ed0-f460-4a2d-ae35-99adfa6370f3','夜坐菴前','孔平仲','宋','宋诗','song-poetry','','[]','人定鳥栖息，菴前聊倚欄。',96,'全唐诗/poet.song.53000.json','["人定鳥栖息，菴前聊倚欄。", "徘徊明月上，正在脩篁端。", "清影冰玉碎，疏音環佩寒。", "翛然耳目靜，覺此宇宙寬。", "人生甘物役，汩沒紅塵間。", "宴坐得俄頃，境幽心已閒。", "諒能長無事，自可駐朱顔。", "所以學道人，類多隠深山。"]'),
('e5553e10-934d-4ce2-be96-ef835ce3378f','杜令無隠亭賞梅','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','梅生要孤高，故在城顛上。',80,'全唐诗/poet.song.53000.json','["梅生要孤高，故在城顛上。", "臘過已多時，花寒猶未放。", "正前乃廬山，積雪千萬丈。", "開樽望崢嶸，酒面已遲上。", "直須玉蕊十分開，洗盡烟嵐春氣回。", "請君掃地更招客，爲君對花卷大白。"]'),
('cc0d01c7-c43a-4bed-9898-230f5da3663b','晚興','孔平仲','宋','宋诗','song-poetry','','[]','春雪弄微陰，晚色連細雨。',48,'全唐诗/poet.song.53000.json','["春雪弄微陰，晚色連細雨。", "皂角芽已長，瑞香花欲吐。", "雖寒亦料峭，稍霽即和煦。", "園林擬杖策，芳物行可數。"]'),
('8b1ac317-8615-41dd-9445-a6e58a6794a5','上元作','孔平仲','宋','宋诗','song-poetry','','[]','春來霧雨久不收，上元三日月如秋。',160,'全唐诗/poet.song.53000.json','["春來霧雨久不收，上元三日月如秋。", "傾城娛樂競沽酒，舊歲豐登仍足油。", "樓前燈山燒荻火，光影動摇桑落洲。", "太守憑高列歌吹，游人烘笑觀俳優。", "銅盤貯梅插烏帽，從兵小史斥下樓。", "侍觴行食皆官妓，目眙不言語或偷。", "短長赤白皆莫校，但取一笑餘何求。", "譬如飲酒且爲樂，不問甘苦醉即休。", "歸來紞如打五鼓，春寒慘慘吹駝裘。", "群兒嬉戲尚未寢，更看紫姑花滿頭。"]'),
('5cbad414-f49c-4671-9433-7a786d431abf','送張天覺','孔平仲','宋','宋诗','song-poetry','','[]','車上不須舞，途窮不須泣。',136,'全唐诗/poet.song.53000.json','["車上不須舞，途窮不須泣。", "萬事倏忽如疾風，莫以乘車輕戴笠。", "愛君清，如玉立。", "愛君直，朱弦急。", "膽肝磊落貯星斗，意氣軒騰脫羈縶。", "聖明天子聚羣材，下至椽杙猶收拾。", "况君屢薄青雲飛，暫爾低回豈長蟄。", "我亦區區有心者，海水期君更注挹。", "蕭蕭江路澀，烟濛客帆濕。", "惜君又作千里行，欲別還留手重執。"]'),
('5a69a646-0e5f-4422-b544-d7d4d6eee1a3','出城至太平將見熊伯通','孔平仲','宋','宋诗','song-poetry','','[]','兩松闢爲門，前見青山橫。',108,'全唐诗/poet.song.53000.json','["兩松闢爲門，前見青山橫。", "坡陀若相接，宛轉疑有情。", "日出鳥呼樂，春歸林翠明。", "問我何所往，行當造殊庭。", "紫微有仙客，住在泉石清。", "咫尺久不覿，渺如隔蓬瀛。", "今將往見之，先已耳目醒。", "願聞直截義，庶使正覺成。", "紛紛焉足道，無使一塵生。"]'),
('2dd7f3ce-9c32-4b8a-b7a8-72e7fcbf8d55','詩贈王從善','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廣庭試群材，俊筆馳短晷。',192,'全唐诗/poet.song.53000.json','["廣庭試群材，俊筆馳短晷。", "鎖廳爭第一，乃後二三子。", "騎龍失頭角，十載困泥滓。", "泛舟自淮南，得邑窮楚尾。", "江上始相逢，清名久吾耳。", "油然睹顔色，悅澤已可喜。", "博學有淵源，高談見根柢。", "有如萬斛鍾，久叩聲益起。", "如君豈易得，蹭蹬乃在此。", "棫樸析爲薪，奈何遺杞梓。", "我本世畸人，儳焉頑似鄙。", "一官傍松楸，自足勝朱紫。", "功名已灰心，藜藿思沒齒。", "欲結方外遊，徜徉訪雲水。", "聞君亦有意，不戀五斗米。", "笑指廬山高，論交從此始。"]'),
('dba7f515-1485-4ffa-89e4-3adb997cf32b','春暄大旱率爾援筆','孔平仲','宋','宋诗','song-poetry','','[]','去歲有閏既苦寒，今年春早亦大暄。',112,'全唐诗/poet.song.53000.json','["去歲有閏既苦寒，今年春早亦大暄。", "清明寒食在二月，禁火正如揮箑天。", "桃花零落壯丹發，漠漠江頭吹柳綿。", "細蟲打窗夜如雨，潤氣蒸礎朝生泉。", "卷簾闢向迎風坐，徹褥去屏思簟眠。", "勸君用心慎倉卒，萬事轉易如車旋。", "安知明日不凜冽，莫以炎凉隨目前。"]'),
('13ee6dea-b31a-4d65-89d5-aabbe0b9a602','送謝仲規致仕','孔平仲','宋','宋诗','song-poetry','','[]','公年五十餘，鬚鬢黑如漆。',240,'全唐诗/poet.song.53000.json','["公年五十餘，鬚鬢黑如漆。", "朝廷方進用，未是挂冠日。", "又非力不任，數以身自乞。", "人疑徇虛名，今也踐其實。", "蕭然巢許姿，臭腐視冕紱。", "東南富人材，卿相近間出。", "急流能勇退，千古未有一。", "賢哉謝夫子，趣尚真不屈。", "騰裝嶺外遠，歸棹江邊疾。", "故鄉何日到，清暑坐華室。", "荔包雜紅紫，茶品分甲乙。", "歲時會親賓，左右列圖帙。", "回頭烟瘴地，揮手風波窟。", "天將勞以生，乃獨取閒佚。", "觀公眉宇秀，凜凜有道骨。", "當爲地上仙，不是籠中物。", "我亦素有心，賤貧嗟汩沒。", "鴻鵠羽翼成，高飛脫羅罻。", "鷦鷯未有巢，側目空自失。", "短章健公决，行且營蓬蓽。"]'),
('f0c92d1a-e04a-43ee-a4f7-9c60edf91ba0','曹亭獨登','孔平仲','宋','宋诗','song-poetry','','[]','問我當何之，曹亭蒼木外。',84,'全唐诗/poet.song.53000.json','["問我當何之，曹亭蒼木外。", "江湖水方漲，曠闊吾所愛。", "微風撼晚色，爽氣回秋籟。", "楊柳隠官堤，芙蕖接公廨。", "白雲依山起，點綴若圖繪。", "何須招客游，清興自無輩。", "落日更憑欄，下看飛鳥背。"]'),
('ca2f8691-a127-4db9-bdb7-ff986fb9bd06','晨出郡南','孔平仲','宋','宋诗','song-poetry','','[]','日未出，山更青。',44,'全唐诗/poet.song.53000.json','["日未出，山更青。", "湖既闊，風自生。", "垂楊弄疏影，啼鳥曳殘聲。", "江城曉色懷抱爽，况在白龍堤上行。"]'),
('c1c2087b-8497-4b7c-977c-954db52caea9','夏旱','孔平仲','宋','宋诗','song-poetry','','[]','元豐四年夏六月，旱風揚塵日流血。',176,'全唐诗/poet.song.53000.json','["元豐四年夏六月，旱風揚塵日流血。", "高田已白低田乾，陂池行車井泉竭。", "多稼如雲欲成就，天胡不仁忍斷絕。", "雷聲隆隆電摇幟，雨竟無成空混熱。", "如聞大河决北方，目極千里波濤黄。", "我願蛟龍卷此水，洒落東南救焦死。", "又聞戎瀘方用兵，戰車甲馬穿雲行。", "安得疏江擁三峽，餘波末流灌百城。", "分支引派入南畝，盡使枯槁得復生。", "志大心勞竟何補，仰視雲漢高溟溟。", "吾徒祿食固可飽，更願眼前無餓莩。"]'),
('0b84decb-eca0-4bfc-87fe-4c24628e7f29','澆瑞香','孔平仲','宋','宋诗','song-poetry','','[]','潑潑瑞香花，載水朝復暮。',72,'全唐诗/poet.song.53000.json','["潑潑瑞香花，載水朝復暮。", "瑞香得膏滋，枝葉乃如故。", "明春花必好，喜此夏秋度。", "大田塵土深，嘉穀可織屨。", "泉源不供飲，何力更灌注。", "嗟吾惠已屯，扃向東庭戶。"]'),
('6c2ddf0e-eaaf-4439-8cf8-8d9afe1b5997','西堂','孔平仲','宋','宋诗','song-poetry','','[]','我置一榻在西堂，南風北風俱得凉。',128,'全唐诗/poet.song.53000.json','["我置一榻在西堂，南風北風俱得凉。", "軒窗開闢無壅塞，枕簟照映生輝光。", "前有秋花鬧如錦，乘時吐秀爭煌煌。", "堂前堂後種植滿，坦腹轉側各相望。", "初開半落皆有意，牽動幽興何其長。", "彌天好夢誰喚覺，林間鳥舌弄絲簧。", "賤官固冗亦偷暇，一室甚卑堪退藏。", "吾心與世久契闊，萬事本無非故忘。"]'),
('12304113-2fc6-42f4-928e-45dcf6a9380a','聞砧作','孔平仲','宋','宋诗','song-poetry','','[]','見蠶成繭能幾日，繒帛輸官千萬疋。',128,'全唐诗/poet.song.53000.json','["見蠶成繭能幾日，繒帛輸官千萬疋。", "丁丁砧杵相和鳴，半夜霜風入秋律。", "一年寒事從今始，四序流光如羽疾。", "昨朝尚喜迎凉坐，閉戶羃窗嫌不密。", "人生天地隨氣轉，此身猶復非吾物。", "癡兒干世孰自量，欲與造化爭飄忽。", "功名富貴固有時，進退屈信何可必。", "匏羹菽飯幸粗飽，何用操瓢向人乞。"]'),
('8a768a0b-1e3e-4c2b-9435-f140fe4ae4de','登齊雲樓','孔平仲','宋','宋诗','song-poetry','','[]','登彼齊雲樓，下視江州城。',144,'全唐诗/poet.song.53000.json','["登彼齊雲樓，下視江州城。", "城前俯大江，流水與天平。", "人烟疏復密，漁舟縱復橫。", "其下各有人，人各有所營。", "意氣充宇宙，機巧鬭生獰。", "蠢然大塊中，何異蟻蝨蠅。", "天地一何廣，人物一何微。", "蠻氏與觸氏，紛爭誰是非。", "就令有所得，究竟欲何爲。", "所以達觀人，事事棄置之。", "登彼齊雲樓，覽世良可悲。", "不如飲美酒，浩歌醉言歸。"]'),
('7c68a7eb-58f2-4bd4-b522-097802a41bca','待月','孔平仲','宋','宋诗','song-poetry','','[]','初宵待月先掃門，雖未出海光照垣。',160,'全唐诗/poet.song.53000.json','["初宵待月先掃門，雖未出海光照垣。", "皎然輝采更無壅，比之常夕尤清妍。", "星辰不復爭芒角，河漢自合收波瀾。", "久之黮黲若蒙垢，坌起四隅陰氣繁。", "人心賞翫欲竟夕，嗟哉頃刻已自昏。", "如何更使魑魅畏，豈非已被蝦蟆吞。", "紛紛庭華墮如雨，訓狐騎屋貌甚尊。", "乘幽挾晦彼固喜，使之如此亦有緣。", "豈無蛇虺出當道，不如青燈坐前軒。", "以書自圍恣所取，黄卷聖賢聊可言。"]'),
('24291c90-f5cb-4d81-80c2-b3fc31f10be4','詠橘','孔平仲','宋','宋诗','song-poetry','','[]','古人詠橘誇甘香，獨我愛此千樹黄。',64,'全唐诗/poet.song.53000.json','["古人詠橘誇甘香，獨我愛此千樹黄。", "燭龍銜珠出扶桑，圓苞簇簇浮朝霜。", "誰家金餠籬內挂，一夜火圍林際光。", "折來便好命佳客，玉壺况有榴花漿。"]'),
('e339dd40-f71d-41f8-bc48-0e5ba978ff66','別友人','孔平仲','宋','宋诗','song-poetry','','[]','江城春風落梅花，我適南州君在家。',64,'全唐诗/poet.song.53000.json','["江城春風落梅花，我適南州君在家。", "離筵勸我一盃酒，送我萬里天之涯。", "少年曾同竹馬戲，漸長聚散良可嗟。", "後時迎笑復何地，寂寞無言雙淚斜。"]'),
('bd99db6a-b547-432f-86a9-c6cb376fce82','遺介之蔗','孔平仲','宋','宋诗','song-poetry','','[]','長不過三尺，堅如太古鐵。',48,'全唐诗/poet.song.53000.json','["長不過三尺，堅如太古鐵。", "身雖糞土賤，名在佳果列。", "中心唯養恬，外貌頗多節。", "憑君暫收採，彼此無摧折。"]'),
('8ec5f4e3-d32b-4fd5-9d66-49da3135a183','疾中偶成呈介之','孔平仲','宋','宋诗','song-poetry','','[]','吾生十五猶童孩，胸中膽氣摩天開。',168,'全唐诗/poet.song.53000.json','["吾生十五猶童孩，胸中膽氣摩天開。", "自憐少年輒有老夫志，恐是天仙犯帝怒，謫在下世馳驅乎塵埃。", "壯志若鐵石，頑直未易摧。", "奈何諸侯不薦賢，天子不聞才。", "空使丈夫兒，藏頭縮角埋蒿萊。", "天不管，地不顧，此理得不嗚呼哉。", "今朝大飲致沉疾，朋友戢迹絕往來。", "使人孤眠北窗下，風雨蕭蕭良可哀。", "冷笑今之世人少信義，旦暮之間輒變喜愛成嫌猜。", "介之不恤我，扶力吟詠攄幽懷。"]'),
('4a66c780-1752-4b22-a80c-c94c4d4976b1','城樓晚望','孔平仲','宋','宋诗','song-poetry','','[]','城樓高跨天中央，登臨舉目極四荒。',64,'全唐诗/poet.song.53000.json','["城樓高跨天中央，登臨舉目極四荒。", "蒼雲彤霞物象變，落日清風天氣凉。", "樹深蒙密幽鳥語，山勢蟬聯烟靄長。", "溪流渰渰東下去，安得扁舟還故鄉。"]'),
('b316deee-39d7-4859-a307-8deb041daf26','西施','孔平仲','宋','宋诗','song-poetry','','[]','邀出苧羅山，送上姑蘇臺。',24,'全唐诗/poet.song.53000.json','["邀出苧羅山，送上姑蘇臺。", "果迷吳主意，都忘越兵來。"]'),
('60f82d61-2628-42a0-96c2-c6611f1375d6','自警','孔平仲','宋','宋诗','song-poetry','','[]','大材耻衒耀，深智甘蒙晦。',48,'全唐诗/poet.song.53000.json','["大材耻衒耀，深智甘蒙晦。", "所以德業新，闇然日光大。", "一時師教誼，百世仰風裁。", "豈比迷識人，恃能多自懷。"]'),
('b5fffcb1-d469-4967-91b0-2ce327a4673b','辯言','孔平仲','宋','宋诗','song-poetry','','[]','兩葉可掩目，兩豆可塞耳。',48,'全唐诗/poet.song.53000.json','["兩葉可掩目，兩豆可塞耳。", "小人多奸邪，君子防近蔽。", "周公未免謗，孔子亦遭毀。", "人言不足信，自古均如此。"]'),
('c49692e9-2fa4-4fcd-8aea-26c20023f40b','自重','孔平仲','宋','宋诗','song-poetry','','[]','千金人所重，一物人所輕。',48,'全唐诗/poet.song.53000.json','["千金人所重，一物人所輕。", "君子欲自尊，接物以至誠。", "行誼金石固，笑語簫韵聲。", "群居自聳畏，暴慢何由形。"]'),
('9c44acde-0193-473d-b415-366665ab834c','述鷗','孔平仲','宋','宋诗','song-poetry','','[]','水濱老父忘機關，醉眠古石紅蕖間。',128,'全唐诗/poet.song.53000.json','["水濱老父忘機關，醉眠古石紅蕖間。", "綠波蕩漾意不動，白雲往來心與閒。", "有鷗素熟翁如此，命侶呼儔就翁喜。", "相親飲啄少畏避，自浮自沉不驚起。", "漁人窺之即謀取，手携羅罔來翁所。", "群鷗瞥見皆遠逝，千里翩翩一回顧。", "鷗不薄翁翁勿疑，避禍未萌真見機。", "漁人羅罔不在側，敢辭旦夕從翁嬉。"]'),
('90dd100c-98d9-4e84-9382-a8fc9e45e29f','夏夜','孔平仲','宋','宋诗','song-poetry','','[]','更漏沉沉人響絕，唯有松風韵清切。',32,'全唐诗/poet.song.53000.json','["更漏沉沉人響絕，唯有松風韵清切。", "是非榮辱不相關，獨臥南軒半床月。"]'),
('98855f13-b842-4517-bd73-03324519d8d4','戲書勸人飲酒','孔平仲','宋','宋诗','song-poetry','','[]','金烏翩翩玉兔馳，流光上下矢發機。',120,'全唐诗/poet.song.53000.json','["金烏翩翩玉兔馳，流光上下矢發機。", "人生于其間，都無百歲期。", "樂府舊傳金縷衣，勸言須惜少年時。", "我今爲君一歌之，酒行到君君莫辭。", "朱顔綠鬢不行樂，白頭面皺將何爲。", "晉時八達唐李白，以飲馳名君所知。", "何須自苦憊，方得爲英奇。", "榮華有分難力取，可笑蘇秦空引錐。"]'),
('b679bd81-87a6-4ad7-8348-de0d4dc80741','李太白','孔平仲','宋','宋诗','song-poetry','','[]','卓哉太白詩家徒，天然俊逸不可拘。',144,'全唐诗/poet.song.53000.json','["卓哉太白詩家徒，天然俊逸不可拘。", "豪文脫去刻削巧，遠意得自渾沌初。", "酒醒落筆洒風雨，當時所就皆須臾。", "驊騮馳驟日千里，鴻鵠軒騰凌九虛。", "蹇馿尺鷃不足道，徐步低翥何區區。", "後人吟咏多自蔽，鎪句鍊字爲良圖。", "撞金拊石皆可聽，未若霹靈轟天衢。", "公之大材不小到，俗議何者相加誣。", "賤生仰公風格美，未能彷彿空躊躇。"]'),
('461973b7-506a-4abf-abdd-e1e8ac4af6d3','凡馬示同學','孔平仲','宋','宋诗','song-poetry','','[]','凡馬慕騏驥，努力思遠行。',72,'全唐诗/poet.song.53000.json','["凡馬慕騏驥，努力思遠行。", "置之跛馿中，咫尺遂自矜。", "學者所慮遠，欲並揚鸞鳴。", "豈以勝時俗，驟爾意氣盈。", "聾瞽固易欺，奈有聰與明。", "作詩戒羣居，吾言非汝輕。"]'),
('5489ce1d-bb0b-4c9d-9090-c347abe260b2','海南碧琉璃瓶','孔平仲','宋','宋诗','song-poetry','','[]','手持蒼翠玉，終日看無足。',48,'全唐诗/poet.song.53000.json','["手持蒼翠玉，終日看無足。", "秋天長在眼，春水忽盈掬。", "瑩然無埃塵，可以清心曲。", "有酒自此傾，金樽莫相瀆。"]'),
('77069a53-f365-440d-b25d-c01ea63182a3','諭志','孔平仲','宋','宋诗','song-poetry','','[]','匣中有神劍，夜夜鳴不休。',72,'全唐诗/poet.song.53000.json','["匣中有神劍，夜夜鳴不休。", "欲汙單于血，思僇佞臣頭。", "不願就斬馬，賤用良自羞。", "深韜度歲月，怨氣射斗牛。", "仗君遠提携，可以安九州。", "莫作鉛刀顧，此非繞指柔。"]'),
('aeac0564-6e96-4b00-a265-6d8822276aae','乞巧','孔平仲','宋','宋诗','song-poetry','','[]','衆人喜乞巧，我以巧爲憂。',96,'全唐诗/poet.song.53000.json','["衆人喜乞巧，我以巧爲憂。", "言巧多欺佞，行巧爲邪柔。", "學巧競穿穴，文巧多彫鎪。", "巧不令如此，宜吾之恥求。", "我欲守拙性，浩然鎮輕浮。", "盡窒衆巧門，化以孔與周。", "此志尚未遂，感激在初秋。", "南顧問牛女，女實能巧不。"]'),
('1775bd8d-3a57-43f7-8c79-f49cbdcb87f9','十日菊','孔平仲','宋','宋诗','song-poetry','','[]','昨日酒中花，今日籬下草。',36,'全唐诗/poet.song.53000.json','["昨日酒中花，今日籬下草。", "馨香尚未改，棄置一何早。", "怨泣露華濕，世情安可保。"]'),
('78ea2149-e3ff-46b4-ab19-4177c11daed7','晦之詩尤瘧鬼某意鬼不能爲端士害奉酬作詩','孔平仲','宋','宋诗','song-poetry','','[]','吾聞烈士仗忠信，出入鬼神皆避逃。',192,'全唐诗/poet.song.53000.json','["吾聞烈士仗忠信，出入鬼神皆避逃。", "維彼小人鬼所狎，祟異皆自不善招。", "晦之履行並仁義，常揭名教爲己操。", "天將大任預連蹇，薄宦南州初折腰。", "劬勞戴星出視事，冒突瘴霧匪一朝。", "浸淫不制偶成疾，愁臥漳浦擁敝袍。", "有時體燥似灼火，憤怒索筆爲長謠。", "句中有意譴瘧鬼，詞氣凌鑠吏部高。", "予竊料君所守正，彼鬼何者能爲妖。", "幽明路異不相忤，有疾自是疏攝調。", "强飯進藥姑自愛，勿惑異說心空摇。", "菊花未落遲君出，猶可共醉樽中醪。"]'),
('3eab4d2e-81df-4343-a003-0fdff6ff644e','送王秀才歸邵州','孔平仲','宋','宋诗','song-poetry','','[]','去家逾年客千里，秋風一夜歸心起。',64,'全唐诗/poet.song.53000.json','["去家逾年客千里，秋風一夜歸心起。", "平明騎馬出郊關，北望邵陵程尚幾。", "道旁送者皆知己，相顧慘悽將挽止。", "丈夫壯心自有圖，暫別何須淚如水。"]'),
('ebef88b6-88d6-46eb-b717-2ded82fd6a71','席上勸王八飲','孔平仲','宋','宋诗','song-poetry','','[]','細雨蕭蕭風淅淅，凍雲倚天如掃墨。',64,'全唐诗/poet.song.53000.json','["細雨蕭蕭風淅淅，凍雲倚天如掃墨。", "高堂置酒送行人，金杯緩飲愁腸滌。", "勸君莫惜暫酩酊，自今一別遂南北。", "後時月夕與花朝，縱飲共醉安可得。"]'),
('d7dde43c-4809-4f46-a108-0b660a972135','冬夕翫月','孔平仲','宋','宋诗','song-poetry','','[]','夜深鳥宿人語靜，中庭獨坐饒清興。',64,'全唐诗/poet.song.53000.json','["夜深鳥宿人語靜，中庭獨坐饒清興。", "霜天高潔無片雲，海月澄明挂孤鏡。", "飛光照物毫杪露，冷氣逼人肌骨冰。", "苦吟未盡愁曉侵，北向時時看斗柄。"]'),
('0b46f413-0d24-40d6-93cb-a76d4bebea54','冬夜','孔平仲','宋','宋诗','song-poetry','','[]','冬夜一何永，幽房寂無侶。',48,'全唐诗/poet.song.53000.json','["冬夜一何永，幽房寂無侶。", "青燈弄微風，敗葉鳴疏雨。", "凄凉角聲動，悲散穿雲去。", "展轉臥書帷，羈愁欲誰語。"]'),
('2b912710-8172-48e0-a577-03421f6fcbfb','封川上元','孔平仲','宋','宋诗','song-poetry','','[]','穿城不千步，十步燃一燈。',48,'全唐诗/poet.song.53000.json','["穿城不千步，十步燃一燈。", "閃閃摇斜風，熒熒若疏星。", "士女魚鳥聚，鼓吹蛙黽聲。", "蠻俗自爲樂，我心愁不醒。"]'),
('2b46cd09-c805-40ce-9cc6-f8ce3f8a2901','瑞蓮','孔平仲','宋','宋诗','song-poetry','','[]','花開自有嬋娟伴，牽人情緒迷人眼。',64,'全唐诗/poet.song.53000.json','["花開自有嬋娟伴，牽人情緒迷人眼。", "寂寞雙紅不動時，皇英對立湘江晚。", "芳心向背如相結，媚臉高低開已半。", "欲隨蛺蝶採清香，堪恨綠池風浪暖。"]'),
('14b34152-7124-4bef-b76d-3371b827592c','江上獨步','孔平仲','宋','宋诗','song-poetry','','[]','晚步碧江上，掀衣忽回顧。',48,'全唐诗/poet.song.53000.json','["晚步碧江上，掀衣忽回顧。", "安得一葉舟，飄然五湖去。", "浩歌風水古，醉倒烟霞暮。", "誰能逐羣動，役役趨世務。"]'),
('0b37f922-8352-4f87-91c1-e3dd1d18ddb3','寓目','孔平仲','宋','宋诗','song-poetry','','[]','白日照園林，悲風久蕭索。',48,'全唐诗/poet.song.53000.json','["白日照園林，悲風久蕭索。", "橫秋隻鶻健，駕海孤帆逸。", "陰雲带雨歸，晴嶂排空出。", "一望一高歌，憑誰縱吟筆。"]'),
('60332e84-1c77-4403-932a-4156919ffc66','有感','孔平仲','宋','宋诗','song-poetry','','[]','驚風拔古松，浮雲掩秋月。',24,'全唐诗/poet.song.53000.json','["驚風拔古松，浮雲掩秋月。", "對景輒悲歌，隨聲入清血。"]'),
('ccd7a4d8-47c2-493a-91f1-3f56cbf24012','題清溪圖','孔平仲','宋','宋诗','song-poetry','','[]','清溪之水清無泥，鳬飛雁下太平池。',240,'全唐诗/poet.song.53000.json','["清溪之水清無泥，鳬飛雁下太平池。", "昔人嘗比翠綃舞，安得卷之必自隨。", "畫師摹寫多巧思，只用烏田數張紙。", "戲拈禿筆掃成圖，濃淡邅迴真得意。", "江磯釣浦遠更深，昔時行處皆可尋。", "張公好雅心不俗，眉山先生爲楚吟。", "公今奉使庾嶺南，峽中喬林與天參。", "白雲摇曳入船戶，清猿呼嘯窺江潭。", "天霾不開地多熱，佛桑山丹赤如血。", "此時一展清溪圖，洒若胸中貯冰雪。", "南方不可以久留，祝公歸來此中州。", "枕白石兮漱清流，蘆聲戰雨曷若颺風之拔木，漁烟凝晚曷若海霧之橫秋。", "我已卜居在九江，九華廬阜鬰相望。", "千里思公如咫尺，扁舟棹月到池陽。"]'),
('0daebb15-1157-41b9-ae70-c1ed6745e6c5','初三夜作','孔平仲','宋','宋诗','song-poetry','','[]','曉色漫漫看雪下，溪流脈脈見潮生。',64,'全唐诗/poet.song.53000.json','["曉色漫漫看雪下，溪流脈脈見潮生。", "船窗靜坐無賓客，樽酒相從只弟兄。", "會合都來能幾日，留連遮莫到三更。", "何如徑就舟中宿，岸斗深泥不可行。"]'),
('4b83bc18-b7e1-4d30-b48a-d06593226eba','再用元韵','孔平仲','宋','宋诗','song-poetry','','[]','小舟衝雪魚新買，濕荻吹烟火旋生。',64,'全唐诗/poet.song.53000.json','["小舟衝雪魚新買，濕荻吹烟火旋生。", "一笑兼留青眼客，半年不見白頭兄。", "厭厭劇飲罍頻恥，衮衮高談僕屢更。", "故使移船相近住，幾番潮信不能行。"]'),
('b6d3691d-37ad-4fa3-ad55-a9a554dcb0aa','初十夜作','孔平仲','宋','宋诗','song-poetry','','[]','泱泱積水遶亭基，月白風清夜坐時。',32,'全唐诗/poet.song.53000.json','["泱泱積水遶亭基，月白風清夜坐時。", "轉舵開船即千里，祇應重到解相思。"]'),
('090ddb03-1387-4e7b-9ab3-edc927be42fa','真州元夕','孔平仲','宋','宋诗','song-poetry','','[]','擾擾州城一彈丸，燈光疏冷月光寒。',32,'全唐诗/poet.song.53000.json','["擾擾州城一彈丸，燈光疏冷月光寒。", "杖行猶恐人相識，紫褐圓絛著道冠。"]'),
('4d9a2517-24d9-4db7-a55d-b2078627d1b3','游江寧天慶觀久視軒見梅已落有寄常父','孔平仲','宋','宋诗','song-poetry','','[]','記得東齋折小梅，數枝寒色未全開。',32,'全唐诗/poet.song.53000.json','["記得東齋折小梅，數枝寒色未全開。", "江上別來今幾日，暖風吹逕雪成堆。"]'),
('d36d31f6-ce68-4c37-b5a2-8d72f2cbfcc0','造王館公第馬上作','孔平仲','宋','宋诗','song-poetry','','[]','濯濯春容在柳梢，野梅相壓吐香苞。',64,'全唐诗/poet.song.53000.json','["濯濯春容在柳梢，野梅相壓吐香苞。", "日邊明晦雲無定，雨後寒暄氣欲交。", "抱蕊懸蟲猶带繭，銜枝飛鳥已營巢。", "高懷不愛三公府，白水青山滿近郊。"]'),
('457d0598-34f4-4d25-b10a-1bed2843a7a5','呈館公','孔平仲','宋','宋诗','song-poetry','','[]','磻溪莘野亦初閒，去逐功名遂不還。',64,'全唐诗/poet.song.53000.json','["磻溪莘野亦初閒，去逐功名遂不還。", "豈有太平辭將相，却來高臥對湖山。", "冥心真出三千界，注想長虛第一班。", "踽踽朱門舊時客，冒寒衝雨到郊關。"]'),
('288dc239-6b8a-4e68-aac8-8f9f43e77667','元子發龍圖以程公詠三園詩見示亦成一篇','孔平仲','宋','宋诗','song-poetry','','[]','名園有一已堪誇，勝事三園屬一家。',64,'全唐诗/poet.song.53000.json','["名園有一已堪誇，勝事三園屬一家。", "杖策可遊緣近宅，得春最久爲多花。", "人居玉府真仙格，地占錢塘最物華。", "見說江湖堂更好，烟波清興浩與涯。"]'),
('5b9028e3-0982-47c0-9dc6-287877aa6b82','題姑孰臺','孔平仲','宋','宋诗','song-poetry','','[]','青山便是玄暉宅，采石相傳李白墳。',32,'全唐诗/poet.song.53000.json','["青山便是玄暉宅，采石相傳李白墳。", "誰使浪仙來此住，姓名輝映少知聞。"]'),
('5b933af4-be5f-4ab0-b643-dccc1ed1e5e4','戲寄葉縣黄魯直','孔平仲','宋','宋诗','song-poetry','','[]','西山曾夢巫山雨，南浦常迷洛浦珠。',32,'全唐诗/poet.song.53000.json','["西山曾夢巫山雨，南浦常迷洛浦珠。", "古縣寂寥官况冷，不知還憶舊歡無。"]'),
('20346654-d679-4578-b122-6832b41c46ab','贈武科胡七','孔平仲','宋','宋诗','song-poetry','','[]','三尺青蛇丈二矛，崛然來應武科求。',64,'全唐诗/poet.song.53000.json','["三尺青蛇丈二矛，崛然來應武科求。", "東南近出人才美，西北當寬帝顧憂。", "戰馬夜嘶榆塞月，征衣寒犯玉關秋。", "古今將相皆無種，好取班超萬里侯。"]'),
('92c4ddc3-2802-47ef-9559-21d85248e57a','和常父','孔平仲','宋','宋诗','song-poetry','','[]','平生苦厭家爲累，今日應如痛定人。',64,'全唐诗/poet.song.53000.json','["平生苦厭家爲累，今日應如痛定人。", "羣婢喧譁寧復有，孤燈瀟灑自相親。", "溫尋簡策評三豕，點綴文章學受辛。", "誰謂丹楓會愁客，深秋清思滿江濱。"]'),
('7be4a7a5-cfba-487f-b5f6-7099790ce31b','喜經父閣試第一','孔平仲','宋','宋诗','song-poetry','','[]','决起南溟近北辰，風雷含蓄待經綸。',64,'全唐诗/poet.song.53000.json','["决起南溟近北辰，風雷含蓄待經綸。", "殿前欲奏三千字，閣下先爲第一人。", "擢等定如唐處厚，封侯終似漢平津。", "應嫌有弟真癡絕，抱甕區區最苦辛。"]'),
('6c9cbcf9-ce62-41d3-a24b-407177a92f2e','喜經父制策第一  其一','孔平仲','宋','宋诗','song-poetry','','[]','過閣程文推首出，臨軒親策復先鳴。',64,'全唐诗/poet.song.53000.json','["過閣程文推首出，臨軒親策復先鳴。", "大科江左未嘗有，此事吾家真最榮。", "獨步以才高宇宙，橫飛不日到蓬瀛。", "翩翩斥鷃蒿萊下，豈識鵬摶九萬程。"]'),
('8e39d9d8-2a9d-4658-a153-5a6acda7f023','喜經父制策第一  其二','孔平仲','宋','宋诗','song-poetry','','[]','親策賢良第一番，吾家羽翼蔚高騫。',64,'全唐诗/poet.song.53000.json','["親策賢良第一番，吾家羽翼蔚高騫。", "當時棄祿嫌民掾，此日登科勝狀元。", "四海望風期將相，雙親聞榜慶兒孫。", "台州已有公台兆，預約當行必踐言。"]'),
('7a4e8d3b-9f29-42b0-8b77-b3c7be7daaaf','初食鱭魚蔞蒿','孔平仲','宋','宋诗','song-poetry','','[]','魚從網師得，蒿自麥田求。',48,'全唐诗/poet.song.53000.json','["魚從網師得，蒿自麥田求。", "斫鱠嘗鮮美，調羹烹滑柔。", "江南見春物，野次助晨羞。", "人各甘香味，鱸蓴未易侔。"]'),
('9beff70a-637a-489a-887c-8126ec80341e','題夏大初丈高居','孔平仲','宋','宋诗','song-poetry','','[]','入門已可愛，庭戶復清陰。',48,'全唐诗/poet.song.53000.json','["入門已可愛，庭戶復清陰。", "更有池臺邃，相連花木深。", "山川供隠几，風月伴抽簪。", "七十鬚渾黑，知公但養心。"]'),
('487aaca4-88b2-48bf-948b-f21ab82d8dfd','萃勝亭','孔平仲','宋','宋诗','song-poetry','','[]','蕭灑東堂秋正皎，思尋一徑上幽亭。',64,'全唐诗/poet.song.53000.json','["蕭灑東堂秋正皎，思尋一徑上幽亭。", "天生喬木爲欹蓋，地借羣山作畫屏。", "有志休官頭未白，多情好客眼偏青。", "知公故欲來高處，目送飛鴻在杳冥。"]'),
('ddab458b-462a-433e-861f-b26d4300c2a2','滕元發池州蕭相樓','孔平仲','宋','宋诗','song-poetry','','[]','相國當時此建旄，正如今日擁三刀。',64,'全唐诗/poet.song.53000.json','["相國當時此建旄，正如今日擁三刀。", "規摹忽起凌千尺，意氣相期在一陶。", "柱礎下連坤軸壯，簷牙斜插斗杓高。", "觀公磊落真人傑，莫向江山賦楚騷。"]'),
('0ed2689c-0794-4bf6-a13c-c0be536e3539','再賦','孔平仲','宋','宋诗','song-poetry','','[]','廊廟之才守一州，暮年名位等酇侯。',64,'全唐诗/poet.song.53000.json','["廊廟之才守一州，暮年名位等酇侯。", "簪纓七葉皆當軸，棟宇千章爲起樓。", "撫事蕭條人已遠，臨風慷慨意相投。", "期公便握璣衡去，留取餘光照斗牛。"]'),
('a571de0e-7b08-4503-83e8-cbcf1e3655c3','哭張子禮','孔平仲','宋','宋诗','song-poetry','','[]','漾檝貴池郡，傷心甘澤園。',48,'全唐诗/poet.song.53000.json','["漾檝貴池郡，傷心甘澤園。", "笑言成死別，風味想生存。", "花木春無主，蒿萊晝掩門。", "尚思歌舞會，些語爲招魂。"]'),
('fbdf0c0c-8070-483f-8c49-a0f8d96f6d1e','出郊','孔平仲','宋','宋诗','song-poetry','','[]','田下泉鳴春雨晴，新秧無數已齊生。',32,'全唐诗/poet.song.53000.json','["田下泉鳴春雨晴，新秧無數已齊生。", "一年農事從今始，會見西風玉粒成。"]'),
('8b5f2ef3-1e9f-44eb-91b8-6ae21afde772','松花','孔平仲','宋','宋诗','song-poetry','','[]','曾聞高節冒冰霜，三月開花滿路香。',32,'全唐诗/poet.song.53000.json','["曾聞高節冒冰霜，三月開花滿路香。", "虬鬣龍鱗今老大，學他挑弄色輕黄。"]'),
('1415d92e-f3af-4ffa-815e-e8548ee69439','蓮葉','孔平仲','宋','宋诗','song-poetry','','[]','蓮葉田田出水齊，清香已有曉風吹。',32,'全唐诗/poet.song.53000.json','["蓮葉田田出水齊，清香已有曉風吹。", "物華光景人誰覺，便是花開結子時。"]'),
('81046a47-47e4-4cc3-a26b-da9c6487cc17','清暉館','孔平仲','宋','宋诗','song-poetry','','[]','湖山秀氣合，庭榭綠陰初。',48,'全唐诗/poet.song.53000.json','["湖山秀氣合，庭榭綠陰初。", "吹臘新嘗酒，鳴榔旋取魚。", "青規諫官疏，丹轂使臣車。", "醉尉無儀檢，將軍莫怪渠。"]'),
('a3dcb443-cfd6-47e0-8ac6-89086c923410','花望之弄璋亭','孔平仲','宋','宋诗','song-poetry','','[]','開亭面峰島，來客慶桑弧。',48,'全唐诗/poet.song.53000.json','["開亭面峰島，來客慶桑弧。", "屢種藍田玉，新還合浦珠。", "海邊桃結子，天外鳳生雛。", "莫笑軒楹陋，高門即似于。"]'),
('f5e9072c-5934-4d8c-869c-e9ec0d2c17c1','西軒','孔平仲','宋','宋诗','song-poetry','','[]','新作朱門向水開，雖臨行路少塵埃。',64,'全唐诗/poet.song.53000.json','["新作朱門向水開，雖臨行路少塵埃。", "久藏勝境因人發，盡放青山入坐來。", "樹影轉簷棋未散，荷香飄枕夢初回。", "晚年事事皆疏懶，頼得閒官養不才。"]'),
('22e61334-99dd-4129-8b62-bddeddd6bea3','夏晝','孔平仲','宋','宋诗','song-poetry','','[]','落花寧是穢，啼鳥不爲喧。',48,'全唐诗/poet.song.53000.json','["落花寧是穢，啼鳥不爲喧。", "野水從侵道，青山任塞門。", "吏身閒似隠，官舍靜於村。", "開卷何曾讀，風來只自翻。"]'),
('8da1b795-04c6-4db4-a95f-82b22678d94f','和唐林夫游家園','孔平仲','宋','宋诗','song-poetry','','[]','荒園忽報枉高旌，旋設屏帷當小亭。',64,'全唐诗/poet.song.53000.json','["荒園忽報枉高旌，旋設屏帷當小亭。", "重複江山天外遠，回還松竹坐中青。", "勸斟美酒罍頻恥，看跋名書墨尚馨。", "莫笑區區身未退，待公鵬擊我鴻冥。"]'),
('466111b7-0ae7-468a-838a-ab67357dfff1','庾樓','孔平仲','宋','宋诗','song-poetry','','[]','高城枕浩渺，層層壓崔嵬。',72,'全唐诗/poet.song.53000.json','["高城枕浩渺，層層壓崔嵬。", "路繞清陰上，山分爽氣來。", "天低風動幕，空迥月浮杯。", "遠眼征帆盡，凉襟細雨開。", "行人望蓬島，游客比春臺。", "豈獨登臨勝，扶傾不易才。"]'),
('9bbd7752-514f-46f3-82fe-439c588d9ab3','夏夜','孔平仲','宋','宋诗','song-poetry','','[]','小雨初收深夜凉，杖藜徐步立回塘。',64,'全唐诗/poet.song.53000.json','["小雨初收深夜凉，杖藜徐步立回塘。", "一天星月清人意，四面芙蕖遺我香。", "大隠嘗聞在朝市，昔人何必濯滄浪。", "應官粗了心無事，便是逍遙物外鄉。"]'),
('26cdf298-f393-4c7e-80c7-f860b77954de','種花口號  其一','孔平仲','宋','宋诗','song-poetry','','[]','幽居裝景要多般，带雨移花便得看。',32,'全唐诗/poet.song.53000.json','["幽居裝景要多般，带雨移花便得看。", "禁奈久長顔色好，繞階更使種鷄冠。"]'),
('3c549805-d416-4d58-bc4b-11130776aee2','種花口號  其二','孔平仲','宋','宋诗','song-poetry','','[]','蜀葵萱草陳根在，金鳳鷄冠著地栽。',32,'全唐诗/poet.song.53000.json','["蜀葵萱草陳根在，金鳳鷄冠著地栽。", "併作暑天庭戶景，深叢時見一花開。"]'),
('e8d8d936-7fb1-4912-bf81-19ce81fd2c21','池上  其一','孔平仲','宋','宋诗','song-poetry','','[]','汲水添池池已深，小魚無數亂浮沉。',32,'全唐诗/poet.song.53000.json','["汲水添池池已深，小魚無數亂浮沉。", "綠萍荷葉皆凉冷，更有庭柯百尺陰。"]'),
('2ed3be35-bddd-4c7f-9921-3fec2ee7dc60','池上  其二','孔平仲','宋','宋诗','song-poetry','','[]','羣魚散漫吸新水，好鳥間關啼翠陰。',32,'全唐诗/poet.song.53000.json','["羣魚散漫吸新水，好鳥間關啼翠陰。", "悠然物我俱自得，一霎南風吹我襟。"]'),
('d47010bd-e0aa-4aa4-b426-3c87dd08840f','桂堂','孔平仲','宋','宋诗','song-poetry','','[]','團團濃綠隔窗紗，曾見叢生瘴海涯。',64,'全唐诗/poet.song.53000.json','["團團濃綠隔窗紗，曾見叢生瘴海涯。", "太守作堂真好事，謫仙題榜更增華。", "孤根直節非今日，秀氣清香自一家。", "氣候人間應較晚，月中子落此開花。"]'),
('8cff6590-dee1-4b7d-acd7-20a374f99ce7','通判成郎中生日人凡送香合壽星皆不受獨以詩獻','孔平仲','宋','宋诗','song-poetry','','[]','和似陽春靜似山，謳謠千里祝公年。',64,'全唐诗/poet.song.53000.json','["和似陽春靜似山，謳謠千里祝公年。", "暫留卑濕江城地，且慶舒長夏景天。", "盛德自當增壽考，高才行且復蕃宣。", "香奩畫軸知無用，只有詩篇不值錢。"]'),
('99da8466-c444-4038-acda-dce93b052242','詩致卓道士靈座','孔平仲','宋','宋诗','song-poetry','','[]','陰陽藻鑑兩俱優，落落高談氣似秋。',64,'全唐诗/poet.song.53000.json','["陰陽藻鑑兩俱優，落落高談氣似秋。", "仙馭晚留山水國，客星曾入帝王州。", "却乘眇莽歸三島，空葬衣冠付一丘。", "作頌馳書謝人世，知君平昔悟浮休。"]'),
('b4172e4d-ff3c-490e-af3b-78908b6a25a5','次韵王通叟','孔平仲','宋','宋诗','song-poetry','','[]','春生湘浦即當還，窮覽雲山得據鞍。',64,'全唐诗/poet.song.53000.json','["春生湘浦即當還，窮覽雲山得據鞍。", "灑落文章終不俗，從容談笑尚能歡。", "千金駿馬將辭主，一曲胡琴遂掩棺。", "世事相因古如此，誰知魯國累邯鄲。"]'),
('68822772-77bc-4932-8c03-64b8322d8f25','夏日甘寢','孔平仲','宋','宋诗','song-poetry','','[]','迴風動木葉，細雨濕蛛絲。',48,'全唐诗/poet.song.53000.json','["迴風動木葉，細雨濕蛛絲。", "心下無閒事，人間有此時。", "微凉紗半捲，幽夢角徐吹。", "此興惟吾解，兒曹莫使知。"]'),
('48b5e725-8545-42b1-836e-978011628da7','晚興','孔平仲','宋','宋诗','song-poetry','','[]','驟雨行荷葉，嘈嘈如語言。',48,'全唐诗/poet.song.53000.json','["驟雨行荷葉，嘈嘈如語言。", "高齋正薄暮，宴坐不知喧。", "極靜開心地，新凉入鬢根。", "交游何用絕，自罕到吾門。"]'),
('e3cac6e3-eeea-4849-aac5-c73e99cc9aed','張子明自廬山歸云十五夜桂子落於太平觀鄉人謂之大熟子豐年之兆也','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','誰撼月中丹桂枝，墮階圓實似珠璣。',64,'全唐诗/poet.song.53000.json','["誰撼月中丹桂枝，墮階圓實似珠璣。", "山中道人拾不盡，湖上仙人携得歸。", "半夜香風飄澗壑，一時甘雨徧郊圻。", "與公寄籍皆江國，且喜田園歲不饑。"]'),
('6bf9154e-b0c0-44bf-8001-36676e1bf2cd','寄唐林夫','孔平仲','宋','宋诗','song-poetry','','[]','北音融結本輕清，欲學含糊想未能。',64,'全唐诗/poet.song.53000.json','["北音融結本輕清，欲學含糊想未能。", "晚節弦歌應自笑，終朝簿領更相仍。", "九江土壤多卑濕，三伏雲氛正鬰蒸。", "宴坐知君無暑氣，風標自敵玉壺冰。"]'),
('ac7a58c8-172e-41e4-8712-241380523189','詠蜀葵','孔平仲','宋','宋诗','song-poetry','','[]','綽約佳人淡薄粧，天真自恃不熏香。',32,'全唐诗/poet.song.53000.json','["綽約佳人淡薄粧，天真自恃不熏香。", "低頭無語嬌尤甚，更著新翻淺色黄。"]'),
('1792903e-76ba-4a50-ba95-8c29d53437e4','詠荷花','孔平仲','宋','宋诗','song-poetry','','[]','一花一葉自相連，待得花開葉已圓。',32,'全唐诗/poet.song.53000.json','["一花一葉自相連，待得花開葉已圓。", "應爲施朱嫌太赤，故將嫩綠間嬋娟。"]'),
('851287d5-fbc2-4a36-88ae-513b3f8802e2','晚興','孔平仲','宋','宋诗','song-poetry','','[]','展簟當簷臥，微風送晚凉。',48,'全唐诗/poet.song.53000.json','["展簟當簷臥，微風送晚凉。", "雲移自徐疾，蕉舞更低昂。", "結網蛛縈足，歸巢鳥亂行。", "支離聊度日，那復論行藏。"]'),
('f4328573-4124-4de5-ac0d-57215c774b24','送吳全甫中舍倅無爲','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','海沂歌舞待王祥，喜得淮南一道堂。',64,'全唐诗/poet.song.53000.json','["海沂歌舞待王祥，喜得淮南一道堂。", "軍號無爲已閒暇，地連秋浦更清凉。", "進趨黽勉心應懶，退食優游策最長。", "我住廬山欲招隠，爲君先去種松篁。"]'),
('8fe930af-3ed5-4c53-82f4-1534d287f422','晚凉  其一','孔平仲','宋','宋诗','song-poetry','','[]','晚凉睡覺欲何之，散步徜徉曲沼西。',32,'全唐诗/poet.song.53000.json','["晚凉睡覺欲何之，散步徜徉曲沼西。", "更上曹亭望江水，畫船却檥白龍堤。"]'),
('00a1f375-aab2-42dd-960e-1c76d2b3bb84','晚凉  其二','孔平仲','宋','宋诗','song-poetry','','[]','晚凉睡覺坐前軒，悄寂無人共語言。',32,'全唐诗/poet.song.53000.json','["晚凉睡覺坐前軒，悄寂無人共語言。", "近見南山片雲起，滿塘荷葉雨聲喧。"]'),
('dc6ebdb1-0ca1-4194-ab88-fd29fdd284d2','賦程氏雲庵','孔平仲','宋','宋诗','song-poetry','','[]','蕭然隠几坐，終日白雲間。',48,'全唐诗/poet.song.53000.json','["蕭然隠几坐，終日白雲間。", "觸石未全起，無心聊與閒。", "幽篁相映带，絕頂有躋攀。", "最稱侵寒望，淮南雪滿山。"]'),
('34c12e94-f105-458f-8ce4-bc683f5df3da','常父相率作吳丞相挽詞  其一','孔平仲','宋','宋诗','song-poetry','','[]','久倦調羹手，新尋辟穀方。',48,'全唐诗/poet.song.53000.json','["久倦調羹手，新尋辟穀方。", "謂還周衮繡，重補舜衣裳。", "忽報中台拆，同嗟一鑑亡。", "森然棟梁氣，今此掩黄腸。"]'),
('b43478e3-dd34-49ed-89ac-d52b87116644','常父相率作吳丞相挽詞  其二','孔平仲','宋','宋诗','song-poetry','','[]','鳴玉東西府，藏舟辰巳年。',48,'全唐诗/poet.song.53000.json','["鳴玉東西府，藏舟辰巳年。", "鹽梅捐鼎實，箕尾返星躔。", "陰德元豐政，遺書太史編。", "後人瞻彷彿，圖像在凌烟。"]'),
('b495b99c-64f5-4dfe-9232-2a36e0c28587','霽夜','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','寂歷簾櫳深夜明，睡迴清夢戍牆鈴。',64,'全唐诗/poet.song.53000.json','["寂歷簾櫳深夜明，睡迴清夢戍牆鈴。", "狂風送雨已何處，淡月籠雲猶未醒。", "早有秋聲隨墮葉，獨將凉意伴流螢。", "明朝準擬南軒望，洗出廬山萬丈青。"]'),
('62bb97a5-0547-4994-aba5-099507ba4b03','晚望','孔平仲','宋','宋诗','song-poetry','','[]','秋江水自壯，更值雨滂沱。',48,'全唐诗/poet.song.53000.json','["秋江水自壯，更值雨滂沱。", "落日增野興，連天吹細波。", "城依湓浦近，舟傍柳湖多。", "吾已忘清濁，安知孺子歌。"]'),
('321a6069-18ed-41b7-8551-4e9bc8e10ec2','禾熟三首  其一','孔平仲','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u6292\u6000", "\u519c\u4e8b", "\u5b8b\u8bd7"]','百里西風禾黍香，鳴泉落竇穀登場。',32,'全唐诗/poet.song.53000.json','["百里西風禾黍香，鳴泉落竇穀登場。", "老牛粗了耕耘債，齧草坡頭臥夕陽。"]'),
('641d34dd-dae7-4970-a610-4280ddb18050','禾熟三首  其二','孔平仲','宋','宋诗','song-poetry','','[]','豐年氣象慰人心，鳥雀啾嘲亦好音。',32,'全唐诗/poet.song.53000.json','["豐年氣象慰人心，鳥雀啾嘲亦好音。", "玉食兒郎豈知此，田家粒粒是黄金。"]'),
('bb30586c-b7fb-4109-82e8-bce8c6a70155','禾熟三首  其三','孔平仲','宋','宋诗','song-poetry','','[]','雨足川原還聚晴，天心斷送此秋成。',32,'全唐诗/poet.song.53000.json','["雨足川原還聚晴，天心斷送此秋成。", "穀收顆顆皆堅好，想見新炊照盌明。"]'),
('84865620-e4dc-4f7c-98d1-fd5f235111a1','深夜','孔平仲','宋','宋诗','song-poetry','','[]','闃寂方深夜，清凉別一天。',48,'全唐诗/poet.song.53000.json','["闃寂方深夜，清凉別一天。", "臨風但獨立，愛月不成眠。", "戍漏傳聲小，庭柯轉影圓。", "露寒侵背側，移榻近堂前。"]'),
('dbb25d4e-d320-4faa-9125-b8cd713d3a70','和朱君况卜居','孔平仲','宋','宋诗','song-poetry','','[]','吾身當老此園中，世路崎嶇幾萬重。',64,'全唐诗/poet.song.53000.json','["吾身當老此園中，世路崎嶇幾萬重。", "且飽稻粱隨雁鶩，盡將雲雨付蛟龍。", "求閒有志終須得，招隠何人肯見從。", "且爲莆田朱處士，比鄰先種七株松。"]'),
('79b4836c-65b7-4ae3-a597-1dcb046ad753','和項元師見遺柳書','孔平仲','宋','宋诗','song-poetry','','[]','古今諸柳孰爲强，矯矯鍼懸術最良。',64,'全唐诗/poet.song.53000.json','["古今諸柳孰爲强，矯矯鍼懸術最良。", "自富詩才堪繼惲，兼深儒學有如芳。", "當時屢獻箴規益，末世惟傳翰墨光。", "石刻見貽真雅賜，崢嶸筆力有餘剛。"]'),
('e961662c-d1b6-4e98-a38f-fbfe0d74f4bd','雞冠花','孔平仲','宋','宋诗','song-poetry','','[]','萌芽澆灌已成叢，一一深紅間淺紅。',32,'全唐诗/poet.song.53000.json','["萌芽澆灌已成叢，一一深紅間淺紅。", "偏近黄昏顔色好，分明秋景畫圖中。"]'),
('b958eb5c-4c55-4da6-bed4-7f2758eb7752','睡起','孔平仲','宋','宋诗','song-poetry','','[]','睡起西風掠鬢輕，蕭然庭院晚寒生。',64,'全唐诗/poet.song.53000.json','["睡起西風掠鬢輕，蕭然庭院晚寒生。", "浮雲便作飛鴻意，細雨仍兼落葉聲。", "物不求餘隨處足，事如能省即心清。", "山林朝市皆相似，何必區區隠釣耕。"]'),
('c8762a9d-20f3-46c0-b02f-c5d98c93202b','送郎祖仁奉禮','孔平仲','宋','宋诗','song-poetry','','[]','碧落聲華蓋世高，哀烏才業亦時豪。',64,'全唐诗/poet.song.53000.json','["碧落聲華蓋世高，哀烏才業亦時豪。", "靈淵自出駒千里，丹穴今看鳳一毛。", "方略從容能處事，精神洒落見揮毫。", "東行想足資清興，江上秋風捲怒濤。"]'),
('8c9eb581-a1e3-4339-a222-9502653b9a72','次韵孫亨甫見寄','孔平仲','宋','宋诗','song-poetry','','[]','進多齟齬退爲安，未省乘軒勝抱關。',64,'全唐诗/poet.song.53000.json','["進多齟齬退爲安，未省乘軒勝抱關。", "半世青衫貧爲祿，新秋明鏡老催顔。", "紛紛江上風吹葉，漠漠淮南雨暗山。", "欲和佳篇寄相憶，韵嚴詞峭不容攀。"]'),
('383704b8-a51b-4efa-af05-59cc0f397532','唐林夫累惠書字法絕精以詩謝之','孔平仲','宋','宋诗','song-poetry','','[]','每承勞問意何窮，尤喜真行字頗工。',64,'全唐诗/poet.song.53000.json','["每承勞問意何窮，尤喜真行字頗工。", "蕭散正如君子性，頡頏兼得古人風。", "曾經廷諍毫端直，自有家藏硯色紅。", "雅稱玉堂詞翰手，枉留山邑簿書中。"]'),
('fc496b19-f68b-4bf2-9ceb-8d6c762e05ad','至城南別祖仁未歸約文之不至','孔平仲','宋','宋诗','song-poetry','','[]','送客柳亭晚，倚欄秋雨酣。',48,'全唐诗/poet.song.53000.json','["送客柳亭晚，倚欄秋雨酣。", "風烟滿湖上，景物似江南。", "萧洒憐神往，從容憶手談。", "老來心易折，離緒已難堪。"]'),
('75627632-91ef-491b-bf35-4fd07b7823e8','對菊有懷郎祖仁','孔平仲','宋','宋诗','song-poetry','','[]','庭下金鈴菊，花開已十分。',48,'全唐诗/poet.song.53000.json','["庭下金鈴菊，花開已十分。", "多情能惠我，對景獨思君。", "秀色三秋好，清香一室聞。", "扁舟今夜雨，何處宿江雲。"]'),
('48a95bc8-6461-40d0-b173-c099976b2be7','寓興','孔平仲','宋','宋诗','song-poetry','','[]','薄寒初著裌衣裳，日景中分不短長。',64,'全唐诗/poet.song.53000.json','["薄寒初著裌衣裳，日景中分不短長。", "池館虛明開水石，園林摇落受風霜。", "黄花滿檻金鈴秀，白酒盈樽玉液香。", "未老不須雲母粉，且教弦管奏清商。"]'),
('acff1f7e-4b65-4ead-8699-c2e862cddbcb','知郡太博臨宴公宇詩以爲謝唐林夫在席','孔平仲','宋','宋诗','song-poetry','','[]','眷深賢守已忘形，肯屈旌旗到小亭。',64,'全唐诗/poet.song.53000.json','["眷深賢守已忘形，肯屈旌旗到小亭。", "坐有嘉賓仙骨秀，門無俗客暮山青。", "薦樽施遣供蔬甲，秉燭相隨看菊鈴。", "欲識主人書館淡，短檠燈火漆函經。"]'),
('7154fd0f-425c-4ffc-bd06-5e49c797d756','秋夕旅館談禪用元韵呈林夫','孔平仲','宋','宋诗','song-poetry','','[]','義以酬知不願形，孤標直氣蔚亭亭。',64,'全唐诗/poet.song.53000.json','["義以酬知不願形，孤標直氣蔚亭亭。", "天涯調官頭將白，江上論文眼倍青。", "自性本空觀水月，外塵相染喻風鈴。", "昨宵共說無生話，勝讀西來一藏經。"]'),
('5d084080-3272-4466-88dd-0c839740e66f','林夫訪及書室夜話又用元韵','孔平仲','宋','宋诗','song-poetry','','[]','珠玉相輝媿我形，正如朽壤附雲亭。',64,'全唐诗/poet.song.53000.json','["珠玉相輝媿我形，正如朽壤附雲亭。", "宦情已比春雲薄，交義猶期老柏青。", "坐久北窗號過雁，談餘荒戍咽疏鈴。", "知君不厭寒宵景，世上風霜已屢經。"]'),
('30b0f8e0-e195-4608-850a-25cf00ef45ce','至城東作  其一','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','地形磅礴接匡廬，曠野人烟乍有無。',64,'全唐诗/poet.song.53000.json','["地形磅礴接匡廬，曠野人烟乍有無。", "栖畝稻粱方待穫，識家雞犬各隨呼。", "農耕半嶺如僧衲，牧跨羸牛似畫圖。", "官守投閒省墳柏，滿林霜露涕沾濡。"]'),
('ab5a49dc-da19-48ec-b7d9-b7d120ffc6d3','至城東作  其二','孔平仲','宋','宋诗','song-poetry','','[]','出郭二十里，依山八九家。',48,'全唐诗/poet.song.53000.json','["出郭二十里，依山八九家。", "茅岡風卷燒，土井兩推沙。", "凍蝶依殘菊，幽禽立臥槎。", "路邊桃李木，猶發小春花。"]'),
('02f8ad61-b20b-41f8-82e7-366ed1fa9dae','惜菊','孔平仲','宋','宋诗','song-poetry','','[]','碧玉枝條手自分，花開晚節最憐君。',64,'全唐诗/poet.song.53000.json','["碧玉枝條手自分，花開晚節最憐君。", "斜簪短髮能迴老，滿泛清樽要助醺。", "著雨半荒猶爛漫，繞欄三嗅倍氤氳。", "更收殘蕊縫爲枕，長得好香深夜聞。"]'),
('73209bec-8c2b-42c4-9773-71229a37f101','西齋冬夕','孔平仲','宋','宋诗','song-poetry','','[]','平生疏野得江湖，歲暮西齋擁一爐。',64,'全唐诗/poet.song.53000.json','["平生疏野得江湖，歲暮西齋擁一爐。", "雨滴空階如自語，風吹長木更相呼。", "世間寵辱收棋局，樓上光陰入酒壺。", "近日睡時全少夢，攀緣狂想自知無。"]'),
('9a4921be-af0b-4b0e-b6ba-e7a85a3cb58d','冬夕即席作','孔平仲','宋','宋诗','song-poetry','','[]','燭滴胡桃淚，香蟠春蚓灰。',48,'全唐诗/poet.song.53000.json','["燭滴胡桃淚，香蟠春蚓灰。", "酒花隨煖聚，酥蕊带寒開。", "自有清歌送，惟聞畫角催。", "隔簾疑曉色，雪壓數枝梅。"]'),
('63922bd6-5d84-4d7c-bd89-c2f425a90491','至日作','孔平仲','宋','宋诗','song-poetry','','[]','年光吹盡任飛灰，且慶舒長舉壽杯。',64,'全唐诗/poet.song.53000.json','["年光吹盡任飛灰，且慶舒長舉壽杯。", "積晦彌旬三尺雨，新陽半夜一聲雷。", "家人環坐相酬勸，賀客先期戒往來。", "熟醉騰騰成小睡，晚寒更起恥殘罍。"]'),
('8fa1d993-55df-4664-a40e-aec5bbb4b8d9','小菴初成奉酬元師','孔平仲','宋','宋诗','song-poetry','','[]','伐竹誅茅挂織蒲，半規小榻一方爐。',64,'全唐诗/poet.song.53000.json','["伐竹誅茅挂織蒲，半規小榻一方爐。", "不隨健鶻摩空去，且免窮猿失木呼。", "自有琴書增道氣，別開世界在仙壺。", "幽人欲到知何意，若說真菴彼豈無。"]'),
('34cb2348-b2af-4dca-88b1-86ed89dd4cf6','口占','孔平仲','宋','宋诗','song-poetry','','[]','東皇旌節下蓬壺，一夕芳菲徧海隅。',64,'全唐诗/poet.song.53000.json','["東皇旌節下蓬壺，一夕芳菲徧海隅。", "紅破露花將引蝶，綠深烟柳已藏烏。", "異鄉旅食頻年久，故國風光此日殊。", "常是登高牽望眼，醉吟今喜在江湖。"]'),
('ba981d8f-dfb6-4bfe-889d-75dce1b7c449','寄常父','孔平仲','宋','宋诗','song-poetry','','[]','紅蓮綠水本優游，清絕東南七寶州。',64,'全唐诗/poet.song.53000.json','["紅蓮綠水本優游，清絕東南七寶州。", "見說新書亦多事，每聞沿檄少歸休。", "少年共計駒千里，末路堪嗟貉一丘。", "正是江邊桃李月，雞鳴度曲寄離憂。"]'),
('71953b89-290b-4c55-ae3a-5ecbed8717f0','和劉江寧韵送張天覺同年三首  其一','孔平仲','宋','宋诗','song-poetry','','[]','傾蓋逢吾喜，開樽爲子斟。',48,'全唐诗/poet.song.53000.json','["傾蓋逢吾喜，開樽爲子斟。", "笑談天下事，忠義古人心。", "戢翼丹霄遠，藏鱗赤壁深。", "彈冠行且起，朝列遲華簪。"]'),
('a67c8b6a-a44a-4947-b129-afa4db9e90dc','和劉江寧韵送張天覺同年三首  其二','孔平仲','宋','宋诗','song-poetry','','[]','酒可平孤悶，無辭滿滿斟。',48,'全唐诗/poet.song.53000.json','["酒可平孤悶，無辭滿滿斟。", "劍橫斗牛氣，松抱雪霜心。", "澤國波濤壯，春天霧雨深。", "清哀記風采，白筆舊曾簪。"]'),
('5f10680a-6a3c-4467-addc-59a86b36c804','和劉江寧韵送張天覺同年三首  其三','孔平仲','宋','宋诗','song-poetry','','[]','戲挹東溟水，期將北斗斟。',48,'全唐诗/poet.song.53000.json','["戲挹東溟水，期將北斗斟。", "大鵬誰振翼，老鸛未償心。", "卷箔江天靜，停檣野岸深。", "晨羞聊一飽，荻筍正如簪。"]'),
('f6e8267e-be9e-410d-88d4-9d976467da2c','寄題蕭升之姨夫竹軒','孔平仲','宋','宋诗','song-poetry','','[]','開軒君子意，種竹歲寒心。',48,'全唐诗/poet.song.53000.json','["開軒君子意，種竹歲寒心。", "高節凌雲秀，孤根得地深。", "秋暄溪上雨，暝宿嶺頭禽。", "預約疏三徑，他時伴醉吟。"]'),
('b749192b-9843-4bba-8abb-8790806d7b6b','席上送孫知損通直廣東漕','孔平仲','宋','宋诗','song-poetry','','[]','度峽經瀧行路難，嶺猿越鳥避旌竿。',64,'全唐诗/poet.song.53000.json','["度峽經瀧行路難，嶺猿越鳥避旌竿。", "身從日下恩光暖，聲落天南暑氣寒。", "事國以忠寧計遠，與人爲福莫如安。", "觀公才大宜高位，豈復區區久外官。"]'),
('a81da05e-1a47-48bf-b24f-231b03fb5f91','春晚遣興','孔平仲','宋','宋诗','song-poetry','','[]','紛紛柳絮入簾飛，正是酴醾花發時。',64,'全唐诗/poet.song.53000.json','["紛紛柳絮入簾飛，正是酴醾花發時。", "斷送日長惟有睡，留連春去可無詩。", "狂鞭迸筍偏當戶，綠葉成陰巧覆墀。", "百舌聲中斜照晚，翛然衰鬢任風吹。"]'),
('e8c2038c-3cce-4dfc-83ad-2b355541935f','上巳飲於湖上','孔平仲','宋','宋诗','song-poetry','','[]','城南春已老，湖上雨初晴。',72,'全唐诗/poet.song.53000.json','["城南春已老，湖上雨初晴。", "草作忘憂綠，風爲解慍清。", "楊花輕欲下，菱葉細方生。", "酒影低雲木，歌聲伴畫鶑。", "賞心殘蕊在，幽曲小舟橫。", "却笑蘭亭會，吟詩半不成。"]'),
('a9cf2686-32f4-4969-a514-15d2d9320e11','口占','孔平仲','宋','宋诗','song-poetry','','[]','積水深踰丈，高林繞若城。',48,'全唐诗/poet.song.53000.json','["積水深踰丈，高林繞若城。", "蝦蟆朝合吹，鸜鵒夜傳更。", "難轉長沙袖，空塵孺子纓。", "生涯吾尚闕，浥浥羨農耕。"]'),
('891d80f3-126c-4412-9f4d-a819503f96da','寄題蕭文照閣','孔平仲','宋','宋诗','song-poetry','','[]','虛明敞高閣，清淺對方塘。',48,'全唐诗/poet.song.53000.json','["虛明敞高閣，清淺對方塘。", "軒冕忘懷久，江湖寓興長。", "紅蕖開細雨，白鳥下殘陽。", "不挂人間事，逍遙自一鄉。"]'),
('c96b1786-b64c-419b-8acb-9e3b84af4fcb','謝郟正甫','孔平仲','宋','宋诗','song-poetry','','[]','當年輦轂參農正，今日江湖望歲星。',64,'全唐诗/poet.song.53000.json','["當年輦轂參農正，今日江湖望歲星。", "冷局自安心有素，故人相厚眼偏青。", "幅巾舒散殊官屬，華衮騰驤入帝庭。", "一薦未爲門下德，荷公敦篤好忘形。"]'),
('4dd4acb0-5f70-47fe-a8ac-ca7f59d5464f','送周文之主簿','孔平仲','宋','宋诗','song-poetry','','[]','俊逸駒千里，孤高桂一枝。',72,'全唐诗/poet.song.53000.json','["俊逸駒千里，孤高桂一枝。", "清才比栖棘，餘事付枯棋。", "小邑今官滿，當塗半己知。", "揚舲發江浦，策馬望京師。", "待詔須金馬，支床笑玉龜。", "都塵亦可畏，莫遣素衣緇。"]'),
('f28189a4-bdee-4cd2-83aa-f207978e46f3','夏日游湖亭','孔平仲','宋','宋诗','song-poetry','','[]','漫漫湖水拍堤浮，欲到南亭泛小舟。',64,'全唐诗/poet.song.53000.json','["漫漫湖水拍堤浮，欲到南亭泛小舟。", "平日登臨如別境，後來語笑尚中流。", "採菱斫鯉皆新美，賭酒圍棋自獻酬。", "對面火雲高萬丈，誰知此地有清秋。"]'),
('6357b472-93d9-436b-ba31-516990d005e7','倦夜','孔平仲','宋','宋诗','song-poetry','','[]','滅燭恐招蚊，迎風罷掩門。',48,'全唐诗/poet.song.53000.json','["滅燭恐招蚊，迎風罷掩門。", "讀書都已廢，就枕益加煩。", "缺月籠烟淡，羣星带暑昏。", "徐行得住處，荷葉滿南軒。"]'),
('919f9876-e519-4afa-b0ca-a99b2087718e','與張子明飲湖亭','孔平仲','宋','宋诗','song-poetry','','[]','小艇衝湖過，幽亭枕水虛。',48,'全唐诗/poet.song.53000.json','["小艇衝湖過，幽亭枕水虛。", "風來荷氣外，人在木陰餘。", "濕印開新酒，長茭族貫魚。", "遙看鶴歸處，便是謫仙居。"]'),
('441c6b1b-321b-42af-9eb4-e0ea8bffb539','大暑','孔平仲','宋','宋诗','song-poetry','','[]','澤國已炎暑，夏天仍永朝。',48,'全唐诗/poet.song.53000.json','["澤國已炎暑，夏天仍永朝。", "炙床爐燄熾，薰野水波摇。", "飛鳥不敢度，鳴蟬應自焦。", "可憐花葉好，顦顇苦霜凋。"]'),
('2c7bc421-0308-4d48-86c6-d1021b7c910b','入山馬上口占','孔平仲','宋','宋诗','song-poetry','','[]','奕奕秋光照眼明，野香山秀互相迎。',64,'全唐诗/poet.song.53000.json','["奕奕秋光照眼明，野香山秀互相迎。", "路穿蒙密無人見，天借陰凉助我行。", "水竇濺流如貝玉，松風疏韵作韶莖。", "一重一掩塵埃遠，故比城中分外清。"]'),
('06bbb2b3-fbe6-49fc-b094-890fee5b650a','再用元韵呈熊伯通','孔平仲','宋','宋诗','song-poetry','','[]','一望膺門眼已明，欣然倒屣辱公迎。',64,'全唐诗/poet.song.53000.json','["一望膺門眼已明，欣然倒屣辱公迎。", "林泉真作仙人宅，杖屨容參長者行。", "道論風生揮玉麈，渴心塵積飲金莖。", "匆匆短棹依城去，連日西齋夢寐清。"]'),
('8843263e-d4b2-45ca-b0a0-56ba47904b54','寄熊伯通','孔平仲','宋','宋诗','song-poetry','','[]','南山九疊勢千霄，中有長松蔭寸苗。',64,'全唐诗/poet.song.53000.json','["南山九疊勢千霄，中有長松蔭寸苗。", "好景常聞太平觀，謫仙更住上清橋。", "風吹石徑秋聲早，泉落雲根暑氣消。", "方外相期蒙雅眷，只應心隠不須招。"]'),
('9e9ee5e8-c828-4d73-b50d-7c3cd1616990','再用霄字韵','孔平仲','宋','宋诗','song-poetry','','[]','豁然披霧睹青霄，沛若爲霖洒旱苗。',64,'全唐诗/poet.song.53000.json','["豁然披霧睹青霄，沛若爲霖洒旱苗。", "身逐歸雲朝傃洞，心隨流水暮縈橋。", "人情不用相輕重，物理從來互長消。", "器業如公合廊廟，佇聞尺一有嘉招。"]'),
('420469d1-5538-4f00-b0fb-2ad7dfc655b0','初伏夜坐','孔平仲','宋','宋诗','song-poetry','','[]','露坐已侵夜，炎威猶未收。',48,'全唐诗/poet.song.53000.json','["露坐已侵夜，炎威猶未收。", "何言百蟲噪，無故一星流。", "苦渴須漿解，微凉以扇求。", "頒冰是今日，堆玉想神州。"]'),
('03ac46e3-1cf8-403f-b1e5-26d3439487f8','池上作','孔平仲','宋','宋诗','song-poetry','','[]','寂歷人初定，逍遙物已齊。',24,'全唐诗/poet.song.53000.json','["寂歷人初定，逍遙物已齊。", "夜凉天似水，月在小橋西。"]'),
('c1fabda3-e12a-47c5-8712-57fb62c61261','午眠','孔平仲','宋','宋诗','song-poetry','','[]','雨盪炎天氣，風生喬木陰。',24,'全唐诗/poet.song.53000.json','["雨盪炎天氣，風生喬木陰。", "清凉一枕睡，勝得萬黄金。"]'),
('ddaf2706-3192-4e66-a70a-b641659545f5','早秋','孔平仲','宋','宋诗','song-poetry','','[]','一雨洗煩熇，凉風開早秋。',48,'全唐诗/poet.song.53000.json','["一雨洗煩熇，凉風開早秋。", "散行身覺快，甘寢夢相求。", "已作黄花意，誰爲墮葉愁。", "南山青似染，準擬更登樓。"]'),
('bd4d88f6-fe81-43c0-be57-50d4a7b0236e','七夕','孔平仲','宋','宋诗','song-poetry','','[]','高列瓜華結綵樓，半空燈燭照清秋。',32,'全唐诗/poet.song.53000.json','["高列瓜華結綵樓，半空燈燭照清秋。", "祇應用盡人間巧，更欲遠從天上求。"]'),
('12c29589-5cf7-4157-bdbd-f3ae30dde149','送馬朝請使廣西','孔平仲','宋','宋诗','song-poetry','','[]','海水揚波今合清，秋風千里使華行。',64,'全唐诗/poet.song.53000.json','["海水揚波今合清，秋風千里使華行。", "言皆有道非徒發，事若無心更不生。", "談笑從容懷遠俗，琴書瀟灑寄高情。", "佇聞靜勝諸蠻服，何必樓船十萬兵。"]'),
('95604239-096f-4cbb-ac16-1045d8d09adf','八月十六日翫月','孔平仲','宋','宋诗','song-poetry','','[]','團團冰鏡吐清輝，今夜何如昨夜時。',64,'全唐诗/poet.song.53000.json','["團團冰鏡吐清輝，今夜何如昨夜時。", "只恐月光無好惡，自憐人意有盈虧。", "風摩露洗非常潔，地闊天高是處宜。", "百尺曹亭吾獨有，更教玉𥴦倚欄吹。"]'),
('007f30fe-8c00-4bad-b656-9426fd4f77a3','送郭明叔任分寧','孔平仲','宋','宋诗','song-poetry','','[]','西安瀟洒我常游，去自脩川泛小舟。',64,'全唐诗/poet.song.53000.json','["西安瀟洒我常游，去自脩川泛小舟。", "民本豐饒矜氣節，士多儒雅出公侯。", "梅山晚翠屏當戶，茶井春芽雪滿甌。", "預想弦歌富閒暇，白雲深倚鳳凰樓。"]'),
('354ce1ff-b416-4be5-a09e-c2a427fbab3f','送提舉太平觀熊舍人  其一','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','未歸西掖掌絲綸，且面南譙作守臣。',64,'全唐诗/poet.song.53000.json','["未歸西掖掌絲綸，且面南譙作守臣。", "三已何嘗觀慍色，一鳴從此却驚人。", "朱轓暫去求民瘼，黄闥行當秉國鈞。", "記取廬山公舊隠，幾多草木待青春。"]'),
('f159a769-9d12-433d-9761-fdf14604d827','送提舉太平觀熊舍人  其二','孔平仲','宋','宋诗','song-poetry','','[]','江州幾日到滁州，風送征帆暮不收。',64,'全唐诗/poet.song.53000.json','["江州幾日到滁州，風送征帆暮不收。", "幽谷水聲先入夢，爐峰山色遠隨舟。", "素無公事多閒暇，當有新詩自唱酬。", "寂寞舊居誰復顧，桂花深鎖一堂秋。"]'),
('bc3ee059-f8b6-464d-beca-6e4066353915','送提舉太平觀熊舍人  其三','孔平仲','宋','宋诗','song-poetry','','[]','高才喻蜀策巂羌，凜凜威名動四方。',64,'全唐诗/poet.song.53000.json','["高才喻蜀策巂羌，凜凜威名動四方。", "裁正稷宮新法度，發揮詞掖好文章。", "暫還紫府烟霞冷，却上青霄道路長。", "寄語吏民休浪喜，使君寧久在滁陽。"]'),
('a19404cf-897f-4cd3-8667-3c5b799f215c','熊伯通阻風未發拏舟就謁留飲數杯','孔平仲','宋','宋诗','song-poetry','','[]','清晨已送君南浦，薄暮未行天北風。',64,'全唐诗/poet.song.53000.json','["清晨已送君南浦，薄暮未行天北風。", "此別謾言千里遠，笑談還此一樽同。", "鐵山重疊雲垂地，玉馬騰驤浪駕空。", "涉險臨危須自戒，且維舟楫莫匆匆。"]'),
('221f3be4-1c07-4fd7-b1be-29519fecc25f','送沈行奉議赴辟陝西','孔平仲','宋','宋诗','song-poetry','','[]','除詔移關陝，征途半斗牛。',72,'全唐诗/poet.song.53000.json','["除詔移關陝，征途半斗牛。", "落帆江蒲月，躍馬戍垣秋。", "葱嶺霜吹劍，龍堆雪點裘。", "兵家破竹勢，幕府湧泉謀。", "且作從軍樂，安知出塞愁。", "觀公頗豐下，努力取封侯。"]'),
('43a29116-eb8f-4b52-bf64-50122b736a83','送覺茲住鳳山','孔平仲','宋','宋诗','song-poetry','','[]','十年虎谿老，却上羌山岑。',48,'全唐诗/poet.song.53000.json','["十年虎谿老，却上羌山岑。", "今回江西去，與人傳法音。", "谷虛聊應物，雲出本無心。", "猿鶴空相怨，舊菴松檜深。"]'),
('182b0124-ea10-4ae4-bbe3-87f8bee3ce0f','送覺茲住鳳山  其一','孔平仲','宋','宋诗','song-poetry','','[]','十年虎谿老，却上羌山岑。',24,'全唐诗/poet.song.53000.json','["十年虎谿老，却上羌山岑。", "今回江西去，與人傳法音。"]'),
('97a3c076-8d3b-4b26-988c-4f7f38978104','送覺茲住鳳山  其二','孔平仲','宋','宋诗','song-poetry','','[]','谷虛聊應物，雲出本無心。',24,'全唐诗/poet.song.53000.json','["谷虛聊應物，雲出本無心。", "猿鶴空相怨，舊菴松檜深。"]'),
('295dd53a-c174-4101-b563-df79490c89ab','九月十八日作','孔平仲','宋','宋诗','song-poetry','','[]','秋來常苦熱，今日令方行。',48,'全唐诗/poet.song.53000.json','["秋來常苦熱，今日令方行。", "浩浩風吹木，冥冥雨壓城。", "薄寒如解慍，殘序亦關情。", "曉鏡須驚老，催人白髮生。"]'),
('a08b5bd9-2e49-4582-9fee-d2f96124e887','蘇子由寄題小菴詩用元韵和','孔平仲','宋','宋诗','song-poetry','','[]','官身粗應三錢府，吏隠聊開一草菴。',64,'全唐诗/poet.song.53000.json','["官身粗應三錢府，吏隠聊開一草菴。", "擁砌幽篁如月映，覆簷喬木與天參。", "畏人自比藏頭雉，老世今同作蛹蠶。", "豈獨忘言兼閉息，舌津晨潄不勝甘。"]'),
('78b3b627-29b6-4e23-b66d-e583212ee449','陶寺丞挽詩','孔平仲','宋','宋诗','song-poetry','','[]','清德如彭澤，高名繼隠居。',48,'全唐诗/poet.song.53000.json','["清德如彭澤，高名繼隠居。", "弦歌非我志，泉石愛吾廬。", "世事冥心外，門風積慶餘。", "魚軒偕鶴髮，歸葬引雙車。"]'),
('087982c8-48e1-4ad8-a3d1-98da6d682d98','黄道士求詩戲爲口號贈之','孔平仲','宋','宋诗','song-poetry','','[]','黄君有術吾將面，不似尋常問進身。',32,'全唐诗/poet.song.53000.json','["黄君有術吾將面，不似尋常問進身。", "二頃良田數間屋，幾時得作一閒人。"]'),
('fdb4af9c-833f-40fc-863c-fdfcb3e20b19','冬晝作','孔平仲','宋','宋诗','song-poetry','','[]','霜陰收欲盡，斑駁意初晴。',48,'全唐诗/poet.song.53000.json','["霜陰收欲盡，斑駁意初晴。", "漸喜山將出，只愁雲更生。", "鳥窺晡後屋，雞唱午間城。", "灰拆紅爐火，微煎傍耳鳴。"]'),
('1e942943-9af0-4b8e-b6b0-d6cea0d9a803','十一月','孔平仲','宋','宋诗','song-poetry','','[]','欲雪還成雨，垂霜却變陰。',48,'全唐诗/poet.song.53000.json','["欲雪還成雨，垂霜却變陰。", "封疆五嶺近，甲子二冬深。", "密葉猶低戶，微風尚快襟。", "松筠雜蕭艾，都有歲寒心。"]'),
('8116208c-8f44-4096-a9f0-e794fbf22e6d','冬曉','孔平仲','宋','宋诗','song-poetry','','[]','城上猶吹角，官廳已罷更。',48,'全唐诗/poet.song.53000.json','["城上猶吹角，官廳已罷更。", "粗疏知我性，懶惰亦人情。", "入被嚴霜冷，橫窗半月明。", "翻身更甘寢，雞唱第三聲。"]'),
('9593f60d-dcf2-4a0e-a769-e930d55463ef','正月三日唐林夫舟中醉題','孔平仲','宋','宋诗','song-poetry','','[]','屢伏青蒲地，嘗登羣玉山。',48,'全唐诗/poet.song.53000.json','["屢伏青蒲地，嘗登羣玉山。", "家貧甘遠適，道直得生還。", "瘴癘謳吟外，風波笑傲間。", "今朝一樽酒，萬事付酡顔。"]'),
('d02375c5-2143-4f45-ace0-67078e900542','四日郡集於景德寺','孔平仲','宋','宋诗','song-poetry','','[]','冷鐸殘香僧舍開，斜風細雨坐中來。',32,'全唐诗/poet.song.53000.json','["冷鐸殘香僧舍開，斜風細雨坐中來。", "使君豈是憎歌舞，自出胡琴送酒杯。"]'),
('1ec7c5e0-e0dd-436a-97e6-dee189448f67','馬上口占','孔平仲','宋','宋诗','song-poetry','','[]','澗底泉初動，山頭雪尚深。',48,'全唐诗/poet.song.53000.json','["澗底泉初動，山頭雪尚深。", "凍條桑破眼，燒地草抽心。", "摇落殊非昔，芳菲想自今。", "浮雲多意思，已解作春陰。"]'),
('aad4b495-b96f-4777-acd9-b2f79477eaef','守倅自開元觀食起欲往紫極宮道過余之家園乃屈同游太守自以爲能知地形余故議卜居之處也以詩謝焉','孔平仲','宋','宋诗','song-poetry','','[]','東已窺丹井，西將造嘿軒。',72,'全唐诗/poet.song.53000.json','["東已窺丹井，西將造嘿軒。", "半途留使騎，枉道至家園。", "敗葉深埋砌，清陰密擁門。", "生涯爲廢宅，景物似荒村。", "經始慚謀拙，臨軒肯屈尊。", "竹間煩佇立，高誼見公存。"]'),
('40e951e8-be8a-4879-b123-9de2d591b2ab','據案小睡','孔平仲','宋','宋诗','song-poetry','','[]','春氣已回人困頓，雨聲不斷夜潺湲。',64,'全唐诗/poet.song.53000.json','["春氣已回人困頓，雨聲不斷夜潺湲。", "四支退食昏如醉，兩眼看書澀有烟。", "散帙橫經那肯讀，埋頭曲肘即成眠。", "只愁稚子窺吾懶，豈畏諸公誚腹便。"]'),
('312c93fc-6fae-4fe3-8b62-6d19dd4f87ff','南軒','孔平仲','宋','宋诗','song-poetry','','[]','細雨紛紛不見山，卷簾烟景畫圖間。',32,'全唐诗/poet.song.53000.json','["細雨紛紛不見山，卷簾烟景畫圖間。", "一池春水風吹皺，戲鴨鳴鷗作隊閒。"]'),
('085ce402-512a-45a0-a7b6-5c59d78154eb','戲爲難韵同官和之','孔平仲','宋','宋诗','song-poetry','','[]','稚柳將成線，殘梅尚有柎。',48,'全唐诗/poet.song.53000.json','["稚柳將成線，殘梅尚有柎。", "破春寒料峭，送晚角喑嗚。", "地僻閒賓榻，泥深隔酒壚。", "此時愁寂寞，幽悶寄操觚。"]'),
('c31d96cc-605d-4eb1-8ed9-c9b7f5346968','賈誼','孔平仲','宋','宋诗','song-poetry','','[]','措置由來有後先，運行無跡盍觀天。',32,'全唐诗/poet.song.53000.json','["措置由來有後先，運行無跡盍觀天。", "色黄數五疑非急，此事知君正少年。"]'),
('0fff0d23-33a0-4887-b275-42486e83afb5','子瞻子由各有寄題小菴詩却用元韵和呈','孔平仲','宋','宋诗','song-poetry','','[]','二公俊軌皆千里，兩首新詩寄一菴。',64,'全唐诗/poet.song.53000.json','["二公俊軌皆千里，兩首新詩寄一菴。", "大隠市朝希柱史，好奇兄弟有岑參。", "雪天凍坐癡于雀，雨夕春眠困若蠶。", "不是本來忘世味，便投閒寂亦難甘。"]'),
('279bf4a9-d838-4a90-94ef-428058ac59d2','久雨不止二月半以敕醮廬山真君殿入夜星月皎然','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','連朝苦陰雨，入夜月華新。',48,'全唐诗/poet.song.53000.json','["連朝苦陰雨，入夜月華新。", "清醮今當夕，真君信有神。", "燈光想如晝，香氣自生春。", "水旱多爲害，當思今爲民。"]'),
('c95cfd97-2e47-4cdf-a8c9-75ca9e6adceb','寄題蕭丈止亭','孔平仲','宋','宋诗','song-poetry','','[]','削跡忘當世，開亭枕近郊。',48,'全唐诗/poet.song.53000.json','["削跡忘當世，開亭枕近郊。", "情非惡冕紱，樂不似衡茅。", "靜看雲歸岫，閒知鸛在巢。", "春風動幽興，植杖數花苞。"]'),
('de2ebb46-6594-4139-9c45-1b00f817f1e5','春夜','孔平仲','宋','宋诗','song-poetry','','[]','酒醒殘月在西廂，悄悄重城春夜長。',32,'全唐诗/poet.song.53000.json','["酒醒殘月在西廂，悄悄重城春夜長。", "何物與人清意思，瑞香花發一亭香。"]'),
('4b8f4359-4169-480c-8bd8-4b5b2d823a19','和經父寄張績','孔平仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','蕭蕭木落洞庭湖，一葉扁舟盡室居。',64,'全唐诗/poet.song.53000.json','["蕭蕭木落洞庭湖，一葉扁舟盡室居。", "吾道已衰投直筆，人情難合卷長裾。", "重輕自繫朝廷勢，褒貶猶存史策書。", "所遇于天皆有分，未將鯢鮒羨鯨魚。"]'),
('0425e688-02bb-485d-8c58-d6fe44584316','阻風呈經父','孔平仲','宋','宋诗','song-poetry','','[]','風響翻空若疾雷，舟行值此頗淹回。',64,'全唐诗/poet.song.53000.json','["風響翻空若疾雷，舟行值此頗淹回。", "坐看鷗鶩浮波去，近見蛟龍带雨來。", "春色未還江上柳，雪香誰寄嶺頭梅。", "欲收美景陪清唱，恨乏當時子建才。"]'),
('1fb3f90b-8ef6-45f9-aa40-f80155c5bd5c','詠櫓','孔平仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','以小能行大，天機寄物形。',96,'全唐诗/poet.song.53000.json','["以小能行大，天機寄物形。", "沿流最有助，深壑屢嘗經。", "迅速功無比，謳鴉韵可聽。", "江空插羽翼，水府散雷霆。", "駕浪來湘浦，摇風過洞庭。", "侵凌秋島霧，破碎暮灣星。", "雁鶩驚羣起，蛟龍睡一醒。", "浩然乘此興，東去絕滄溟。"]'),
('ff86a009-807b-4a8e-bb13-819f2b6876dc','詠柁','孔平仲','宋','宋诗','song-poetry','','[]','厥初誰創物，似此亦難求。',96,'全唐诗/poet.song.53000.json','["厥初誰創物，似此亦難求。", "擺合千尋浪，回旋萬斛舟。", "行如一臥扇，力敵九氂牛。", "出沒居相半，東西勢自由。", "高風當絕倚，淺瀨亦徐收。", "軋軋微鳴曉，峨峨迥浸秋。", "隨灣掉轉尾，避石掣開頭。", "自有施功地，何嘗厭下流。"]'),
('5d393f81-c413-4a12-9b8e-8efda13cfaf7','至日阻風飲於轉運行衙呈經父','孔平仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','枉渚停風棹，華堂置酒壺。',48,'全唐诗/poet.song.53000.json','["枉渚停風棹，華堂置酒壺。", "雲低岳陽市，雪滿洞庭湖。", "醉眼看梅蕊，歡心合棣柎。", "去年今夕夢，江國面京都。"]'),
('e06bcb52-191f-4a95-8815-a2677d23a0cd','和經父寄張績  其一','孔平仲','宋','宋诗','song-poetry','','[]','解縱裊鴟啄鳳凰，天心似此亦難詳。',64,'全唐诗/poet.song.53000.json','["解縱裊鴟啄鳳凰，天心似此亦難詳。", "但知斬馬憑孤劍，豈爲摧車避太行。", "得者折腰猶下列，失之垂翅合南翔。", "不如長揖塵埃去，同老逍遙物外鄉。"]'),
('cce2258b-9041-4973-9e27-55428c144ddb','和經父寄張績  其二','孔平仲','宋','宋诗','song-poetry','','[]','半通官職萬人才，卷蓄經綸未得開。',64,'全唐诗/poet.song.53000.json','["半通官職萬人才，卷蓄經綸未得開。", "鸞鳳託巢雖枳棘，神仙定籍已蓬萊。", "但存漆室葵心在，莫學荆山玉淚哀。", "倚伏萬端寧有定，塞翁失馬尚歸來。"]'),
('99c218d6-847d-4e0c-8856-625ab0ad3ddd','和經父登黄鶴樓','孔平仲','宋','宋诗','song-poetry','','[]','複靄重沙望不窮，坐收千里一樽中。',64,'全唐诗/poet.song.53000.json','["複靄重沙望不窮，坐收千里一樽中。", "天邊江漢波濤闊，地下神仙窟宅通。", "窗影偷來湓浦白，簷光飛入沔城紅。", "豁然已盡登臨興，雲閣章亭謾在東。"]'),
('ae41ee99-030c-4300-af16-52cbcc31b73e','詠冰','孔平仲','宋','宋诗','song-poetry','','[]','厚薄因風結，方圓隨器成。',48,'全唐诗/poet.song.53000.json','["厚薄因風結，方圓隨器成。", "黄河白馬渡，大澤老狐行。", "暖曲流雲液，隅甃晃水精。", "皎然心一寸，願比玉壺清。"]'),
('e8fe4a97-6f1d-43fc-9199-a3c873c1da52','詠網','孔平仲','宋','宋诗','song-poetry','','[]','已向晴漪下，還于晚架張。',48,'全唐诗/poet.song.53000.json','["已向晴漪下，還于晚架張。", "鱗餘銀皎皎，目带淚浪浪。", "細入詩人詠，輕隨釣叟裝。", "結繩相效久，遺象本歸藏。"]'),
('cd82855a-0934-410a-8400-e896475e907d','瑞香花','孔平仲','宋','宋诗','song-poetry','','[]','去年荆楚賞芳菲，今歲江淮水渺瀰。',64,'全唐诗/poet.song.53000.json','["去年荆楚賞芳菲，今歲江淮水渺瀰。", "綠髮方當少壯日，清樽不負艷陽時。", "風波此去猶千里，桃杏何緣見一枝。", "獨有瑞香花兩檻，遠將春色自相隨。"]'),
('28c9f36c-7395-43db-9208-8291fe6c63fd','李白祠堂  其一','孔平仲','宋','宋诗','song-poetry','','[]','灑落風標真謫仙，精神猶恐筆難傳。',32,'全唐诗/poet.song.53000.json','["灑落風標真謫仙，精神猶恐筆難傳。", "文章若出斯人手，壯浪雄豪一自然。"]'),
('85870db0-c7dd-4c50-866e-82a447d976fb','李白祠堂  其二','孔平仲','宋','宋诗','song-poetry','','[]','太白之精出李白，詩中元帥酒家豪。',32,'全唐诗/poet.song.53000.json','["太白之精出李白，詩中元帥酒家豪。", "軒然眉目已如此，况著當年宮錦袍。"]'),
('32ee968c-08c2-43b6-8d03-e2930415d3ad','雙頭牡丹','孔平仲','宋','宋诗','song-poetry','','[]','牡丹意態已無窮，况是連房鬭淺紅。',64,'全唐诗/poet.song.53000.json','["牡丹意態已無窮，况是連房鬭淺紅。", "曉色競開雙萼上，春光分占一枝中。", "娥英窈窕臨湘浦，姊妹輕盈倚漢宮。", "只爲多嬌便相妬，芳心相隔不相同。"]'),
('9797578f-f313-47c5-9c6e-ca80737be031','寄經父','孔平仲','宋','宋诗','song-poetry','','[]','借問東來常太晚，富春亭下艤扁舟。',64,'全唐诗/poet.song.53000.json','["借問東來常太晚，富春亭下艤扁舟。", "陰天漠漠行梅雨，寒色蕭蕭報麥秋。", "曲渚浪平猶未渡，隔江風緊不勝愁。", "此中望斷相思眼，家在蓬萊更倚樓。"]'),
('c56bf113-9d4d-4628-91ea-0f92cf677453','選官圖口號','孔平仲','宋','宋诗','song-poetry','','[]','環合官圖展，觀呼象子圓。',96,'全唐诗/poet.song.53000.json','["環合官圖展，觀呼象子圓。", "飛騰隨八赤，摧折在雙玄。", "已貴翻投裔，將薨却上天。", "須臾文換武，俄頃後馳先。", "錯雜賢愚品，偏頗造化權。", "望移情欲脫，患失膽俱懸。", "慍色觀三已，豪心待九遷。", "寧知即罷局，榮辱兩茫然。"]'),
('28a054f5-c66a-4604-81cc-a555448de29a','熙寧四年中秋','孔平仲','宋','宋诗','song-poetry','','[]','月滿光尤好，秋殷氣更清。',48,'全唐诗/poet.song.53000.json','["月滿光尤好，秋殷氣更清。", "頻年苦陰雨，此夜獨清明。", "後閣羅甥妹，前堂合弟兄。", "團圓最相稱，盡飲至更深。"]'),
('bc2e0d20-96cc-4910-87b2-75de209795ba','和舍弟送行至密州','孔平仲','宋','宋诗','song-poetry','','[]','一覽鳳凰句，况當鴻雁秋。',48,'全唐诗/poet.song.53000.json','["一覽鳳凰句，况當鴻雁秋。", "雲山回倦首，烟雨上扁舟。", "土俗京東陋，官居學舍幽。", "蓬萊醉中夢，尋我海邊州。"]'),
('1724ee1c-8640-40e9-a9d5-790676f7fc52','次韵和堂父發越州','孔平仲','宋','宋诗','song-poetry','','[]','北堂相送出城西，忍見臨分獨自歸。',64,'全唐诗/poet.song.53000.json','["北堂相送出城西，忍見臨分獨自歸。", "日暮荒村一回首，秋風吹涕各沾衣。", "水通鑑曲行將盡，山似稽陰認却非。", "薄宦牽攣不得已，此心何以報春暉。"]'),
('34b269a6-6583-4d55-9949-dd3722fe1edb','渡浙江未得','孔平仲','宋','宋诗','song-poetry','','[]','辭家已四日，三日雨兼風。',48,'全唐诗/poet.song.53000.json','["辭家已四日，三日雨兼風。", "海水飛天上，江雲入坐中。", "愁腸寒更結，歸夢濕難通。", "未有淹留恨，封圻尚淛東。"]'),
('2e87b409-9703-4966-acb5-c14fc0c35802','西興','孔平仲','宋','宋诗','song-poetry','','[]','舟行頗濡滯，累日驛前溪。',48,'全唐诗/poet.song.53000.json','["舟行頗濡滯，累日驛前溪。", "大雨翻盆盎，狂風作鼓鼙。", "兩潮空朝晚，一水限東西。", "憶昔游湖棹，新晴傍會稽。"]'),
('4ee8d905-6c52-49d8-bd91-5b34479f94b0','懷越','孔平仲','宋','宋诗','song-poetry','','[]','城隍壓高峻，樓觀抱青蒼。',48,'全唐诗/poet.song.53000.json','["城隍壓高峻，樓觀抱青蒼。", "東磴迎風細，西池引步長。", "蓬萊山刻畫，清白水甘香。", "海內行幾半，茲遊最不忘。"]'),
('acf38040-9d4e-4135-9d15-c03a5debf9ba','次韵和常父渡江寄經父','孔平仲','宋','宋诗','song-poetry','','[]','江風初息浪花低，軋軋扁舟犯曉雞。',32,'全唐诗/poet.song.53000.json','["江風初息浪花低，軋軋扁舟犯曉雞。", "想得蓬萊秋睡覺，暖寒方索玉東西。"]'),
('73b065ca-a337-4581-a00e-095fc329ae3e','新開湖','孔平仲','宋','宋诗','song-poetry','','[]','湖應與海接，歲暮水猶多。',48,'全唐诗/poet.song.53000.json','["湖應與海接，歲暮水猶多。", "浄色平蒼野，餘香積敗荷。", "舟行依累石，鳬起散圓波。", "誰似漁翁樂，鳴榔作楚歌。"]'),
('02e6e950-3eeb-4d16-8d50-4ea23ba975b2','題清斯堂','孔平仲','宋','宋诗','song-poetry','','[]','河流與淮接，於此一堂成。',48,'全唐诗/poet.song.53000.json','["河流與淮接，於此一堂成。", "水色已可愛，主人心更清。", "魚潜晚日靜，柳落秋空明。", "本自無塵土，何須歌濯纓。"]'),
('739b687f-d646-4fd9-b47d-4f0d47bf2241','發山陽','孔平仲','宋','宋诗','song-poetry','','[]','黄昏飲官酒，半夜解扁舟。',48,'全唐诗/poet.song.53000.json','["黄昏飲官酒，半夜解扁舟。", "鈎簾得清景，風月滿淮流。", "天垂與波接，野靜更烟浮。", "深有乘槎興，銀河或可求。"]'),
('b76ae313-fe3d-4526-a874-67e970263675','送登州太守出城馬上作','孔平仲','宋','宋诗','song-poetry','','[]','匆匆送客出城闉，霜意方高日漸醺。',64,'全唐诗/poet.song.53000.json','["匆匆送客出城闉，霜意方高日漸醺。", "青嶂倚空先有雪，黄沙匝地半和雲。", "旌旗明滅隨車遠，鼓角悲凉隔水聞。", "正是無憀一回首，兩行白馬映紅裙。"]'),
('0ed36b7d-2edf-4d17-9085-f43f0128bc6a','呈夢錫節推林思永察推','孔平仲','宋','宋诗','song-poetry','','[]','崎嶇寒苦遠騰裝，喜得高才共此方。',64,'全唐诗/poet.song.53000.json','["崎嶇寒苦遠騰裝，喜得高才共此方。", "當以清談銷日月，更將和氣敵冰霜。", "堂前絳帳慚容迹，幕下紅蓮幸借香。", "閒夕肯來相伴否，小窗殘燭厭更長。"]'),
('cf8c6af5-7540-4004-bac1-2cccdb56add6','適值劉從道供奉往信陽鎮用前韵送之','孔平仲','宋','宋诗','song-poetry','','[]','君馬匆匆赴信陽，雖云同郡似它方。',64,'全唐诗/poet.song.53000.json','["君馬匆匆赴信陽，雖云同郡似它方。", "村沙卷盡黄昏日，海水吹成半夜霜。", "別恨不須青草色，歸期當及小桃香。", "閒官冷局遙相望，兩覺迢迢歲月長。"]'),
('6f234114-ed03-4d55-872e-3bf335452d7e','夢錫同遊賀園題詩云誰知清淡者冬月亦登臨','孔平仲','宋','宋诗','song-poetry','','[]','寒景崢嶸歲已深，誰知清淡亦登臨。',64,'全唐诗/poet.song.53000.json','["寒景崢嶸歲已深，誰知清淡亦登臨。", "雨吹廢館苔添暈，霜落空城樹減陰。", "向曉旋留題葉句，隔年先有探花心。", "相期紅藥濃開日，一醉東風費萬金。"]'),
('b795da19-acee-4dc5-8444-0ee6fac0994a','新作書室夢錫示詩羨其清坐','孔平仲','宋','宋诗','song-poetry','','[]','新闢西垣小室成，開編靜得古人情。',64,'全唐诗/poet.song.53000.json','["新闢西垣小室成，開編靜得古人情。", "崢嶸老柏寒尤健，窈窕幽窗雪更明。", "我愧濫巾居此地，君能傾蓋似平生。", "篇詩何必深相羨，淥水芙蓉豈不清。"]'),
('c2be827d-fb9e-4190-9395-941a1c451e60','呈幕客','孔平仲','宋','宋诗','song-poetry','','[]','夜雨曉未歇，清寒侵客顔。',48,'全唐诗/poet.song.53000.json','["夜雨曉未歇，清寒侵客顔。", "雲昏天带海，風闊地無山。", "蓮幕君籌畫，茅齋我閉關。", "新書正多事，何幸擁爐閒。"]'),
('649bab0d-3abf-46a6-a883-265c136e01e1','寄從道','孔平仲','宋','宋诗','song-poetry','','[]','相逢苦不早，相別又匆匆。',48,'全唐诗/poet.song.53000.json','["相逢苦不早，相別又匆匆。", "祖席侵華燭，征車傍北風。", "車斜酬唱闕，爾汝笑談空。", "遙想支頤處，孤村海霧中。"]'),
('d1de91ee-f4a4-4745-be79-23ac9929affb','晚晴見雪呈夢錫','孔平仲','宋','宋诗','song-poetry','','[]','東北風聲急，西南日景斜。',96,'全唐诗/poet.song.53000.json','["東北風聲急，西南日景斜。", "斷雲方散錦，飛雪忽成花。", "見落初猶少，量深久漸加。", "遠天明映玉，晴地濕團沙。", "浩蕩隨陰氣，須臾變水華。", "清輝迷粉蝶，寒色带昏鴉。", "又是流年暮，同居滄海涯。", "寂寥求自遣，小詠寄詩家。"]'),
('fee09323-e705-4aa0-8420-e944b955ae13','立春','孔平仲','宋','宋诗','song-poetry','','[]','春風不擇地，亦到海邊城。',48,'全唐诗/poet.song.53000.json','["春風不擇地，亦到海邊城。", "衮衮衣冠會，喧喧鼓吹迎。", "爲牛一何苦，舉世盡相爭。", "旅客心偏靜，停杯想耦耕。"]'),
('f49ad836-b943-46c4-9582-f525dc8cb1a8','春雪','孔平仲','宋','宋诗','song-poetry','','[]','纔喜春風昨夜歸，凌晨又見雪飄衣。',64,'全唐诗/poet.song.53000.json','["纔喜春風昨夜歸，凌晨又見雪飄衣。", "綴林似惜梅花落，撲地爭先柳絮飛。", "寒氣却迴侵暖律，陰雲徐上蔽晴暉。", "近來四序皆無主，欲向東皇問是非。"]'),
('5af8fb51-b382-4e4f-9a74-5ac23d9cd340','正月十四夜','孔平仲','宋','宋诗','song-poetry','','[]','都人行正樂，天氣忽微陰。',48,'全唐诗/poet.song.53000.json','["都人行正樂，天氣忽微陰。", "盡恐明朝雪，如何此夕心。", "輪蹄迷道遠，鼓吹亂更深。", "我獨甘幽靜，青燈照苦吟。"]'),
('33a026e4-9be9-4572-9f43-ba564c554e56','十五夜','孔平仲','宋','宋诗','song-poetry','','[]','今宵好元夕，去歲大豐年。',48,'全唐诗/poet.song.53000.json','["今宵好元夕，去歲大豐年。", "委巷通車馬，高臺奏管弦。", "燈光照人暖，月色爲時圓。", "此樂真難得，無辭酒滿船。"]'),
('25dee50f-dcdf-4e46-a3d8-acf27328120b','十六夜','孔平仲','宋','宋诗','song-poetry','','[]','明夜更無今夜燈，都人爲此不勝情。',64,'全唐诗/poet.song.53000.json','["明夜更無今夜燈，都人爲此不勝情。", "皆愁隔歲期猶遠，共約追歡直到明。", "君飲露臺春易醉，我眠書館月同清。", "東風亦有相撩意，夢覺猶傳弦管聲。"]'),
('89aef200-f902-4935-99d2-293094294add','春陽','孔平仲','宋','宋诗','song-poetry','','[]','春陽已出地，冰雪尚崢嶸。',48,'全唐诗/poet.song.53000.json','["春陽已出地，冰雪尚崢嶸。", "半作泥塗濕，尤妨車馬行。", "溪流成小派，海氣亂新晴。", "湮鬰須披豁，誰同上古城。"]'),
('61d74c8d-9923-4900-a051-f7c968a6e581','古來','孔平仲','宋','宋诗','song-poetry','','[]','古來豪俊起，大半在山東。',72,'全唐诗/poet.song.53000.json','["古來豪俊起，大半在山東。", "甚矣承平久，蕭然武備空。", "封疆瀕北狄，士卒戍西戎。", "器械恬兒戲，城隍駭土功。", "朝廷急掃敝，草莽許輸忠。", "元恨天門遠，無由半策通。"]'),
('24807344-674a-4282-8811-ebf66858b342','次韵和常父  其一','孔平仲','宋','宋诗','song-poetry','','[]','臥龍當日醉吟身，冷落天涯一旅人。',64,'全唐诗/poet.song.53000.json','["臥龍當日醉吟身，冷落天涯一旅人。", "早夕思親增悵望，嘯歌懷古更愁辛。", "角吹海上千山月，草入江南萬里春。", "欲去尚留心未决，夢魂長在越谿濱。"]'),
('49d362b8-6679-49a3-ab13-4ee4334b975a','次韵和常父  其二','孔平仲','宋','宋诗','song-poetry','','[]','赴官並出江湖上，講學聯居海岱中。',64,'全唐诗/poet.song.53000.json','["赴官並出江湖上，講學聯居海岱中。", "會合尤嗟別離促，音書何似笑言同。", "黄鶑度曲爭催曉，紅杏薰香半倚風。", "景物佳時憶相見，恨無雙翅逐飛鴻。"]'),
('ab5ba305-8fc7-4801-8adb-3ec6cc25d2a4','寄常父','孔平仲','宋','宋诗','song-poetry','','[]','歷城未到已嘗聞，文綵魚鹽市不貧。',64,'全唐诗/poet.song.53000.json','["歷城未到已嘗聞，文綵魚鹽市不貧。", "千里山川齊故地，百年風俗舜遺民。", "泉聲滑滑長如雨，海氣昏昏晚得春。", "北渚環波皆好景，爲兄詩筆長精神。"]'),
('02799377-d5da-48ff-af75-520cf584c49d','春色最佳呈夢錫  其一','孔平仲','宋','宋诗','song-poetry','','[]','小雨初收物象新，日華徐上氣氤氳。',32,'全唐诗/poet.song.53000.json','["小雨初收物象新，日華徐上氣氤氳。", "欲知春色最佳處，萬里青山無片雲。"]'),
('20b9f391-08ec-4b40-8c95-f6d9286c81ed','春色最佳呈夢錫  其二','孔平仲','宋','宋诗','song-poetry','','[]','探遍名園花未紅，高臺極目興何窮。',32,'全唐诗/poet.song.53000.json','["探遍名園花未紅，高臺極目興何窮。", "欲知春色最佳處，盡在綠楊深淺中。"]'),
('771d8efa-1cc9-4f8a-acd9-71f252e6fada','春色最佳呈夢錫  其三','孔平仲','宋','宋诗','song-poetry','','[]','紅日遲遲晝未央，北窗高枕傲羲皇。',32,'全唐诗/poet.song.53000.json','["紅日遲遲晝未央，北窗高枕傲羲皇。", "欲知春色最佳處，啼鳥一聲幽夢長。"]'),
('6b90d412-9b67-4e9f-999d-c9ddd81c7e6e','春閨六言  其一','孔平仲','宋','宋诗','song-poetry','','[]','夢回紅玉孤枕，日上真珠半簾。',56,'全唐诗/poet.song.53000.json','["夢回紅玉孤枕，日上真珠半簾。", "雲彩陰晴不定，柳梢濃淡相兼。", "雁柱怨憑曲寄，獸爐愁逐香添。", "更倚危樓目斷，却訴東風淚沾。"]'),
('9a14b15c-dcd0-4f0f-9205-984f14e9d8e6','春閨六言  其二','孔平仲','宋','宋诗','song-poetry','','[]','燕子舞開烟綠，杜鵑啼破花紅。',56,'全唐诗/poet.song.53000.json','["燕子舞開烟綠，杜鵑啼破花紅。", "滿地夕陽芳草，有時細雨斜風。", "錦帳尚寒夢短，彩牋雖遠情通。", "淚痕染在襟上，愁緒織向機中。"]'),
('0385ca29-1dfc-4f6b-8e6e-ecfaefee87c9','登資聖閣','孔平仲','宋','宋诗','song-poetry','','[]','平時嘗仰望，今日一登臨。',48,'全唐诗/poet.song.53000.json','["平時嘗仰望，今日一登臨。", "海岱封疆小，乾坤氣象深。", "廢城增古意，疊嶂起詩心。", "遠目方馳騁，春雲還自陰。"]'),
('6625a201-e9fb-49b8-8510-bc1d07cad6ea','上巳','孔平仲','宋','宋诗','song-poetry','','[]','上巳陪游騎，城南俯落暉。',48,'全唐诗/poet.song.53000.json','["上巳陪游騎，城南俯落暉。", "溪山俱可愛，花木自相依。", "佳節雖行樂，他邦未得歸。", "蘭亭應禊飲，回首白雲飛。"]'),
('cd255f0c-4a7e-4037-90f6-c765791cc05a','八日','孔平仲','宋','宋诗','song-poetry','','[]','花下飲餘留晚轡，溪邊行處把春衫。',32,'全唐诗/poet.song.53000.json','["花下飲餘留晚轡，溪邊行處把春衫。", "東風作惡波微起，不得移舟滴水巖。"]'),
('a59139b4-a487-40fc-bc3d-1dff407aa696','寄常父','孔平仲','宋','宋诗','song-poetry','','[]','繚繞龍山半府陰，春來漂泊阻登臨。',64,'全唐诗/poet.song.53000.json','["繚繞龍山半府陰，春來漂泊阻登臨。", "蓬萊閣下花多少，清曠亭前水淺深。", "暮靄漫天迷望目，東風絕海送歸心。", "新詩亦有思家意，應記當年共醉吟。"]'),
('e5a2c983-2051-4671-a56b-aa5b3261f9b4','行香','孔平仲','宋','宋诗','song-poetry','','[]','枕上杜鵑啼，匆匆早起時。',24,'全唐诗/poet.song.53000.json','["枕上杜鵑啼，匆匆早起時。", "出行天未曉，月在杏花枝。"]'),
('ffeab812-54ec-4a49-96a8-fb2fb15095db','次韵和昌齡落梅','孔平仲','宋','宋诗','song-poetry','','[]','玉摧繁艷蕙消香，漸見園林綠葉光。',32,'全唐诗/poet.song.53000.json','["玉摧繁艷蕙消香，漸見園林綠葉光。", "莫誚春風少情思，爲君開徧萬紅芳。"]'),
('e4f70059-ec3f-4550-bf41-1e23916449b7','登賀園高亭','孔平仲','宋','宋诗','song-poetry','','[]','東武名園數賀家，更於高處望春華。',32,'全唐诗/poet.song.53000.json','["東武名園數賀家，更於高處望春華。", "深紅淺白知多少，直到南山盡是花。"]'),
('61707800-33d7-411a-9c26-79e62cd5318f','戲促二幕客','孔平仲','宋','宋诗','song-poetry','','[]','寄語紅蓮幕，當歌金縷衣。',24,'全唐诗/poet.song.53000.json','["寄語紅蓮幕，當歌金縷衣。", "探春曾有約，今日已春歸。"]'),
('5b2947b1-b1f1-4d58-9b45-f9fe3e6a3405','晝眠呈夢錫','孔平仲','宋','宋诗','song-poetry','','[]','百忙之際一閒身，更有高眠可詫君。',64,'全唐诗/poet.song.53000.json','["百忙之際一閒身，更有高眠可詫君。", "春入四支濃似酒，風吹孤夢亂如雲。", "諸生弦誦何妨靜，滿席圖書不廢勤。", "向晚欠伸徐出戶，落花簾外自紛紛。"]'),
('985f55f7-71e0-49f1-ae73-ef0a0b55e430','初食牂牁菜','孔平仲','宋','宋诗','song-poetry','','[]','九仙山中牂牁菜，幾日春風長綠苗。',64,'全唐诗/poet.song.53000.json','["九仙山中牂牁菜，幾日春風長綠苗。", "有客提携到深巷，自言采掇下青霄。", "口嘗異味雖珍美，目斷孤雲却寂寥。", "千里思親不獨飽，慨然食罷一長謠。"]'),
('f3fd4e59-4425-4c46-94b3-a3535fe5e806','呈王子高殿丞','孔平仲','宋','宋诗','song-poetry','','[]','天上人間事不同，相思何日却相逢。',32,'全唐诗/poet.song.53000.json','["天上人間事不同，相思何日却相逢。", "芙蓉城在蓬萊外，海闊波深千萬重。"]'),
('531b4892-4b7b-43fd-a1ac-eaad5d8329dc','接通判於邸氏園園人獻牡丹太守不收余私取其絕好者以歸','孔平仲','宋','宋诗','song-poetry','','[]','薄暮歸來何所携，牡丹初翦半開時。',32,'全唐诗/poet.song.53000.json','["薄暮歸來何所携，牡丹初翦半開時。", "濃香盛色俱堪愛，占得春風第一枝。"]'),
('f9db5b1a-94be-41cf-a774-17d10e275280','兄長寄五詩依韵和寄詩各有所懷  其一','孔平仲','宋','宋诗','song-poetry','','[]','憶昔西尋山下園，芙蓉香裏醉頹然。',64,'全唐诗/poet.song.53000.json','["憶昔西尋山下園，芙蓉香裏醉頹然。", "幽篁迸筍無餘地，老木交陰不計年。", "徹幕旋迎秦望雨，汎杯旁引鑑湖泉。", "舊遊寂寞今誰到，應有秋苔長綠錢。"]'),
('137165ab-0dce-45a9-b19c-5eff6b1cdf8e','兄長寄五詩依韵和寄詩各有所懷  其二','孔平仲','宋','宋诗','song-poetry','','[]','昔同訪客到山陰，馬上相隨不廢吟。',64,'全唐诗/poet.song.53000.json','["昔同訪客到山陰，馬上相隨不廢吟。", "平視溪流綠烟遠，回看府宅白雲深。", "紛紛落麈陪高論，艷艷浮蛆勸滿斟。", "賓主如今各分散，詩成長詠作吳音。"]'),
('541adb36-596e-4e2d-9113-6c07635505f7','兄長寄五詩依韵和寄詩各有所懷  其三','孔平仲','宋','宋诗','song-poetry','','[]','蓬萊彼此一閒身，把酒臨風送晚春。',64,'全唐诗/poet.song.53000.json','["蓬萊彼此一閒身，把酒臨風送晚春。", "城邑萬家供氣象，湖山千里助精神。", "深林鳥語留連客，野徑花香著莫人。", "今日天涯共怊悵，歸心夜夜轉車輪。"]'),
('3d367436-f1ef-4986-9014-aadc65f0a7d0','兄長寄五詩依韵和寄詩各有所懷  其四','孔平仲','宋','宋诗','song-poetry','','[]','憶昔幽尋到井儀，繁花落盡綠陰時。',64,'全唐诗/poet.song.53000.json','["憶昔幽尋到井儀，繁花落盡綠陰時。", "雲迷步武多相失，風入襟懷只自知。", "金斗倒垂交勸飲，玉蟾分面各題詩。", "淋浪醉墨留西壁，好事於今刻作碑。"]'),
('6a6ba4ab-d521-48b5-ad65-01b782950488','兄長寄五詩依韵和寄詩各有所懷  其五','孔平仲','宋','宋诗','song-poetry','','[]','昔尋小隠到王家，早出歸時逼晚衙。',64,'全唐诗/poet.song.53000.json','["昔尋小隠到王家，早出歸時逼晚衙。", "勝奕高亭弄紋局，擷芳深徑採新茶。", "竹邊雲過陰相得，蓮外風來氣益嘉。", "夜坐西堂有餘興，解酲更進一銀瓜。"]'),
('de61b0f2-1b12-4c56-ac6e-d7b10ba0a1b2','郡聚','孔平仲','宋','宋诗','song-poetry','','[]','幕府多閒暇，城臺避鬰蒸。',48,'全唐诗/poet.song.53000.json','["幕府多閒暇，城臺避鬰蒸。", "金杯揮落日，銀椀嚼寒冰。", "老婦歌猶好，雙鬟舞最能。", "深宵紅燭短，坐客醉忘興。"]'),
('a4dc5a08-c762-4556-b4b1-8b56a932ac8f','正月七夜飲節之廨舍','孔平仲','宋','宋诗','song-poetry','','[]','草草杯盤具，喧喧笑語親。',48,'全唐诗/poet.song.53000.json','["草草杯盤具，喧喧笑語親。", "浩歌回白雪，醉眼失青春。", "梨栗無遺顆，肴饈屢乞鄰。", "頹然極樂際，心迹兩俱泯。"]'),
('bcd0b157-56ee-4bb2-a09c-607d57b4a4f5','六月五日','孔平仲','宋','宋诗','song-poetry','','[]','灑汗通宵已廢眠，起來猶覺眼生烟。',64,'全唐诗/poet.song.53000.json','["灑汗通宵已廢眠，起來猶覺眼生烟。", "黄埃滾滾人行地，赤氣騰騰日出天。", "紈扇急揮風亦熱，銀瓶空掛井無泉。", "狂心於此思霜雪，安得師文扣羽弦。"]'),
('fcf304d3-9fcf-4f4e-bc96-c81527945e16','喜雨上太守','孔平仲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','曾佩金章禱象龍，滂沱飛雨出無窮。',64,'全唐诗/poet.song.53000.json','["曾佩金章禱象龍，滂沱飛雨出無窮。", "泰山吐霧連朝暗，東海驅波半夜空。", "爽壓炎蒸民少病，潤流枯涸歲將豐。", "黄堂下視相歡意，助以袁宏一扇風。"]'),
('43a6316b-ef49-4b08-a89a-e047114d284f','晚霽','孔平仲','宋','宋诗','song-poetry','','[]','夜雨百泉響，晚晴風報秋。',48,'全唐诗/poet.song.53000.json','["夜雨百泉響，晚晴風報秋。", "雲歸青山去，水入平川流。", "疫癘且不作，稻粱行亦稠。", "吾徒今則喜，向者爲民憂。"]'),
('e3be925f-ef76-46f1-afd1-fd6347807f80','雙門','孔平仲','宋','宋诗','song-poetry','','[]','崔嵬城闕倚雲端，萬里天風襟袖間。',32,'全唐诗/poet.song.53000.json','["崔嵬城闕倚雲端，萬里天風襟袖間。", "更有清凉無限意，坐看飛雨出南山。"]'),
('ba0163a9-42d7-4554-8dcf-b69859b619ec','送蔡充道赴密院召','孔平仲','宋','宋诗','song-poetry','','[]','彈劍常爲猛虎吟，掃清夷虜丈夫心。',64,'全唐诗/poet.song.53000.json','["彈劍常爲猛虎吟，掃清夷虜丈夫心。", "人留海上烟花老，夢入塞垣冰雪深。", "千里樞庭馳召節，幾年家府探歸音。", "此行儻未封侯貴，一策猶能綰萬金。"]'),
('ed8f5c68-af97-429e-872f-92e7c4b8216e','寄常父  其一','孔平仲','宋','宋诗','song-poetry','','[]','六月凉泉聲似雨，千家脩竹勢凌雲。',32,'全唐诗/poet.song.53000.json','["六月凉泉聲似雨，千家脩竹勢凌雲。", "齊州瀟灑共閒暇，洗耳清流對此君。"]'),
('247e0ece-5d8f-48ac-b8c0-712a840928d6','寄常父  其二','孔平仲','宋','宋诗','song-poetry','','[]','紅蓼最宜秋雨濕，綠槐無奈晚風吹。',32,'全唐诗/poet.song.53000.json','["紅蓼最宜秋雨濕，綠槐無奈晚風吹。", "向來不用憂煩暑，庭戶清凉自有詩。"]'),
('03742223-2c40-4a07-9e5a-45276bdce4ac','七月二十六日','孔平仲','宋','宋诗','song-poetry','','[]','蘄州小簟琴光枕，學館無人日午時。',64,'全唐诗/poet.song.53000.json','["蘄州小簟琴光枕，學館無人日午時。", "睡去沈酣本避暑，夢迴展轉却添疲。", "倏忽雲雷出天意，清凉風雨報秋思。", "世間此味宜無比，只說羲皇已自卑。"]'),
('162bd38e-23bc-426f-82fe-723bb1711be4','謝夢錫見臨','孔平仲','宋','宋诗','song-poetry','','[]','雪月交光夜正寒，何人相伴語更闌。',64,'全唐诗/poet.song.53000.json','["雪月交光夜正寒，何人相伴語更闌。", "惟君枉駕時能慰，令我幽居意解歡。", "小僕旋來熒火燭，病妻無力治盃盤。", "清談已倦還觀史，冷淡相看不厭難。"]'),
('a769e7fd-21f4-4c28-9a80-7584d12fc9a5','送張通判','孔平仲','宋','宋诗','song-poetry','','[]','清若冰壺斷若金，孜孜常見恤民深。',64,'全唐诗/poet.song.53000.json','["清若冰壺斷若金，孜孜常見恤民深。", "三年佐郡神明政，一旦歸朝父老心。", "遺愛海波無斷處，去思秋色有餘陰。", "臨行曲爲留旬日，少慰攀轅淚滿襟。"]'),
('f5e337ac-a2ad-4ec2-9698-00926f38b57b','西行','孔平仲','宋','宋诗','song-poetry','','[]','繚繞西行入亂山，白雲深處據征鞍。',64,'全唐诗/poet.song.53000.json','["繚繞西行入亂山，白雲深處據征鞍。", "蕎花著雨相爭秀，棗頰迎陽一半丹。", "鞅掌未能逃物役，乾坤何處託身安。", "莒臺東嚮情無限，那更秋風作暮寒。"]'),
('9219d1c3-df21-4a82-804f-ac902ae5b463','荆林館','孔平仲','宋','宋诗','song-poetry','','[]','古木森然滿驛庭，繁陰凌亂月分明。',32,'全唐诗/poet.song.53000.json','["古木森然滿驛庭，繁陰凌亂月分明。", "千枝萬葉誰拘管，攪作秋風一片聲。"]'),
('9f91cb4c-90d4-4b19-8d9d-8f0935cb4f30','馬上','孔平仲','宋','宋诗','song-poetry','','[]','秋山剝棗熟，野水漚麻香。',48,'全唐诗/poet.song.53000.json','["秋山剝棗熟，野水漚麻香。", "鳥倦投空木，蟬悲送夕陽。", "去程猶未幾，歸興一何長。", "應爲西齋睡，疏慵意不忘。"]'),
('d35acaf1-895d-41fa-a423-f9f07273492a','近兖','孔平仲','宋','宋诗','song-poetry','','[]','龜蒙山上泉如湧，白石河邊雨已流。',64,'全唐诗/poet.song.53000.json','["龜蒙山上泉如湧，白石河邊雨已流。", "喬木烟深迷故國，黄蘆風急戰高秋。", "新科一變人方銳，舊學都忘我可羞。", "驅馬遠來徒自苦，敢將衡鑑定三州。"]'),
('4a6c4f30-a703-4ca2-b98e-1c0b8fa38e71','毛陽','孔平仲','宋','宋诗','song-poetry','','[]','客路方投轡，郵亭獨掩門。',24,'全唐诗/poet.song.53000.json','["客路方投轡，郵亭獨掩門。", "無人共燈火，秋雨更黄昏。"]'),
('583fc425-4c83-4124-a063-52b690508c9f','次韵和張道濟長官立秋後作','孔平仲','宋','宋诗','song-poetry','','[]','萬里悄然若有霜，南山秋色兩蒼蒼。',64,'全唐诗/poet.song.53000.json','["萬里悄然若有霜，南山秋色兩蒼蒼。", "巳經晚雨驅除熱，更得西風斷送凉。", "瀚海人空雲弄白，吳江波闊葉吹黄。", "知君昨夜書帷夢，半在親庭半在鄉。"]'),
('60752406-9088-4805-8a91-42720bd9ad06','飲夢錫官舍出文君西子小小畫真','孔平仲','宋','宋诗','song-poetry','','[]','西施蘇小卓文君，畫筆相傳窈窕真。',64,'全唐诗/poet.song.53000.json','["西施蘇小卓文君，畫筆相傳窈窕真。", "雖有金珠并粉黛，恨無笑語與精神。", "一罇美酒留連客，千載芳魂著莫人。", "醉眼恍然迷不覺，自慚心地尚埃塵。"]'),
('3a5c632e-29c0-4dea-8a43-8b79cd87d1ed','走筆  其一','孔平仲','宋','宋诗','song-poetry','','[]','霽雪如泉滴，荒城作阜遮。',48,'全唐诗/poet.song.53000.json','["霽雪如泉滴，荒城作阜遮。", "買猿裝野景，插柳待春華。", "終日開黄卷，諸生望絳紗。", "王官倦奔走，何幸獨安家。"]'),
('f55d51c8-9487-4f7c-9725-325aeabbcc40','走筆  其二','孔平仲','宋','宋诗','song-poetry','','[]','種竹禁當雪，栽花準擬春。',48,'全唐诗/poet.song.53000.json','["種竹禁當雪，栽花準擬春。", "詩書最閒局，寢食自由身。", "浙外音題數，齊州問訊頻。", "郵筒煩郡縣，此外不干人。"]'),
('79c46474-23a2-4b5b-ad7d-eaac10d6b4cc','走筆  其三','孔平仲','宋','宋诗','song-poetry','','[]','觸目方多事，栖身獨此堂。',48,'全唐诗/poet.song.53000.json','["觸目方多事，栖身獨此堂。", "窗迎先得日，簷送曉留霜。", "散漫皆書帙，逍遙或道裝。", "牆東雖可隠，林下未能忘。"]'),
('2d381702-520e-4ec9-9ec5-866df5e7e2ec','寄常父二首  其一','孔平仲','宋','宋诗','song-poetry','','[]','欲和來詩詩未就，恍然心在歷山陽。',32,'全唐诗/poet.song.53000.json','["欲和來詩詩未就，恍然心在歷山陽。", "寒燈一點靜相照，風雪打窗冬夜長。"]'),
('168c51ca-daa0-4f3f-ade2-d0f2d9e86a03','寄常父二首  其二','孔平仲','宋','宋诗','song-poetry','','[]','不得家書又幾朝，思親夢斷不堪招。',64,'全唐诗/poet.song.53000.json','["不得家書又幾朝，思親夢斷不堪招。", "欲歸每恨川途遠，久客空驚歲月消。", "雪意尚濃雲黯淡，角聲吹絕晚蕭條。", "相看惟有兄相近，回首時能慰寂寥。"]'),
('3b4bc8f6-e4b5-40eb-b145-5d17c08aa3c8','送董少卿','孔平仲','宋','宋诗','song-poetry','','[]','莊重邦之望，疏明衆所欽。',168,'全唐诗/poet.song.53000.json','["莊重邦之望，疏明衆所欽。", "守符頻握虎，使節屢頒金。", "天子東州幸，時蒙皂蓋臨。", "名卿鎮以靜，循吏見於今。", "豈弟民無擾，廉隅俗不侵。", "清樽但談宴，和氣入謳吟。", "盛德推先進，高懷在直尋。", "兩忘兼寵辱，一笑寄浮沈。", "積雪留行色，朱輪挽去音。", "夢回雙闕表，愛結水棠陰。", "賤子非良器，經年託泮林。", "清暉瞻畫戟，諄誨俯華簪。", "與進恩尤厚，臨分戀最深。", "送公無外飾，終始古人心。"]'),
('2f1b70fd-8dd4-48f3-8ac0-41cec77edda1','哦亭','孔平仲','宋','宋诗','song-poetry','','[]','點點花芽撥草根，深春終日在東園。',64,'全唐诗/poet.song.53000.json','["點點花芽撥草根，深春終日在東園。", "烟筠冉冉陰相亂，燕雀啾啾語自繁。", "倚伏萬端寧有定，是非一致亦何言。", "誰能伴我哦亭上，爛漫同斟濁酒樽。"]'),
('7e76023f-2fcf-4b51-b061-7973ae5685f1','中和節','孔平仲','宋','宋诗','song-poetry','','[]','二月中和節，海邊猶積陰。',48,'全唐诗/poet.song.53000.json','["二月中和節，海邊猶積陰。", "風雷失春信，霜雪損花心。", "挾纊誰能禦，圍爐興愈深。", "寒暄地氣異，故國想如今。"]'),
('4d3c533d-3ccf-4357-8090-c2d33776523e','晨興','孔平仲','宋','宋诗','song-poetry','','[]','清閒薄體不成眠，起步庭除思悄然。',32,'全唐诗/poet.song.53000.json','["清閒薄體不成眠，起步庭除思悄然。", "正是雨晴寒食夜，杏花枝上月嬋娟。"]'),
('37b1b921-f62e-48e2-8631-42e1061f3a2f','以事往齊州初發密','孔平仲','宋','宋诗','song-poetry','','[]','匆匆行色犯晨鷄，起見荒坡落月低。',32,'全唐诗/poet.song.53000.json','["匆匆行色犯晨鷄，起見荒坡落月低。", "多謝使君相送厚，已將歌舞出城西。"]'),
('5d42fee3-4ade-4d2b-94b4-80e80edeebe3','折柳亭','孔平仲','宋','宋诗','song-poetry','','[]','楊柳已藏鴉，高亭望物華。',48,'全唐诗/poet.song.53000.json','["楊柳已藏鴉，高亭望物華。", "平時常送客，此日自離家。", "別酒杯何滿，征途日欲斜。", "醉行三十里，春思滿鶑花。"]'),
('a71fabf2-daf0-4d32-bfab-85ba4fefd988','里伏驛','孔平仲','宋','宋诗','song-poetry','','[]','去家一日已思家，浩渺歸期未有涯。',32,'全唐诗/poet.song.53000.json','["去家一日已思家，浩渺歸期未有涯。", "滿眼春風最多恨，無言似笑小桃花。"]'),
('6cabf33e-70f9-4bb6-a1a3-9c0dcfd5317e','將至青州','孔平仲','宋','宋诗','song-poetry','','[]','磅礴西南萬疊山，屈盤飛舞意相關。',32,'全唐诗/poet.song.53000.json','["磅礴西南萬疊山，屈盤飛舞意相關。", "天形地勢俱雄壯，人指青州在此間。"]'),
('48d3172a-03ee-41af-b684-9bbe1c8c88d1','青州席上','孔平仲','宋','宋诗','song-poetry','','[]','笙歌相引入東園，二月青州花正繁。',64,'全唐诗/poet.song.53000.json','["笙歌相引入東園，二月青州花正繁。", "銀幕四圍香獸暖，繡茵十幅舞靴翻。", "游人見此心應樂，野客頹然思已煩。", "向晚凭欄得瀟灑，狂風吹雨出雲門。"]'),
('13ebd0ab-c105-4661-82a4-0f01bbc5e04c','馬上小睡','孔平仲','宋','宋诗','song-poetry','','[]','夾路桃花眼自醉，昏昏不覺據鞍眠。',32,'全唐诗/poet.song.53000.json','["夾路桃花眼自醉，昏昏不覺據鞍眠。", "覺來已失初時景，流水青山忽滿前。"]'),
('3e702d30-330b-4717-ab6d-ceee2e37076e','王舍人莊','孔平仲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','西出齊州似不遠，晚留逆旅尚徘徊。',32,'全唐诗/poet.song.53000.json','["西出齊州似不遠，晚留逆旅尚徘徊。", "泰山一夜興雲雨，洗耳流泉待我來。"]'),
('f5bce98f-b3cf-420b-a43a-bd58003d6ea2','上曾子固','孔平仲','宋','宋诗','song-poetry','','[]','海邦窮僻想知音，疋馬春風入岱陰。',64,'全唐诗/poet.song.53000.json','["海邦窮僻想知音，疋馬春風入岱陰。", "千里山川忘道遠，一門兄弟辱恩深。", "發揚底滯先生德，振拔崎嶇長者心。", "更以詩篇壯行色，東歸勝挾萬黄金。"]'),
('38c4b8c7-68c0-416f-8299-c3b88fa9194d','和常父見寄','孔平仲','宋','宋诗','song-poetry','','[]','濟南風物稱閒官，兄弟偕遊意益歡。',64,'全唐诗/poet.song.53000.json','["濟南風物稱閒官，兄弟偕遊意益歡。", "幽圃水聲從地涌，畫橋山色逼人寒。", "別來夢想猶相接，他處塵埃不足觀。", "寂寞東齋又經夏，落花新葉共誰看。"]'),
('0471bcbf-9e1f-4477-818e-e6690ed9769e','呈夢錫','孔平仲','宋','宋诗','song-poetry','','[]','結綬本何意，浩歌今欲歸。',48,'全唐诗/poet.song.53000.json','["結綬本何意，浩歌今欲歸。", "從君臥病去，使我出門希。", "燕領新雛出，鴟盤落景飛。", "何時起相見，一笑兩忘機。"]'),
('1ff2e7c3-bb8a-4609-bee3-aa5c2cd8aa5b','銀河詠','孔平仲','宋','宋诗','song-poetry','','[]','江湖有客臥孤城，每見銀河眼亦明。',64,'全唐诗/poet.song.53000.json','["江湖有客臥孤城，每見銀河眼亦明。", "萬里長風吹不斷，一番微雨洗尤清。", "星辰白石參差亂，雲氣飛梁倏忽生。", "牛女東西波浪隔，夜寒天闊不勝情。"]'),
('b16f1fdc-bf59-4f9f-82f2-922f5697af6e','學舍','孔平仲','宋','宋诗','song-poetry','','[]','簿領如棼處處忙，日華偏向此中長。',64,'全唐诗/poet.song.53000.json','["簿領如棼處處忙，日華偏向此中長。", "吟餘林表孤雲改，夢覺窗間小雨凉。", "珮玉上趨承斗極，棹歌深入釣滄浪。", "何如瀟灑詩書局，不在山林不廟堂。"]'),
('bf2a08f0-985c-4525-ab25-571d173e791e','風雨有秋色率然成小詩呈道濟長官','孔平仲','宋','宋诗','song-poetry','','[]','學館人歸靜若山，久陰梅濕上衣冠。',64,'全唐诗/poet.song.53000.json','["學館人歸靜若山，久陰梅濕上衣冠。", "酣酣雨意牽愁遠，颯颯秋聲吹夢寒。", "竹笋解包堆屋角，蓼花抽穗出牆端。", "此時最憶吳江上，千頃烟波一釣竿。"]'),
('c226507d-4ae4-4a03-ae94-a057b93bc492','游田氏池亭','孔平仲','宋','宋诗','song-poetry','','[]','磅礴青山入望長，古城東下見回塘。',64,'全唐诗/poet.song.53000.json','["磅礴青山入望長，古城東下見回塘。", "雲陰更雜梧桐影，野氣仍連菡蓞香。", "久處塵埃思浣濯，忽逢虛曠自清凉。", "主人華髮能談笑，猶撫歸鞍恨夕陽。"]'),
('7af6ba87-1c9a-46d2-8321-caaeac88c690','雨中戲夢錫','孔平仲','宋','宋诗','song-poetry','','[]','雲橫金嶺迷驅轍，水溢沂河卷斷梁。',32,'全唐诗/poet.song.53000.json','["雲橫金嶺迷驅轍，水溢沂河卷斷梁。", "預祝愁霖貫秋序，留君行色到重陽。"]'),
('c6057d69-488b-4ac1-8608-f8ba89bbd56d','寄常父','孔平仲','宋','宋诗','song-poetry','','[]','秋風又摇落，歷下意何如。',48,'全唐诗/poet.song.53000.json','["秋風又摇落，歷下意何如。", "學館人歸後，山城月上初。", "東西各引領，咫尺但通書。", "難共重陽醉，黄花日向疏。"]'),
('f9f4268d-2d93-4d70-a75b-34c5c5905e08','白日','孔平仲','宋','宋诗','song-poetry','','[]','白日無所適，况茲秋夜深。',48,'全唐诗/poet.song.53000.json','["白日無所適，况茲秋夜深。", "青燈可自照，缺月强相侵。", "糺縵觀時事，崎嶇見俗心。", "退藏無乃幸，矍起捧吾襟。"]'),
('903f7678-d89f-4d43-ae61-0a70d83e6d14','餞夢錫於折柳亭醉中倚柱','孔平仲','宋','宋诗','song-poetry','','[]','折柳亭邊柳已衰，送行猶拗最高枝。',32,'全唐诗/poet.song.53000.json','["折柳亭邊柳已衰，送行猶拗最高枝。", "西風黄葉蕭蕭地，多少傷心爲別離。"]'),
('4f8ce9da-4700-4b13-a8ba-b5618af6af11','楊慎之著作孫正甫推官歐陽甫長官隨詔使東來併會齋中','孔平仲','宋','宋诗','song-poetry','','[]','故人得會合，况復有鄉閭。',48,'全唐诗/poet.song.53000.json','["故人得會合，况復有鄉閭。", "靜失秋天幕，幽忘海上居。", "留連且徹曉，分散即如初。", "笑語同燈火，還思遠寄書。"]'),
('a4335925-22da-4265-998f-f0046a4d6805','經社','孔平仲','宋','宋诗','song-poetry','','[]','經社無甘雨，深秋已肅霜。',48,'全唐诗/poet.song.53000.json','["經社無甘雨，深秋已肅霜。", "鋤犁心最切，牟麥事尤妨。", "比屋何緣飽，天行固不常。", "自吾來此土，連歲見豐穰。"]'),
('14a7e30d-e93e-4745-bc73-8806e59c5054','熙寧口號  其一','孔平仲','宋','宋诗','song-poetry','','[]','日坐明堂講太平，時聞深詔下青冥。',32,'全唐诗/poet.song.53000.json','["日坐明堂講太平，時聞深詔下青冥。", "數重遣使詢新法，四面興師翦不庭。"]'),
('76dae6c2-041a-4e07-b924-d699285cd060','熙寧口號  其二','孔平仲','宋','宋诗','song-poetry','','[]','萬戶康寧五穀豐，江淮相接至山東。',32,'全唐诗/poet.song.53000.json','["萬戶康寧五穀豐，江淮相接至山東。", "須知錫福由京邑，天子新成太一宮。"]'),
('e229ab68-75c0-4bc0-8488-f9a2a67c06ff','熙寧口號  其三','孔平仲','宋','宋诗','song-poetry','','[]','祇因銅落久紛紛，砥礪廉隅自聖君。',32,'全唐诗/poet.song.53000.json','["祇因銅落久紛紛，砥礪廉隅自聖君。", "能使普天無賄賂，此風曠古未嘗聞。"]'),
('a17ae77e-70fa-4b59-b1d6-ea0dbee7684f','熙寧口號  其四','孔平仲','宋','宋诗','song-poetry','','[]','近聞寇盜理戈殳，太府輸金入大爐。',32,'全唐诗/poet.song.53000.json','["近聞寇盜理戈殳，太府輸金入大爐。", "百鍊剛刀斫西夏，萬鈞强弩射單于。"]'),
('d483b47f-8b16-4e7a-a0f8-0b95f164c3e1','熙寧口號  其五','孔平仲','宋','宋诗','song-poetry','','[]','百姓命懸三尺法，千秋誰恤兩端情。',32,'全唐诗/poet.song.53000.json','["百姓命懸三尺法，千秋誰恤兩端情。", "近聞崇尚刑名學，陛下之心乃好生。"]'),
('80664ddd-7539-4dcc-afdc-0321fb10c975','大風','孔平仲','宋','宋诗','song-poetry','','[]','不雨今已久，北風還起埃。',48,'全唐诗/poet.song.53000.json','["不雨今已久，北風還起埃。", "聲搴海嶽動，寒挾雪霜來。", "落羽高千丈，脩筠折幾枚。", "未應由虎嘯，吾欲訟奔雷。"]'),
('f3cfc4a2-153a-4d7e-8f86-f208803e538d','新霜','孔平仲','宋','宋诗','song-poetry','','[]','皎皎寒月白，清晨霜滿林。',48,'全唐诗/poet.song.53000.json','["皎皎寒月白，清晨霜滿林。", "萌芽至今日，肅殺爾何心。", "入水成冰暈，迷天作雪陰。", "自茲開火閣，却坐小窗深。"]'),
('062a0d6e-9d53-43a3-9303-00b7904c6eb3','寄常父','孔平仲','宋','宋诗','song-poetry','','[]','海上窮秋白日陰，霜飈獵獵稍相侵。',64,'全唐诗/poet.song.53000.json','["海上窮秋白日陰，霜飈獵獵稍相侵。", "手持黄菊江南意，目送征鴻萬里心。", "每想清談真麗矚，欲彈流水少知音。", "東山兄弟非難繼，誰敢先爲招隠吟。"]'),
('6c43709e-d2d7-4fc9-8097-d8a1f1435a0f','十月旦懷夢錫','孔平仲','宋','宋诗','song-poetry','','[]','去歲開爐郡中起，芙蓉幕下醉相邀。',64,'全唐诗/poet.song.53000.json','["去歲開爐郡中起，芙蓉幕下醉相邀。", "今年兩事俱蕭索，白日孤城轉寂寥。", "緣飾新茶烹小鳳，咨嗟名畫展蒼鵰。", "長篇藁出依然在，千里思君不可招。"]'),
('f11b7fed-8c27-41ca-97c0-188dd2553a28','知郡姚駕部十月三日生日','孔平仲','宋','宋诗','song-poetry','','[]','冰爲清潔玉爲淳，籍籍名家第一人。',64,'全唐诗/poet.song.53000.json','["冰爲清潔玉爲淳，籍籍名家第一人。", "皂蓋已頒東郡政，綵衣猶侍北堂親。", "遐年此去隨長景，和氣生來得少春。", "何以獻公今日壽，仙山不朽海無津。"]'),
('b06a94f4-6e78-4f1c-98a7-bc113f68b3c9','寄板橋卞進之主簿','孔平仲','宋','宋诗','song-poetry','','[]','以才牽挽自由身，歲暮無家寄海濱。',64,'全唐诗/poet.song.53000.json','["以才牽挽自由身，歲暮無家寄海濱。", "擾擾滿前人一把，紛紛趨事抱千鈞。", "風掀駝島波聲壯，雲倚蓬山雪意新。", "回首高城已摇落，菊花羞逼小陽春。"]'),
('46885b33-7647-41f5-9314-18f7e173db6b','步日','孔平仲','宋','宋诗','song-poetry','','[]','步日問吾影，汝何爲此留。',48,'全唐诗/poet.song.53000.json','["步日問吾影，汝何爲此留。", "天寒歲云暮，地僻海之陬。", "涉世心彌壯，逢人語或收。", "蛟龍得雲雨，千丈拔靈湫。"]'),
('c5a07501-8c92-409a-ab22-f61856a77e0e','寄蕭虛中','孔平仲','宋','宋诗','song-poetry','','[]','平川摻袂屢星霜，楚尾畿東各一鄉。',64,'全唐诗/poet.song.53000.json','["平川摻袂屢星霜，楚尾畿東各一鄉。", "安得便風傳訊問，只應明月共輝光。", "茅齋夜出猶能記，古觀秋吟最不忘。", "近日詩成無和者，思君才俊似青楊。"]'),
('3e04272a-cbbc-4835-afed-17950030a7ed','獨夜','孔平仲','宋','宋诗','song-poetry','','[]','徘徊想此夜，夜長猶未眠。',24,'全唐诗/poet.song.53000.json','["徘徊想此夜，夜長猶未眠。", "出門還復入，無語月空圓。"]'),
('0a5ded59-a546-499a-ae43-5d731008e855','晨雨','孔平仲','宋','宋诗','song-poetry','','[]','經秋久不雨，既雨亦紛紛。',48,'全唐诗/poet.song.53000.json','["經秋久不雨，既雨亦紛紛。", "氣入書帷暖，聲從屋瓦聞。", "問人疑落霰，出戶見行雲。", "亭午全開霽，青山遠可分。"]'),
('4304e7c7-7e7a-47ff-b9f3-c21989b29407','訪道濟','孔平仲','宋','宋诗','song-poetry','','[]','出門已晚鼓，訪客傍西城。',48,'全唐诗/poet.song.53000.json','["出門已晚鼓，訪客傍西城。", "無事詩書局，相過僚友情。", "風來稍塵暗，日落更寒生。", "歸路逢燈火，喧喧馬屢驚。"]'),
('859dc7e9-2be6-43ab-bd96-d23e267f2672','月夜','孔平仲','宋','宋诗','song-poetry','','[]','出戶憐清影，循除擁敝裘。',48,'全唐诗/poet.song.53000.json','["出戶憐清影，循除擁敝裘。", "霜寒方午夜，月色似中秋。", "丹桂何常有，姮娥爲我留。", "竹陰如壁畫，更助眼前幽。"]'),
('3f7f6cb7-8fb3-4f96-b930-afb06f352249','寄常父','孔平仲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','台州與京邑，中有泰山陰。',48,'全唐诗/poet.song.53000.json','["台州與京邑，中有泰山陰。", "誰謂三隅遠，長分一寸心。", "南陔戒已舊，棠棣興尤深。", "思作團圓計，囊無買舍金。"]'),
('c0f947a3-ff7e-481d-8e04-8aaa6bf187cf','再用前意','孔平仲','宋','宋诗','song-poetry','','[]','台州雲海闊，梁苑雪天低。',48,'全唐诗/poet.song.53000.json','["台州雲海闊，梁苑雪天低。", "地隔書來少，心分夢去迷。", "惟兄最鄰近，同路隔東西。", "常欲投簪笏，相招傍虎溪。"]'),
('9949744f-1291-4c1c-9116-9722d6e3c2f6','雨中','孔平仲','宋','宋诗','song-poetry','','[]','江南梅已熟，塞北杏初黄。',48,'全唐诗/poet.song.53000.json','["江南梅已熟，塞北杏初黄。", "颯颯連朝雨，蕭蕭滿眼凉。", "海山陰不斷，節物意何長。", "坐想蕭灘景，烟波對渺茫。"]'),
('8090146c-99f1-4e30-8552-89fc3c24a042','試墨','孔平仲','宋','宋诗','song-poetry','','[]','長夏人雖厭，茲晨物所遭。',48,'全唐诗/poet.song.53000.json','["長夏人雖厭，茲晨物所遭。", "鳴蜩抱枝急，新燕出巢高。", "衣葛寧嫌薄，驅蚊亦憚勞。", "時時得一雨，蒸濕地生毛。"]'),
('f6155934-c021-49c8-b3d3-7702f8e81394','有感時夢錫尋醫而思求免官','孔平仲','宋','宋诗','song-poetry','','[]','去歲城門坐徹晚，前年火閣飯連宵。',64,'全唐诗/poet.song.53000.json','["去歲城門坐徹晚，前年火閣飯連宵。", "當時已是嫌羈束，今日那堪轉寂寥。", "綠水紅蓮非舊客，清風明月想同寮。", "不知比我離高密，誰向長亭折柳條。"]'),
('187bf4eb-43be-4801-b5f8-d0bde13a33fc','久雨','孔平仲','宋','宋诗','song-poetry','','[]','一日三日雨，雨中有青天。',144,'全唐诗/poet.song.53000.json','["一日三日雨，雨中有青天。", "未能舒靉靆，何苦弄潺湲。", "卷海長風裏，傾河白日邊。", "泥鳴萬丸躍，瓦破百繩穿。", "鳥雀深依舍，蛟龍痛着鞭。", "醉陰昏翠巘，走濁亂青川。", "急灑隨奔電，餘霏倚斷烟。", "興居愁濕熱，行步阻流泉。", "閔僕衣爲障，看兒板作船。", "稍移茶近火，更使带添綿。", "僻陋無人迹，幽閒足晝眠。", "夢回聞點滴，垂晚興蕭然。"]'),
('03b8a0c6-cf86-47c3-90b9-38a7f6ec3346','酬聶察推','孔平仲','宋','宋诗','song-poetry','','[]','昔年隨宦在筠陽，總角頻趨數仞牆。',64,'全唐诗/poet.song.53000.json','["昔年隨宦在筠陽，總角頻趨數仞牆。", "綠水近經王儉府，錦衣今見買臣鄉。", "能談舊事情何厚，忽枉新詩味更長。", "閭里優游正多暇，幸君時訪讀書堂。"]'),
('912b09a0-ae2a-42f5-95bf-617ae00b3904','食冰','孔平仲','宋','宋诗','song-poetry','','[]','又見頒冰出，曾看白雪收。',48,'全唐诗/poet.song.53000.json','["又見頒冰出，曾看白雪收。", "清輝分積玉，爽氣忽高秋。", "盡室雖同享，吾親獨異州。", "淮南地卑濕，安得代蘭羞。"]'),
('f930430a-f426-4d2a-ae2c-1ae1bf986a95','郡聚','孔平仲','宋','宋诗','song-poetry','','[]','促坐留賓醉，傳呼放晚衙。',48,'全唐诗/poet.song.53000.json','["促坐留賓醉，傳呼放晚衙。", "門庭少公事，節物正秋華。", "齋釀新篘美，官奴遠囗佳。", "歸時雖落月，銀蠟照紅紗。"]'),
('8639ae2a-cf57-4cfa-938d-8584f20b01ee','陳宗聖縣丞往登州問有所幹以此託之','孔平仲','宋','宋诗','song-poetry','','[]','北望登州匹馬馳，駝裘孤扇任風吹。',64,'全唐诗/poet.song.53000.json','["北望登州匹馬馳，駝裘孤扇任風吹。", "才聞使者方相委，事屬公家不敢辭。", "聚落蕭條宿山縣，波濤浩蕩瞰天池。", "煩君一上蓬萊閣，歸說扶桑日出時。"]'),
('005a50d7-9cbb-4d86-b95c-18047ee0f421','郡集','孔平仲','宋','宋诗','song-poetry','','[]','旋徹銀杯泛海螺，故人相遇樂如何。',64,'全唐诗/poet.song.53000.json','["旋徹銀杯泛海螺，故人相遇樂如何。", "東西合作雙雙舞，工拙分爲一一歌。", "吹角共驚冬晷短，添爐更覺晚寒多。", "不須苦鍊登州語，大抵東音唯與阿。"]'),
('0709b461-b526-406b-96ed-f70157deec77','送段從道司戶','孔平仲','宋','宋诗','song-poetry','','[]','擾擾東來又西去，風霜匽薄不勝勞。',32,'全唐诗/poet.song.53000.json','["擾擾東來又西去，風霜匽薄不勝勞。", "請君飲馬沂河上，徐看家山萬疊高。"]'),
('82e41ef0-f2fb-4e57-b77c-5f424be4d067','早陰','孔平仲','宋','宋诗','song-poetry','','[]','青女隨明月，來時夜已深。',24,'全唐诗/poet.song.53000.json','["青女隨明月，來時夜已深。", "霜花結不就，散作海天陰。"]'),
('3dcd5128-d1d4-48d8-9ba4-fe1c14e946e1','寓目','孔平仲','宋','宋诗','song-poetry','','[]','倏此年華晚，蕭然學館幽。',48,'全唐诗/poet.song.53000.json','["倏此年華晚，蕭然學館幽。", "常閒心却悶，極靜景多愁。", "葉走堂階響，雲依殿吻浮。", "黄茅日西下，戲犬在城頭。"]'),
('3526caa4-563a-44da-b405-556b72958799','初雪即霽','孔平仲','宋','宋诗','song-poetry','','[]','紛紛千里暗，雪下海邊城。',48,'全唐诗/poet.song.53000.json','["紛紛千里暗，雪下海邊城。", "方與冬爲瑞，如何晚即晴。", "竹枝微覺重，瓦口未能平。", "深夜庭前看，尤添月色清。"]'),
('af33e813-20bc-4ab5-871a-cd19e816987c','夜觀殘雪','孔平仲','宋','宋诗','song-poetry','','[]','牆陰留得雪斕斑，有客更深獨自看。',64,'全唐诗/poet.song.53000.json','["牆陰留得雪斕斑，有客更深獨自看。", "江上落梅人不掃，山頭明月夜初寒。", "清心直與神仙比，好景只應圖畫難。", "宇宙之中無一物，碧天如水靜漫漫。"]'),
('e16c366a-ec44-4b05-aa3c-2bb5566d51f7','冬至日作','孔平仲','宋','宋诗','song-poetry','','[]','今宵當月滿，此日又陽生。',48,'全唐诗/poet.song.53000.json','["今宵當月滿，此日又陽生。", "明浄乾坤氣，歡和井邑聲。", "年年對佳節，處處樂昇平。", "遙想京師盛，新宮太一迎。"]'),
('672c7288-d504-4d65-87bd-ad9a3a8ddc4a','小酌','孔平仲','宋','宋诗','song-poetry','','[]','落日山城晚，黄雲雪意濃。',24,'全唐诗/poet.song.53000.json','["落日山城晚，黄雲雪意濃。", "更須開一甕，頻醉送殘冬。"]'),
('5abbe6d1-270a-4a8e-8ae2-6c632a99b6c9','雪意遽解','孔平仲','宋','宋诗','song-poetry','','[]','向晚黄雲天爲低，卷簾注目雪花飛。',32,'全唐诗/poet.song.53000.json','["向晚黄雲天爲低，卷簾注目雪花飛。", "誰知夜半陰晴別，皎皎庭前寒月輝。"]'),
('7e6365a8-6f21-4170-9e82-5df57a811b63','題老杜集','孔平仲','宋','宋诗','song-poetry','','[]','七月鴟鴞乃至此，語言閎大復瑰奇。',64,'全唐诗/poet.song.53000.json','["七月鴟鴞乃至此，語言閎大復瑰奇。", "直侔造物并包體，不作諸家細碎詩。", "吏部徒能歎光燄，翰林何敢望藩籬。", "讀罷還看有餘味，令人心服是吾師。"]'),
('9e12b514-5d92-43e0-971c-26a72e85e91e','聞登萊大雪','孔平仲','宋','宋诗','song-poetry','','[]','聞說登萊雪一尺，此中晴色更無雲。',32,'全唐诗/poet.song.53000.json','["聞說登萊雪一尺，此中晴色更無雲。", "安得北風從海上，滿天吹過玉紛紛。"]'),
('002a1f6a-2e4f-43e5-8a78-53046987abe8','集于昌齡之舍','孔平仲','宋','宋诗','song-poetry','','[]','一醉昏昏萬不知，黄昏促席夜深歸。',32,'全唐诗/poet.song.53000.json','["一醉昏昏萬不知，黄昏促席夜深歸。", "明朝惟見家人說，昨夜歸時雪滿衣。"]'),
('c9cc2e3f-4e0f-48a9-a2c5-7bcf7726deb1','隨倅入京師答同列贈別','孔平仲','宋','宋诗','song-poetry','','[]','揮鞭西指鳳凰城，疏野之心無所營。',32,'全唐诗/poet.song.53000.json','["揮鞭西指鳳凰城，疏野之心無所營。", "預約牡丹花下酒，歸時節物近清明。"]'),
('cd3981df-3108-46af-9315-c0ad040000a3','途中口占','孔平仲','宋','宋诗','song-poetry','','[]','兩歲東州不自知，人情全在欲分時。',64,'全唐诗/poet.song.53000.json','["兩歲東州不自知，人情全在欲分時。", "餞行連日侵銀燭，送別臨岐駐玉羈。", "望見蒙山思馬耳，路經沂水憶河淇。", "歸來定得從容否，寄語庭前紅藥枝。"]'),
('88640f8b-ace7-4b88-a244-941248116ee5','寄內','孔平仲','宋','宋诗','song-poetry','','["\u5199\u666f", "\u6292\u60c5", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','試說途中景，方知別後心。',24,'全唐诗/poet.song.53000.json','["試說途中景，方知別後心。", "行人日暮少，風雪亂山深。"]'),
('2bd0bfd7-5c40-4227-ae56-897a5ca96ec1','省謁有日','孔平仲','宋','宋诗','song-poetry','','[]','捧檄欣然喜可知，輕裘淺𩍐去如飛。',32,'全唐诗/poet.song.53000.json','["捧檄欣然喜可知，輕裘淺𩍐去如飛。", "親庭一別今三載，即得從容戲綵衣。"]'),
('0af129d9-a173-4bbc-89ec-6be405053202','不雨','孔平仲','宋','宋诗','song-poetry','','[]','雨意竟寥寂，浮雲如湧泉。',48,'全唐诗/poet.song.53000.json','["雨意竟寥寂，浮雲如湧泉。", "商羊空自舞，霹靂謾加鞭。", "溽暑煩揮箑，荒灣久住船。", "何時出污濁，洗悶向清川。"]'),
('1c7b6f19-8ccb-4a64-b9ad-b1c2968e8013','昔時','孔平仲','宋','宋诗','song-poetry','','[]','昔時過此心何如，今時過此心何須。',32,'全唐诗/poet.song.53000.json','["昔時過此心何如，今時過此心何須。", "回波爲我將雙淚，逆上三江轉五湖。"]'),
('ca493154-8dca-4085-a3bf-dfbce823f5ea','詠蘆','孔平仲','宋','宋诗','song-poetry','','[]','地近長蘆蘆已深，舟行兩岸蔚森森。',64,'全唐诗/poet.song.53000.json','["地近長蘆蘆已深，舟行兩岸蔚森森。", "能藏蛇虺連山澗，强庇蛙蟆接水陰。", "疑汝此中無勁節，使吾終日隔遙岑。", "春風暑雨多情思，霜霰崢嶸想不禁。"]'),
('c2fe1098-bbee-43cc-90ec-24bc1cdf5661','郭公','孔平仲','宋','宋诗','song-poetry','','[]','枉渚潮初落，平岡日又西。',24,'全唐诗/poet.song.53000.json','["枉渚潮初落，平岡日又西。", "蘆叢深處泊，惟有郭公啼。"]'),
('1cc9350e-d0f0-4fcc-a8c8-586c338a9ff9','芙蓉堂','孔平仲','宋','宋诗','song-poetry','','[]','芙蓉堂下花如錦，記得當年此泊舟。',32,'全唐诗/poet.song.53000.json','["芙蓉堂下花如錦，記得當年此泊舟。", "今日重來皆蔓草，水紅無數强排秋。"]'),
('04800086-9fca-469a-8683-2f5d2d8daa1e','弄水亭','孔平仲','宋','宋诗','song-poetry','','[]','弄水垂吾手，圓波觸石堤。',48,'全唐诗/poet.song.53000.json','["弄水垂吾手，圓波觸石堤。", "夜深翻斗極，秋霽把虹蜺。", "鳥泛閒相得，烟生望稍迷。", "問源思杖策，人指白雲西。"]'),
('107fd2e4-609a-428e-89ec-107e4c458797','趙屯寺','孔平仲','宋','宋诗','song-poetry','','[]','崎嶇自牛徑，瀟灑得僧房。',48,'全唐诗/poet.song.53000.json','["崎嶇自牛徑，瀟灑得僧房。", "壞壁題名滿，幽軒背日凉。", "澗花時委地，鄰竹稍過牆。", "歸路風猶緊，垂楊作意狂。"]'),
('1a3937c5-177c-40c4-aca5-009ef55bc7f7','揚子道中寄陳君佐  其一','孔平仲','宋','宋诗','song-poetry','','[]','別我如不忍，念君方索居。',48,'全唐诗/poet.song.53000.json','["別我如不忍，念君方索居。", "蕭然對松竹，獨自理圖書。", "擊鉢詩無敵，連環辯有餘。", "驊騮志萬里，那久困鹽車。"]'),
('29db350e-318a-4089-8270-273832e83c2d','揚子道中寄陳君佐  其二','孔平仲','宋','宋诗','song-poetry','','[]','會合未云久，笑言今苦賒。',48,'全唐诗/poet.song.53000.json','["會合未云久，笑言今苦賒。", "山空愁夜鶴，野闊沸春蛙。", "雨漲新波滿，烟昏故壘遮。", "輸君官守佚，吟遍郡園花。"]'),
('ec1a0bf4-f3da-4c69-9134-5464c5ab6b70','天長道中','孔平仲','宋','宋诗','song-poetry','','[]','柔桑滿野麥成川，晴色連陂雨在田。',64,'全唐诗/poet.song.53000.json','["柔桑滿野麥成川，晴色連陂雨在田。", "顧影寂寥誰與語，據鞍閒暇不妨眠。", "塵勞可厭非今日，老大無堪異昔年。", "此去聊爲上都客，行當貨馬覓歸船。"]'),
('c5a78798-98b2-4d80-aaf1-88213351206f','至盱眙作','孔平仲','宋','宋诗','song-poetry','','[]','郵亭繫馬日西斜，却向盱眙望白沙。',64,'全唐诗/poet.song.53000.json','["郵亭繫馬日西斜，却向盱眙望白沙。", "春色淡中唯有柳，曉風狂過已無花。", "古人出處真難一，吾道窮通未可涯。", "白水黄粱不須具，呼奴挈榼取流霞。"]'),
('67201ec4-c8cb-4b60-8cf7-b204f8d83120','寓目','孔平仲','宋','宋诗','song-poetry','','[]','枝上餘花脫盡紅，行人驅馬綠陰中。',32,'全唐诗/poet.song.53000.json','["枝上餘花脫盡紅，行人驅馬綠陰中。", "青春裁翦應辛苦，不奈東南一夜風。"]'),
('aae602cd-dfa6-449c-9d14-c9c7982b50fd','汴上行','孔平仲','宋','宋诗','song-poetry','','[]','芳草連坡掛柳綿，春風卷地落榆錢。',32,'全唐诗/poet.song.53000.json','["芳草連坡掛柳綿，春風卷地落榆錢。", "時光解與行人別，若有離情應泫然。"]'),
('d74d4cb2-f279-4407-bb7f-a549907e1723','發青陽驛','孔平仲','宋','宋诗','song-poetry','','[]','悠悠驅馬汴河灣，幾處郵亭略解鞍。',64,'全唐诗/poet.song.53000.json','["悠悠驅馬汴河灣，幾處郵亭略解鞍。", "春盡榆錢堆狹路，曉陰花雨作輕寒。", "山川相背圖中畫，日月雙移坂上丸。", "行役漸多身漸老，詩題聊寄旅程難。"]'),
('9b581e26-2a01-4113-8b16-00786e1c28b4','發靈驛作','孔平仲','宋','宋诗','song-poetry','','[]','晨裝獨入古河堤，杜宇無端向客啼。',32,'全唐诗/poet.song.53000.json','["晨裝獨入古河堤，杜宇無端向客啼。", "昨夜東風吹猛雨，綠陰遮合不成泥。"]'),
('aa551c93-2a5d-4496-995a-83a03ec77d93','河亭獨酌寄林次中','孔平仲','宋','宋诗','song-poetry','','[]','沙岸朝來雨乍晴，東風舒卷柳條輕。',32,'全唐诗/poet.song.53000.json','["沙岸朝來雨乍晴，東風舒卷柳條輕。", "消愁亦有旗亭酒，誰與當樽唱渭城。"]'),
('6e19ede4-b88a-4955-b99f-12c0d33067d5','偶書','孔平仲','宋','宋诗','song-poetry','','[]','季子懸頭思趙國，越王嘗膽望吳城。',32,'全唐诗/poet.song.53000.json','["季子懸頭思趙國，越王嘗膽望吳城。", "少年莫念紛華事，功業多從辛苦生。"]'),
('30d15544-4495-4012-9bd3-9c09482b1235','入亳州界','孔平仲','宋','宋诗','song-poetry','','[]','贏糧襆被望都門，路出符離日未醺。',64,'全唐诗/poet.song.53000.json','["贏糧襆被望都門，路出符離日未醺。", "清汴橫飛天上浪，方塘穩鎖鏡中雲。", "淮南風物多相似，江上音書久不聞。", "寄語北山姑待我，莫因西去勒移文。"]'),
('33bda1d4-f89d-4bc1-9950-d4634f45325d','濟陽作','孔平仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','曾浮輕舸下長江，依舊東風卷綠楊。',64,'全唐诗/poet.song.53000.json','["曾浮輕舸下長江，依舊東風卷綠楊。", "往事山川空滿目，新年鬚鬢欲成霜。", "烟塵莽蒼隨長路，雲日蕭條隔舊鄉。", "膂力四方男子事，不須彈鋏苦悲傷。"]'),
('7471ee08-d529-4726-9995-c7c9041a0417','榆錢','孔平仲','宋','宋诗','song-poetry','','[]','鏤雪裁綃箇箇圓，日斜風定穩如穿。',32,'全唐诗/poet.song.53000.json','["鏤雪裁綃箇箇圓，日斜風定穩如穿。", "憑誰細與東君說，買住青春費幾錢。"]'),
('edb748f1-d5ee-4505-a59c-d7fac747b92c','柳絮','孔平仲','宋','宋诗','song-poetry','','[]','風定漫漫雪不飛，忽然飄蕩幾時歸。',32,'全唐诗/poet.song.53000.json','["風定漫漫雪不飛，忽然飄蕩幾時歸。", "瓊林金谷知多少，半入樓臺半拂衣。"]'),
('04381a66-85ca-43a4-bcd5-a25410962404','廢廟','孔平仲','宋','宋诗','song-poetry','','[]','靈宇何年置，荒臺漸欲平。',48,'全唐诗/poet.song.53000.json','["靈宇何年置，荒臺漸欲平。", "丹青多泯滅，苔蘚太分明。", "棟宇非難復，威靈想不行。", "長林相蔽翳，惟有暮鴉鳴。"]'),
('152d13d6-6599-4dbb-bf07-e44dd981071b','雍丘驛作','孔平仲','宋','宋诗','song-poetry','','[]','京塵漠漠稍侵衣，秣馬雍丘日未西。',32,'全唐诗/poet.song.53000.json','["京塵漠漠稍侵衣，秣馬雍丘日未西。", "驛舍蕭然無與語，遠牆閒覓故人題。"]'),
('57c87726-5910-4446-adb9-beaa877162a8','寄蘇子由','孔平仲','宋','宋诗','song-poetry','','[]','歷下攀遊今幾年，相逢顔鬢覺蒼然。',64,'全唐诗/poet.song.53000.json','["歷下攀遊今幾年，相逢顔鬢覺蒼然。", "西齊美錦窺詩軸，北郭濃霞入酒船。", "別思忽隨春浩蕩，還期已過月團圓。", "君家早有爲霖望，莫學隆中但穩眠。"]'),
('ee3ad356-6210-47df-b1e1-d42923e4b4fe','入陳留界','孔平仲','宋','宋诗','song-poetry','','[]','青青麥隴鳥相呼，淡淡長空尺靄無。',32,'全唐诗/poet.song.53000.json','["青青麥隴鳥相呼，淡淡長空尺靄無。", "驛道寬平人語好，共知明日到皇都。"]'),
('2d39b79d-27a2-4d49-953d-36edf782a689','自雍丘取別路至陳留界較汴堤徑二十里','孔平仲','宋','宋诗','song-poetry','','[]','平生羞捷徑，到此尚狐疑。',24,'全唐诗/poet.song.53000.json','["平生羞捷徑，到此尚狐疑。", "望斷澹臺路，登高賦所思。"]'),
('fbc0cb07-2a30-4f71-8658-2b162a212d81','次韵偶書','孔平仲','宋','宋诗','song-poetry','','[]','凄風下殘葉，疏雨滴黄昏。',48,'全唐诗/poet.song.53000.json','["凄風下殘葉，疏雨滴黄昏。", "山氣先冬冷，江流入夜渾。", "無兵誅二鄙，有策濟群元。", "鬰鬰平生志，憑誰薦一言。"]'),
('c8675fa6-fa06-48d7-bfa6-575708d766b8','有感','孔平仲','宋','宋诗','song-poetry','','[]','末俗皆趨利，貧心獨惡華。',48,'全唐诗/poet.song.53000.json','["末俗皆趨利，貧心獨惡華。", "葛衣冬已晏，黍飯日將斜。", "岳重淵騫伍，毫輕許史家。", "浩然忘世慮，書劍一生涯。"]'),
('1cde67be-3714-4c48-96fd-9529baaa0f13','喻意','孔平仲','宋','宋诗','song-poetry','','[]','楚天陰易久，顔巷意何孤。',48,'全唐诗/poet.song.53000.json','["楚天陰易久，顔巷意何孤。", "貧賤身雖困，英雄膽未枯。", "西山縻虎足，北海拔龍鬚。", "一劍何時起，功成泛五湖。"]'),
('cddd3d8d-6c09-4daf-a0d5-7489fc3dfdc9','秋夜偶書','孔平仲','宋','宋诗','song-poetry','','[]','擊劍悲歌涕滴胸，清時一向老英雄。',32,'全唐诗/poet.song.53000.json','["擊劍悲歌涕滴胸，清時一向老英雄。", "白狼黑犬如相犯，願語南山矍鑠翁。"]'),
('167501aa-2ed9-4a43-896b-8738f2f93c55','贈王吉甫  其一','孔平仲','宋','宋诗','song-poetry','','[]','項王戰敗恥歸東，仗劍南游寂寞中。',64,'全唐诗/poet.song.53000.json','["項王戰敗恥歸東，仗劍南游寂寞中。", "雨雪蕭條千里暗，乾坤浩蕩一身窮。", "文章未屬清時用，議論徒多烈士風。", "四海望霖龍折角，爲君悲絕訴蒼穹。"]'),
('7701a5ff-7387-4f98-983e-a797ebb81333','贈王吉甫  其二','孔平仲','宋','宋诗','song-poetry','','[]','生計簞瓢少鬰陶，談經千古見秋毫。',64,'全唐诗/poet.song.53000.json','["生計簞瓢少鬰陶，談經千古見秋毫。", "神驅筆下鋒鋩俊，天縱胸中氣象豪。", "事業今朝心孔孟，功名他日踵蕭曹。", "行行努力牽牛餌，北海波中釣巨鰲。"]'),
('3ce167c2-432f-4b24-b6f0-d069d395ddcc','贈王吉甫  其三','孔平仲','宋','宋诗','song-poetry','','[]','嗟予困羈旅，雨昏蕭寺中。',48,'全唐诗/poet.song.53000.json','["嗟予困羈旅，雨昏蕭寺中。", "客情隨日淡，詩思入秋雄。", "目斷故鄉路，心飛黄葉風。", "文軒又將去，坐覺笑談空。"]'),
('d5305452-c3f8-4241-9284-48b0f07cef80','秋夕','孔平仲','宋','宋诗','song-poetry','','[]','月色清餘睡，寒霜入病軀。',48,'全唐诗/poet.song.53000.json','["月色清餘睡，寒霜入病軀。", "漏隨詩思急，燈伴客心孤。", "匣鎖劍三尺，身沈天一隅。", "蛟龍困勺水，永夜憶江湖。"]'),
('91fb94a0-92a1-40e5-94d7-5abcf3a91a1f','十月寒','孔平仲','宋','宋诗','song-poetry','','[]','初寒十月終，凜烈若窮冬。',48,'全唐诗/poet.song.53000.json','["初寒十月終，凜烈若窮冬。", "陰谷凍猛虎，冰潭僵老龍。", "霜威刷六合，雪影暗千峰。", "孤客坐無火，悲吟聽暮鐘。"]'),
('d72a59cc-1ed7-4da3-b95f-a5a982bbef29','別介之','孔平仲','宋','宋诗','song-poetry','','[]','歸去白雲居，山行百里餘。',48,'全唐诗/poet.song.53000.json','["歸去白雲居，山行百里餘。", "腰藏三尺劍，腹載五車書。", "暮雨添雲重，秋風落翠疏。", "此時別離興，滴淚滿襟裾。"]'),
('a6125a2b-9a37-400c-867a-ff481d5a9516','談道亭睡覺而成','孔平仲','宋','宋诗','song-poetry','','[]','松竹晝陰環，清風枕席間。',48,'全唐诗/poet.song.53000.json','["松竹晝陰環，清風枕席間。", "夢隨啼鳥散，心伴白雲閑。", "漁艇歸前浦，樵歌下遠山。", "徘徊明月夜，高興向忘還。"]'),
('7dc7d019-600a-4588-b261-8fee5366c1c3','呈介之','孔平仲','宋','宋诗','song-poetry','','[]','鐵面嶔巖鬼亦驚，世間兒女敢相輕。',64,'全唐诗/poet.song.53000.json','["鐵面嶔巖鬼亦驚，世間兒女敢相輕。", "文章自古傳周燮，德行當時貴滅明。", "四海生靈雖帖泰，兩邊豺虎尚縱橫。", "胸中久畜平戎策，不日敷施報太平。"]'),
('88ab0fe3-2885-4ba8-9cd8-4016d464d93e','呈介之求禮部唱和一閱','孔平仲','宋','宋诗','song-poetry','','[]','金紫相摩上玉堂，南宮詩戰鎮相將。',64,'全唐诗/poet.song.53000.json','["金紫相摩上玉堂，南宮詩戰鎮相將。", "毫端寫出青春色，窗下吟銷白晝長。", "辭艷迸開昆嶂火，文章翻出鐵林鎗。", "愁中欲得神仙句，更藉夫君不閉藏。"]'),
('b729f5cd-3cc3-40b9-83af-ff379ea0de34','夜坐舟中偶成','孔平仲','宋','宋诗','song-poetry','','[]','臲卼扁舟抱寒水，逍遙野客坐孤蓬。',64,'全唐诗/poet.song.53000.json','["臲卼扁舟抱寒水，逍遙野客坐孤蓬。", "一天星月清吟外，萬里江山極望中。", "遯迹未能離草莽，機心唯欲破羌戎。", "此心未遂難爲語，負劍長吁氣滿空。"]'),
('16c2ef56-9def-4370-bfd0-2e2c87dd0cc8','送郭聖原歸廬陵','孔平仲','宋','宋诗','song-poetry','','[]','文章豪逸難爲敵，格志孤高自出凡。',64,'全唐诗/poet.song.53000.json','["文章豪逸難爲敵，格志孤高自出凡。", "兩歲論交重金石，今朝泣別倚松杉。", "滿江春碧圍仙棹，入曉風輕送錦帆。", "此去天涯皆獨立，寂寥相望隔溪巖。"]'),
('e9013c5e-0785-4a79-b0e5-4521fefff0ba','蹇叔以登亭有感示予因以答之','孔平仲','宋','宋诗','song-poetry','','[]','何處登臨可極觀，危軒隠在碧雲端。',64,'全唐诗/poet.song.53000.json','["何處登臨可極觀，危軒隠在碧雲端。", "千年古樹少春態，一片江天带暮寒。", "人似神仙君自好，心如鐵石我難干。", "花紅柳綠休多語，且把詩書仔細看。"]'),
('700d8c16-6ee8-40c6-b3a3-e8411923c7c1','清明雨不果出','孔平仲','宋','宋诗','song-poetry','','[]','雷勢黑飛天馬陣，雨聲狂播鐵林鎗。',32,'全唐诗/poet.song.53000.json','["雷勢黑飛天馬陣，雨聲狂播鐵林鎗。", "清明節物都誰賞，寂寞無聊戀故鄉。"]'),
('9c80dd38-84c7-4e1f-b8ca-9e975718aa90','和酬介之','孔平仲','宋','宋诗','song-poetry','','[]','筆刃詞鋒劍戟稠，千金明月暗相投。',64,'全唐诗/poet.song.53000.json','["筆刃詞鋒劍戟稠，千金明月暗相投。", "君雞已勇誇長嘴，我豕徒勞詫白頭。", "清似愁中聞玉笛，美如饑後嘬蘭羞。", "伯牙未老鍾期在，再寫孤音漫繼酬。"]'),
('de76aee8-1de9-4f0d-8c84-604f31f5a926','書齋獨坐有懷','孔平仲','宋','宋诗','song-poetry','','[]','孤燭夜自明，四壁冷無聲。',48,'全唐诗/poet.song.53000.json','["孤燭夜自明，四壁冷無聲。", "欹枕清無寐，思時憤不平。", "林中多虎豹，天上有欃槍。", "匣劍蟠龍氣，何時仗汝評。"]'),
('da920007-db5f-4d0b-a1a5-cf3f32626fbe','呈介之','孔平仲','宋','宋诗','song-poetry','','[]','古柏青黄苦暗凋，怪松千尺老嶕嶢。',64,'全唐诗/poet.song.53000.json','["古柏青黄苦暗凋，怪松千尺老嶕嶢。", "詞源浩浩聲連海，筆力衝衝氣逼霄。", "賈賦任雄難作敵，杜詩雖健亦相饒。", "英豪自古非塵物，他日峨冠立漢朝。"]'),
('207364dc-d043-47d8-9205-cd660e7d7d47','登談道亭','孔平仲','宋','宋诗','song-poetry','','[]','爲厭紅塵觸目生，與君携手上幽亭。',64,'全唐诗/poet.song.53000.json','["爲厭紅塵觸目生，與君携手上幽亭。", "波光碎碧瑠璃地，竹影疏青翡翠屏。", "雲惹閑心歸遠岫，風吹詩思入滄溟。", "名機利械都忘去，才得人間醉一醒。"]'),
('7184b982-e04f-4d7b-b81d-51d06663ff44','和介之','孔平仲','宋','宋诗','song-poetry','','[]','井邑喧囂不忍行，捲簾終日愛江亭。',64,'全唐诗/poet.song.53000.json','["井邑喧囂不忍行，捲簾終日愛江亭。", "竹聲滿耳蕭蕭雨，山色挨簷曲曲屏。", "連夜劍光摩北斗，幾時鵬翼起南溟。", "與君分義尤相合，有酒頻來此醉醒。"]'),
('8a7ddba3-d9a8-4f41-80fa-d5168722a770','別館春','孔平仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','別館無人迹，春歸空綠蕪。',48,'全唐诗/poet.song.53000.json','["別館無人迹，春歸空綠蕪。", "落花深不掃，啼鳥靜相呼。", "坐想龍山景，方淹瘴海隅。", "幾因北窗臥，一夢到西湖。"]'),
('2ee7494e-5f13-4d53-a235-d97de1f37666','清夜','孔平仲','宋','宋诗','song-poetry','','[]','夜久景逾清，行吟到小亭。',48,'全唐诗/poet.song.53000.json','["夜久景逾清，行吟到小亭。", "梨花带明月，銀漢淡疏星。", "渡水漁歌遠，巡山鬼火青。", "此時塵慮息，豁若醉初醒。"]'),
('c912a7e3-4977-486e-8e88-11d8e730c1b4','中夜口占','孔平仲','宋','宋诗','song-poetry','','[]','晴漢疑收練，陰雲忽湧濤。',48,'全唐诗/poet.song.53000.json','["晴漢疑收練，陰雲忽湧濤。", "山空鬼聚嘯，月黑虎長號。", "露偪睡魔走，風飄詩膽豪。", "靜中余所樂，六印一鴻毛。"]'),
('8b7a69d8-43de-4c8d-887b-d1b12934462f','求言','孔平仲','宋','宋诗','song-poetry','','[]','人多護所短，孰肯告之言。',48,'全唐诗/poet.song.53000.json','["人多護所短，孰肯告之言。", "不自聰明廣，何由道義尊。", "知非君子趣，文過鄙夫存。", "安得同心友，相攀至聖門。"]'),
('64bb008d-a14c-4cf6-a3d3-5a3a83e46082','口號','孔平仲','宋','宋诗','song-poetry','','[]','今日朱顔客，明朝白髮人。',24,'全唐诗/poet.song.53000.json','["今日朱顔客，明朝白髮人。", "莫教行樂晚，須惜少年春。"]'),
('8f965334-9e77-48af-bbf2-f004479ee96d','西軒偶書','孔平仲','宋','宋诗','song-poetry','','[]','瀟灑無俗韵，登臨紓遠情。',48,'全唐诗/poet.song.53000.json','["瀟灑無俗韵，登臨紓遠情。", "吟題紅葉滿，臥看白雲生。", "山色差屏翠，溪流瀉鏡明。", "優游此終日，其樂勝公卿。"]'),
('9f879f91-04d9-42c9-a07b-c7ca967276d1','寬恤民力','孔平仲','宋','宋诗','song-poetry','','[]','天地清明日，君臣際會秋。',96,'全唐诗/poet.song.53000.json','["天地清明日，君臣際會秋。", "雷霆大號徧，雨雪湛恩流。", "士卒休羣戍，耕桑勸九州。", "中邦節賜予，下吏省誅求。", "物繼由庚詠，民喧擊壤謳。", "泰寧堪坐致，寬恤此良謀。", "戶曉爲今失，官詢校古羞。", "愚言惟聖擇，神斷戒優游。"]'),
('3caa78bb-23c9-4a34-bd37-352b1cb5cee9','覽鏡','孔平仲','宋','宋诗','song-poetry','','[]','拂拭菱花試一臨，貌隨年改歎光陰。',64,'全唐诗/poet.song.53000.json','["拂拭菱花試一臨，貌隨年改歎光陰。", "朱顔慘淡塵埃滿，白髮蕭疏瘴霧侵。", "自笑腐唇因苦學，誰知瘦骨爲愁吟。", "平生履行無人識，嗟爾頑銅豈照心。"]'),
('ba9bd5d5-c1e0-4047-9326-8af8932f6c78','偶書','孔平仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','經歲留南戍，頻時思故邦。',48,'全唐诗/poet.song.53000.json','["經歲留南戍，頻時思故邦。", "青山又薄暮，斜日滿西窗。", "遣憤詩千首，迷愁酒百缸。", "何緣幸免去，歸棹破長江。"]'),
('5f95eeb5-ee67-41eb-ae2f-ec039f08bbde','近乾元節方教樂而雨','孔平仲','宋','宋诗','song-poetry','','[]','半月新調樂府班，佳期今近迫陰顔。',64,'全唐诗/poet.song.53000.json','["半月新調樂府班，佳期今近迫陰顔。", "歌喉斷續微風外，舞隊差池細雨間。", "坐賞賓朋愁不解，來遊士女半皆還。", "人心共望晴明景，嗟爾乖龍獨阻艱。"]'),
('96f1d4d0-e861-4e5b-9d67-70b0800feb56','城樓晚眺','孔平仲','宋','宋诗','song-poetry','','[]','華閣倚青空，凭欄嘯遠風。',48,'全唐诗/poet.song.53000.json','["華閣倚青空，凭欄嘯遠風。", "溪光梅雨後，山影夕陽中。", "細草傷心綠，餘霞照面紅。", "此身歸計未，客棹自西東。"]'),
('b41bae46-ad3c-4ef9-ad44-4528177c8c8b','余得文竹寸餘上有仙翁神女像相偶而坐異之作詩','孔平仲','宋','宋诗','song-poetry','','[]','千載皇英恨未平，淚沾湘竹錦文成。',64,'全唐诗/poet.song.53000.json','["千載皇英恨未平，淚沾湘竹錦文成。", "我收寸管尤瑰異，上有羣仙無姓名。", "乍見偶同神女夢，靜看獨認赤松迎。", "世間此物真難滯，它日相從上太清。"]'),
('9243a07b-bc83-4ed8-9fdb-9779a8aa4018','即事','孔平仲','宋','宋诗','song-poetry','','[]','久病情懷已索然，况當景氣似秋天。',64,'全唐诗/poet.song.53000.json','["久病情懷已索然，况當景氣似秋天。", "書窗靜滴芭蕉雨，吟砌輕籠薜荔烟。", "雲結繁陰低遠岫，風排白浪滿平川。", "多愁無計堪消遣，斗酒澆成一覺眠。"]'),
('fc59ab8b-171e-4a6f-9eb7-4c2b19c4ff91','陶侃','孔平仲','宋','宋诗','song-poetry','','[]','梭作龍飛應自喜，指將針决欲何求。',32,'全唐诗/poet.song.53000.json','["梭作龍飛應自喜，指將針决欲何求。", "頼君乍覺登天夢，不爾王敦一輩流。"]'),
('4a45bc01-aa79-4a09-bd75-6a10ffcddee3','扶蘇','孔平仲','宋','宋诗','song-poetry','','[]','天下精兵掌握間，便宜長嘯入秦關。',32,'全唐诗/poet.song.53000.json','["天下精兵掌握間，便宜長嘯入秦關。", "奈何伏劍區區死，不辨書從趙李奸。"]'),
('cda066bb-fb34-4913-8aaf-5b193354032d','屈平','孔平仲','宋','宋诗','song-poetry','','[]','進居卿相謀何拙，退臥林泉道未降。',32,'全唐诗/poet.song.53000.json','["進居卿相謀何拙，退臥林泉道未降。", "堪笑先生不知命，褊心一斥便沈江。"]'),
('f8496118-c2c5-4c03-bfb6-4bc5a0acfd33','平津侯','孔平仲','宋','宋诗','song-poetry','','[]','待士聲名畫餠虛，天資多忌與人疏。',32,'全唐诗/poet.song.53000.json','["待士聲名畫餠虛，天資多忌與人疏。", "未聞東閣升賢者，已見膠西置仲舒。"]'),
('71b57525-8f06-49da-b1dd-52ab38d966ba','和人見贈','孔平仲','宋','宋诗','song-poetry','','[]','少年有志慕軻雄，十載潜心黄卷中。',64,'全唐诗/poet.song.53000.json','["少年有志慕軻雄，十載潜心黄卷中。", "富貴未來嗟命蹇，文章多妙嘆童蒙。", "駑材尚藉鞭驅力，頑璞須資刻琢功。", "誘掖相成期在子，可慚誇詠枉清風。"]'),
('dca2d82b-4799-49f8-b193-1734322d0e0f','王秀才謀歸作詩留之','孔平仲','宋','宋诗','song-poetry','','[]','相邀盂飯與盤蔬，坐偶行從半歲餘。',64,'全唐诗/poet.song.53000.json','["相邀盂飯與盤蔬，坐偶行從半歲餘。", "夜倚松窗詠風月，晝揮玉麈講詩書。", "論交切切初謀協，告別匆匆晚意疏。", "須亮主人攀惜甚，挽回歸袖欲投車。"]'),
('e1d4fd90-dbc4-47ee-beb3-0727c98c4ef3','戲呈葉秘校求薔薇栽','孔平仲','宋','宋诗','song-poetry','','[]','今歲花開應笑君，對花都不召嘉賓。',32,'全唐诗/poet.song.53000.json','["今歲花開應笑君，對花都不召嘉賓。", "東鄰乞種歸封植，我欲自爲花主人。"]'),
('698c8f9c-4ea6-48da-a058-744c74b23fb1','葉晦之送薔薇栽仍貽詩因以韵和','孔平仲','宋','宋诗','song-poetry','','[]','曾約種花爲主人，花開猶在隔年春。',32,'全唐诗/poet.song.53000.json','["曾約種花爲主人，花開猶在隔年春。", "只應未賞君先去，自是芙蓉幕下賓。"]'),
('6b2cd379-769e-437e-b229-4b8b351fb917','秋晚懷晦之','孔平仲','宋','宋诗','song-poetry','','[]','宿鳥窺簷日漸昏，徘徊顧視少埃氛。',64,'全唐诗/poet.song.53000.json','["宿鳥窺簷日漸昏，徘徊顧視少埃氛。", "高槐結陣鳴秋雨，疊嶂爭豪出暝雲。", "愁病巑岏誰省我，笑談磊落獨憐君。", "遙思靜坐西窗下，只與何人治典墳。"]'),
('0520d82c-7c65-439b-acf0-9629b8230a2a','晦之病酒因書以戒之','孔平仲','宋','宋诗','song-poetry','','[]','本爲情沈飲，翻成病染身。',24,'全唐诗/poet.song.53000.json','["本爲情沈飲，翻成病染身。", "今朝高枕處，應羨獨醒人。"]'),
('8dc381bd-cae5-42e0-95c2-cb3165cff1cc','月夕待人不至','孔平仲','宋','宋诗','song-poetry','','[]','故人相約一訪我，東望不至心躊躇。',32,'全唐诗/poet.song.53000.json','["故人相約一訪我，東望不至心躊躇。", "清風滿袖月千里，此處苦吟誰和予。"]'),
('de82fc60-ce58-40c4-a349-5a60fbe4120f','偶書','孔平仲','宋','宋诗','song-poetry','','[]','羈旅淹南戍，栖遲繞塞垣。',48,'全唐诗/poet.song.53000.json','["羈旅淹南戍，栖遲繞塞垣。", "海氛朝自暗，山氣晝常昏。", "蟲穴風來毒，蠻溪水出渾。", "故鄉方遠想，斜日更啼猿。"]'),
('ca602441-953d-4ed6-8f73-b3f534723259','寄中淵','孔平仲','宋','宋诗','song-poetry','','[]','我行君在家，南北各天涯。',48,'全唐诗/poet.song.53000.json','["我行君在家，南北各天涯。", "恨別三秋久，悲思萬里賒。", "歸心瀧浪急，遠目嶺雲遮。", "相見何時再，青山日又斜。"]'),
('2956b735-df7d-495b-b711-827a1c76e951','十月梨花','孔平仲','宋','宋诗','song-poetry','','[]','皓質輕盈粉乍勻，小園初放一枝新。',32,'全唐诗/poet.song.53000.json','["皓質輕盈粉乍勻，小園初放一枝新。", "意嫌開在梅花後，先吐香心不待春。"]'),
('57face61-2a0f-4735-baae-5ad87d6c2585','重到山寺','孔平仲','宋','宋诗','song-poetry','','[]','人迹少到此，山扉長悄然。',48,'全唐诗/poet.song.53000.json','["人迹少到此，山扉長悄然。", "空庭但噪雀，古木自生烟。", "鼠拱頹牆穴，蝸交腐棟涎。", "登臨未窮覽，斜影促歸鞭。"]'),
('8bad82ba-8c0a-47df-b11f-00e0ac138f87','介之惠詩言斥於禮部欲自此高退山園且招予游故答此章','孔平仲','宋','宋诗','song-poetry','','[]','角藝詞場欲進身，混然誰辨玉并珉。',64,'全唐诗/poet.song.53000.json','["角藝詞場欲進身，混然誰辨玉并珉。", "無常勝負如六博，不幸沈浮知幾人。", "君已自甘龍退蟄，我猶有待蠖求伸。", "未腰相印男兒恥，他日功成方卜鄰。"]'),
('7e966831-b626-462a-83da-cb4dcaf4b26b','寓目','孔平仲','宋','宋诗','song-poetry','','[]','雲慘天如褐，山橫日易昏。',48,'全唐诗/poet.song.53000.json','["雲慘天如褐，山橫日易昏。", "寒鴉啼古木，饑雀噪空園。", "紅葉風飄勢，蒼苔雨滴痕。", "行吟有清興，寂寞與誰論。"]'),
('d9889709-ec8b-411b-b2fd-34ab70e5b1d8','歲暮作','孔平仲','宋','宋诗','song-poetry','','[]','目極天地曠，心淒原野荒。',48,'全唐诗/poet.song.53000.json','["目極天地曠，心淒原野荒。", "高梧脫葉瘦，凍雀抱枝僵。", "松柏凌寒在，鵰鴻得意翔。", "平時豈相混，此日辨風霜。"]'),
('62a3d046-090a-4571-a7b4-8f28e021a23d','冬晚懷介之','孔平仲','宋','宋诗','song-poetry','','[]','竄迹南遊歲再侵，思歸望遠久沈吟。',64,'全唐诗/poet.song.53000.json','["竄迹南遊歲再侵，思歸望遠久沈吟。", "風敲古木寒聲碎，雲擁江天暝色深。", "飲可滌愁誰伴醉，詩從寫恨少知音。", "想君笑語如饑渴，何日相逢慰此心。"]'),
('038178eb-74aa-496b-a5b1-e0da4dec3fbb','偶書','孔平仲','宋','宋诗','song-poetry','','[]','窮骨支離甚，危腸感激多。',48,'全唐诗/poet.song.53000.json','["窮骨支離甚，危腸感激多。", "人生易日月，世路苦風波。", "素志償猶未，朱顔顧幾何。", "不如都棄置，對酒且高歌。"]'),
('884b17fd-7092-4f4f-8d05-eca2d0b6af41','春陰','孔平仲','宋','宋诗','song-poetry','','[]','慘淡春陰久，蕭條客望中。',48,'全唐诗/poet.song.53000.json','["慘淡春陰久，蕭條客望中。", "愁雲抱孤嶺，密雨暗長空。", "草色萋已綠，花開枝半紅。", "何時見晴景，携酒趁東風。"]'),
('00e68c45-529a-4c7e-ad23-448e36628e87','寒食宴北山席上走筆得松字','孔平仲','宋','宋诗','song-poetry','','[]','駘蕩禁烟節，相隨上北峰。',48,'全唐诗/poet.song.53000.json','["駘蕩禁烟節，相隨上北峰。", "雨餘澄遠水，風細韵長松。", "柳影摇歌席，花香入酒鍾。", "南州富閒暇，行樂且從容。"]'),
('c661d3d5-99a5-46fb-a287-5fac6a70428c','春歸','孔平仲','宋','宋诗','song-poetry','','[]','春到强娛樂，春歸心寂然。',48,'全唐诗/poet.song.53000.json','["春到强娛樂，春歸心寂然。", "夕陽芳草地，梅雨落花天。", "梁舌獨調燕，林聲漸噪蟬。", "朱顔隨物改，誰與駐流年。"]'),
('88d6fcc5-1ce2-4ad6-bb12-dcf7bf38283f','晦之厭州縣之勞作詩奉勉','孔平仲','宋','宋诗','song-poetry','','[]','踠足驊騮鎩羽鴻，似君今日歎途窮。',64,'全唐诗/poet.song.53000.json','["踠足驊騮鎩羽鴻，似君今日歎途窮。", "濯纓空有滄浪志，斂板猶趨塵土中。", "論議最宜陪鳳沼，文章獨可直鼇宮。", "暫時淹卹寧非命，得失須觀塞上翁。"]'),
('733b0be3-f40e-4346-a050-772a6d3b2d7d','旦夕北歸徵晦之詩爲別','孔平仲','宋','宋诗','song-poetry','','[]','殊邦會遇喜親依，聚散參差志願違。',64,'全唐诗/poet.song.53000.json','["殊邦會遇喜親依，聚散參差志願違。", "君屈清才尚南戍，我隨流水欲東歸。", "沈吟晚日愁堪掬，顧盼江雲淚滿衣。", "冀得佳篇慰離苦，且令行色有餘輝。"]'),
('cf555768-668c-49a8-a8f4-75a3b716a81a','回王秀才二賦','孔平仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','郭璞長江宋玉風，君才可與角豪雄。',64,'全唐诗/poet.song.53000.json','["郭璞長江宋玉風，君才可與角豪雄。", "織成故典文之巧，琢就新詞學者工。", "昔日貌觀輕子羽，今朝穎出喜毛公。", "頻煩教我勤多矣，疏决蒙泉使向東。"]'),
('c3ae60df-4115-4743-9a74-377c1a5839be','族人春飲','孔平仲','宋','宋诗','song-poetry','','[]','柳榭陰陰春半時，相邀閒暇賞芳菲。',64,'全唐诗/poet.song.53000.json','["柳榭陰陰春半時，相邀閒暇賞芳菲。", "家人共酌榴花酒，蠻妓爭歌金縷衣。", "火焰高低紅躑躅，繡龍濃淡小薔薇。", "此中莫惜長歡醉，自古人生七十稀。"]'),
('70393f77-4163-4c84-a3cf-8799292d4bf9','雲','孔平仲','宋','宋诗','song-poetry','','[]','白雲高潔倚愁空，本謂無心與我同。',32,'全唐诗/poet.song.53000.json','["白雲高潔倚愁空，本謂無心與我同。", "奈何一夕陽風發，吹到巫山十二峰。"]'),
('2efcf898-0bdb-423f-b1c9-1ac3d9989746','自和喻意四首  其一','孔平仲','宋','宋诗','song-poetry','','[]','寒夜風雨細，陰房燈火孤。',48,'全唐诗/poet.song.53000.json','["寒夜風雨細，陰房燈火孤。", "一身無羽翼，萬事有榮枯。", "壯志斷鼇足，雄謀編虎鬚。", "蛟龍困尺水，夢想在江湖。"]'),
('220ed22c-f62a-4e1f-af86-23fc9a6b48e8','自和喻意四首  其二','孔平仲','宋','宋诗','song-poetry','','[]','青山望不極，落日意偏孤。',48,'全唐诗/poet.song.53000.json','["青山望不極，落日意偏孤。", "生計一瓢足，秋風雙鬢枯。", "顧予蘭紉佩，笑子帛纏鬚。", "別有相同處，胸中萬頃湖。"]'),
('69d74160-d5cc-4153-8343-7bdf7a10fbac','自和喻意四首  其三','孔平仲','宋','宋诗','song-poetry','','[]','千里聲相應，平生德不孤。',48,'全唐诗/poet.song.53000.json','["千里聲相應，平生德不孤。", "豹文方霧隠，松節豈霜枯。", "壯志橫磨劍，衰顔早照鬚。", "莫同魚鳥態，忘我向江湖。"]'),
('793933f9-84a1-43c4-b78e-683eb92a87bf','自和喻意四首  其四','孔平仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','好靜心常爽，憑高興愈孤。',48,'全唐诗/poet.song.53000.json','["好靜心常爽，憑高興愈孤。", "山雲長掩翠，原火漸焚枯。", "雨竹雙妃淚，霜松四皓鬚。", "猶嫌望中隘，思泛洞庭湖。"]'),
('d78401c1-a67f-45ed-ab08-278ea6410753','夏夜書事','孔平仲','宋','宋诗','song-poetry','','[]','空庭愁寂一蟬鳴，齋閣陰陰夏簟清。',64,'全唐诗/poet.song.53000.json','["空庭愁寂一蟬鳴，齋閣陰陰夏簟清。", "鳥背送回殘照去，林梢看得晚凉生。", "歸鴉映水繽紛黑，斜月穿簾點滴明。", "一夜渴心不得曉，唯聽深井轆轤聲。"]'),
('8688a386-1a85-40a6-bc88-3b8485031e2b','和子瞻西掖種竹二首  其一','孔平仲','宋','宋诗','song-poetry','','[]','西垣種竹滿庭隅，正值天街小雨初。',64,'全唐诗/poet.song.53000.json','["西垣種竹滿庭隅，正值天街小雨初。", "漸近凉風侵夢覺，已留清露滴吟餘。", "卜鄰近喜蒼苔滿，託迹方驚上苑疏。", "昨夜青藜光照席，綠陰相對小除書。"]'),
('b738d991-98fc-4dcb-9ab2-bc00a8cfbbf5','和子瞻西掖種竹二首  其二','孔平仲','宋','宋诗','song-poetry','','[]','此君安可一朝無，請看西園種竹初。',64,'全唐诗/poet.song.53000.json','["此君安可一朝無，請看西園種竹初。", "嶰谷正當吹鳳後，葛陂猶是化龍餘。", "風摇夢枕秋聲碎，月滿吟憲夜影疏。", "他日如封管城子，莫嫌老禿不中書。"]'),
('ed8180b8-44f3-4e11-932f-ee60f3af82bf','題女媧山女媧廟  其一','孔平仲','宋','宋诗','song-poetry','','[]','攬轡金房道，崎嶇難具陳。',48,'全唐诗/poet.song.53000.json','["攬轡金房道，崎嶇難具陳。", "浮嵐長作雨，冷氣不知春。", "少見寬平野，多逢腋腫民。", "欲知來處遠，巫峽是西鄰。"]'),
('a2d07aa9-ba80-4bd9-92a4-c3e295ef4dd0','題女媧山女媧廟  其二','孔平仲','宋','宋诗','song-poetry','','[]','突兀隘空虛，他山總不如。',24,'全唐诗/poet.song.53000.json','["突兀隘空虛，他山總不如。", "君看路傍石，盡是補天餘。"]'),
('6b93b067-ff61-44ac-9863-629303282d9c','和蕭十六人名  其一','孔平仲','宋','宋诗','song-poetry','','[]','贛江淹泊嗟旅滯，子夜蕭蕭復無睡。',128,'全唐诗/poet.song.53000.json','["贛江淹泊嗟旅滯，子夜蕭蕭復無睡。", "鄉程千里斷書來，律管仲冬迎日至。", "空山屈曲環高塔，與子游嬉同眺視。", "日沈北陸雲冥冥，晚景丹楓照川涘。", "蘭房鳳枕可自娛，桃李尋春舊遊地。", "便將躍馬超然往，向人直不疑心事。", "嬋娟一笑應奉留，醉倚王孫寶釵墜。", "更持大白起祝君，偕老子須堅此志。"]'),
('8796e221-dc7f-4da3-94cd-fedfccf0573b','和蕭十六人名  其二','孔平仲','宋','宋诗','song-poetry','','[]','式微子歎歸期滯，疏鐘皓月僧窗睡。',128,'全唐诗/poet.song.53000.json','["式微子歎歸期滯，疏鐘皓月僧窗睡。", "滿郭丹楓已送秋，李白桃紅春又至。", "綠楊朱戶鎖娉婷，燕趙一笑誰相視。", "紅顔回盼能溺人，有若大川無際涘。", "吾曹操行薄雲天，去險就平當擇地。", "嚴君平昔教諸子，肯向贛江爲此事。", "勿損仁義縱歡娛，力與主張興廢墜。", "不才强使酬杜詩，搦管寧能言鄙志。"]'),
('c168eb9d-6a9b-4bd1-a079-dd05c97d7a48','和蕭十六人名  其三','孔平仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','贛陽嶠北氣鬰滯，晨興何晏惟昏睡。',128,'全唐诗/poet.song.53000.json','["贛陽嶠北氣鬰滯，晨興何晏惟昏睡。", "江左雄豪每自奇，學孟希韓非不至。", "奈何進取位尚卑，上官儀檢多輕視。", "金朱浮華奚足戀，策馬周遊窮海涘。", "從茲岩谷永遁逃，請師丹竈捐塵事。", "廬山簡寂尋舊隠，雪竇參禪入初地。", "誰能榮謝混流俗，居常衮衮隨升墜。", "鋪張翰墨作小詩，聊陳平昔烟霞志。"]'),
('b08d9cfa-8d95-460d-bd29-5e96e5af24a7','和蕭十六人名  其四','孔平仲','宋','宋诗','song-poetry','','[]','爲憐城郭太留滯，知子思家方悶睡。',128,'全唐诗/poet.song.53000.json','["爲憐城郭太留滯，知子思家方悶睡。", "故停車馬良久住，相顧雍容情益至。", "樓高適意同一登，目極四周堪遠視。", "野田橫望繞天涯，梅朵開齊映江涘。", "冬溫庭筠尚抽筍，僧房喬木陰鋪地。", "丘樊嘉遁素有心，蕭蕭思話山中事。", "清楊俊邁君自許，魯國淵源吾不墜。", "與君詩戰奈何休，抑揚雄思聊書志。"]'),
('c92b5f38-b9ad-47fe-805b-20756c57bcfb','和蕭十六人名  其五','孔平仲','宋','宋诗','song-poetry','','[]','丘樊英俊君猶滯，掩卷無言偃然睡。',128,'全唐诗/poet.song.53000.json','["丘樊英俊君猶滯，掩卷無言偃然睡。", "江左思歸未得歸，家鄉百里奚由至。", "有樓望遠最舒曠，躡屐徐登極臨視。", "雲容弄白起危巔，霞氣如朱浮淺涘。", "侵梁松影側窺簷，飄徑柳芳深委地。", "諦法真空佛有靈，面顔安樂僧無事。", "風摇柏直力相爭，霜壓橘黄香欲墜。", "夕陽城郭人漸稀，疏鐘傳響催歸志。"]'),
('b0909147-6ab0-47a1-86ef-6cc1b19555c9','和蕭十六人名  其六','孔平仲','宋','宋诗','song-poetry','','[]','爲文愛子都無滯，疾讀數張堪醒睡。',128,'全唐诗/poet.song.53000.json','["爲文愛子都無滯，疾讀數張堪醒睡。", "唱高郢曲詞調古，銳比干將才力至。", "主張衡鑑付誰人，奈何並不蒙收視。", "吾王尊儒跨古始，有宋登科連海涘。", "况君當時苗裔遠，酇侯喜且興門地。", "少年自許升青雲，衰謝安知未成事。", "栖栖孔孟嘗如此，吾曹節操無顛墜。", "願言雅度尚自寬，時來濟物當如志。"]'),
('8efbb784-6399-4872-bf97-017c86c0ae26','方逢原借示方干先生詩以集句詩贈之  其一','孔平仲','宋','宋诗','song-poetry','','[]','裁霞曳繡一篇篇，要見功夫在筆端。',32,'全唐诗/poet.song.53000.json','["裁霞曳繡一篇篇，要見功夫在筆端。", "心恐借留中不遂，尋常未便借人看。"]'),
('bce8aaa2-1b8c-4462-8fbd-d6080bdf24c1','方逢原借示方干先生詩以集句詩贈之  其二','孔平仲','宋','宋诗','song-poetry','','[]','潜夫自有孤雲侶，蟾蜍影裏清吟苦。',32,'全唐诗/poet.song.53000.json','["潜夫自有孤雲侶，蟾蜍影裏清吟苦。", "澄心不出風騷外，援筆便成鸚鵡賦。"]'),
('0b8bdef0-5c59-4992-9423-630ec257f6be','方逢原借示方干先生詩以集句詩贈之  其三','孔平仲','宋','宋诗','song-poetry','','[]','醉醒多在釣魚磯，越國雲溪秀發時。',32,'全唐诗/poet.song.53000.json','["醉醒多在釣魚磯，越國雲溪秀發時。", "只用篇章爲教化，聲聲可作後人師。"]'),
('840500a2-b747-4eaf-9dd6-42744dd0cc0a','方逢原借示方干先生詩以集句詩贈之  其四','孔平仲','宋','宋诗','song-poetry','','[]','援筆皆成出世文，坐看孤峭却勞神。',32,'全唐诗/poet.song.53000.json','["援筆皆成出世文，坐看孤峭却勞神。", "直須分付丹青手，緬想應無前後人。"]'),
('51c74050-fd61-459d-863f-d03ffeb9c7fe','方逢原借示方干先生詩以集句詩贈之  其五','孔平仲','宋','宋诗','song-poetry','','[]','遠壑度年如晦暝，澄潭到底不容塵。',32,'全唐诗/poet.song.53000.json','["遠壑度年如晦暝，澄潭到底不容塵。", "公卿若更遺名姓，甘棹漁舟下釣綸。"]'),
('1c60fab0-e992-4075-95ab-06d09031a3de','戲張天覺  其一','孔平仲','宋','宋诗','song-poetry','','[]','踔躒英才比孟陽，合排三戟坐朝堂。',64,'全唐诗/poet.song.53000.json','["踔躒英才比孟陽，合排三戟坐朝堂。", "鱸魚莫憶江東鱠，竹葉聊煎仲景湯。", "屢選青錢文足羨，嘗乘白馬諫何强。", "知君每厲霜崖操，未怕朱雲請尚方。"]'),
('f2b38364-f50f-4e8a-9d08-1ca93d2bb50c','戲張天覺  其二','孔平仲','宋','宋诗','song-poetry','','[]','當路埋輪氣慨慷，身長九尺貌堂堂。',64,'全唐诗/poet.song.53000.json','["當路埋輪氣慨慷，身長九尺貌堂堂。", "高吟當似封侯祐，巧詆寧同小吏湯。", "幽閣畫眉多窈窕，華巔飲酒自康强。", "知君博物饒才思，近試家傳辟穀方。"]'),
('7c663b18-4349-440a-a153-402b4367963b','八音詩呈諸公','孔平仲','宋','宋诗','song-poetry','','[]','金罍美酒斗十千，石榴花開窗戶前。',64,'全唐诗/poet.song.53000.json','["金罍美酒斗十千，石榴花開窗戶前。", "絲棼萬事何足言，竹溪六逸方醉眠。", "匏瓜繫焉雖不久，土風堪美人皆賢。", "革易暌散心惘然，木在高山魚逐泉。"]'),
('76575a41-c04b-4d92-b415-4bcb183bbfac','再賦','孔平仲','宋','宋诗','song-poetry','','[]','金房此去路幾千，石瀨齒齒秋風前。',64,'全唐诗/poet.song.53000.json','["金房此去路幾千，石瀨齒齒秋風前。", "絲侵兩鬢老不言，竹實已空饑鳳眠。", "匏笙吹作別離曲，土壞漸異思諸賢。", "革屨練服何蕭然，木陰緩步尋雙泉。"]'),
('1ef0486d-9284-4f18-bac1-1d6e1fb6b726','和天覺錢朝散度上餘興之作','孔平仲','宋','宋诗','song-poetry','','[]','金輪演法教大千，石沙蒸飯戒在前。',64,'全唐诗/poet.song.53000.json','["金輪演法教大千，石沙蒸飯戒在前。", "絲挂千鈞危何言，竹映南窗猶可眠。", "匏簧弦索莫妄想，土視粉黛寧非賢。", "革面匪誠君豈然，木强我只思林泉。"]'),
('2644f201-978b-480b-8d4b-1e3b887ca124','和天覺贈仲光','孔平仲','宋','宋诗','song-poetry','','[]','金聲玉振辨服千，石稜蝟磔奮無前。',64,'全唐诗/poet.song.53000.json','["金聲玉振辨服千，石稜蝟磔奮無前。", "絲亂獲理頼正言，竹有特操非芊眠。", "匏羹淡薄葅醢貴，土鼓擯棄淫哇賢。", "革去浮僞真慨然，木秀風摧堆毀泉。"]'),
('65da2d32-8f22-4921-bbf3-aa1c03270e2b','奉使京西呈諸公','孔平仲','宋','宋诗','song-poetry','','[]','金科備使提三千，石馬泥牛鞭不前。',64,'全唐诗/poet.song.53000.json','["金科備使提三千，石馬泥牛鞭不前。", "絲麻民足吾何言，竹輿山行秋雨眠。", "匏黄芋紫漢上囗，土人當有龐葛賢。", "革車戰艦今不然，木杪鳳栖龍戲泉。"]'),
('63ead918-8df4-49c3-b9d3-ef1cfe5ae3fd','寶劍一首贈天覺','孔平仲','宋','宋诗','song-poetry','','[]','金裝寶劍值萬千，石上橫磨太古前。',64,'全唐诗/poet.song.53000.json','["金裝寶劍值萬千，石上橫磨太古前。", "絲緱消爛那復言，竹杖未化蛟龍眠。", "匏裁瓠切隨所用，土拭當有張雷賢。", "革室夜鎖聲鏗然，木刃誰與淬寒泉。"]'),
('0cd7773f-8b59-4bc3-992e-7cca17743f73','和天覺','孔平仲','宋','宋诗','song-poetry','','[]','金章玉佩動百千，石火光中風葉前。',64,'全唐诗/poet.song.53000.json','["金章玉佩動百千，石火光中風葉前。", "絲鞭相揖笑不言，竹下有人想待眠。", "匏身落蒂終腐爛，土壁繪像誰愚賢。", "革貪懲躁心泰然，木食草衣行飲泉。"]'),
('056f3dd8-f229-41eb-a739-dc7630b7d5cd','平上去入四首寄豫章舊同官  其一','孔平仲','宋','宋诗','song-poetry','','[]','思君何時休，川長波悠悠。',48,'全唐诗/poet.song.53000.json','["思君何時休，川長波悠悠。", "棋枰今生塵，詩筒誰相酬。", "諸公皆才豪，吾衰慚非儔。", "猶當陪從容，重游東湖舟。"]'),
('5f851acb-e3b4-48b4-a5d8-6e15726f8cee','平上去入四首寄豫章舊同官  其二','孔平仲','宋','宋诗','song-poetry','','[]','鍾陵朋寮中，我鄙且蹇淺。',48,'全唐诗/poet.song.53000.json','["鍾陵朋寮中，我鄙且蹇淺。", "諸公無緇磷，許我以繾綣。", "難題詩交鋒，小戶酒減盞。", "荒村今誰同，引領迤邐遠。"]'),
('26c6ef7e-212e-4c7b-a3da-6f0fc7469fc9','平上去入四首寄豫章舊同官  其三','孔平仲','宋','宋诗','song-poetry','','[]','鏗鏘非金絲，唱和旦至暮。',48,'全唐诗/poet.song.53000.json','["鏗鏘非金絲，唱和旦至暮。", "予頑居其間，鄭衛厠大濩。", "濛濛烟波中，遇興自綴句。", "猶承諸公餘，膏潤譬霧露。"]'),
('6284710e-3216-4b9c-bac3-d05bba9d9c01','平上去入四首寄豫章舊同官  其四','孔平仲','宋','宋诗','song-poetry','','[]','相從雖須臾，博約實得益。',48,'全唐诗/poet.song.53000.json','["相從雖須臾，博約實得益。", "交情何其深，弗易若竹柏。", "烟迷青楓林，日落白石壁。", "船窗居無聊，嘿嘿獨憶昔。"]'),
('7ef29e2c-be53-43be-b715-b2c7fa32a9cd','寄江西舊同寮','孔平仲','宋','宋诗','song-poetry','','[]','爲詩摛奇詞，美矣似花蕊。',96,'全唐诗/poet.song.53000.json','["爲詩摛奇詞，美矣似花蕊。", "而思衰遲資，揣己恥比儗。", "卑萎疲追隨，此鄙彼綺靡。", "差池誰知之，迤邐上梓里。", "移時池之涯，或息石壁側。", "詩嬉誰爲雌，奕劇白敵黑。", "追馳麾罷羸，力擊劃霹靂。", "羈離彌思維，闃寂益憶昔。"]'),
('fb001a3a-e9db-42d9-ada0-7cd5b8dbef31','還鄉展省道中作四聲詩寄豫章寮友  其一','孔平仲','宋','宋诗','song-poetry','','[]','蕭灘波潺湲，巴丘山崔嵬。',48,'全唐诗/poet.song.53000.json','["蕭灘波潺湲，巴丘山崔嵬。", "江天如相迎，風吹浮雲開。", "思鄉人皆然，惟予頻歸來。", "松楸稱青鮮，舂容生泉臺。"]'),
('38667ae2-c091-4eff-ab3c-183c4cbe0da9','還鄉展省道中作四聲詩寄豫章寮友  其二','孔平仲','宋','宋诗','song-poetry','','[]','久雨水陡長，泱漭似海廣。',48,'全唐诗/poet.song.53000.json','["久雨水陡長，泱漭似海廣。", "葦底解小艇，曉起蕩兩槳。", "早飯野篠下，鳥語靜愈響。", "有酒我不飲，引領但子想。"]'),
('b3e9854c-0d29-409a-a534-5118c156eebe','還鄉展省道中作四聲詩寄豫章寮友  其三','孔平仲','宋','宋诗','song-poetry','','[]','四際又暮夜，意詣尚未到。',48,'全唐诗/poet.song.53000.json','["四際又暮夜，意詣尚未到。", "繫纜坐樹陰，嘒嘒厭聚噪。", "徑步氣向暝，岸嘯韵自報。", "內顧自慰幸，比歲屢拜掃。"]'),
('c721333c-cf0a-4ed4-b8a4-ac555112c123','還鄉展省道中作四聲詩寄豫章寮友  其四','孔平仲','宋','宋诗','song-poetry','','[]','執熱逼入伏，一葉益局促。',48,'全唐诗/poet.song.53000.json','["執熱逼入伏，一葉益局促。", "日落月欲出，豁若脫桎梏。", "木色鬰碧幄，竹節削綠玉。", "赤脚踏白石，宿泊得沐浴。"]'),
('86f63b00-4bd4-4b08-927b-b6e5b830e2e5','寄江西同官','孔平仲','宋','宋诗','song-poetry','','[]','心欲從容且再期，月餘聚散忽參差。',64,'全唐诗/poet.song.53000.json','["心欲從容且再期，月餘聚散忽參差。", "工於酬唱皆詞客，各有輸贏屢奕棋。", "木蔭坐時班細草，早凉行處折紅葵。", "天涯回首思高會，日落烟昏今自悲。"]'),
('6d542108-4deb-4b62-8919-2451303dca40','呈魏道輔','孔平仲','宋','宋诗','song-poetry','','[]','今夕清寒轉不禁，小窗積雪氣蕭森。',64,'全唐诗/poet.song.53000.json','["今夕清寒轉不禁，小窗積雪氣蕭森。", "林迎新歲花爭出，山背殘陽影半尋。", "寸步故人猶隔面，回陽孤館想來音。", "日期笑語歡相慰，心亦須君續斷琴。"]'),
('6bc81e03-277b-4a43-bc8c-8dea641a2581','呈張子平','孔平仲','宋','宋诗','song-poetry','','[]','王駱聲華星斗旁，方州投老憩甘棠。',64,'全唐诗/poet.song.53000.json','["王駱聲華星斗旁，方州投老憩甘棠。", "木逃剪伐枝長碧，石耐鎸磨性有常。", "巾褚藏經勤問學，子孫傳業富文章。", "十年流落歸何暮，日聽除書侍玉皇。"]');
